#include <iostream>
#include <vector>
#include <algorithm>
#include <limits>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int T;
    std::cin >> T;
    while (T--) {
        int n;
        long long k;
        std::cin >> n >> k;
        std::vector<long long> a(n);
        long long min_val = std::numeric_limits<long long>::max();
        int min_idx = -1;
        for (int i = 0; i < n; ++i) {
            std::cin >> a[i];
            if (a[i] < min_val) {
                min_val = a[i];
                min_idx = i;
            }
        }

        long long total_spells = 0;
        for (int i = 0; i < n; ++i) {
            if (i == min_idx) {
                continue; // Cannot copy a pile to itself
            }
            // For each other pile, we can add min_val until it exceeds k
            // a[i] + x * min_val <= k
            // x * min_val <= k - a[i]
            // x <= (k - a[i]) / min_val
            total_spells += (k - a[i]) / min_val;
        }
        std::cout << total_spells << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
    }

    // The simplest way to get a different permutation with the same fingerprint
    // is to reverse the original permutation.
    // F(p) = sort([p_1+p_2, p_2+p_3, ..., p_{n-1}+p_n])
    // Let p' be the reverse of p: p'_i = p_{n-i+1}.
    // p' = [p_n, p_{n-1}, ..., p_2, p_1]
    // F(p') = sort([p_n+p_{n-1}, p_{n-1}+p_{n-2}, ..., p_2+p_1])
    // Since addition is commutative, the set of sums {p_i+p_{i+1}} is the same
    // as the set of sums {p_{i+1}+p_i}.
    // Therefore, F(p) and F(p') will be identical.
    // The only case where p' might be equal to p is if p is a palindrome,
    // but a permutation cannot be a palindrome unless n=1 (which is not allowed, n>=2)
    // or n=2 and p=[1,2] or p=[2,1] (which are not palindromes).
    // For n=2, p=[1,2], p'=[2,1]. They are different.
    // For n > 2, a permutation cannot be a palindrome because it would imply
    // p_1 = p_n, p_2 = p_{n-1}, etc., which would mean elements are repeated
    // if n is odd, or if n is even and p_i = p_{n-i+1} for all i,
    // then the set of elements {p_1, ..., p_{n/2}} would be the same as
    // {p_{n/2+1}, ..., p_n} but in reverse order, which is fine.
    // However, for p to be a palindrome, p_i must equal p_{n-i+1}.
    // For example, if n=4, p=[1,2,3,4]. Reverse is [4,3,2,1]. Different.
    // If p=[1,2,2,1], not a permutation.
    // A permutation cannot be a palindrome unless n=1.
    // For n >= 2, reversing a permutation always yields a different permutation.

    std::reverse(p.begin(), p.end());

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;
}

