    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <cmath>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int T;
    std::cin >> T;
    while (T--) {
        long long a, b;
        std::cin >> a >> b;
        if (a == b) {
            std::cout << 0 << "\n";
            continue;
        }
        long long diff = std::abs(a - b);
        long long presses = 0;

        // Use 5s
        presses += diff / 5;
        diff %= 5;

        // Remaining diff can be 0, 1, 2, 3, 4
        if (diff == 0) {
            // No additional presses needed
        } else if (diff == 1) {
            // Can be achieved by 1 press (+1 or -1)
            presses += 1;
        } else if (diff == 2) {
            // Can be achieved by 1 press (+2 or -2)
            presses += 1;
        } else if (diff == 3) {
            // Can be achieved by 2 presses (e.g., +1, +2 or +2, +1)
            // Or (5, -2) if we had a 5 before.
            // If diff was 3, and we used 5s, it means the original diff was X*5 + 3.
            // We can replace one 5 with (2+1) or (1+2) or (5-2) or (5-1-1)
            // Example: 8 -> 5+3. If we use 5, remaining 3. Need 2 more. Total 1+2=3.
            // Alternative: 8 -> 5+2+1. Total 3.
            // Alternative: 8 -> 2+2+2+2. Total 4.
            // Alternative: 8 -> 5+5-2. Total 3.
            // The greedy approach for 3 is 1+2 or 2+1, which is 2 presses.
            presses += 2;
        } else if (diff == 4) {
            // Can be achieved by 2 presses (e.g., +2, +2)
            // Or (5, -1) if we had a 5 before.
            // If diff was 4, and we used 5s, it means the original diff was X*5 + 4.
            // We can replace one 5 with (2+2) or (1+1+2) or (5-1)
            // Example: 9 -> 5+4. If we use 5, remaining 4. Need 2 more. Total 1+2=3.
            // Alternative: 9 -> 5+2+2. Total 3.
            // Alternative: 9 -> 5+1+1+1+1. Total 5.
            // Alternative: 9 -> 5+5-1. Total 3.
            // The greedy approach for 4 is 2+2, which is 2 presses.
            presses += 2;
        }
        std::cout << presses << "\n";
    }
    return 0;
}

