        bool common_char_found = false;
        // A simple way to check for common characters is to use a frequency array
        // or a boolean array for presence.
        // Since characters are lowercase Latin letters, an array of size 26 is sufficient.
        bool s_chars[26] = {false};
        bool t_chars[26] = {false};

        for (char c : s) {
            s_chars[c - 'a'] = true;
        }

