#include <iostream>
#include <vector>
#include <numeric>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    std::vector<long long> b(n);
    int has_pos_one = 0; // 1 if there's a 1 at or before current index
    int has_neg_one = 0; // 1 if there's a -1 at or before current index

    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }
    for (int i = 0; i < n; ++i) {
        std::cin >> b[i];
    }

    for (int i = 0; i < n; ++i) {
        if (a[i] != b[i]) {
            if (a[i] < b[i]) { // Need to increase a[i]
                if (!has_pos_one) {
                    std::cout << "NO\n";
                    return;
                }
            } else { // a[i] > b[i], need to decrease a[i]
                if (!has_neg_one) {
                    std::cout << "NO\n";
                    return;
                }
            }
        }

        // Update has_pos_one and has_neg_one for the next iteration
        if (a[i] == 1) {
            has_pos_one = 1;
        } else if (a[i] == -1) {
            has_neg_one = 1;
        }
    }

    std::cout << "YES\n";
}

