#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    long long T;
    std::cin >> n >> T;
    std::vector<long long> a(n);
    std::vector<int> p(n); // 0 for white (c), 1 for black (d)

    bool T_is_even = (T % 2 == 0);
    long long T_half = T / 2;

    int color_for_T_half = 0; // 0 for white, 1 for black. Alternates for T/2 elements.

    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
        if (a[i] < T_half) {
            p[i] = 0; // Always put elements < T/2 into array c (white)
        } else if (a[i] > T_half) {
            p[i] = 1; // Always put elements > T/2 into array d (black)
        } else { // a[i] == T_half
            if (T_is_even) {
                // For elements equal to T/2, alternate colors
                p[i] = color_for_T_half;
                color_for_T_half = 1 - color_for_T_half; // Flip color for next T/2 element
            } else {
                // T is odd, so a[i] == T/2 is impossible for integer a[i]
                // This branch should not be reached if a[i] are integers.
                // However, if T/2 is interpreted as float, then a[i] == T/2 means a[i] is not an integer.
                // Given a_i are non-negative integers, this case implies T must be even.
                // If T is odd, a[i] can never be T/2. So this else branch is effectively for T_is_even.
                // To be safe, if T is odd and a[i] somehow equals T/2 (e.g., T=7, a[i]=3.5),
                // it would fall into < T/2 or > T/2 based on integer comparison.
                // But problem states a_i are integers. So if T is odd, a[i] can't be T/2.
                // Thus, this else block is only for T_is_even.
                p[i] = color_for_T_half;
                color_for_T_half = 1 - color_for_T_half;
            }
        }
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::vector<std::vector<int>> a(n, std::vector<int>(n));
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < n; ++j) {
            std::cin >> a[i][j];
        }
    }

    std::vector<int> p(n);
    for (int i = 0; i < n; ++i) {
        int max_val_in_row = 0;
        for (int j = 0; j < n; ++j) {
            if (i == j) continue;
            if (a[i][j] > max_val_in_row) {
                max_val_in_row = a[i][j];
            }
        }
        p[i] = max_val_in_row;
    }

    // Check if any element in p is n-1 and no element is n.
    // This happens if the original permutation contained n, but min(n, x) = x for x < n.
    // So, if p[i] was n, max_val_in_row would be n-1 (assuming n-1 is present in p).
    // If n is not present in the reconstructed p, it means one of the p[i] values
    // should actually be n.
    bool n_found = false;
    for (int val : p) {
        if (val == n) {
            n_found = true;
            break;
        }
    }

    if (!n_found) {
        // If n is not found in the reconstructed p, it means one of the elements
        // that was originally n got assigned n-1 because all other elements were smaller.
        // We need to find the first occurrence of n-1 and change it to n.
        // Since the problem guarantees a solution, there will be exactly one such case.
        for (int i = 0; i < n; ++i) {
            if (p[i] == n - 1) {
                p[i] = n;
                break;
            }
        }
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <string>
#include <algorithm>
#include <vector>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        std::string s;
        std::cin >> s;
        int max_gap = 0;
        int last_r_pos = -1; // Represents the position of the last 'R' or the starting point 0.
                             // If last_r_pos is -1, it means the frog is at cell 0.
                             // If last_r_pos is i, it means the frog is at cell i.
                             // The actual cell index is last_r_pos + 1 for string s.

        for (int i = 0; i < s.length(); ++i) {
            if (s[i] == 'R') {
                // The current cell is i+1.
                // The previous 'R' or start was at last_r_pos.
                // The distance between the current 'R' and the previous 'R' (or start) is (i+1) - (last_r_pos + 1) = i - last_r_pos.
                // Or, more simply, the distance between indices is i - last_r_pos.
                max_gap = std::max(max_gap, i - last_r_pos);
                last_r_pos = i;
            }
        }
        // After iterating through the string, consider the jump from the last 'R' (or start if no 'R's) to n+1.
        // The last 'R' was at index last_r_pos. The cell is last_r_pos + 1.
        // The target is n+1.
        // The distance is (n+1) - (last_r_pos + 1) = n - last_r_pos.
        max_gap = std::max(max_gap, (int)s.length() - last_r_pos);
        std::cout << max_gap << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long x;
        std::cin >> x;

        // Precompute costs for nice staircases
        // A nice staircase with n stairs has n = 2^k - 1.
        // The cost for n stairs is n * (n + 1) / 2.
        // For n = 2^k - 1, cost = (2^k - 1) * (2^k) / 2.
        // Let m = 2^k. Then cost = (m - 1) * m / 2.
        // The sequence of m values is 2, 4, 8, 16, ...
        // The sequence of n values is 1, 3, 7, 15, ...
        // The sequence of costs is:
        // k=1, m=2, n=1: cost = (2-1)*2/2 = 1
        // k=2, m=4, n=3: cost = (4-1)*4/2 = 6
        // k=3, m=8, n=7: cost = (8-1)*8/2 = 28
        // k=4, m=16, n=15: cost = (16-1)*16/2 = 120
        // ...
        // The maximum x is 10^18.
        // We need to find k such that (2^k - 1) * 2^k / 2 <= 10^18.
        // Approximately (2^k)^2 / 2 <= 10^18 => (2^k)^2 <= 2 * 10^18
        // 2^k <= sqrt(2 * 10^18) = sqrt(2) * 10^9 approx 1.414 * 10^9
        // log2(1.414 * 10^9) = log2(1.414) + 9 * log2(10) approx 0.5 + 9 * 3.32 = 0.5 + 29.88 = 30.38
        // So k can go up to about 30.
        // Let's generate costs.

        std::vector<long long> nice_staircase_costs;
        long long current_m = 2; // Represents 2^k
        while (true) {
            long long cost = (current_m - 1) * current_m / 2;
            if (cost > x) { // If the smallest possible nice staircase is already too expensive
                break;
            }
            nice_staircase_costs.push_back(cost);
            if (current_m > x / 2) { // Avoid overflow for current_m * 2, and also if (current_m - 1) * current_m / 2 is already large
                break;
            }
            current_m *= 2;
        }

        int count = 0;
        for (int i = nice_staircase_costs.size() - 1; i >= 0; --i) {
            if (x >= nice_staircase_costs[i]) {
                x -= nice_staircase_costs[i];
                count++;
            }
        }
        std::cout << count << "\n";
    }
    return 0;
}

