void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    std::vector<int> pos(n + 1); // pos[val] stores the 0-indexed position of val in p
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
        pos[p[i]] = i;
    }

    std::string result = "";
    int min_idx = pos[1];
    int max_idx = pos[1];

    for (int m = 1; m <= n; ++m) {
        // Update min_idx and max_idx to include the current number 'm'
        min_idx = std::min(min_idx, pos[m]);
        max_idx = std::max(max_idx, pos[m]);

        // Check if the current subsegment [min_idx, max_idx]
        // contains all numbers from 1 to m and has length m.
        // The length of the subsegment is (max_idx - min_idx + 1).
        // If it contains all numbers from 1 to m, and its length is m,
        // then it must be a permutation of 1 to m.
        if (max_idx - min_idx + 1 == m) {
            result += '1';
        } else {
            result += '0';
        }
    }
    std::cout << result << std::endl;
}

