            std::cout << "Y 0.000000000 0.000000000\n";
        } else if (d < 4.0) {
            std::cout << "N\n";
        } else {
            // d^2 - 4d >= 0 is true for d >= 4
            // a = (d + sqrt(d^2 - 4d)) / 2
            // b = (d - sqrt(d^2 - 4d)) / 2
            double sqrt_discriminant = std::sqrt(d * d - 4.0 * d);
            double a = (d + sqrt_discriminant) / 2.0;
            double b = (d - sqrt_discriminant) / 2.0;

            // Check non-negativity for a and b.
            // Since d >= 4, d^2 - 4d >= 0.
            // sqrt(d^2 - 4d) is real.
            // d + sqrt(d^2 - 4d) is clearly non-negative.
            // For b, we need d - sqrt(d^2 - 4d) >= 0.
            // This is equivalent to d >= sqrt(d^2 - 4d).
            // Since both sides are non-negative, we can square them:
            // d^2 >= d^2 - 4d
            // 0 >= -4d
            // 4d >= 0
            // d >= 0.
            // Since d is given as non-negative, and we already handled d=0,
            // and for d >= 4, both a and b will be non-negative.

            std::cout << "Y " << std::fixed << std::setprecision(9) << a << " " << b << "\n";
        }
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <cmath>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    long long s;
    std::cin >> n >> s;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    std::sort(a.begin(), a.end());

    long long operations = 0;
    int median_idx = n / 2;

    // First, make the median element equal to s
    operations += std::abs(a[median_idx] - s);

    // If a[median_idx] is less than s, we need to increase it.
    // All elements to its left (a[0]...a[median_idx-1]) must be <= s.
    // If any of them are > s, they must be decreased to s.
    if (a[median_idx] < s) {
        for (int i = 0; i < median_idx; ++i) {
            if (a[i] > s) {
                operations += (a[i] - s);
            }
        }
    }
    // If a[median_idx] is greater than s, we need to decrease it.
    // All elements to its right (a[median_idx+1]...a[n-1]) must be >= s.
    // If any of them are < s, they must be increased to s.
    else if (a[median_idx] > s) {
        for (int i = median_idx + 1; i < n; ++i) {
            if (a[i] < s) {
                operations += (s - a[i]);
            }
        }
    }
    // If a[median_idx] == s, no operations for the median itself.
    // We still need to check elements to its left and right.
    // Elements to the left must be <= s.
    for (int i = 0; i < median_idx; ++i) {
        if (a[i] > s) {
            operations += (a[i] - s);
        }
    }
    // Elements to the right must be >= s.
    for (int i = median_idx + 1; i < n; ++i) {
        if (a[i] < s) {
            operations += (s - a[i]);
        }
    }

    std::cout << operations << std::endl;

    return 0;
}

#include <iostream>
