#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n == 1) {
        std::cout << "Yes\n";
        return;
    }

    // Calculate the maximum possible length of the strictly increasing prefix
    // starting from index 0 (value 0)
    // For a_i to be part of the increasing prefix, it must be at least i.
    // We can decrease a_i to i if a_i >= i.
    // The actual value of a_i can be larger than i, but it must be at least i.
    // So, we find the first index `i` where `a[i] < i`.
    // All elements before this index `i` (i.e., `a[0]` to `a[i-1]`) can potentially
    // form the increasing prefix `0, 1, ..., i-1`.
    int left_len = 0;
    for (int i = 0; i < n; ++i) {
        if (a[i] >= i) {
            left_len++;
        } else {
            break;
        }
    }

    // Calculate the maximum possible length of the strictly decreasing suffix
    // starting from index n-1 (value 0)
    // For a_i to be part of the decreasing suffix, it must be at least (n-1-i).
    // We can decrease a_i to (n-1-i) if a_i >= (n-1-i).
    // The actual value of a_i can be larger than (n-1-i), but it must be at least (n-1-i).
    // So, we find the first index `i` (from right) where `a[i] < (n-1-i)`.
    // All elements after this index `i` (i.e., `a[i+1]` to `a[n-1]`) can potentially
    // form the decreasing suffix `..., 1, 0`.
    int right_len = 0;
    for (int i = n - 1; i >= 0; --i) {
        if (a[i] >= (n - 1 - i)) {
            right_len++;
        } else {
            break;
        }
    }

    // If the sum of the lengths of the potential increasing prefix and decreasing suffix
    // is greater than or equal to n, it means there's at least one common element
    // that can serve as the peak 'k'.
    // For example, if left_len = 3 and right_len = 4 for n = 5:
    // Left part can be 0, 1, 2 (indices 0, 1, 2)
    // Right part can be 2, 1, 0 (indices 2, 3, 4)
    // Index 2 is common.
    // The condition `left_len + right_len >= n` ensures that there is at least one index `k`
    // such that `a[k]` can be part of both the increasing prefix and the decreasing suffix.
    // Specifically, `k` must be in `[0, left_len-1]` and `k` must be in `[n-right_len, n-1]`.
    // The intersection of these ranges is non-empty if `left_len-1 >= n-right_len`,
    // which simplifies to `left_len + right_len >= n + 1`.
    // Wait, the problem statement says `a_1 < ... < a_k` and `a_k > ... > a_n`.
    // This means `a_k` is the peak.
    // The left part is `a_0, ..., a_{k-1}` and the right part is `a_{k+1}, ..., a_{n-1}`.
    // The peak `a_k` must satisfy `a_k >= k` (from left) and `a_k >= n-1-k` (from right).
    // The `left_len` is the count of elements `a[0]...a[left_len-1]` that can form `0...left_len-1`.
    // The `right_len` is the count of elements `a[n-right_len]...a[n-1]` that can form `right_len-1...0`.
    // If `left_len + right_len > n`, it means there's an overlap.
    // For example, if `n=3`, `left_len=2`, `right_len=2`. `left_len+right_len = 4 > 3`.
    // `a[0], a[1]` can be `0, 1`. `a[1], a[2]` can be `1, 0`.
    // `a[1]` is the peak. It can be `1`.
    // The condition `left_len + right_len > n` is correct.
    // If `left_len + right_len == n`, it means there is no overlap, and the peak would be "between" the two parts.
    // E.g., `n=2`, `left_len=1`, `right_len=1`. `left_len+right_len = 2 = n`.
    // `a[0]` can be `0`. `a[1]` can be `0`. No peak possible.
    // The peak `k` must be an actual index.
    // The indices that can be a peak are `[0, left_len-1]` from the left perspective,
    // and `[n-right_len, n-1]` from the right perspective.
    // We need to find an index `k` such that `k < left_len` AND `k >= n - right_len`.
    // This means `left_len > n - right_len`, or `left_len + right_len > n`.

    if (left_len + right_len > n) {
        std::cout << "Yes\n";
    } else {
        std::cout << "No\n";
    }
}

