#include <algorithm>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    std::sort(a.begin(), a.end());

    int count = 0;
    int j = 0; // Pointer for the elements we want to place (larger elements)
    for (int i = 0; i < n; ++i) { // Pointer for the original positions (smaller elements)
        // We are trying to find an element a[j] such that a[j] > a[i]
        // Since both arrays are sorted, if a[j] > a[i], then a[j+1], a[j+2], ... will also be > a[i]
        // We want to use the smallest possible a[j] that is greater than a[i]
        // to save larger elements for later, potentially larger a[i]'s.
        while (j < n && a[j] <= a[i]) {
            j++;
        }
        if (j < n) { // Found an element a[j] > a[i]
            count++;
            j++; // Move to the next element in the 'larger' pool
        } else {
            // No more elements in 'a' are greater than a[i]
            // Since 'a' is sorted, no subsequent a[k] (k > i) will have a greater element available either.
            break; 
        }
    }

    std::cout << count << std::endl;

    return 0;
}

#include <iostream>
