struct Element {
    long long value;
    int original_index;
};

bool compareElements(const Element& a, const Element& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int m;
    std::cin >> m;

    std::vector<Element> a_elements(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> a_elements[i].value;
        a_elements[i].original_index = i; // Not strictly needed for A, but good practice
    }

    std::vector<Element> b_elements(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> b_elements[i].value;
        b_elements[i].original_index = i;
    }

    // Sort A in ascending order
    std::sort(a_elements.begin(), a_elements.end(), compareElements);

    // Sort B in descending order based on value
    // If values are equal, original index doesn't matter for sorting B itself,
    // but it's crucial for mapping back to the output array.
    std::sort(b_elements.begin(), b_elements.end(), [](const Element& a, const Element& b) {
        return a.value > b.value;
    });

    std::vector<long long> result_a_prime(m);

    // Assign sorted A values to positions determined by sorted B's original indices
    for (int i = 0; i < m; ++i) {
        // The i-th smallest A value (a_elements[i].value)
        // should be paired with the B value that was originally at b_elements[i].original_index
        // (which is the i-th largest B value).
        // So, a_elements[i].value goes into the position b_elements[i].original_index in the result array.
        result_a_prime[b_elements[i].original_index] = a_elements[i].value;
    }

    for (int i = 0; i < m; ++i) {
        std::cout << result_a_prime[i] << (i == m - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

