// Function to check if a subarray is a permutation of length 'len'
// It checks if all numbers from 1 to len are present exactly once.
bool is_permutation(const std::vector<int>& arr, int start_idx, int len) {
    if (len <= 0) {
        return false; // A permutation must have positive length
    }
    if (start_idx + len > arr.size()) {
        return false; // Subarray out of bounds
    }

    std::vector<bool> seen(len + 1, false); // Use 1-based indexing for numbers
    int max_val = 0;

    for (int i = 0; i < len; ++i) {
        int val = arr[start_idx + i];
        if (val <= 0 || val > len) {
            return false; // Value out of range [1, len]
        }
        if (seen[val]) {
            return false; // Duplicate value
        }
        seen[val] = true;
        if (val > max_val) {
            max_val = val;
        }
    }

    // After checking all elements, ensure all numbers from 1 to len were seen
    // and the maximum value is indeed len.
    // The max_val check is redundant if all numbers from 1 to len are present.
    // The seen array check is sufficient.
    for (int i = 1; i <= len; ++i) {
        if (!seen[i]) {
            return false;
        }
    }
    return true;
}

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    int max_val_a = 0;
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
        if (a[i] > max_val_a) {
            max_val_a = a[i];
        }
    }

    std::vector<std::pair<int, int>> results;

    // Precompute prefix maximums and suffix maximums
    std::vector<int> prefix_max(n);
    prefix_max[0] = a[0];
    for (int i = 1; i < n; ++i) {
        prefix_max[i] = std::max(prefix_max[i - 1], a[i]);
    }

    std::vector<int> suffix_max(n);
    suffix_max[n - 1] = a[n - 1];
    for (int i = n - 2; i >= 0; --i) {
        suffix_max[i] = std::max(suffix_max[i + 1], a[i]);
    }

    // Precompute prefix counts and suffix counts for distinct elements
    std::vector<int> prefix_distinct_count(n);
    std::vector<bool> seen_prefix(n + 1, false); // Max value can be n-1
    int current_distinct_prefix = 0;
    for (int i = 0; i < n; ++i) {
        if (!seen_prefix[a[i]]) {
            seen_prefix[a[i]] = true;
            current_distinct_prefix++;
        }
        prefix_distinct_count[i] = current_distinct_prefix;
    }

    std::vector<int> suffix_distinct_count(n);
    std::vector<bool> seen_suffix(n + 1, false);
    int current_distinct_suffix = 0;
    for (int i = n - 1; i >= 0; --i) {
        if (!seen_suffix[a[i]]) {
            seen_suffix[a[i]] = true;
            current_distinct_suffix++;
        }
        suffix_distinct_count[i] = current_distinct_suffix;
    }

    for (int l1 = 1; l1 < n; ++l1) { // l1 can range from 1 to n-1
        int l2 = n - l1;

        // Optimization: Check maximum values and distinct counts first
        if (prefix_max[l1 - 1] != l1 || prefix_distinct_count[l1 - 1] != l1) {
            continue;
        }
        if (suffix_max[l1] != l2 || suffix_distinct_count[l1] != l2) {
            continue;
        }

        // Full check for p1
        std::vector<bool> seen_p1(l1 + 1, false);
        bool p1_is_perm = true;
        for (int i = 0; i < l1; ++i) {
            if (a[i] <= 0 || a[i] > l1 || seen_p1[a[i]]) {
                p1_is_perm = false;
                break;
            }
            seen_p1[a[i]] = true;
        }
        if (!p1_is_perm) {
            continue;
        }
        // Check if all numbers from 1 to l1 are present
        for (int i = 1; i <= l1; ++i) {
            if (!seen_p1[i]) {
                p1_is_perm = false;
                break;
            }
        }
        if (!p1_is_perm) {
            continue;
        }

        // Full check for p2
        std::vector<bool> seen_p2(l2 + 1, false);
        bool p2_is_perm = true;
        for (int i = 0; i < l2; ++i) {
            if (a[l1 + i] <= 0 || a[l1 + i] > l2 || seen_p2[a[l1 + i]]) {
                p2_is_perm = false;
                break;
            }
            seen_p2[a[l1 + i]] = true;
        }
        if (!p2_is_perm) {
            continue;
        }
        // Check if all numbers from 1 to l2 are present
        for (int i = 1; i <= l2; ++i) {
            if (!seen_p2[i]) {
                p2_is_perm = false;
                break;
            }
        }
        if (!p2_is_perm) {
            continue;
        }

        results.push_back({l1, l2});
    }

    std::cout << results.size() << "\n";
    for (const auto& p : results) {
        std::cout << p.first << " " << p.second << "\n";
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

