int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::map<int, long long> x_counts;
    std::map<int, long long> y_counts;
    std::map<std::pair<int, int>, long long> xy_counts;

    for (int i = 0; i < n; ++i) {
        int x, y;
        std::cin >> x >> y;
        x_counts[x]++;
        y_counts[y]++;
        xy_counts[{x, y}]++;
    }

    long long total_pairs = 0;

    // Pairs on the same vertical line
    for (auto const& [x_coord, count] : x_counts) {
        if (count >= 2) {
            total_pairs += count * (count - 1) / 2;
        }
    }

    // Pairs on the same horizontal line
    for (auto const& [y_coord, count] : y_counts) {
        if (count >= 2) {
            total_pairs += count * (count - 1) / 2;
        }
    }

    // Subtract pairs that were counted twice (i.e., points that coincide)
    // These are pairs of identical points (x_i, y_i) = (x_j, y_j)
    // Such pairs are counted in both x_counts and y_counts.
    for (auto const& [coords, count] : xy_counts) {
        if (count >= 2) {
            total_pairs -= count * (count - 1) / 2;
        }
    }

    std::cout << total_pairs << std::endl;

    return 0;
}

