void solve() {
    std::string s;
    std::cin >> s;
    int x;
    std::cin >> x;

    int n = s.length();
    std::string w(n, '1'); // Initialize w with all '1's

    // Step 1: Use s_i = '0' to determine '0's in w
    for (int i = 0; i < n; ++i) {
        if (s[i] == '0') {
            // If s[i] is '0', then w[i-x] (if exists) must be '0'
            if (i - x >= 0) {
                w[i - x] = '0';
            }
            // And w[i+x] (if exists) must be '0'
            if (i + x < n) {
                w[i + x] = '0';
            }
        }
    }

    // Step 2: Verify if the constructed w can produce s
    std::string s_prime(n, '0'); // Calculate the s' that would be produced by our w
    for (int i = 0; i < n; ++i) {
        bool is_one = false;
        // Check w[i-x]
        if (i - x >= 0 && w[i - x] == '1') {
            is_one = true;
        }
        // Check w[i+x]
        if (i + x < n && w[i + x] == '1') {
            is_one = true;
        }
        if (is_one) {
            s_prime[i] = '1';
        }
    }

    // Step 3: Compare s_prime with the original s
    if (s_prime == s) {
        std::cout << w << std::endl;
    } else {
        std::cout << -1 << std::endl;
    }
}

