// Function to convert a number to its parity pattern string
std::string get_parity_pattern(long long n) {
    if (n == 0) {
        return "0";
    }
    std::string pattern = "";
    while (n > 0) {
        if ((n % 10) % 2 == 0) { // Even digit
            pattern += '0';
        } else { // Odd digit
            pattern += '1';
        }
        n /= 10;
    }
    // The problem statement implies that patterns are compared from right to left.
    // Storing them reversed (rightmost digit first) simplifies comparison/hashing.
    // Example: 241 -> 1 (odd), 4 (even), 2 (even) -> "100"
    return pattern;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int t;
    std::cin >> t;

    // Using a map to store counts of each normalized parity pattern.
    // The key is the normalized pattern string, value is its count.
    std::map<std::string, int> counts;

    for (int i = 0; i < t; ++i) {
        char type;
        std::cin >> type;

        if (type == '+') {
            long long a;
            std::cin >> a;
            std::string pattern = get_parity_pattern(a);
            counts[pattern]++;
        } else if (type == '-') {
            long long a;
            std::cin >> a;
            std::string pattern = get_parity_pattern(a);
            counts[pattern]--;
        } else if (type == '?') {
            std::string s;
            std::cin >> s;
            // Normalize the query pattern: pad with '0's to length 18
            // and reverse it to match the stored format (rightmost digit first).
            std::string normalized_query_pattern = "";
            for (char c : s) {
                normalized_query_pattern += c;
            }
            // The problem states "If the pattern is shorter than this integer, it's supplemented with 0-s from the left."
            // and "If the integer is shorter than the pattern its decimal notation is supplemented with the 0-s from the left."
            // This means we should pad both to a common maximum length (18 for 10^18 numbers).
            // Since we store patterns reversed (rightmost digit first), padding with '0's from the left
            // for the original number means padding with '0's at the end of our reversed string.
            // For the query pattern, if it's "010", it means rightmost is '0', middle '1', leftmost '0'.
            // If we reverse it to "010" (same in this case), and pad to 18, it becomes "01000...0".
            // This matches how we store numbers like 92 -> "01" (reversed).
            // If the query pattern is "010", and number is 92, its pattern is "01".
            // We need to match "01" with "010".
            // The rule is "parity of the i-th from the right digit ... matches the i-th from the right digit of the pattern."
            // This implies that if the number's pattern is shorter, it's effectively padded with '0's at the end (rightmost first).
            // If the query pattern is shorter, it's effectively padded with '0's at the end (rightmost first).
            // So, we need to pad the query pattern to the maximum possible length (18 digits for 10^18-1)
            // with '0's at the end of our reversed string.
            // Example: s = "010" (original). Reversed: "010". Padded to 18: "010000000000000000".
            // Example: s = "1" (original). Reversed: "1". Padded to 18: "100000000000000000".
            // This is consistent with how get_parity_pattern works and how map keys are formed.

            // The problem statement implies that the pattern `s` is given in standard left-to-right order.
            // "i-th from the right digit in decimal notation matches the i-th from the right digit of the pattern."
            // This means we should reverse the input pattern `s` to match our stored format.
            std::reverse(normalized_query_pattern.begin(), normalized_query_pattern.end());

            // Pad the reversed query pattern with '0's to length 18.
            // This ensures that if a number's pattern is shorter than the query,
            // or vice-versa, they are effectively compared up to the max length.
            // Since we store patterns with rightmost digit first, padding with '0's
            // at the end of our reversed string corresponds to padding with '0's
            // at the beginning of the original number/pattern.
            while (normalized_query_pattern.length() < 18) {
                normalized_query_pattern += '0';
            }

            // Now, iterate through the map and check for matches.
            // A stored pattern `p` matches `normalized_query_pattern` if
            // `p` is a prefix of `normalized_query_pattern`.
            // This is because `p` represents a number, and if `p` is shorter than 18,
            // it's implicitly padded with '0's to the right (in our reversed string).
            // So, "100" (for 241) matches "10000..." (for query "001").
            // And "01" (for 92) matches "01000..." (for query "010").

            int match_count = 0;
            for (auto const& [stored_pattern, count] : counts) {
                if (count > 0) {
                    // Check if the stored pattern is a prefix of the normalized query pattern.
                    // This handles cases where the number is shorter than the query pattern.
                    // Example: stored_pattern="01" (for 92), normalized_query_pattern="0100..." (for "010")
                    // "01" is a prefix of "0100...", so it matches.

                    // Also, we need to handle cases where the stored pattern is longer than the query pattern.
                    // Example: stored_pattern="0100" (for 2212), normalized_query_pattern="0100..." (for "010")
                    // The problem states: "If the pattern is shorter than this integer, it's supplemented with 0-s from the left."
                    // This means if the query pattern "010" is shorter than 2212's pattern "0100",
                    // the query pattern "010" is effectively "0010" for comparison.
                    // So, we need to compare up to the length of the *shorter* of the two,
                    // and assume padding with '0's for the longer one.
                    // Since we padded the query pattern to 18, we just need to check if the stored pattern
                    // matches the prefix of the normalized query pattern up to the length of the stored pattern.

                    bool current_pattern_matches = true;
                    for (size_t k = 0; k < stored_pattern.length(); ++k) {
                        if (k >= normalized_query_pattern.length()) {
                            // This case should not happen if normalized_query_pattern is always length 18.
                            // But if it were shorter, it means the stored pattern is longer.
                            // We assume padding with '0's for the query pattern.
                            if (stored_pattern[k] != '0') {
                                current_pattern_matches = false;
                                break;
                            }
                        } else if (stored_pattern[k] != normalized_query_pattern[k]) {
                            current_pattern_matches = false;
                            break;
                        }
                    }
                    if (current_pattern_matches) {
                        match_count += count;
                    }
                }
            }
            std::cout << match_count << "\n";
        }
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long l, r, Ql, Qr;
    std::cin >> n >> l >> r >> Ql >> Qr;

    std::vector<long long> w(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> w[i];
    }

    std::vector<long long> prefix_sum(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        prefix_sum[i + 1] = prefix_sum[i] + w[i];
    }

    long long min_energy = -1;

    // Iterate through all possible counts of items taken from the left
    // 'i' represents the number of items taken from the left (0 to n)
    for (int i = 0; i <= n; ++i) {
        long long current_energy = 0;

        // Cost for items taken from the left
        // These are w[0]...w[i-1]
        current_energy += prefix_sum[i] * l;

        // Cost for items taken from the right
        // These are w[i]...w[n-1] (total n-i items)
        // The sum of weights for these items is prefix_sum[n] - prefix_sum[i]
        current_energy += (prefix_sum[n] - prefix_sum[i]) * r;

        // Add penalty for consecutive actions
        int left_count = i;
        int right_count = n - i;

        if (left_count > right_count) {
            // More items taken from left.
            // The last few items taken from left might be consecutive.
            // The difference is left_count - right_count.
            // If left_count = right_count + 1, then the last item taken from left
            // is not consecutive with another left item (it's the first of a new sequence).
            // If left_count = right_count + k (k > 1), then k-1 extra Ql penalties.
            current_energy += (left_count - right_count - 1) * Ql;
        } else if (right_count > left_count) {
            // More items taken from right.
            // The last few items taken from right might be consecutive.
            // The difference is right_count - left_count.
            // If right_count = left_count + k (k > 1), then k-1 extra Qr penalties.
            current_energy += (right_count - left_count - 1) * Qr;
        }

        if (min_energy == -1 || current_energy < min_energy) {
            min_energy = current_energy;
        }
    }

    std::cout << min_energy << std::endl;

    return 0;
}

