// Function to find prime factors of a number
std::map<long long, int> prime_factorize(long long n) {
    std::map<long long, int> factors;
    for (long long i = 2; i * i <= n; ++i) {
        while (n % i == 0) {
            factors[i]++;
            n /= i;
        }
    }
    if (n > 1) {
        factors[n]++;
    }
    return factors;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long p, q;
        std::cin >> p >> q;

        if (p % q != 0) {
            std::cout << p << "\n";
            continue;
        }

        // If p is divisible by q, we need to find a divisor x of p such that x is not divisible by q.
        // We want the largest such x.
        // This means we need to remove some prime factors from p that are also in q,
        // such that the resulting number is no longer divisible by q, but is as large as possible.

        // Find prime factors of q
        std::map<long long, int> q_factors = prime_factorize(q);

        long long max_x = 1;

        // Iterate through each prime factor of q
        for (auto const& [prime_factor, q_exponent] : q_factors) {
            // Calculate the highest power of prime_factor that divides p
            long long current_p = p;
            int p_exponent = 0;
            while (current_p > 0 && current_p % prime_factor == 0) {
                p_exponent++;
                current_p /= prime_factor;
            }

            // If p_exponent is less than q_exponent, it means p is not divisible by q^q_exponent.
            // In this case, we don't need to remove this prime factor from p to make it not divisible by q.
            // However, the problem states p % q == 0, so p_exponent must be >= q_exponent for all prime factors of q.
            // We need to reduce the power of prime_factor in p such that it's less than q_exponent.
            // The largest such divisor of p would be p / (prime_factor ^ (p_exponent - q_exponent + 1)).
            // This ensures that the resulting number has (q_exponent - 1) powers of prime_factor,
            // making it not divisible by q^q_exponent (and thus not by q).

            long long divisor_to_remove = 1;
            for (int i = 0; i < p_exponent - q_exponent + 1; ++i) {
                divisor_to_remove *= prime_factor;
            }
            max_x = std::max(max_x, p / divisor_to_remove);
        }
        std::cout << max_x << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <algorithm>
#include <numeric>

void solve() {
    int n;
    std::cin >> n;
    std::string s;
    std::cin >> s;

    std::string result(n, ' ');
    bool possible = false;

    for (char split_char = '0'; split_char <= '9'; ++split_char) {
        std::string current_coloring(n, ' ');
        char last1 = '0';
        char last2 = '0';
        bool valid_split = true;
        bool first_digit_in_2_assigned = false;

        for (int i = 0; i < n; ++i) {
            char digit = s[i];
            if (digit < split_char) {
                // Must be color 1
                if (digit < last1) {
                    valid_split = false;
                    break;
                }
                current_coloring[i] = '1';
                last1 = digit;
            } else if (digit > split_char) {
                // Must be color 2
                if (digit < last2) {
                    valid_split = false;
                    break;
                }
                current_coloring[i] = '2';
                last2 = digit;
                first_digit_in_2_assigned = true;
            } else { // digit == split_char
                // Can be color 1 or 2
                // Prioritize color 2 if it helps maintain non-decreasing order for S1
                // and if it doesn't violate S2's non-decreasing order.
                // If we put it in color 1, it must be >= last1.
                // If we put it in color 2, it must be >= last2.
                // Also, if we put it in color 1, it must be <= first_digit_in_2.
                // The strategy is: put it in color 2 if it's the first 'split_char' or if it's after the first 'split_char'
                // and we've already started assigning to color 2.
                // More simply: put it in color 1 if it's before the first digit assigned to color 2.
                // Put it in color 2 if it's after or equal to the first digit assigned to color 2.
                // This ensures that all 'split_char's assigned to color 1 come before all 'split_char's assigned to color 2.

                // If we haven't started assigning to color 2 yet (i.e., no digit > split_char has been encountered)
                // AND this digit is >= last1, we can assign it to color 1.
                // This ensures all 'split_char's that go to color 1 are before any 'split_char' that goes to color 2.
                if (!first_digit_in_2_assigned && digit >= last1) {
                    current_coloring[i] = '1';
                    last1 = digit;
                } else {
                    // Otherwise, assign to color 2.
                    // This covers cases where:
                    // 1. first_digit_in_2_assigned is true (meaning we've already seen a digit > split_char)
                    // 2. digit < last1 (cannot be color 1 anyway, so must be color 2 if possible)
                    // In both cases, we try to assign to color 2.
                    if (digit < last2) {
                        valid_split = false;
                        break;
                    }
                    current_coloring[i] = '2';
                    last2 = digit;
                    first_digit_in_2_assigned = true;
                }
            }
        }

        if (valid_split) {
            possible = true;
            result = current_coloring;
            break;
        }
    }

    if (possible) {
        std::cout << result << "\n";
    } else {
        std::cout << "-\n";
    }
}

