    // If b=1, then b-1=0, sum_r = 0.
    // If b=2, then b-1=1, sum_r = 1.
    long long sum_r = (b - 1);
    sum_r = (sum_r * b) % MOD;

    // We need to divide by 2. Since MOD is prime, we can multiply by modular inverse of 2.
    // Modular inverse of 2 modulo 10^9 + 7 is (10^9 + 8) / 2 = 500000004.
    long long inv2 = 500000004;
    sum_r = (sum_r * inv2) % MOD;

