int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;
    int n = s.length();

    // Precompute character occurrences for first letter
    std::vector<std::vector<int>> char_indices(26);
    for (int i = 0; i < n; ++i) {
        char_indices[s[i] - 'a'].push_back(i);
    }

    double total_win_probability = 0.0;

    // Iterate over each possible first character t[0]
    for (int char_code = 0; char_code < 26; ++char_code) {
        const std::vector<int>& possible_k_values = char_indices[char_code];
        if (possible_k_values.empty()) {
            continue; // This character never appears as t[0]
        }

        // For a given t[0], Vasya wants to choose p to maximize win probability
        double max_win_prob_for_c1 = 0.0;

        // Iterate over all possible second positions p (1-indexed, so 1 to n-1)
        // This corresponds to index (p-1) in 0-indexed string
        for (int p_idx = 1; p_idx < n; ++p_idx) { // p_idx is the 0-indexed position of the second letter
            // For a fixed t[0] (char_code) and a fixed second position p_idx
            // Count how many k values from possible_k_values are uniquely determined

            std::map<char, std::vector<int>> groups_by_t_p_idx;
            for (int k : possible_k_values) {
                char t_p_idx_char = s[(p_idx + k) % n];
                groups_by_t_p_idx[t_p_idx_char].push_back(k);
            }

            int uniquely_determined_count = 0;
            for (const auto& pair : groups_by_t_p_idx) {
                if (pair.second.size() == 1) {
                    uniquely_determined_count++;
                }
            }

            // Probability of winning given this t[0] and chosen p_idx
            double current_win_prob_for_c1_p_idx = static_cast<double>(uniquely_determined_count) / possible_k_values.size();

            max_win_prob_for_c1 = std::max(max_win_prob_for_c1, current_win_prob_for_c1_p_idx);
        }

        // Add the contribution of this t[0] to the total probability
        // The probability of t[0] being this character is possible_k_values.size() / n
        total_win_probability += max_win_prob_for_c1 * possible_k_values.size();
    }

    std::cout << std::fixed << std::setprecision(15) << total_win_probability / n << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <cmath>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;

    if (n == 1) {
        std::cout << 1 << std::endl;
        return 0;
    }

    int k = static_cast<int>(std::sqrt(n));
    if (k * k < n) {
        k++;
    }

    // The optimal construction strategy is to divide the numbers into blocks of size k
    // and reverse each block.
    // For example, if n=4, k=2: [2,1, 4,3]
    // If n=5, k=3: [3,2,1, 5,4]
    // If n=6, k=3: [3,2,1, 6,5,4]
    // If n=7, k=3: [3,2,1, 6,5,4, 7]
    // If n=8, k=3: [3,2,1, 6,5,4, 8,7]
    // If n=9, k=3: [3,2,1, 6,5,4, 9,8,7]

    std::vector<int> p(n);
    int current_val = n;
    for (int i = 0; i < n; i += k) {
        int block_start_idx = i;
        int block_end_idx = std::min(i + k, n);

        // Fill the block in decreasing order
        for (int j = block_end_idx - 1; j >= block_start_idx; --j) {
            p[j] = current_val--;
        }
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

