        }
        // Case 2: (0 -> 0, 1 -> 1)
        // B_j ^ C_j = 0
        // (A_j | B_j) ^ C_j = 1
        // This implies B_j = C_j.
        // Then (A_j | B_j) ^ B_j = 1.
        // If B_j = 0, then (A_j | 0) ^ 0 = A_j = 1. So A_j=1, B_j=0, C_j=0.
        // If B_j = 1, then (A_j | 1) ^ 1 = 1. (A_j | 1) is always 1. So 1 ^ 1 = 0 != 1. This doesn't work.
        // So A_j=1, B_j=0, C_j=0.
        else if (v0 == 0 && v1 == 1) {
            // A_j = 1, B_j = 0, C_j = 0
            // (x_j & 1 | 0) ^ 0 = x_j
            final_A |= (1 << j);
        }
        // Case 3: (0 -> 1, 1 -> 0)
        // B_j ^ C_j = 1
        // (A_j | B_j) ^ C_j = 0
        // This implies B_j != C_j.
        // If B_j = 0, then C_j = 1.
        // Then (A_j | 0) ^ 1 = 0 => A_j ^ 1 = 0 => A_j = 1. So A_j=1, B_j=0, C_j=1.
        // If B_j = 1, then C_j = 0.
        // Then (A_j | 1) ^ 0 = 0 => (A_j | 1) = 0. This is impossible.
        // So A_j=1, B_j=0, C_j=1.
        else if (v0 == 1 && v1 == 0) {
            // A_j = 1, B_j = 0, C_j = 1
            // (x_j & 1 | 0) ^ 1 = x_j ^ 1
            final_A |= (1 << j);
            final_C |= (1 << j);
        }
        // Case 4: (0 -> 1, 1 -> 1)
        // B_j ^ C_j = 1
        // (A_j | B_j) ^ C_j = 1
        // This implies B_j != C_j.
        // If B_j = 0, then C_j = 1.
        // Then (A_j | 0) ^ 1 = 1 => A_j ^ 1 = 1 => A_j = 0. So A_j=0, B_j=0, C_j=1.
        // If B_j = 1, then C_j = 0.
        // Then (A_j | 1) ^ 0 = 1 => (A_j | 1) = 1. This is always true.
        // So A_j=0, B_j=1, C_j=0.
        // We prefer A_j=0, B_j=1, C_j=0 for simplicity.
        else { // v0 == 1 && v1 == 1
            // A_j = 0, B_j = 1, C_j = 0
            // (x_j & 0 | 1) ^ 0 = 1
            final_B |= (1 << j);
        }
    }

    std::vector<std::pair<char, int>> result_ops;
    if (final_A != 1023) { // If A is not all 1s, we need an AND operation
        result_ops.push_back({'&', final_A});
    }
    if (final_B != 0) { // If B is not all 0s, we need an OR operation
        result_ops.push_back({'|', final_B});
    }
    if (final_C != 0) { // If C is not all 0s, we need an XOR operation
        result_ops.push_back({'^', final_C});
    }

    std::cout << result_ops.size() << std::endl;
    for (const auto& op : result_ops) {
        std::cout << op.first << " " << op.second << std::endl;
    }

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <cmath>
#include <numeric>
#include <algorithm>

// Function to solve a single query
void solve() {
    std::string s;
    std::cin >> s;
    int n = s.length();
    long long good_substrings_count = 0;

    // Max length for which 2^L-1 is still relatively small,
    // and 2^L-1 can be equal to L.
    // For L=18, 2^18-1 = 262143.
    // For L=19, 2^19-1 = 524287.
    // Max possible length is N = 2e5.
    // If L > 18, then 2^L-1 > N.
    // So, if a substring has length L > 18, its value f(s_l...s_r) will be > N.
    // Since f(s_l...s_r) must equal L, this is impossible for L > 18.
    // Thus, we only need to check substrings with length up to ~18-20.
    // Let's pick a safe upper bound, say 20.
    const int MAX_CHECK_LEN = 20; 

    for (int i = 0; i < n; ++i) {
        // Case 1: Substrings starting with '0'
        // These substrings must have length equal to their value.
        // If s[i] == '0', then f(s[i...r]) can be 0 only if all characters are '0'.
        // If s[i] == '0', and the substring is s[i...r], its value is f(s[i+1...r]).
        // The length is r - i + 1.
        // We need r - i + 1 = f(s[i...r]).
        // If s[i] == '0', then f(s[i...r]) = f(s[i+1...r]).
        // The maximum value for f(s[i...r]) is N.
        // The maximum length for f(s[i...r]) to be N is about 18-19 bits.
        // So, we only need to check a limited number of characters after s[i].

        // Count consecutive zeros starting from s[i]
        if (s[i] == '0') {
            int j = i;
            while (j < n && s[j] == '0') {
                j++;
            }
            // Now s[i...j-1] are all '0's.
            // For any substring s[i...k] where k < j, its value is 0.
            // We need k - i + 1 = 0, which means k = i - 1, impossible.
            // So, no good substrings consisting only of '0's.
            // The only exception is if the problem definition allows f(0) = 0,
            // and length 1. But f(0) is 0, length 1. So 1 != 0.
            // The example f(000) = 0. Length 3. 3 != 0.
            // So, a substring of all zeros cannot be good.
            // We can skip all these zeros and start checking from s[j].
            i = j - 1; // Loop will increment i to j.
            continue;
        }

        // Case 2: Substrings starting with '1'
        // These substrings have a non-zero value.
        // We iterate through possible end points 'j' for substrings starting at 'i'.
        // The length of the substring s[i...j] is len = j - i + 1.
        // The value of the substring s[i...j] is val.
        // We need len = val.

        long long current_val = 0;
        for (int j = i; j < n; ++j) {
            int len = j - i + 1;

            // Optimization: If len is too large, current_val will exceed N.
            // If len > MAX_CHECK_LEN, then current_val can be up to 2^len - 1.
            // If len > 18, then 2^len - 1 > 2e5.
            // If current_val > N, then it cannot be equal to len (since len <= N).
            // So we can break early if current_val exceeds N.
            // Also, if len itself is already greater than N, we can break.
            // The maximum possible value for len is N.
            // The maximum possible value for current_val is N.
            // If current_val > N, it can't be equal to len.
            // If len > N, it can't be equal to current_val.
            // Since len is always <= N, we only need to check current_val > N.
            // A tighter bound: if len > MAX_CHECK_LEN, then current_val will be large.
            // If current_val exceeds N, we can stop.
            // If current_val exceeds len, and len is small, it might still be possible.
            // Example: s = "10000000000000000000" (1 followed by 19 zeros)
            // i=0, j=0: s[0]='1', len=1, val=1. Good.
            // i=0, j=1: s[0..1]="10", len=2, val=2. Good.
            // i=0, j=2: s[0..2]="100", len=3, val=4. Not good.
            // i=0, j=3: s[0..3]="1000", len=4, val=8. Not good.
            // ...
            // i=0, j=18: s[0..18]="1" followed by 18 '0's. len=19, val=2^18 = 262144. Not good.
            // Here, val quickly exceeds len.
            // The maximum length we need to consider for current_val to be equal to len is about 18-19.
            // If len > 19, then 2^len-1 > 2^19-1 = 524287.
            // The maximum possible len is N = 2e5.
            // So if len > 19, then current_val will be at least 2^19-1 (if all 1s) or smaller.
            // But if s[i] is '1', then current_val >= 2^(len-1).
            // If len > 19, then 2^(len-1) >= 2^19 > 2e5.
            // So if len > 19, current_val will always be greater than N, and thus greater than len.
            // So we only need to check len up to 19.
            // Let's use a slightly larger constant for safety, say 20.
            if (len > MAX_CHECK_LEN && current_val > len) { // current_val will only grow, so it will never equal len
                break;
            }

            current_val = (current_val << 1) | (s[j] - '0');

            // If current_val exceeds N, it can't be equal to len (since len <= N).
            // This check is important for performance.
            if (current_val > n) {
                break;
            }

            if (current_val == len) {
                good_substrings_count++;
            }
        }
    }

    std::cout << good_substrings_count << std::endl;
}

int main() {
    // Optimize C++ standard streams for faster input/output.
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <map>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(2 * n);
    int initial_s = 0;
    int initial_b = 0;
    for (int i = 0; i < 2 * n; ++i) {
        std::cin >> a[i];
        if (a[i] == 1) {
            initial_s++;
        } else {
            initial_b++;
        }
    }

    int initial_diff = initial_s - initial_b;

    // Calculate prefix sums for the left side (jars 0 to n-1)
    // and suffix sums for the right side (jars n to 2n-1)
    // We want to find a combination of L jars eaten from left and R jars eaten from right
    // such that the remaining jars have equal counts of S and B.
    // This means (total_S - eaten_S) == (total_B - eaten_B)
    // (total_S - total_B) == (eaten_S - eaten_B)
    // initial_diff == (eaten_S - eaten_B)

    // Let's define current_diff as (count_1 - count_2) for a subsegment.
    // We need to find L and R such that the difference of (1s - 2s) among the eaten jars
    // is equal to initial_diff.
    // The jars eaten are a[0...L-1] and a[2n-R...2n-1].
    // Let diff_L be (count_1 - count_2) for a[0...L-1].
    // Let diff_R be (count_1 - count_2) for a[2n-R...2n-1].
    // The total difference from eaten jars is diff_L + diff_R.
    // We need diff_L + diff_R = initial_diff.

    // Map to store the minimum number of jars eaten from the left side (L)
    // for a given difference (count_1 - count_2).
    // Key: difference, Value: L (number of jars eaten)
    std::map<int, int> left_diff_to_L;
    left_diff_to_L[0] = 0; // 0 jars eaten from left, difference is 0

    int current_diff_left = 0;
    for (int L = 1; L <= n; ++L) {
        if (a[L - 1] == 1) {
            current_diff_left++;
        } else {
            current_diff_left--;
        }
        if (left_diff_to_L.find(current_diff_left) == left_diff_to_L.end()) {
            left_diff_to_L[current_diff_left] = L;
        }
    }

    int min_jars_eaten = 2 * n; // Max possible jars eaten

    // Iterate through possible number of jars eaten from the right side (R)
    // Calculate the difference for these R jars.
    // Then check if the required difference for the left side exists in the map.
    int current_diff_right = 0;
    // Case: 0 jars eaten from right.
    // Required diff from left: initial_diff - 0 = initial_diff.
    if (left_diff_to_L.count(initial_diff)) {
        min_jars_eaten = std::min(min_jars_eaten, left_diff_to_L[initial_diff]);
    }

    for (int R = 1; R <= n; ++R) {
        // Jars are 0-indexed. Rightmost jar is 2n-1.
        // R jars from right means a[2n-R], ..., a[2n-1].
        // The jar being added is a[2n-R].
        if (a[2 * n - R] == 1) {
            current_diff_right++;
        } else {
            current_diff_right--;
        }

        int required_diff_left = initial_diff - current_diff_right;
        if (left_diff_to_L.count(required_diff_left)) {
            min_jars_eaten = std::min(min_jars_eaten, left_diff_to_L[required_diff_left] + R);
        }
    }

    std::cout << min_jars_eaten << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

