    int n;
    std::cin >> n;

    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 2) { // Sequences of length 1 or 2 are always stable
        std::cout << 0 << "\n";
        for (int i = 0; i < n; ++i) {
            std::cout << a[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
        return 0;
    }

    std::vector<int> left_ones(n, -1); // Stores index of the nearest 1 to the left
    std::vector<int> right_ones(n, n); // Stores index of the nearest 1 to the right

    int last_one_idx = -1;
    for (int i = 0; i < n; ++i) {
        if (a[i] == 1) {
            last_one_idx = i;
        }
        left_ones[i] = last_one_idx;
    }

    int first_one_idx = n;
    for (int i = n - 1; i >= 0; --i) {
        if (a[i] == 1) {
            first_one_idx = i;
        }
        right_ones[i] = first_one_idx;
    }

    int max_dist = 0;
    for (int i = 0; i < n; ++i) {
        if (a[i] == 0) {
            int dist_left = (left_ones[i] == -1) ? n : (i - left_ones[i]);
            int dist_right = (right_ones[i] == n) ? n : (right_ones[i] - i);
            max_dist = std::max(max_dist, std::min(dist_left, dist_right));
        }
    }

    int k = (max_dist + 1) / 2;

    std::vector<int> b = a;
    for (int i = 1; i < n - 1; ++i) {
        if (a[i] == 0) {
            int dist_left = (left_ones[i] == -1) ? n : (i - left_ones[i]);
            int dist_right = (right_ones[i] == n) ? n : (right_ones[i] - i);
            if (dist_left <= k && dist_right <= k) {
                b[i] = 1;
            }
        } else { // a[i] == 1
            int dist_left = (left_ones[i] == -1 || left_ones[i] == i) ? n : (i - left_ones[i]);
            int dist_right = (right_ones[i] == n || right_ones[i] == i) ? n : (right_ones[i] - i);
            if (dist_left > k && dist_right > k) {
                b[i] = 0;
            }
        }
    }

    std::cout << k << "\n";
    for (int i = 0; i < n; ++i) {
        std::cout << b[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

