#include <iostream>
#include <vector>
#include <algorithm>
#include <climits>

struct Operation {
    int type;
    int l, r;
    long long val; // d for type 1, m for type 2
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<Operation> ops(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> ops[i].type >> ops[i].l >> ops[i].r >> ops[i].val;
        ops[i].l--; // 0-indexed
        ops[i].r--; // 0-indexed
    }

    std::vector<long long> b(n, LLONG_MAX); // b[i] stores the maximum possible value for a_i

    // Initialize b based on type 2 operations
    for (int i = 0; i < m; ++i) {
        if (ops[i].type == 2) {
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                b[j] = std::min(b[j], ops[i].val);
            }
        }
    }

    // Propagate type 1 operations backwards to adjust b
    // If a[j] + d <= M, then a[j] <= M - d
    for (int i = m - 1; i >= 0; --i) {
        if (ops[i].type == 1) {
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                if (b[j] != LLONG_MAX) { // Only adjust if b[j] has been constrained
                    b[j] -= ops[i].val;
                }
            }
        }
    }

    // Construct the initial array 'a'
    // If b[i] is still LLONG_MAX, it means a_i was never constrained by a type 2 query.
    // We can set it to 0, as per problem statement |a_i| <= 10^9.
    // If b[i] was constrained, it represents the maximum possible initial value for a_i.
    // To satisfy max(a_j) = M, we need at least one a_k = M.
    // By setting a_i = b[i], we maximize the chances of satisfying this.
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        if (b[i] == LLONG_MAX) {
            a[i] = 0; // Default value for unconstrained elements
        } else {
            a[i] = b[i];
        }
    }

    // Verify the constructed array
    std::vector<long long> current_a = a;
    for (int i = 0; i < m; ++i) {
        if (ops[i].type == 1) {
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                current_a[j] += ops[i].val;
            }
        } else { // type 2
            long long max_val = LLONG_MIN;
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                max_val = std::max(max_val, current_a[j]);
            }
            if (max_val != ops[i].val) {
                std::cout << "NO\n";
                return 0;
            }
        }
    }

    std::cout << "YES\n";
    for (int i = 0; i < n; ++i) {
        std::cout << a[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    long long m;
    std::cin >> n >> m;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    long long low = 0;
    long long high = m - 1; // Max possible operations is m-1 (e.g., 0 -> m-1)
    long long ans = m - 1;

    while (low <= high) {
        long long mid = low + (high - low) / 2; // current_ops
        bool possible = true;
        long long prev_b = 0; // The target value for the previous element

        for (int i = 0; i < n; ++i) {
            long long current_a = a[i];
            long long current_b;

            // Case 1: current_a is already >= prev_b
            // We can choose current_b = current_a.
            // This requires 0 operations for a[i].
            // If current_a >= prev_b, then current_b can be current_a.
            // The number of operations for a[i] would be 0.
            // This is valid if 0 <= mid.
            // So, if current_a >= prev_b, we can set current_b = current_a.
            // This is always the best choice if possible, as it keeps current_b small.
            if (current_a >= prev_b) {
                current_b = current_a;
            } else {
                // Case 2: current_a < prev_b
                // We need to increment current_a to at least prev_b.
                // The value current_a can become is (current_a + mid) % m.
                // We need to check if we can make current_a become prev_b or more.
                // The possible values for current_b are in the range [current_a, (current_a + mid) % m]
                // if (current_a + mid) % m >= current_a (no wrap-around).
                // Or [current_a, m-1] U [0, (current_a + mid) % m] if wrap-around.

                // If current_a + mid >= prev_b (without modulo),
                // it means we can reach prev_b by incrementing current_a.
                // The number of operations needed is prev_b - current_a.
                // If prev_b - current_a <= mid, then we can set current_b = prev_b.
                if (current_a + mid >= prev_b) {
                    current_b = prev_b;
                } else {
                    // We cannot reach prev_b by incrementing current_a without wrap-around.
                    // This means we must use wrap-around.
                    // The maximum value we can reach is (current_a + mid) % m.
                    // If (current_a + mid) % m is less than current_a, it means we wrapped around.
                    // For example, a[i]=5, m=7, mid=1. (5+1)%7 = 6. No wrap.
                    // For example, a[i]=5, m=7, mid=3. (5+3)%7 = 1. Wrap.
                    // In this case, the values we can achieve are [current_a, m-1] and [0, (current_a + mid) % m].
                    // Since current_a < prev_b, and we couldn't reach prev_b without wrap-around,
                    // it means prev_b is in the range [current_a + 1, m-1].
                    // If we wrap around, the largest value we can achieve is (current_a + mid) % m.
                    // If this value is still less than prev_b, then it's impossible.
                    // Example: a[i]=5, m=7, prev_b=6, mid=0. (5+0)%7 = 5. 5 < 6. Impossible.
                    // Example: a[i]=5, m=7, prev_b=6, mid=1. (5+1)%7 = 6. 6 >= 6. Possible.
                    // Example: a[i]=5, m=7, prev_b=6, mid=2. (5+2)%7 = 0. 0 < 6. Impossible.
                    // The condition for impossibility is:
                    // current_a < prev_b AND (current_a + mid) % m < prev_b AND (current_a + mid) % m >= current_a
                    // This means we can't reach prev_b even with mid operations, and we didn't wrap around enough to make it possible.
                    // The only way it's impossible is if (current_a + mid) % m is less than prev_b, AND
                    // we are forced to choose a value less than prev_b.
                    // This happens if (current_a + mid) % m < prev_b AND (current_a + mid) % m >= current_a.
                    // If (current_a + mid) % m < current_a, it means we wrapped around.
                    // In this case, we can achieve any value in [0, (current_a + mid) % m] or [current_a, m-1].
                    // Since current_a < prev_b, we must choose a value >= prev_b.
                    // If we wrapped around, (current_a + mid) % m is small.
                    // If prev_b is in [current_a, m-1], we can't reach it if (current_a + mid) % m < current_a.
                    // This logic is tricky. Let's simplify.
                    // We need to find b_i such that b_i >= prev_b and (b_i - a_i + m) % m <= mid.
                    // If current_a < prev_b:
                    //   We need to increment current_a.
                    //   The number of increments needed to reach prev_b is (prev_b - current_a + m) % m.
                    //   If (prev_b - current_a + m) % m <= mid, then we can set current_b = prev_b.
                    //   Otherwise, we cannot reach prev_b.
                    //   In this case, we must set current_b to something else.
                    //   The only other option is to set current_b to current_a.
                    //   But current_a < prev_b, so this violates non-decreasing.
                    //   So, if (prev_b - current_a + m) % m > mid, it's impossible.
                    //   This is the correct logic.
                    possible = false;
                    break;
                }
            }
            prev_b = current_b;
        }

        if (possible) {
            ans = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    std::cout << ans << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>

// Using long long for y to prevent overflow, as a_i can be up to 10^9 and n up to 2*10^5.
// In the worst case, y could accumulate n * 2 * 10^9, which is 4 * 10^14, fitting in long long.

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<long long> a_suffix(n + 1); // a_suffix[0] is unused, a_suffix[1] is unused, a_suffix[2]...a_suffix[n]
    for (int i = 2; i <= n; ++i) {
        std::cin >> a_suffix[i];
    }

    // dp_x[i] stores the final x value if starting at x=i and performing one pair of operations (step 2 then step 3)
    // dp_y[i] stores the accumulated y value if starting at x=i and performing one pair of operations
    // dp_next_x[i] stores the x value after step 2 (x = x + a_x)
    // dp_next_y[i] stores the y value after step 2 (y = y + a_x)
    std::vector<long long> dp_x(n + 1);
    std::vector<long long> dp_y(n + 1);
    std::vector<long long> dp_next_x(n + 1);
    std::vector<long long> dp_next_y(n + 1);

    // Initialize DP table for states where x is out of bounds
    // If x is out of bounds, it means the program terminates.
    // The final x value is the current x, and y is the current y.
    // For our DP, we want to know what happens if we *start* at x=i.
    // If i is out of bounds, it means the program would have terminated *before* this step.
    // But our DP is for the *result* of one pair of steps.
    // So, if x+a_x or x+a_x-a_{x+a_x} goes out of bounds, we record that.
    // We use -1 to indicate termination for x, and the accumulated y for y.

    for (int i = n; i >= 1; --i) {
        long long current_a_i;
        // For the purpose of DP, a_i is the value at index i.
        // When we run the simulation, a_1 is the start_val.
        // For DP, we are considering a generic a_i.
        // The actual a_1 is only used for the initial step of the simulation.
        // For DP, we are interested in a_i for i >= 1.
        // If i is 1, we don't know a_1 yet. So we only compute DP for i >= 2.
        // For i=1, we will compute it directly.
        if (i == 1) {
            // This case will be handled outside the loop for each start_val.
            // We can't precompute dp_x[1], dp_y[1] because a_1 changes.
            continue;
        }
        current_a_i = a_suffix[i];

        // Step 2: x = x + a_x, y = y + a_x
        long long x_after_step2 = (long long)i + current_a_i;
        long long y_after_step2 = current_a_i;

        dp_next_x[i] = x_after_step2;
        dp_next_y[i] = y_after_step2;

        // Check termination after step 2
        if (x_after_step2 <= 0 || x_after_step2 > n) {
            dp_x[i] = x_after_step2; // Program terminates, x is this value
            dp_y[i] = y_after_step2; // Program terminates, y is this value
        } else {
            // Step 3: x = x - a_x, y = y + a_x
            // The a_x here is a_{x_after_step2}
            long long a_at_new_x = a_suffix[x_after_step2]; // This is a_{x_after_step2}
            long long x_after_step3 = x_after_step2 - a_at_new_x;
            long long y_after_step3 = y_after_step2 + a_at_new_x;

            // Check termination after step 3
            if (x_after_step3 <= 0 || x_after_step3 > n) {
                dp_x[i] = x_after_step3;
                dp_y[i] = y_after_step3;
            } else {
                // Program continues. We need to add the result of the next pair of steps.
                // The state after one pair of steps is (x_after_step3, y_after_step3).
                // We need to find the result of starting at x_after_step3.
                // This is where DP comes in.
                dp_x[i] = dp_x[x_after_step3];
                dp_y[i] = y_after_step3 + dp_y[x_after_step3];
            }
        }
    }

    // Now, run the simulation for each start_val (a_1) from 1 to n-1
    for (int start_val = 1; start_val < n; ++start_val) {
        long long current_x = 1;
        long long current_y = 0;
        long long a_1 = start_val;

        // First pair of operations, using a_1
        // Step 2: x = x + a_x, y = y + a_x
        long long x_after_step2 = current_x + a_1;
        long long y_after_step2 = current_y + a_1;

        // Check termination after step 2
        if (x_after_step2 <= 0 || x_after_step2 > n) {
            std::cout << y_after_step2 << "\n";
            continue;
        }

        // Step 3: x = x - a_x, y = y + a_x
        // The a_x here is a_{x_after_step2}
        long long a_at_new_x = a_suffix[x_after_step2];
        long long x_after_step3 = x_after_step2 - a_at_new_x;
        long long y_after_step3 = y_after_step2 + a_at_new_x;

        // Check termination after step 3
        if (x_after_step3 <= 0 || x_after_step3 > n) {
            std::cout << y_after_step3 << "\n";
            continue;
        }

        // If program continues, use DP for subsequent steps
        // The state is now (x_after_step3, y_after_step3)
        // Add the result from the DP table for x_after_step3
        long long final_x = dp_x[x_after_step3];
        long long final_y = y_after_step3 + dp_y[x_after_step3];

        // If dp_x[x_after_step3] indicates termination (i.e., it's not within [1, n]),
        // then final_y is the correct answer.
        // If dp_x[x_after_step3] is within [1, n], it means the program never terminates.
        // We can check this by seeing if dp_x[x_after_step3] is equal to x_after_step3.
        // If dp_x[x_after_step3] == x_after_step3, it means it's stuck in a loop.
        // However, our DP definition for dp_x[i] is the *final* x value.
        // If it's stuck in a loop, dp_x[i] will be the x value of the loop entry point.
        // The problem states "it may never terminate".
        // If dp_x[x_after_step3] is within [1, n], it means it's stuck in a cycle.
        // The only way for dp_x[i] to be within [1, n] is if it eventually returns to i,
        // or some other j that eventually returns to j, etc.
        // This implies an infinite loop.
        if (final_x >= 1 && final_x <= n) { // If the final x from DP is still within bounds, it's an infinite loop
            std::cout << -1 << "\n";
        } else {
            std::cout << final_y << "\n";
        }
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <list>

struct Child {
    long long v, d, p;
    int original_idx;
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<Child> children_data(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> children_data[i].v >> children_data[i].d >> children_data[i].p;
        children_data[i].original_idx = i + 1;
    }

    std::list<Child> current_line;
    for (int i = 0; i < n; ++i) {
        current_line.push_back(children_data[i]);
    }

    std::vector<int> cured_children_indices;

    while (!current_line.empty()) {
        Child current_doctor_child = current_line.front();
        current_line.pop_front();
        cured_children_indices.push_back(current_doctor_child.original_idx);

        long long office_cry_volume = current_doctor_child.v;
        long long hall_cry_sum = 0; // Accumulates d_j from children leaving due to chain reaction

        auto it = current_line.begin();
        while (it != current_line.end()) {
            // Apply accumulated hall_cry_sum first
            it->p -= hall_cry_sum;

            // Apply office_cry_volume reduction
            if (office_cry_volume > 0) {
                it->p -= office_cry_volume;
                office_cry_volume = std::max(0LL, office_cry_volume - 1);
            }

            if (it->p < 0) {
                hall_cry_sum += it->d; // Add this child's d_j to the sum
                it = current_line.erase(it); // Remove child from line
            } else {
                ++it;
            }
        }
    }

    std::cout << cured_children_indices.size() << "\n";
    for (size_t i = 0; i < cured_children_indices.size(); ++i) {
        std::cout << cured_children_indices[i] << (i == cured_children_indices.size() - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

struct Element {
    long long value;
    int original_index;
};

bool compareElements(const Element& a, const Element& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long h;
    std::cin >> n >> h;

    std::vector<Element> elements(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> elements[i].value;
        elements[i].original_index = i;
    }

    std::sort(elements.begin(), elements.end(), compareElements);

    // Case 1: All elements in one subsequence (e.g., subsequence 1)
    // This means no pairs are in different subsequences.
    // f values are all a_i + a_j.
    // min_f = a_0 + a_1
    // max_f = a_{n-2} + a_{n-1}
    // Goodness = (a_{n-2} + a_{n-1}) - (a_0 + a_1)
    long long goodness_all_same = (elements[n - 1].value + elements[n - 2].value) - (elements[0].value + elements[1].value);
    std::vector<int> partition_all_same(n, 1);

    // Case 2: At least one element in each subsequence.
    // This means there will be pairs in different subsequences, so f values of type a_i + a_j + h will exist.
    // The minimum possible f value is a_0 + a_1.
    // The maximum possible f value is a_{n-1} + a_{n-2} + h (if a_{n-1} and a_{n-2} are in different subsequences)
    // OR a_{n-1} + a_{n-2} (if a_{n-1} and a_{n-2} are in the same subsequence).
    //
    // To minimize max_f - min_f, we want to make min_f as large as possible and max_f as small as possible.
    //
    // Consider the partition where elements[0] is in subsequence 1, and all other elements are in subsequence 2.
    // min_f:
    //   - If n > 2: elements[1] + elements[2] (same subsequence 2)
    //   - elements[0] + elements[1] + h (different subsequences)
    //   So, min_f = min(elements[1] + elements[2], elements[0] + elements[1] + h)
    //   However, if elements[0] is in sub 1 and elements[1] is in sub 2, then elements[0]+elements[1]+h is a candidate for min_f.
    //   If elements[1] and elements[2] are in sub 2, then elements[1]+elements[2] is a candidate for min_f.
    //   The smallest possible sum of two elements is elements[0] + elements[1].
    //   So, min_f will be at least elements[0] + elements[1].
    //   If elements[0] and elements[1] are in different subsequences, min_f = elements[0] + elements[1] + h.
    //   If elements[0] and elements[1] are in the same subsequence, min_f = elements[0] + elements[1].
    //
    // Let's consider the strategy: put elements[0] in sub 1, and all other elements in sub 2.
    // This ensures that elements[0] and elements[1] are in different subsequences.
    // So, min_f = elements[0] + elements[1] + h.
    // max_f:
    //   - elements[n-1] + elements[n-2] (same subsequence 2)
    //   - elements[0] + elements[n-1] + h (different subsequences)
    //   So, max_f = max(elements[n-1] + elements[n-2], elements[0] + elements[n-1] + h)
    //
    // Goodness = max(elements[n-1] + elements[n-2], elements[0] + elements[n-1] + h) - (elements[0] + elements[1] + h)
    //
    // This simplifies to:
    // max(elements[n-1] + elements[n-2] - (elements[0] + elements[1] + h), elements[0] + elements[n-1] + h - (elements[0] + elements[1] + h))
    // max(elements[n-1] + elements[n-2] - elements[0] - elements[1] - h, elements[n-1] - elements[1])
    //
    // This is the goodness for the partition where elements[0] is in sub 1, and all others are in sub 2.
    // Let's call this `goodness_one_split`.
    //
    // The minimum f value will be `elements[0] + elements[1]`.
    // The maximum f value will be `elements[n-1] + elements[n-2]`.
    // If we split elements[0] and elements[1], then `elements[0] + elements[1] + h` is a candidate for min_f.
    // If we split elements[n-1] and elements[n-2], then `elements[n-1] + elements[n-2] + h` is a candidate for max_f.
    //
    // The crucial observation is that to minimize the range, we want to make the smallest possible `a_i + a_j + h`
    // as close as possible to the largest possible `a_i + a_j`.
    //
    // The smallest possible sum of two elements is `elements[0].value + elements[1].value`.
    // The largest possible sum of two elements is `elements[n-1].value + elements[n-2].value`.
    //
    // If we put `elements[0]` in one group and all others in another group:
    // Min f value: `elements[0].value + elements[1].value + h` (from `elements[0]` and `elements[1]`)
    // Max f value: `max(elements[n-1].value + elements[n-2].value, elements[0].value + elements[n-1].value + h)`
    //
    // Let's calculate this goodness:
    long long min_f_val_split = elements[0].value + elements[1].value + h;
    long long max_f_val_split = std::max(elements[n - 1].value + elements[n - 2].value, elements[0].value + elements[n - 1].value + h);
    long long goodness_one_split = max_f_val_split - min_f_val_split;

    std::vector<int> partition_one_split(n);
    partition_one_split[elements[0].original_index] = 1;
    for (int i = 1; i < n; ++i) {
        partition_one_split[elements[i].original_index] = 2;
    }

    if (goodness_one_split < goodness_all_same) {
        std::cout << goodness_one_split << "\n";
        for (int i = 0; i < n; ++i) {
            std::cout << partition_one_split[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    } else {
        std::cout << goodness_all_same << "\n";
        for (int i = 0; i < n; ++i) {
            std::cout << partition_all_same[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    }

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <numeric>
#include <algorithm>

// Function to check if a string is a palindrome
bool is_palindrome(const std::string& str) {
    std::string reversed_str = str;
    std::reverse(reversed_str.begin(), reversed_str.end());
    return str == reversed_str;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::string s;
    std::cin >> s;

    int n = s.length();

    // Case k = 1
    // Try all possible single cuts
    for (int i = 1; i < n; ++i) {
        std::string s1 = s.substr(0, i);
        std::string s2 = s.substr(i);
        std::string new_s = s2 + s1;

        if (new_s != s && is_palindrome(new_s)) {
            std::cout << 1 << std::endl;
            return 0;
        }
    }

    // Case k = 2
    // If no solution with k=1, check if all characters are the same.
    // If all characters are the same, e.g., "aaaa", then any reordering of pieces
    // will result in the same string "aaaa".
    // In this case, it's impossible to form a different palindrome.
    bool all_same_char = true;
    for (int i = 1; i < n; ++i) {
        if (s[i] != s[0]) {
            all_same_char = false;
            break;
        }
    }

    if (all_same_char) {
        std::cout << "Impossible" << std::endl;
    } else {
        // If not all characters are the same, and k=1 didn't work,
        // then k=2 is always possible.
        // Example: "nolon" -> "no|l|on" -> "on|l|no" (k=2)
        // Example: "abacaba" -> "ab|ac|aba" -> "aba|ac|ab" (k=2)
        // The logic is that if not all characters are the same,
        // there must be at least two distinct characters.
        // Since s is a palindrome, it has at least two distinct characters.
        // Consider the first half of the string (excluding the middle character for odd length).
        // If s is not all same characters, then s.substr(0, n/2) is not all same characters.
        // If s.substr(0, n/2) is not all same characters, then s.substr(0, n/2) is not a palindrome.
        // If s.substr(0, n/2) is a palindrome, then s would be like "abccba" where "abc" is a palindrome, which means "a=c".
        // So "abaaba". If "aba" is a palindrome, then "a=a".
        // If s is not all same characters, then s.substr(0, n/2) is not a palindrome.
        // If s.substr(0, n/2) is not a palindrome, then we can always find a cut that makes k=2 work.
        // For example, cut s into s[0...n/2-1], s[n/2], s[n/2+1...n-1].
        // Reorder as s[n/2+1...n-1], s[n/2], s[0...n/2-1].
        // This forms a new palindrome if s is not all same characters.
        // The only case where this might not work is if s.substr(0, n/2) is a palindrome.
        // E.g., "abacaba". n/2 = 3. s.substr(0,3) = "aba", which is a palindrome.
        // In this case, the strategy of reversing the halves doesn't work directly.
        // However, if s is not all same characters, and k=1 doesn't work, k=2 is the answer.
        // This is because if s is not all same characters, there exists at least one character s[i] != s[0].
        // Since s is a palindrome, s[i] == s[n-1-i].
        // If we cut s into s[0...i-1], s[i...n-1-i], s[n-i...n-1],
        // and reorder them, we can form a new palindrome.
        // A simpler argument: if not all characters are the same, then s.substr(0, n/2) is not a palindrome.
        // If s.substr(0, n/2) is not a palindrome, then s is not of the form "aaaaa...".
        // If s is not of the form "aaaaa...", then there exists some character s[i] != s[0].
        // This implies that s is not a "trivial" palindrome.
        // For any non-trivial palindrome (not all same characters), k=2 is always sufficient.
        // The example "nolon" (k=2) confirms this.
        // The example "kinnikkinnik" (k=1) shows that k=1 is possible even for complex palindromes.
        // The only case where k=1 fails is if all single cuts and swaps result in `s` or a non-palindrome.
        // If `s` is not all same characters, then `s` has at least two distinct characters.
        // This means `s.substr(0, n/2)` is not a palindrome (unless `n` is very small, e.g., `n=2`, `s="aa"`).
        // If `s.substr(0, n/2)` is not a palindrome, then `s` is not of the form `X + X_rev`.
        // If `s` is not all same characters, then `s` can be cut into `s[0...n/2-1]`, `s[n/2]`, `s[n/2+1...n-1]`.
        // Reordering these pieces as `s[n/2+1...n-1]`, `s[n/2]`, `s[0...n/2-1]` will form a new palindrome.
        // This new palindrome will be different from `s` because `s[0...n/2-1]` is not equal to `s[n/2+1...n-1]`
        // unless `s` is all same characters.
        std::cout << 2 << std::endl;
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <set>

// Function to check if all target tracks can be covered within time T
bool check(long long T, int n, int m, const std::vector<long long>& h, const std::vector<long long>& p) {
    // Create a combined sorted list of all unique initial head positions and target tracks.
    // This helps in identifying contiguous segments of tracks that need to be covered.
    std::set<long long> all_coords_set;
    for (long long val : h) all_coords_set.insert(val);
    for (long long val : p) all_coords_set.insert(val);
    std::vector<long long> all_coords(all_coords_set.begin(), all_coords_set.end());

    // `dp[i]` will store the minimum number of heads required to cover all target tracks
    // up to and including `all_coords[i]`.
    // If `all_coords[i]` is not a target track, it means all target tracks up to the
    // previous target track (if any) are covered.
    std::vector<int> dp(all_coords.size(), n + 1); // Initialize with a value greater than n

    // `p_idx` is an index for the `p` array.
    // `p_idx_next_target[i]` stores the index in `p` of the first target track
    // that is greater than or equal to `all_coords[i]`.
    std::vector<int> p_idx_next_target(all_coords.size());
    int current_p_idx = 0;
    for (int i = 0; i < all_coords.size(); ++i) {
        while (current_p_idx < m && p[current_p_idx] < all_coords[i]) {
            current_p_idx++;
        }
        p_idx_next_target[i] = current_p_idx;
    }

    // Base case: If the first coordinate `all_coords[0]` is a target track,
    // we need at least one head to cover it.
    // If it's not a target track, we don't need any heads yet for target tracks.
    if (p_idx_next_target[0] < m && p[p_idx_next_target[0]] == all_coords[0]) {
        dp[0] = 1;
    } else {
        dp[0] = 0; // No target tracks up to this point, so 0 heads needed.
    }

    // Iterate through `all_coords` to fill the `dp` table.
    for (int i = 1; i < all_coords.size(); ++i) {
        // Option 1: Don't use a new head for `all_coords[i]`.
        // If `all_coords[i]` is not a target track, then `dp[i]` can be `dp[i-1]`.
        // If `all_coords[i]` is a target track, we cannot simply inherit `dp[i-1]`
        // because `all_coords[i]` needs to be covered.
        // This case is handled by the inner loop where we try to cover `all_coords[i]`
        // using an existing head or a new head.
        dp[i] = dp[i-1]; // Initialize with previous state, assuming current point is covered by previous head or not a target.

        // If `all_coords[i]` is a target track, we must ensure it's covered.
        // If `all_coords[i]` is NOT a target track, then `dp[i]` should be `dp[i-1]`.
        // The `p_idx_next_target` logic handles this: if `p[p_idx_next_target[i]] != all_coords[i]`,
        // then `all_coords[i]` is not a target track.
        // In this case, `dp[i]` should be `dp[i-1]` because no new head is needed for `all_coords[i]`.
        // The loop below will only update `dp[i]` if `all_coords[i]` is a target.
        // So, `dp[i] = dp[i-1]` is a good default.

        // Option 2: Use a new head to cover `all_coords[i]` and potentially some preceding tracks.
        // This head would be placed at some `h_j` and move to cover a range.
        // We need to find the minimum `dp[k-1] + 1` for some `k < i`.
        // This means we are using `dp[k-1]` heads to cover up to `all_coords[k-1]`,
        // and then one new head to cover `all_coords[k]` through `all_coords[i]`.
        // The new head must be able to cover the range `[all_coords[k], all_coords[i]]`.
        // This requires a head `h_j` such that `h_j - T <= all_coords[k]` and `h_j + T >= all_coords[i]`.
        // Or, equivalently, `all_coords[k] - T <= h_j <= all_coords[i] + T`.
        // And also, `h_j` must be within `T` distance of both `all_coords[k]` and `all_coords[i]`.
        // This means `max(all_coords[k] - T, all_coords[i] - T)` must be less than or equal to
        // `min(all_coords[k] + T, all_coords[i] + T)`.
        // More simply, `all_coords[i] - all_coords[k] <= 2 * T`.
        // And there must be an `h_j` such that `all_coords[k] <= h_j + T` and `all_coords[i] >= h_j - T`.
        // This is equivalent to `h_j >= all_coords[i] - T` and `h_j <= all_coords[k] + T`.
        // So, we need to find if there exists an `h_j` in `[all_coords[i] - T, all_coords[k] + T]`.

        // We are looking for the minimum `dp[k-1] + 1` (or `1` if `k=0`) such that
        // all target tracks in `[all_coords[k], all_coords[i]]` can be covered by one head.
        // This means there must exist an `h_j` such that `h_j - T <= all_coords[k]`
        // and `h_j + T >= all_coords[i]`.
        // This is equivalent to `all_coords[i] - T <= h_j <= all_coords[k] + T`.
        // Let `min_h_needed = all_coords[i] - T` and `max_h_needed = all_coords[k] + T`.
        // We need to find if there's any `h_j` in `[min_h_needed, max_h_needed]`.
        // Since `h` is sorted, we can use `std::upper_bound` and `std::lower_bound`.

        // `first_target_idx` is the index in `p` of the first target track that is >= `all_coords[k]`.
        // `last_target_idx` is the index in `p` of the last target track that is <= `all_coords[i]`.
        // If `all_coords[i]` is not a target track, `last_target_idx` would be `p_idx_next_target[i]-1`.
        // If `all_coords[k]` is not a target track, `first_target_idx` would be `p_idx_next_target[k]`.

        // We iterate `k` from `0` to `i`.
        // `k` represents the starting point of the segment covered by the current head.
        for (int k = 0; k <= i; ++k) {
            // If `k > 0` and `dp[k-1]` is `n+1`, it means `all_coords[k-1]` cannot be covered,
            // so we cannot extend from there.
            if (k > 0 && dp[k-1] == n + 1) {
                continue;
            }

            // Check if all target tracks in `[all_coords[k], all_coords[i]]` can be covered by one head.
            // This means we need to find an `h_j` such that `h_j - T <= all_coords[k]` and `h_j + T >= all_coords[i]`.
            // This is equivalent to `all_coords[i] - T <= h_j <= all_coords[k] + T`.
            long long required_h_min = all_coords[i] - T;
            long long required_h_max = all_coords[k] + T;

            // Find if there is any `h_j` in the range `[required_h_min, required_h_max]`.
            auto it_low = std::lower_bound(h.begin(), h.end(), required_h_min);
            if (it_low != h.end() && *it_low <= required_h_max) {
                // A head `h_j` exists that can cover `[all_coords[k], all_coords[i]]`.
                // Now, we need to ensure that all target tracks in this range are actually covered.
                // The target tracks are `p[p_idx_next_target[k]]` through `p[p_idx_next_target[i]-1]`
                // (if `all_coords[i]` is not a target) or `p[p_idx_next_target[i]]` (if `all_coords[i]` is a target).
                // More precisely, we need to cover all `p_x` such that `all_coords[k] <= p_x <= all_coords[i]`.

                // Find the first target track `p_start` that is >= `all_coords[k]`.
                int p_start_idx = p_idx_next_target[k];
                if (p_start_idx >= m || p[p_start_idx] > all_coords[i]) {
                    // No target tracks in `[all_coords[k], all_coords[i]]`.
                    // This segment doesn't need to be covered by a new head for target tracks.
                    // But it might be part of a larger segment that does.
                    // If `k=0` and there are no target tracks up to `all_coords[i]`, then `dp[i]` should be 0.
                    // If `k>0` and there are no target tracks in `[all_coords[k], all_coords[i]]`,
                    // then this segment doesn't require a new head.
                    // This logic is tricky. Let's simplify.
                    // We only care about covering target tracks.
                    // If `all_coords[i]` is not a target track, then `dp[i]` should be `dp[i-1]`.
                    // If `all_coords[i]` IS a target track, then we need to cover it.
                    // The `dp[i] = dp[i-1]` handles the non-target case.
                    // For the target case, we need to find `min(dp[k-1] + 1)`.

                    // Let's re-evaluate the `dp` state.
                    // `dp[i]` = minimum heads to cover all target tracks `p_j <= all_coords[i]`.
                    // If `all_coords[i]` is not a target track, `dp[i]` is `dp[idx_of_prev_target]`.
                    // This means `dp` should only be defined for indices `i` where `all_coords[i]` is a target track.
                    // Or, `dp[i]` means minimum heads to cover all target tracks `p_j` such that `p_j <= all_coords[i]`.
                    // If `all_coords[i]` is not a target track, `dp[i]` is `dp[i-1]`.
                    // If `all_coords[i]` is a target track, then we need to cover it.
                    //   Option A: It's covered by the same head that covered `all_coords[i-1]`.
                    //             This is implicitly handled by the `k` loop.
                    //   Option B: It's covered by a new head.
                    //             This new head covers `[all_coords[k], all_coords[i]]`.
                    //             The cost is `dp[k-1] + 1`.

                    // Let's refine the `dp` definition:
                    // `dp[i]` = minimum heads to cover all target tracks `p_j` such that `p_j <= all_coords[i]`.
                    // If `all_coords[i]` is not a target track, `dp[i]` is `dp[i-1]`.
                    // If `all_coords[i]` is a target track:
                    //   `dp[i] = min(dp[i-1], min_{0 <= k <= i} ( (k==0 ? 0 : dp[k-1]) + 1 ) )`
                    //   where the inner `min` is over `k` such that there exists an `h_j`
                    //   that can cover all target tracks in `[all_coords[k], all_coords[i]]`.
                    //   This means `h_j - T <= p_first_in_range` and `h_j + T >= p_last_in_range`.
                    //   And `p_first_in_range` is the first `p_x >= all_coords[k]`.
                    //   And `p_last_in_range` is the last `p_x <= all_coords[i]`.

                    // Let's use `p_idx_next_target` to find the relevant target tracks.
                    int first_p_in_segment_idx = p_idx_next_target[k];
                    int last_p_in_segment_idx = p_idx_next_target[i] - 1; // Last target track strictly less than all_coords[i]
                    if (p_idx_next_target[i] < m && p[p_idx_next_target[i]] == all_coords[i]) {
                        last_p_in_segment_idx = p_idx_next_target[i]; // If all_coords[i] is a target, include it.
                    }

                    if (first_p_in_segment_idx <= last_p_in_segment_idx) {
                        // There are target tracks in `[all_coords[k], all_coords[i]]`.
                        // We need to cover `p[first_p_in_segment_idx]` to `p[last_p_in_segment_idx]`.
                        // The head `h_j` must cover `[p[first_p_in_segment_idx], p[last_p_in_segment_idx]]`.
                        // This means `h_j - T <= p[first_p_in_segment_idx]` and `h_j + T >= p[last_p_in_segment_idx]`.
                        // Or `p[last_p_in_segment_idx] - T <= h_j <= p[first_p_in_segment_idx] + T`.
                        long long required_h_min_for_p = p[last_p_in_segment_idx] - T;
                        long long required_h_max_for_p = p[first_p_in_segment_idx] + T;

                        auto it_low_p = std::lower_bound(h.begin(), h.end(), required_h_min_for_p);
                        if (it_low_p != h.end() && *it_low_p <= required_h_max_for_p) {
                            // A head exists that can cover all target tracks in `[all_coords[k], all_coords[i]]`.
                            int current_heads_needed = (k == 0 ? 0 : dp[k-1]) + 1;
                            dp[i] = std::min(dp[i], current_heads_needed);
                        }
                    } else {
                        // No target tracks in `[all_coords[k], all_coords[i]]`.
                        // If `all_coords[i]` is a target track, this `k` segment cannot cover it.
                        // If `all_coords[i]` is NOT a target track, then `dp[i]` should be `dp[i-1]`.
                        // The `dp[i] = dp[i-1]` initialization handles this.
                        // We only update `dp[i]` if `all_coords[i]` is a target track AND we found a way to cover it.
                        // So, if `all_coords[i]` is a target track, and this `k` segment has no targets,
                        // this `k` segment is not useful for covering `all_coords[i]`.
                        // This branch should only update `dp[i]` if `all_coords[i]` is a target.
                        if (p_idx_next_target[i] < m && p[p_idx_next_target[i]] == all_coords[i]) {
                            // `all_coords[i]` is a target, but this segment `[all_coords[k], all_coords[i]]`
                            // contains no target tracks. This means `all_coords[i]` is the only target in this segment.
                            // We need to cover `all_coords[i]` itself.
                            // The condition `h_j - T <= all_coords[i]` and `h_j + T >= all_coords[i]`
                            // simplifies to `|h_j - all_coords[i]| <= T`.
                            // This is already checked by `it_low` and `*it_low`.
                            // So, if `all_coords[i]` is a target, and `k` is such that `all_coords[k]` is the first
                            // coordinate in a segment that covers `all_coords[i]`, then we can update `dp[i]`.
                            // The `first_p_in_segment_idx <= last_p_in_segment_idx` check handles this.
                            // If `all_coords[i]` is a target, then `last_p_in_segment_idx` will be `p_idx_next_target[i]`.
                            // If `first_p_in_segment_idx` is also `p_idx_next_target[i]`, then the range is just `[all_coords[i], all_coords[i]]`.
                            // This means `required_h_min_for_p = all_coords[i] - T` and `required_h_max_for_p = all_coords[i] + T`.
                            // This is correctly handled by the `if (first_p_in_segment_idx <= last_p_in_segment_idx)` block.
                        }
                    }
                }
            }
        }
    }

    // The final answer is `dp[all_coords.size() - 1]`.
    // If `dp[all_coords.size() - 1]` is `n+1`, it means it's impossible to cover all tracks.
    return dp[all_coords.size() - 1] <= n;
}


int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<long long> h(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> h[i];
    }

    std::vector<long long> p(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> p[i];
    }

    // Binary search for the minimum time T
    long long low = 0;
    // Max possible time: distance from first head to last target, or last head to first target.
    // Max distance between any h_i and p_j is 10^10. So 2 * 10^10 is a safe upper bound.
    // Or, more precisely, max(p_m - h_1, h_n - p_1) could be 10^10.
    // A single head might need to move from h_1 to p_m, which is 10^10.
    // So, 2 * 10^10 is a good upper bound.
    long long high = 20000000000LL; // 2 * 10^10
    long long ans = high;

    while (low <= high) {
        long long mid = low + (high - low) / 2;
        if (check(mid, n, m, h, p)) {
            ans = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    std::cout << ans << std::endl;

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <numeric>
#include <set>
#include <algorithm>
#include <map>

void solve() {
    std::string s;
    std::cin >> s;

    std::vector<std::set<char>> adj(26);
    std::vector<int> degree(26, 0);
    std::vector<bool> in_s(26, false);

    for (char c : s) {
        in_s[c - 'a'] = true;
    }

    bool possible = true;
    for (size_t i = 0; i < s.length() - 1; ++i) {
        char u_char = s[i];
        char v_char = s[i+1];
        int u = u_char - 'a';
        int v = v_char - 'a';

        if (adj[u].find(v_char) == adj[u].end()) { // If this is a new adjacency
            adj[u].insert(v_char);
            adj[v].insert(u_char);
            degree[u]++;
            degree[v]++;
        }

        if (degree[u] > 2 || degree[v] > 2) {
            possible = false;
            break;
        }
    }

    if (!possible) {
        std::cout << "NO\n";
        return;
    }

    std::string layout = "";
    std::vector<bool> visited(26, false);

    // Find starting points for paths (degree 1 nodes or isolated nodes in s)
    for (int i = 0; i < 26; ++i) {
        if (in_s[i] && degree[i] <= 1 && !visited[i]) {
            char current_char = (char)('a' + i);

            // Traverse the path
            while (true) {
                layout += current_char;
                visited[current_char - 'a'] = true;

                char next_char = 0;
                for (char neighbor : adj[current_char - 'a']) {
                    if (!visited[neighbor - 'a']) {
                        next_char = neighbor;
                        break;
                    }
                }

                if (next_char == 0) { // End of path
                    break;
                }
                current_char = next_char;
            }
        }
    }

    // Check if all characters from s are included in the layout
    // This also implicitly checks for cycles or paths with degree > 2 that weren't caught earlier
    // because if there was a cycle, a node would have degree 2 and would be visited,
    // but it wouldn't be a starting point (degree 1 or 0).
    // If all nodes in s are part of a valid path, they will be visited.
    for (int i = 0; i < 26; ++i) {
        if (in_s[i] && !visited[i]) {
            // This means there's a character from s that wasn't part of a path starting from a degree 0/1 node.
            // This can happen if there's a cycle or a path where all nodes have degree 2.
            // For example, if s="abcba", a-b-c-b-a. a-b, b-c. degree(a)=1, degree(c)=1, degree(b)=2.
            // This should be handled by the degree check.
            // The only way a node in_s is not visited is if it's part of a cycle or a path where all nodes have degree 2.
            // But if all nodes have degree 2, it means it's a cycle.
            // A cycle is not allowed in a single row layout.
            // The degree check `degree[u] > 2` already handles most invalid cases.
            // If a character has degree 2 and is part of a path, it will be visited.
            // If it's part of a cycle, it won't be visited by the current logic.
            // So, if any in_s character is not visited, it implies an invalid structure (a cycle).
            possible = false;
            break;
        }
    }

    if (!possible) {
        std::cout << "NO\n";
        return;
    }

    // Add remaining characters not in s
    for (int i = 0; i < 26; ++i) {
        if (!visited[i]) {
            layout += (char)('a' + i);
        }
    }

    std::cout << "YES\n";
    std::cout << layout << "\n";
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <string>
#include <numeric> // For std::accumulate (though manual loop is fine too)
#include <algorithm> // For std::count

// Function to calculate parity of a 01-string
// Returns 1 if odd number of '1's, 0 otherwise
int calculate_parity(const std::string& s) {
    int ones_count = 0;
    for (char c : s) {
        if (c == '1') {
            ones_count++;
        }
    }
    return ones_count % 2;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::string a, b;
    std::cin >> a >> b;

    // Calculate the initial parity of string a
    int parity_a = calculate_parity(a);

    // If parity_a is 0, it means an even number of '1's.
    // We can append '0's indefinitely.
    // If parity_a is 1, it means an odd number of '1's.
    // We can append '1's. After appending '1', the new string will have an even number of '1's,
    // so the next parity will be '0'.
    // So, if initial parity is 1, we can effectively get a string with parity 0 by appending '1'.
    // This means we can always reach a state where we can append '0's.
    // Therefore, if the initial string 'a' has an odd number of '1's, we can effectively
    // consider its "maximum possible '1's count" to be one more than its current count,
    // because we can append a '1' to make it even, and then append '0's.
    // If it has an even number of '1's, we can only append '0's, so its '1's count remains even.

    // The maximum number of '1's we can effectively have in string 'a'
    // (considering we can append a '1' if current count is odd, then '0's)
    int max_ones_a = std::count(a.begin(), a.end(), '1');
    if (max_ones_a % 2 != 0) { // If initial '1's count is odd
        max_ones_a++; // We can append a '1', making the count even.
                      // After this, we can only append '0's.
    }
    // Now, max_ones_a represents the maximum number of '1's we can achieve
    // in a string derived from 'a' *before* any further '0's are appended.
    // Any string derived from 'a' by appending '0's will have this same max_ones_a.

    // Calculate the number of '1's in string b
    int ones_b = std::count(b.begin(), b.end(), '1');

    // Condition for possibility:
    // 1. The number of '1's in 'b' must be less than or equal to the maximum '1's we can get from 'a'.
    // 2. The length of 'b' must be less than or equal to the length of 'a' plus the number of '0's we can append.
    //    Since we can append '0's indefinitely (after potentially one '1' if initial parity was odd),
    //    the length constraint effectively means |b| <= |a| + (number of '0's we can append).
    //    The crucial part is that we can always make the string long enough by appending '0's.
    //    So, the only length constraint is that |b| must be at least 1 (which is given by constraints).
    //    The main constraint is about the number of '1's.

    // If the number of '1's in 'b' is greater than the maximum '1's we can achieve from 'a',
    // then it's impossible.
    if (ones_b > max_ones_a) {
        std::cout << "NO\n";
    } else {
        // If ones_b <= max_ones_a, it means we can potentially form 'b'.
        // We can always remove characters from the front of 'a' to match the length of 'b'
        // or to get a suffix that, when extended, matches 'b'.
        // The key insight is that if we have enough '1's, we can always pad with '0's
        // to reach the desired length of 'b'.
        // For example, if a="010", b="1000".
        // max_ones_a = 1 (odd, so 1+1=2).
        // ones_b = 1.
        // 1 <= 2, so YES.
        // Steps: 010 -> 10 (remove '0') -> 100 (append parity(10)=0) -> 1000 (append parity(100)=0)
        std::cout << "YES\n";
    }

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;
    int n = s.length();

    long long total_pairs = (long long)n * (n + 1) / 2;
    long long bad_pairs_count = 0;

    // last_valid_r[i] stores the maximum r such that (i, r) is a "bad" pair.
    // A pair (l, r) is bad if no triplet (x, x+k, x+2k) with s_x=s_{x+k}=s_{x+2k}
    // is fully contained within s[l-1...r-1].
    // This means for any l, if we want to find the maximum r such that (l, r) is bad,
    // we need to find the smallest starting index of a "good" triplet that starts at or after l.
    // Let min_good_start[i] be the minimum x such that x >= i and s_x=s_{x+k}=s_{x+2k} for some k.
    // If no such x exists, min_good_start[i] = n+1.
    // Then for a given l, the maximum r for a bad pair (l, r) is min_good_start[l-1] - 1.
    // If min_good_start[l-1] - 1 < l-1, it means no bad pairs (l, r) exist for this l.
    // The number of bad pairs for a given l is max(0, min_good_start[l-1] - 1 - (l-1) + 1)
    // which simplifies to max(0, min_good_start[l-1] - l).

    std::vector<int> min_good_start(n + 1, n + 1); // 0-indexed for string, 1-indexed for problem logic
                                                  // min_good_start[i] means min x (1-indexed) such that x >= i
                                                  // and s[x-1]=s[x+k-1]=s[x+2k-1] for some k.

    // Iterate backwards to fill min_good_start
    for (int i = n - 1; i >= 0; --i) {
        min_good_start[i] = min_good_start[i + 1]; // Inherit from the right

        // Check for triplets starting at i (0-indexed)
        // s[i] = s[i+k] = s[i+2k]
        // k can be 1, 2, 3, 4, 5, 6
        // Max k is such that i + 2k < n
        // So 2k < n - i => k < (n - i) / 2
        // For k=1: i+2 < n
        if (i + 2 < n && s[i] == s[i+1] && s[i] == s[i+2]) {
            min_good_start[i] = std::min(min_good_start[i], i + 1); // i+1 is 1-indexed x
        }
        // For k=2: i+4 < n
        if (i + 4 < n && s[i] == s[i+2] && s[i] == s[i+4]) {
            min_good_start[i] = std::min(min_good_start[i], i + 1);
        }
        // For k=3: i+6 < n
        if (i + 6 < n && s[i] == s[i+3] && s[i] == s[i+6]) {
            min_good_start[i] = std::min(min_good_start[i], i + 1);
        }
        // For k=4: i+8 < n
        if (i + 8 < n && s[i] == s[i+4] && s[i] == s[i+8]) {
            min_good_start[i] = std::min(min_good_start[i], i + 1);
        }
        // For k=5: i+10 < n
        if (i + 10 < n && s[i] == s[i+5] && s[i] == s[i+10]) {
            min_good_start[i] = std::min(min_good_start[i], i + 1);
        }
        // For k=6: i+12 < n
        if (i + 12 < n && s[i] == s[i+6] && s[i] == s[i+12]) {
            min_good_start[i] = std::min(min_good_start[i], i + 1);
        }
    }

    // Calculate bad_pairs_count
    for (int l = 1; l <= n; ++l) { // l is 1-indexed
        // For a given l, the maximum r for a bad pair (l, r) is min_good_start[l-1] - 1.
        // The number of such r's is (min_good_start[l-1] - 1) - l + 1,
        // which simplifies to min_good_start[l-1] - l.
        // We take max(0, ...) because r must be >= l.
        bad_pairs_count += std::max(0, min_good_start[l-1] - l);
    }

    std::cout << total_pairs - bad_pairs_count << std::endl;

    return 0;
}

