void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
    }

    // The problem statement guarantees that a solution exists.
    // Reversing the permutation always produces a different permutation
    // (unless n=1, but n >= 2) and preserves the set of adjacent sums.
    // For example, if p = [p1, p2, ..., pn],
    // sums are [p1+p2, p2+p3, ..., p_{n-1}+pn].
    // If p' = [pn, p_{n-1}, ..., p1],
    // sums are [pn+p_{n-1}, p_{n-1}+p_{n-2}, ..., p2+p1].
    // These two sets of sums are identical, just in reverse order.
    // Sorting them will yield the same fingerprint.
    // Since n >= 2, p and reverse(p) are different unless p is a palindrome,
    // but even if p is a palindrome, reverse(p) is still a valid permutation
    // with the same fingerprint. The problem asks for *a* different permutation,
    // but the example output for n=2, p=[1,2] is p'=[2,1], which is reverse(p).
    // The problem statement guarantees a solution exists, and reverse(p) is
    // always a valid permutation. It will be different from p unless p is a palindrome.
    // If p is a palindrome, reverse(p) is p itself.
    // However, the problem statement implies that for any given p, there is *some* p' != p.
    // The simplest strategy is to reverse the permutation.
    // This works for all given examples.

    std::reverse(p.begin(), p.end());

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;
}

