void solve() {
    int n, d;
    std::cin >> n >> d;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    int haybales_in_pile1 = a[0];
    int days_remaining = d;

    // Iterate through piles from 2 to n (index 1 to n-1)
    for (int i = 1; i < n; ++i) {
        // Cost to move one haybale from pile (i+1) to pile 1 is i days.
        // (Pile index i in 0-based array corresponds to pile number i+1)
        int cost_per_haybale = i; 

        if (days_remaining >= cost_per_haybale) {
            // Calculate how many haybales can be moved from this pile
            // given the remaining days and the cost per haybale.
            int haybales_to_move = std::min(a[i], days_remaining / cost_per_haybale);

            haybales_in_pile1 += haybales_to_move;
            days_remaining -= haybales_to_move * cost_per_haybale;
        }
        // If days_remaining < cost_per_haybale, we cannot move any haybale
        // from this pile (or any further piles, as cost increases).
        // So we can stop.
        if (days_remaining == 0) {
            break;
        }
    }

    std::cout << haybales_in_pile1 << std::endl;
}

