    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::vector<std::vector<int>> a(n, std::vector<int>(n));
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < n; ++j) {
            std::cin >> a[i][j];
        }
    }

    std::vector<int> p(n);
    for (int i = 0; i < n; ++i) {
        int max_val_in_row = 0;
        for (int j = 0; j < n; ++j) {
            if (i == j) continue;
            if (a[i][j] > max_val_in_row) {
                max_val_in_row = a[i][j];
            }
        }
        p[i] = max_val_in_row;
    }

    // Check if any element in p is not n-1. If all are n-1, it means
    // the actual value for that position should be n.
    // This happens if the true p_i is n, then min(p_i, p_j) = p_j for all j != i.
    // The maximum of these p_j values would be n-1.
    bool n_found = false;
    for (int i = 0; i < n; ++i) {
        if (p[i] == n) {
            n_found = true;
            break;
        }
    }

    if (!n_found) {
        // If no p[i] was determined to be n, it means the true n was
        // always the larger value in min(p_i, p_j) for the row where p_i=n.
        // So, for the element p_k that is actually n, its row max_val_in_row
        // would be n-1. We need to find one such element and change it to n.
        // Since the problem guarantees a solution, and all values 1 to n are used,
        // there must be exactly one element that is n.
        // If all p[i] are <= n-1, then one of them must be n-1, and that's the one
        // that should be n.
        for (int i = 0; i < n; ++i) {
            if (p[i] == n - 1) {
                p[i] = n;
                break;
            }
        }
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

