                // We need to be able to jump from last_R_pos+1 to i+1.
                // The required d for this segment is (i+1) - (last_R_pos+1) = i - last_R_pos.
                max_dist = std::max(max_dist, i - last_R_pos);
                last_R_pos = i;
            }
        }

        // After iterating through the string, we need to consider the jump from the last 'R'
        // (or 0 if no 'R's) to the target n+1.
        // The distance is (n+1) - (last_R_pos + 1) = n - last_R_pos.
        max_dist = std::max(max_dist, n - last_R_pos);

