                // This is equivalent to k = 2^i for i = 0, 1, 2, ...
                // The next k is 2*k.
                // However, the problem statement implies k is 2^i - 1.
                // Let's re-evaluate the sequence of stairs: 1, 3, 7, 15, ...
                // These are 2^1-1, 2^2-1, 2^3-1, 2^4-1, ...
                // Let m be the number of stairs. m = 2^p - 1.
                // The cost is (2^p - 1) * (2^p + 1) / 2 = (4^p - 1) / 2.
                // Let's use the variable `k` to represent `2^p`.
                // So, `num_stairs = k - 1`.
                // The cost is `(k - 1) * (k + 1) / 2 = (k*k - 1) / 2`.
                // The sequence of `k` values (which are powers of 2) would be 2, 4, 8, 16, ...
                // Let's restart with `k` being the number of stairs.
                // Stairs: 1, 3, 7, 15, ...
                // Cost: 1, 7, 31, 127, ...
                // Let `n` be the number of stairs.
                // `n_0 = 1`. Cost `C_0 = 1`.
                // `n_1 = 3`. Cost `C_1 = 7`.
                // `n_2 = 7`. Cost `C_2 = 31`.
                // `n_p = 2^(p+1) - 1`. Cost `C_p = (2^(p+1) - 1) * (2^(p+1) + 1) / 2 = (4^(p+1) - 1) / 2`.
                // Let `current_n_stairs` be the number of stairs for the current nice staircase.
                // Initially, `current_n_stairs = 1`.
                // The cost is `(current_n_stairs * (current_n_stairs + 1)) / 2`.
                // This is not the formula for nice staircases.
                // The cost for a nice staircase with `n` stairs is `(n * (n+1)) / 2`.
                // The condition for being nice is that `n` must be of the form `2^p - 1`.
                // So, `n = 2^p - 1`.
                // The cost is `(2^p - 1) * (2^p) / 2`.
                // Let `p_val` be the power of 2.
                // For p=1, n=1. Cost = 1 * 2 / 2 = 1.
                // For p=2, n=3. Cost = 3 * 4 / 2 = 6.
                // For p=3, n=7. Cost = 7 * 8 / 2 = 28.
                // For p=4, n=15. Cost = 15 * 16 / 2 = 120.
                // The example says for 8 cells, we can build 1-stair (cost 1) and 3-stair (cost 6). Total 7. Answer 2.
                // This matches my calculation.
                // So, the sequence of `n` values for nice staircases is `1, 3, 7, 15, 31, ...` (i.e., `2^p - 1` for `p >= 1`).
                // The cost for a staircase with `N` stairs is `N * (N + 1) / 2`.
                // Let `current_n_stairs` be the number of stairs for the current nice staircase.
                // Start with `current_n_stairs = 1`.
                // Cost = `1 * (1 + 1) / 2 = 1`.
                // Next `current_n_stairs = 3`.
                // Cost = `3 * (3 + 1) / 2 = 6`.
                // Next `current_n_stairs = 7`.
                // Cost = `7 * (7 + 1) / 2 = 28`.
                // Next `current_n_stairs = 15`.
                // Cost = `15 * (15 + 1) / 2 = 120`.
                // The sequence of `current_n_stairs` is `1, 3, 7, 15, ...` which is `2^p - 1`.
                // If `current_n_stairs = N`, then the next one is `2*N + 1`.
                // Let's use `current_n_stairs` as the variable.
                // Initial `current_n_stairs = 1`.
                // Cost = `current_n_stairs * (current_n_stairs + 1) / 2`.
                // If `x >= cost`, then `count++`, `x -= cost`, `current_n_stairs = 2 * current_n_stairs + 1`.
                // Otherwise, break.
            } else {
                break;
            }
            k = 2 * k + 1; // This `k` is `current_n_stairs`.
                           // The variable name `k` was confusing. Let's rename it to `current_n_stairs`.
        }
        std::cout << count << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <cmath>
#include <iomanip>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    double h;
    std::cin >> n >> h;

    // The total area of the carrot is (1/2) * base * height = (1/2) * 1 * h = h/2.
    // Each of the n pieces must have an area of (h/2) / n = h / (2n).

    // Consider a cut at height x from the apex.
    // This cut forms a smaller triangle similar to the original carrot.
    // If the original carrot has height H and base B, then a triangle of height x
    // will have a base B' such that x/H = B'/B. So B' = B * (x/H).
    // For our carrot, H=h, B=1. So, B' = 1 * (x/h) = x/h.
    // The area of this smaller triangle is (1/2) * B' * x = (1/2) * (x/h) * x = x^2 / (2h).

    // We want the i-th cut (at height x_i from apex) to enclose an area
    // equal to i times the area of a single piece.
    // That is, Area(triangle up to x_i) = i * (h / (2n)).
    // So, x_i^2 / (2h) = i * h / (2n).
    // x_i^2 = i * h^2 / n.
    // x_i = sqrt(i * h^2 / n) = h * sqrt(i / n).

    for (int i = 1; i < n; ++i) {
        double x_i = h * std::sqrt(static_cast<double>(i) / n);
        std::cout << std::fixed << std::setprecision(12) << x_i << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n, k;
    std::cin >> n >> k;

    std::vector<int> p(n);
    int left = 1;
    int right = k + 1; // The largest number we use to generate k distinct differences

    // Generate k distinct differences: k, k-1, ..., 1
    // This is done by alternating between the smallest available number (left)
    // and the largest available number (right) from the range [1, k+1].
    // The numbers used will be 1, k+1, 2, k, 3, k-1, ...
    // The differences will be:
    // |1 - (k+1)| = k
    // |(k+1) - 2| = k-1
    // |2 - k| = k-2
    // ...
    // This sequence generates differences k, k-1, k-2, ..., 1.
    // There are k such differences.
    for (int i = 0; i <= k; ++i) {
        if (i % 2 == 0) { // Even index, take from left (small)
            p[i] = left;
            left++;
        } else { // Odd index, take from right (large)
            p[i] = right;
            right--;
        }
    }

    // After generating the first k+1 elements, we have used numbers from 1 to k+1.
    // The remaining numbers are k+2, k+3, ..., n.
    // To ensure no new distinct differences are introduced, we can append these
    // remaining numbers in increasing order. This will only generate a difference of 1.
    // Since 1 is already among the k distinct differences generated above,
    // this does not add any new distinct differences.
    for (int i = k + 1; i < n; ++i) {
        p[i] = i + 1;
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n, k;
    std::cin >> n >> k;
    std::string s;
    std::cin >> s;

    std::string result = "";
    int open_count = 0;
    int close_count = 0;
    int balance = 0;

    for (char c : s) {
        if (c == '(') {
            // Try to pick an opening bracket if we still need them
            // and if picking it won't exceed the maximum possible balance for a k-length sequence
            // (which is k/2, as we need k/2 opening brackets in total)
            if (open_count < k / 2) {
                result += '(';
                open_count++;
                balance++;
            }
        } else { // c == ')'
            // Try to pick a closing bracket if we still need them
            // and if the current balance allows it (balance > 0)
            // and if picking it won't make us exceed k/2 closing brackets
            if (close_count < k / 2 && balance > 0) {
                result += ')';
                close_count++;
                balance--;
            }
        }
        // Optimization: if we have already formed a sequence of length k, we can stop
        if (result.length() == k) {
            break;
        }
    }

    std::cout << result << std::endl;

    return 0;
}

