void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    std::vector<int> pos(n + 1); // pos[x] stores the 0-indexed position of x in p
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
        pos[p[i]] = i;
    }

    std::string result = "";
    result.reserve(n);

    int current_min_idx = pos[1];
    int current_max_idx = pos[1];

    for (int m = 1; m <= n; ++m) {
        // For m=1, the segment is just [1].
        // current_min_idx and current_max_idx are already initialized to pos[1].
        // The length is 1. min is 1, max is 1.
        // So m=1 is always beautiful.

        // For m > 1, we extend the segment to include 'm'.
        // The segment must contain all numbers from 1 to m.
        // We maintain the minimum and maximum indices (leftmost and rightmost)
        // that contain all numbers from 1 up to the current 'm-1'.
        // When we consider 'm', we need to include 'm' into this range.
        // The new range will be [min(current_min_idx, pos[m]), max(current_max_idx, pos[m])].

        if (m > 1) {
            current_min_idx = std::min(current_min_idx, pos[m]);
            current_max_idx = std::max(current_max_idx, pos[m]);
        }

        // Check if the current segment [current_min_idx, current_max_idx]
        // is a permutation of 1, ..., m.
        // This means its length must be exactly m.
        if (current_max_idx - current_min_idx + 1 == m) {
            result += '1';
        } else {
            result += '0';
        }
    }
    std::cout << result << "\n";
}

