        // It depends on m % 10.
        // Let's precompute the sum of last digits for i=1 to 10 for each possible last digit of m.
        // m_last_digit = m % 10
        // sums_of_first_10_digits[m_last_digit] will store sum of (i * m_last_digit) % 10 for i=1 to 10.
