        // The last digit of (i * m) is (i * (m % 10)) % 10. This is also incorrect.
        // The last digit of (i * m) is (i * m) % 10.
        // The sequence of last digits (i*m)%10 for i=1 to 10 is periodic.
        // The sum of these 10 digits is what we need.

        std::vector<int> cycle_sum_values(10);
        for (int i = 0; i < 10; ++i) {
