    // So, if A+D == 0, Box 4 is impossible.
    if ((A + B) % 2 == 0 && (A + D > 0)) {
        ans4 = "Ya";
    }

    // Special case: total_toys == 1
    // If only one toy, it is the super toy.
    if (total_toys == 1) {
        ans1 = "Tidak"; ans2 = "Tidak"; ans3 = "Tidak"; ans4 = "Tidak";
        if (A == 1) ans1 = "Ya";
        if (B == 1) ans2 = "Ya";
        if (C == 1) ans3 = "Ya";
        if (D == 1) ans4 = "Ya";
    }

    std::cout << ans1 << " " << ans2 << " " << ans3 << " " << ans4 << std::endl;
}

