}

#include <iostream>
#include <vector>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }
    std::sort(a.begin(), a.end());
    int count = 0;
    int left_ptr = 0; // Pointer for elements to be placed (potential b[i])
    int right_ptr = 0; // Pointer for original elements (potential a[i])

    // We want to find b[i] > a[i].
    // To maximize this, we should try to match the smallest available b[i]
    // with the smallest available a[i] such that b[i] > a[i].
    // This greedy strategy works:
    // Sort the array 'a'. Let's call it 'sorted_a'.
    // We use 'sorted_a' as both the source for original values (a[i])
    // and the source for permuted values (b[i]).
    //
    // We iterate through 'sorted_a' with two pointers.
    // 'left_ptr' points to a potential 'a[i]' value.
    // 'right_ptr' points to a potential 'b[i]' value.
    //
    // If sorted_a[right_ptr] > sorted_a[left_ptr],
    // we found a pair (sorted_a[left_ptr], sorted_a[right_ptr])
    // where the permuted value is greater than the original value.
    // We increment count and advance both pointers.
    //
    // If sorted_a[right_ptr] <= sorted_a[left_ptr],
    // sorted_a[right_ptr] is not large enough to be greater than sorted_a[left_ptr].
    // To maximize our chances, we should try to find a larger 'b[i]' value.
    // So, we advance 'right_ptr' to consider a larger element for 'b[i]'.
    // We do not advance 'left_ptr' because sorted_a[left_ptr] still needs a match.

    while (right_ptr < n) {
        if (a[right_ptr] > a[left_ptr]) {
            // Found a pair where a[right_ptr] can be placed at a position
            // originally occupied by a[left_ptr], and a[right_ptr] > a[left_ptr].
            count++;
            left_ptr++;
            right_ptr++;
        } else {
            // a[right_ptr] is not greater than a[left_ptr].
            // We need a larger element for a[right_ptr] to be useful.
            // So, we try the next element for a[right_ptr].
            right_ptr++;
        }
    }
    std::cout << count << std::endl;
    return 0;
}

