// Function to check if a subarray is a permutation
// `arr` is the array, `start` is the starting index, `len` is the length
// `max_val` is the maximum value expected in the permutation (which is `len`)
bool is_permutation(const std::vector<int>& arr, int start, int len, int max_val) {
    if (len == 0) return true; // An empty sequence can be considered a permutation of length 0
    if (max_val != len) return false; // A permutation of length L must contain numbers 1 to L.

    std::vector<bool> seen(len + 1, false);
    for (int i = 0; i < len; ++i) {
        int val = arr[start + i];
        if (val < 1 || val > len || seen[val]) {
            return false;
        }
        seen[val] = true;
    }
    return true;
}

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    int max_val_prefix = 0;
    int max_val_suffix = 0;

    // Calculate max_val_prefix for each prefix length
    // max_val_prefix[i] stores the maximum value in a[0...i]
    std::vector<int> prefix_max(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
        if (i == 0) {
            prefix_max[i] = a[i];
        } else {
            prefix_max[i] = std::max(prefix_max[i-1], a[i]);
        }
    }

    // Calculate max_val_suffix for each suffix length
    // max_val_suffix[i] stores the maximum value in a[i...n-1]
    std::vector<int> suffix_max(n);
    for (int i = n - 1; i >= 0; --i) {
        if (i == n - 1) {
            suffix_max[i] = a[i];
        } else {
            suffix_max[i] = std::max(suffix_max[i+1], a[i]);
        }
    }

    // Precompute permutation checks for prefixes and suffixes
    std::vector<bool> is_prefix_perm(n + 1, false); // is_prefix_perm[L] is true if a[0...L-1] is a permutation of length L
    std::vector<bool> is_suffix_perm(n + 1, false); // is_suffix_perm[L] is true if a[n-L...n-1] is a permutation of length L

    std::vector<bool> seen_prefix(n + 1, false);
    bool current_prefix_valid = true;
    for (int l = 1; l <= n; ++l) {
        int val = a[l-1];
        if (val < 1 || val > l || seen_prefix[val]) {
            current_prefix_valid = false;
        }
        seen_prefix[val] = true;
        if (current_prefix_valid && prefix_max[l-1] == l) {
            is_prefix_perm[l] = true;
        }
    }

    std::vector<bool> seen_suffix(n + 1, false);
    bool current_suffix_valid = true;
    for (int l = 1; l <= n; ++l) {
        int val = a[n-l];
        if (val < 1 || val > l || seen_suffix[val]) {
            current_suffix_valid = false;
        }
        seen_suffix[val] = true;
        if (current_suffix_valid && suffix_max[n-l] == l) {
            is_suffix_perm[l] = true;
        }
    }

    std::vector<std::pair<int, int>> results;
    for (int l1 = 1; l1 < n; ++l1) { // l1 is length of p1, l2 is length of p2
        int l2 = n - l1;
        if (is_prefix_perm[l1] && is_suffix_perm[l2]) {
            results.push_back({l1, l2});
        }
    }

    std::cout << results.size() << "\n";
    for (const auto& p : results) {
        std::cout << p.first << " " << p.second << "\n";
    }
}

