#include <iostream>
#include <vector>
#include <numeric>
#include <functional>

void solve() {
    int n;
    std::cin >> n;
    long long current_sum = 0;
    long long current_xor_sum = 0;
    for (int i = 0; i < n; ++i) {
        long long a;
        std::cin >> a;
        current_sum += a;
        current_xor_sum ^= a;
    }

    // We need to find b1, b2, b3 such that (current_sum + b1 + b2 + b3) = 2 * (current_xor_sum ^ b1 ^ b2 ^ b3)
    // Let S = current_sum, X = current_xor_sum
    // We need S' = 2 * X'
    // S' = S + b1 + b2 + b3
    // X' = X ^ b1 ^ b2 ^ b3

    // Strategy: Append at most 3 elements.
    // The problem guarantees a solution always exists.
    // A simple strategy is to append two elements such that the XOR sum becomes 0,
    // and then append a third element to satisfy the sum condition.

    // Step 1: Make the XOR sum 0.
    // If current_xor_sum is not 0, we can append current_xor_sum itself.
    // New XOR sum: current_xor_sum ^ current_xor_sum = 0.
    // New sum: current_sum + current_xor_sum.
    // Let b1 = current_xor_sum.
    // After appending b1:
    // S_1 = current_sum + b1
    // X_1 = current_xor_sum ^ b1 = 0

    // Now we need to find b2, b3 such that (S_1 + b2 + b3) = 2 * (X_1 ^ b2 ^ b3)
    // Since X_1 = 0, this simplifies to (S_1 + b2 + b3) = 2 * (b2 ^ b3).

    // Let's try to make b2 ^ b3 = b2 + b3. This happens if b2 and b3 have no common set bits (b2 & b3 = 0).
    // If we can achieve b2 ^ b3 = b2 + b3, then we need S_1 + b2 + b3 = 2 * (b2 + b3).
    // This means S_1 = b2 + b3.
    // So we need to find b2, b3 such that b2 & b3 = 0 and b2 + b3 = S_1.
    // This is not always possible with arbitrary S_1.

    // A simpler approach:
    // We need S' = 2 * X'.
    // Let's try to make X' = X_target and S' = 2 * X_target.
    // We can always achieve this by appending at most 3 elements.

    // Let's append two elements:
    // b1 = current_xor_sum
    // b2 = current_sum + current_xor_sum
    // This is not quite right.

    // Consider the target state: S_final = 2 * X_final.
    // Let's try to make X_final = X_0.
    // Then we need S_final = 2 * X_0.
    // We need to append elements $b_1, \dots, b_k$ such that:
    // $X_0 \oplus b_1 \oplus \dots \oplus b_k = X_0$
    // $S_0 + b_1 + \dots + b_k = 2 \cdot X_0$

    // From the first equation, $b_1 \oplus \dots \oplus b_k = 0$.
    // From the second equation, $b_1 + \dots + b_k = 2 \cdot X_0 - S_0$.
    // Let $Y = 2 \cdot X_0 - S_0$. We need $b_1 \oplus \dots \oplus b_k = 0$ and $b_1 + \dots + b_k = Y$.
    // If $Y < 0$, this strategy won't work with non-negative $b_i$.
    // $S_0 \ge X_0$ is always true. So $2X_0 - S_0$ can be negative.

    // A robust strategy:
    // 1. Append `current_xor_sum` to make the XOR sum 0.
    //    Let $b_1 = \text{current\_xor\_sum}$.
    //    New sum: $S_1 = \text{current\_sum} + b_1$.
    //    New XOR sum: $X_1 = \text{current\_xor\_sum} \oplus b_1 = 0$.
    //    Now we need to find $b_2, b_3$ such that $(S_1 + b_2 + b_3) = 2 \cdot (X_1 \oplus b_2 \oplus b_3)$.
    //    $(S_1 + b_2 + b_3) = 2 \cdot (0 \oplus b_2 \oplus b_3) = 2 \cdot (b_2 \oplus b_3)$.

    // 2. We need $S_1 + b_2 + b_3 = 2 \cdot (b_2 \oplus b_3)$.
    //    Let $b_2 = S_1$.
    //    Then $S_1 + S_1 + b_3 = 2 \cdot (S_1 \oplus b_3)$.
    //    $2 \cdot S_1 + b_3 = 2 \cdot (S_1 \oplus b_3)$.
    //    This implies $b_3 = 2 \cdot (S_1 \oplus b_3) - 2 \cdot S_1$.
    //    This is not easy to solve for $b_3$.

    // Let's use the property $A+B = (A \oplus B) + 2(A \text{ AND } B)$.
    // We need $S' = 2X'$.
    // This means $S' - X' = X'$.
    // We know $S' - X'$ is always an even number (because $S' - X' = \sum a_i - \bigoplus a_i = \sum (a_i - (a_i \text{ mod } 2)) - (\bigoplus (a_i \text{ mod } 2)) = \text{even} - \text{even} = \text{even}$).
    // So $X'$ must be an even number.

    // Let's try to append two elements.
    // Let $X_0$ be the current XOR sum, $S_0$ be the current sum.
    // We want to find $b_1, b_2$ such that:
    // $S_0 + b_1 + b_2 = 2 \cdot (X_0 \oplus b_1 \oplus b_2)$.

    // Consider appending $b_1 = X_0$.
    // New XOR sum $X_1 = X_0 \oplus X_0 = 0$.
    // New sum $S_1 = S_0 + X_0$.
    // Now we need to append $b_2$ such that $S_1 + b_2 = 2 \cdot (0 \oplus b_2) = 2 \cdot b_2$.
    // This means $S_1 = b_2$.
    // So, we can append $b_1 = X_0$ and $b_2 = S_0 + X_0$.
    // The new array will have sum $S_0 + X_0 + (S_0 + X_0) = 2(S_0 + X_0)$.
    // The new XOR sum will be $X_0 \oplus X_0 \oplus (S_0 + X_0) = 0 \oplus (S_0 + X_0) = S_0 + X_0$.
    // Let $X_{final} = S_0 + X_0$.
    // The condition $S_{final} = 2 \cdot X_{final}$ becomes $2(S_0 + X_0) = 2 \cdot (S_0 + X_0)$, which is true.
    // This strategy always works and uses at most 2 elements.
    // The elements are $X_0$ and $S_0 + X_0$.
    // $X_0$ can be up to $2^{20}$ (max $a_i$ is $10^9$, $2^{29} > 10^9$, so $X_0$ fits in long long).
    // $S_0$ can be up to $10^5 \cdot 10^9 = 10^{14}$.
    // So $S_0 + X_0$ can be up to $10^{14} + 2^{20}$, which fits in long long ($10^{18}$ limit).

    // If the array is already good, $S_0 = 2 \cdot X_0$.
    // Then $X_0$ and $S_0 + X_0 = 2X_0 + X_0 = 3X_0$.
    // Appending $X_0$ and $3X_0$ would make the array good.
    // But the problem says we don't have to minimize. So if it's already good, we can output 0 elements.

    if (current_sum == 2 * current_xor_sum) {
        std::cout << 0 << std::endl << std::endl;
    } else {
        std::cout << 2 << std::endl;
        long long b1 = current_xor_sum;
        long long b2 = current_sum + current_xor_sum;
        std::cout << b1 << " " << b2 << std::endl;
    }
}

