int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;

    long long total_steps = 0;
    long long b_count = 0;
    long long MOD = 1e9 + 7;

    // Iterate from right to left
    for (int i = s.length() - 1; i >= 0; --i) {
        if (s[i] == 'b') {
            b_count = (b_count + 1) % MOD;
        } else { // s[i] == 'a'
            // An 'a' at this position will interact with all 'b's to its right.
            // Each 'b' to its right will cause one "ab" -> "bba" operation.
            // This 'a' will move past all 'b_count' 'b's.
            // So, it contributes 'b_count' steps.
            total_steps = (total_steps + b_count) % MOD;

            // After this 'a' moves past all 'b_count' 'b's, it effectively
            // becomes 'b_count' new 'b's to its left (from the 'bba' rule).
            // These new 'b's will then be available for 'a's further to the left.
            // The number of 'b's effectively doubles for the next 'a' to the left.
            b_count = (b_count * 2) % MOD;
        }
    }

    std::cout << total_steps << std::endl;

    return 0;
}

