// Function to convert a number to its parity pattern string
// For example, 241 -> "001" (right to left: 1 is odd, 4 is even, 2 is even)
// Padded to 18 digits with leading '0's.
std::string get_parity_pattern(long long n) {
    std::string pattern = "";
    if (n == 0) {
        pattern = "0";
    } else {
        while (n > 0) {
            if ((n % 10) % 2 == 0) {
                pattern += '0';
            } else {
                pattern += '1';
            }
            n /= 10;
        }
    }
    // Pad with leading zeros to 18 digits
    // The pattern is built right-to-left, so we need to reverse it for standard representation
    // and then pad. Or, more simply, just pad to 18 characters.
    // Since we are comparing right-to-left, the order of digits in `pattern` is already correct
    // for direct comparison with a query pattern that is also processed right-to-left.
    // However, map keys are strings, so we need a canonical form.
    // Let's make it fixed length 18, with rightmost digit parity at index 17, etc.
    // Example: 241 -> "001" (reversed from 100)
    // If we want "00...000100", we need to pad to the left.
    // The current `pattern` string has the rightmost digit parity at index 0.
    // So, if `pattern` is "100" for 241, we need to pad it to "00...00100".
    // The length of the pattern string is at most 18.
    // We need to pad it to 18 characters with '0's at the beginning.
    std::string canonical_pattern = std::string(18 - pattern.length(), '0') + pattern;
    return canonical_pattern;
}

int main() {
    // Optimize C++ standard streams for competitive programming
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int t;
    std::cin >> t;

    // Use a map to store counts of numbers based on their parity patterns.
    // The key will be the 18-digit parity pattern string.
    std::map<std::string, int> counts;

    for (int i = 0; i < t; ++i) {
        char type;
        std::cin >> type;

        if (type == '+') {
            long long a;
            std::cin >> a;
            counts[get_parity_pattern(a)]++;
        } else if (type == '-') {
            long long a;
            std::cin >> a;
            counts[get_parity_pattern(a)]--;
        } else { // type == '?'
            std::string s;
            std::cin >> s;
            // Pad the query pattern to 18 digits with leading '0's
            std::string query_pattern = std::string(18 - s.length(), '0') + s;
            std::cout << counts[query_pattern] << "\n";
        }
    }

    return 0;
}

