#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::vector<std::vector<int>> b(n, std::vector<int>(n));
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < n; ++j) {
            std::cin >> b[i][j];
        }
    }

    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        int current_a_i = 0;
        for (int j = 0; j < n; ++j) {
            if (i == j) {
                continue;
            }
            current_a_i |= b[i][j];
        }
        a[i] = current_a_i;
    }

    for (int i = 0; i < n; ++i) {
        std::cout << a[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long l, r, Ql, Qr;
    std::cin >> n >> l >> r >> Ql >> Qr;

    std::vector<long long> w(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> w[i];
    }

    std::vector<long long> prefix_sum(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        prefix_sum[i + 1] = prefix_sum[i] + w[i];
    }

    long long min_energy = -1;

    // Iterate over all possible counts of items taken from the left
    // Let 'i' be the number of items taken from the left.
    // Then 'n - i' items are taken from the right.
    for (int i = 0; i <= n; ++i) {
        int j = n - i; // Number of items taken from the right

        long long current_energy = 0;

        // Energy for items taken from the left
        current_energy += prefix_sum[i] * l;

        // Energy for items taken from the right
        current_energy += (prefix_sum[n] - prefix_sum[n - j]) * r;

        // Add penalty for imbalance
        if (i > j) {
            // More items from left. If we took 'i' left items and 'j' right items,
            // the last 'i - j - 1' left items must have been taken consecutively
            // after all right items were taken, or after a right item was taken
            // and then a left item, etc.
            // The number of "extra" left items that might incur Ql penalty is i - j - 1.
            // This is equivalent to (i - j) - 1.
            // The number of times we switch from right to left and then take another left
            // is (i - j - 1).
            // The problem statement says "If the previous action was the same (left-hand),
            // then the robot spends extra Ql energy units".
            // This means if we have k_L left items and k_R right items,
            // and k_L > k_R, then (k_L - k_R - 1) times we took a left item
            // when the previous item was also a left item.
            // Example: L L L R R. k_L=3, k_R=2. k_L-k_R-1 = 0. No penalty.
            // Example: L L L R. k_L=3, k_R=1. k_L-k_R-1 = 1. One penalty.
            // This is equivalent to (i - j) - 1 if i > j.
            // The number of "excess" items from one side that are taken consecutively
            // after the other side's items are exhausted or balanced.
            // If i > j, there are i - j more items from the left.
            // The first i - j items from the left are "balanced" by j items from the right.
            // The remaining i - j items are taken from the left.
            // The first of these i - j items might not incur a penalty if the last item
            // taken was from the right.
            // But if we consider the total sequence, after j items from right and j items from left,
            // we are left with i - j items from the left.
            // To take these i - j items, we will incur Ql penalty for (i - j - 1) of them.
            // This is because the first of these i - j items might be taken after a right item,
            // but the subsequent i - j - 1 items will be taken after a left item.
            current_energy += (i - j - 1) * Ql;
        } else if (j > i) {
            // More items from right. Similar logic.
            current_energy += (j - i - 1) * Qr;
        }

        if (min_energy == -1 || current_energy < min_energy) {
            min_energy = current_energy;
        }
    }

    std::cout << min_energy << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm> // For std::min

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n == 0) { // Edge case, though problem constraints say n >= 1
        std::cout << 0 << "\n";
        return;
    }

    int bad_prices_count = 0;
    // Initialize min_suffix with the last element, as there are no elements after it.
    // The last element itself can never be a bad price by definition.
    int min_suffix = a[n - 1]; 

    // Iterate from the second to last element backwards to the first element.
    // For each element a[i], we compare it with the minimum price found so far
    // in the suffix a[i+1...n-1].
    for (int i = n - 2; i >= 0; --i) {
        if (a[i] > min_suffix) {
            bad_prices_count++;
        } else {
            // If a[i] is not greater than min_suffix, it means a[i] is
            // either equal to or less than min_suffix.
            // In this case, a[i] becomes the new minimum for the suffix
            // starting from a[i] itself.
            min_suffix = a[i];
        }
    }

    std::cout << bad_prices_count << "\n";
}

