// Function to find prime factors of a number
// Returns a vector of pairs: (prime_factor, exponent)
std::vector<std::pair<long long, int>> get_prime_factors(long long n) {
    std::vector<std::pair<long long, int>> factors;
    for (long long i = 2; i * i <= n; ++i) {
        if (n % i == 0) {
            int count = 0;
            while (n % i == 0) {
                n /= i;
                count++;
            }
            factors.push_back({i, count});
        }
    }
    if (n > 1) {
        factors.push_back({n, 1});
    }
    return factors;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int t;
    std::cin >> t;
    while (t--) {
        long long p, q;
        std::cin >> p >> q;

        if (p % q != 0) {
            std::cout << p << "\n";
            continue;
        }

        // p is divisible by q. We need to find the largest x < p such that p % x == 0 and x % q != 0.
        // This means we need to remove some factors from p such that x is no longer divisible by q.
        // To maximize x, we should remove the minimum necessary factors.

        // Get prime factors of q
        std::vector<std::pair<long long, int>> q_factors = get_prime_factors(q);

        long long max_x = 1; // Initialize with a small value, will be updated

        // Iterate through each prime factor f of q
        for (const auto& factor_pair : q_factors) {
            long long f = factor_pair.first;
            // int q_exponent = factor_pair.second; // Not directly needed for this logic

            // Calculate the largest power of f that divides p
            long long current_p = p;
            long long p_f_power = 0;
            while (current_p > 0 && current_p % f == 0) {
                current_p /= f;
                p_f_power++;
            }

            // Calculate the largest power of f that divides q
            long long current_q = q;
            long long q_f_power = 0;
            while (current_q > 0 && current_q % f == 0) {
                current_q /= f;
                q_f_power++;
            }

            // If p is divisible by q, then p_f_power must be >= q_f_power for all f.
            // To make x not divisible by q, we must reduce the exponent of f in x
            // to be less than q_f_power.
            // The largest such x would be p / (f^(p_f_power - q_f_power + 1)).
            // This removes just enough factors of f to make x not divisible by q.
            // We want to maximize x, so we take the maximum of these candidates.

            // The number of factors of f to remove from p is (p_f_power - q_f_power + 1)
            // This ensures that the resulting x has (p_f_power - (p_f_power - q_f_power + 1)) = q_f_power - 1 factors of f,
            // which is less than q_f_power, so x is not divisible by q by this factor f.

            long long candidate_x = p;
            for (int i = 0; i < (p_f_power - q_f_power + 1); ++i) {
                candidate_x /= f;
            }

            max_x = std::max(max_x, candidate_x);
        }
        std::cout << max_x << "\n";
    }

    return 0;
}

#include <iostream>
#include <algorithm>
#include <vector>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        int n;
        std::cin >> n;
        long long min_x = -2000000000LL; // Effectively negative infinity
        long long max_x = 2000000000LL;  // Effectively positive infinity
        long long min_y = -2000000000LL; // Effectively negative infinity
        long long max_y = 2000000000LL;  // Effectively positive infinity

        for (int i = 0; i < n; ++i) {
            long long x, y;
            int f1, f2, f3, f4;
            std::cin >> x >> y >> f1 >> f2 >> f3 >> f4;

            // If f1=0, robot cannot move left. So target X must be >= current x.
            if (f1 == 0) {
                min_x = std::max(min_x, x);
            }
            // If f3=0, robot cannot move right. So target X must be <= current x.
            if (f3 == 0) {
                max_x = std::min(max_x, x);
            }
            // If f4=0, robot cannot move down. So target Y must be >= current y.
            if (f4 == 0) {
                min_y = std::max(min_y, y);
            }
            // If f2=0, robot cannot move up. So target Y must be <= current y.
            if (f2 == 0) {
                max_y = std::min(max_y, y);
            }
        }

        if (min_x <= max_x && min_y <= max_y) {
            // A valid point exists. We can pick any point within the valid range.
            // The problem guarantees that if a solution exists, one with coordinates
            // not exceeding 10^5 by absolute value exists.
            // So, we can clamp min_x and min_y to stay within the guaranteed range
            // if they happen to be outside the -10^5 to 10^5 range due to our
            // initial large bounds, but still within the valid interval.
            // For example, if min_x is 10^9, but max_x is 10^5, we can pick 10^5.
            // The problem statement implies that if min_x <= max_x, then there's
            // a point (X,Y) with |X|,|Y| <= 10^5.
            // So, simply picking (min_x, min_y) is fine, as long as it's within the
            // valid range. The problem guarantees that if min_x <= max_x and min_y <= max_y,
            // then there exists an X in [min_x, max_x] and Y in [min_y, max_y]
            // such that |X|, |Y| <= 10^5.
            // We can just output min_x and min_y directly.
            // The coordinates can be up to 10^5, so our initial large bounds are fine.
            // The problem guarantees that if a solution exists, one with coordinates
            // not exceeding 10^5 by absolute value exists.
            // So, if min_x is, say, 10^6, but max_x is 10^5, then min_x > max_x, and we output 0.
            // If min_x is -10^6, and max_x is 10^5, then min_x <= max_x, and we can pick min_x.
            // But the problem guarantees that if a solution exists, one with coordinates
            // not exceeding 10^5 by absolute value exists.
            // So, if min_x is -10^6, it means all robots can reach -10^6.
            // But if there's a solution, there's one with X in [-10^5, 10^5].
            // This implies that if min_x <= max_x, then there must be some X in [min_x, max_x]
            // that is also in [-10^5, 10^5].
            // So, we can just output min_x and min_y.
            std::cout << 1 << " " << min_x << " " << min_y << "\n";
        } else {
            std::cout << 0 << "\n";
        }
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::string s;
    std::cin >> s;

    std::vector<int> d(n);
    for (int i = 0; i < n; ++i) {
        d[i] = s[i] - '0';
    }

    for (int x = 0; x <= 9; ++x) {
        std::vector<int> colors(n);
        std::vector<int> s1_digits;
        std::vector<int> s2_digits;
        bool possible_x = true;

        for (int i = 0; i < n; ++i) {
            if (d[i] < x) {
                colors[i] = 1;
                s1_digits.push_back(d[i]);
            } else if (d[i] > x) {
                colors[i] = 2;
                s2_digits.push_back(d[i]);
            } else { // d[i] == x
                // Try to assign to color 2 first, if possible
                // This means d[i] is the first 'x' or previous 'x's were also color 2
                // Or, if we haven't seen any digit > x yet, we can assign to color 1
                // The strategy is: all d_i < x are color 1.
                // All d_i > x are color 2.
                // For d_i == x:
                // If we haven't seen any d_j > x yet, we can assign d_i to color 1.
                // If we have seen d_j > x, then d_i must be color 2.
                // This is equivalent to finding the first occurrence of 'x' that we want to color 2.
                // All 'x's before that are color 1, all 'x's after that are color 2.
                // This is handled by the loop below.
            }
        }

        // Check if s1_digits and s2_digits are non-decreasing
        for (size_t i = 1; i < s1_digits.size(); ++i) {
            if (s1_digits[i] < s1_digits[i-1]) {
                possible_x = false;
                break;
            }
        }
        if (!possible_x) continue;

        for (size_t i = 1; i < s2_digits.size(); ++i) {
            if (s2_digits[i] < s2_digits[i-1]) {
                possible_x = false;
                break;
            }
        }
        if (!possible_x) continue;

        // Now, handle digits equal to x
        // Find the split point for digits equal to x
        // All d_i == x before split_idx are color 1
        // All d_i == x at or after split_idx are color 2
        // The split_idx is the first index where d[i] == x that we assign to color 2.
        // All d[i] == x before this index must be color 1.
        // All d[i] == x after this index must be color 2.
        // This means we need to find the first 'x' that is greater than or equal to the last digit of S1.
        // And all 'x's after that must be greater than or equal to the first digit of S2.
        // This is equivalent to finding the first 'x' that we want to color 2.
        // All 'x's before it are color 1, all 'x's after it are color 2.

        int last_s1_val = -1;
        if (!s1_digits.empty()) {
            last_s1_val = s1_digits.back();
        }

        int first_s2_val = 10;
        if (!s2_digits.empty()) {
            first_s2_val = s2_digits.front();
        }

        // If last_s1_val > first_s2_val, then this x is not possible.
        // This check is implicitly handled by the full construction below.

        // Find the first index `k` such that d[k] == x and we want to color it 2.
        // All d[i] == x for i < k will be color 1.
        // All d[i] == x for i >= k will be color 2.
        // If no such k exists, all x's are color 1 (k=n) or all x's are color 2 (k=0).

        int split_k = n; // Default: all x's are color 1
        for (int i = 0; i < n; ++i) {
            if (d[i] == x) {
                if (d[i] >= last_s1_val) { // This 'x' can potentially be the first 'x' in S2
                    split_k = i;
                    break;
                } else { // This 'x' must be in S1
                    colors[i] = 1;
                }
            }
        }

        // Now, fill in the remaining 'x's based on split_k
        for (int i = 0; i < n; ++i) {
            if (d[i] == x) {
                if (i < split_k) {
                    colors[i] = 1;
                } else {
                    colors[i] = 2;
                }
            }
        }

        // Reconstruct S1 and S2 to check validity
        std::vector<int> final_s1_digits;
        std::vector<int> final_s2_digits;
        for (int i = 0; i < n; ++i) {
            if (colors[i] == 1) {
                final_s1_digits.push_back(d[i]);
            } else {
                final_s2_digits.push_back(d[i]);
            }
        }

        bool current_x_valid = true;
        for (size_t i = 1; i < final_s1_digits.size(); ++i) {
            if (final_s1_digits[i] < final_s1_digits[i-1]) {
                current_x_valid = false;
                break;
            }
        }
        if (!current_x_valid) continue;

        for (size_t i = 1; i < final_s2_digits.size(); ++i) {
            if (final_s2_digits[i] < final_s2_digits[i-1]) {
                current_x_valid = false;
                break;
            }
        }
        if (!current_x_valid) continue;

        if (!final_s1_digits.empty() && !final_s2_digits.empty()) {
            if (final_s1_digits.back() > final_s2_digits.front()) {
                current_x_valid = false;
            }
        }

        if (current_x_valid) {
            for (int i = 0; i < n; ++i) {
                std::cout << colors[i];
            }
            std::cout << "\n";
            return;
        }
    }

    std::cout << "-\n";
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <algorithm>
#include <cmath>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        long long n, m, k;
        std::cin >> n >> m >> k;

        // Ensure n >= m by swapping if necessary.
        // This simplifies calculations as we can always assume n is the larger coordinate.
        if (n < m) {
            std::swap(n, m);
        }

        // Minimum moves required to reach (n, m) is n (if n >= m).
        // This is because each move can change x by at most 1 and y by at most 1.
        // To cover a distance of n in x-coordinate, at least n moves are needed.
        if (k < n) {
            std::cout << -1 << "\n";
            continue;
        }

        // Parity check:
        // Each move changes the sum of coordinates (x+y) by -2, 0, or 2 for diagonal moves,
        // and by -1 or 1 for axial moves.
        // This means (x+y) changes parity with each move.
        // So, (x_final + y_final) % 2 must be equal to (x_initial + y_initial + k) % 2.
        // Since (x_initial, y_initial) is (0,0), we need (n+m)%2 == k%2.
        if ((n + m) % 2 != k % 2) {
            std::cout << -1 << "\n";
            continue;
        }

        // If n and m have different parities, and k has the same parity as (n+m),
        // then k must be odd.
        // In this case, we can reach (n,m) in k moves.
        // The maximum number of diagonal moves is k-1.
        // This is achieved by making k-1 diagonal moves to (n-1, m-1) or similar,
        // and then one axial move.
        // Example: (0,0) -> (1,1) -> (2,0) -> (3,1) ...
        // If n and m have different parities, then n-m is odd.
        // If k is even, (n+m)%2 != k%2, so this case is already handled by the parity check.
        // If k is odd, (n+m)%2 == k%2.
        // Example: (2,1) in 3 moves. n=2, m=1. n+m=3 (odd). k=3 (odd). Parity matches.
        // Max diagonal moves: k-1 = 2.
        // Path: (0,0) -> (1,1) -> (2,0) -> (2,1). 2 diagonal, 1 axial.
        if ((n % 2) != (m % 2)) { // n and m have different parities
            std::cout << k - 1 << "\n";
        } else { // n and m have the same parity
            // If n and m have the same parity, then n-m is even.
            // If k is even, (n+m)%2 == k%2.
            // Example: (2,2) in 2 moves. n=2, m=2. n+m=4 (even). k=2 (even). Parity matches.
            // Max diagonal moves: k = 2.
            // Path: (0,0) -> (1,1) -> (2,2). 2 diagonal, 0 axial.
            // Example: (2,2) in 4 moves. n=2, m=2. n+m=4 (even). k=4 (even). Parity matches.
            // Max diagonal moves: k = 4.
            // Path: (0,0) -> (1,1) -> (0,2) -> (1,1) -> (2,2). 4 diagonal, 0 axial.
            // This is achieved by making k moves, all diagonal.
            // We can reach (n,m) in n moves (all diagonal up to (m,m), then n-m axial moves to (n,m)).
            // If k > n, we can make (k-n) extra moves.
            // Each pair of extra moves can be (x,y) -> (x+1,y+1) -> (x,y) (2 diagonal moves, net 0 displacement).
            // Or (x,y) -> (x+1,y) -> (x,y) (2 axial moves, net 0 displacement).
            // Or (x,y) -> (x+1,y+1) -> (x+1,y) (1 diagonal, 1 axial, net (1,0) displacement).
            // To maximize diagonal moves, we want to use diagonal moves for the "extra" moves.
            // If k and n have the same parity, we can make k diagonal moves.
            // The remaining k-n moves must be even.
            // We can use (k-n)/2 pairs of diagonal moves that cancel out, e.g., (x,y) -> (x+1,y+1) -> (x,y).
            // This adds 2 diagonal moves for each pair, without changing the final position.
            // So, if n and m have same parity, and k has same parity as (n+m),
            // then k must be even.
            // In this case, we can make k diagonal moves.
            std::cout << k << "\n";
        }
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <set>
#include <algorithm>
#include <map>

void solve() {
    std::string s;
    std::cin >> s;

    std::map<char, std::set<char>> adj;
    for (char c = 'a'; c <= 'z'; ++c) {
        adj[c] = std::set<char>();
    }

    bool possible = true;
    for (size_t i = 0; i < s.length() - 1; ++i) {
        char c1 = s[i];
        char c2 = s[i+1];
        adj[c1].insert(c2);
        adj[c2].insert(c1);
    }

    for (char c = 'a'; c <= 'z'; ++c) {
        if (adj[c].size() > 2) {
            possible = false;
            break;
        }
    }

    if (!possible) {
        std::cout << "NO\n";
        return;
    }

    std::string layout = "";
    std::set<char> visited;
    char start_node = '\0';

    // Find a starting node for a path (degree 1) or a cycle (any node if all degree 2)
    for (char c = 'a'; c <= 'z'; ++c) {
        if (adj[c].size() == 1) {
            start_node = c;
            break;
        }
    }

    if (start_node == '\0') { // All nodes have degree 0 or 2
        // Check for isolated nodes (degree 0) or a single cycle
        bool all_degree_0_or_2 = true;
        for (char c = 'a'; c <= 'z'; ++c) {
            if (adj[c].size() != 0 && adj[c].size() != 2) {
                all_degree_0_or_2 = false;
                break;
            }
        }
        if (!all_degree_0_or_2) { // Should not happen based on previous check (adj.size() > 2)
            std::cout << "NO\n";
            return;
        }

        // If all non-isolated nodes have degree 2, it must be a cycle or multiple cycles.
        // The problem implies a single linear layout. A cycle is not a linear layout.
        // However, if the password itself forms a cycle, it's fine.
        // Example: "abacaba" -> a-b, a-c. This is a path.
        // Example: "abcda" -> a-b, b-c, c-d, d-a. This is a cycle.
        // The problem states "adjacent on the keyboard". A cycle cannot be laid out linearly.
        // So, if start_node is still '\0', it means all connected components are cycles.
        // This is impossible for a linear keyboard.
        // Except if the password itself is a cycle, e.g., "abcda".
        // In this case, 'a' has neighbors 'b' and 'd'. 'b' has 'a' and 'c'.
        // This forms a cycle. A cycle cannot be laid out linearly.
        // So, if start_node is still '\0', it means all connected components are cycles.
        // This is impossible for a linear keyboard.
        // The only exception is if the graph is empty (no edges), then any layout is fine.
        // But if there are edges and no degree 1 nodes, it means all connected components are cycles.
        // A cycle cannot be represented on a linear keyboard.
        // So, if start_node is still '\0' and there are any edges, it's impossible.

        bool has_edges = false;
        for (char c = 'a'; c <= 'z'; ++c) {
            if (!adj[c].empty()) {
                has_edges = true;
                break;
            }
        }

        if (has_edges) {
            std::cout << "NO\n";
            return;
        }
        // If no edges, then start_node remains '\0', and we can print any layout.
        // This case is handled below by printing remaining_chars.
    }

    if (start_node != '\0') {
        char current = start_node;
        char prev = '\0'; // Sentinel for the previous character

        while (current != '\0' && visited.find(current) == visited.end()) {
            layout += current;
            visited.insert(current);

            char next_char = '\0';
            for (char neighbor : adj[current]) {
                if (neighbor != prev) {
                    next_char = neighbor;
                    break;
                }
            }
            prev = current;
            current = next_char;
        }
    }

    // Add any remaining unvisited characters (isolated nodes or other components)
    for (char c = 'a'; c <= 'z'; ++c) {
        if (visited.find(c) == visited.end()) {
            layout += c;
        }
    }

    // Final check: ensure all characters are present and unique
    if (layout.length() != 26) {
        // This should not happen if the logic is correct, but as a safeguard.
        std::cout << "NO\n";
        return;
    }

    std::cout << "YES\n";
    std::cout << layout << "\n";
}

