#include <iomanip>

// Function to compute the Z-array for a given string
// Z[i] is the length of the longest common prefix between s and s[i...]
std::vector<int> compute_z_array(const std::string& s) {
    int n = s.length();
    std::vector<int> z(n);
    z[0] = n; // Conventionally, z[0] is n or 0, but for string matching it's often n.
              // For our purpose, we don't use z[0] directly in comparisons.
              // Let's set it to 0 as it's not a prefix match with itself starting at index 0.
              // Or, more precisely, it's the length of the string itself.
              // For the standard Z-algorithm, z[0] is usually not defined or set to 0.
              // However, for string matching, it's often useful to think of it as n.
              // Let's use the standard definition where z[0] is not used for comparisons.
              // The actual Z-algorithm implementation usually starts from i=1.
    int l = 0, r = 0;
    for (int i = 1; i < n; ++i) {
        if (i <= r) {
            z[i] = std::min(r - i + 1, z[i - l]);
        }
        while (i + z[i] < n && s[z[i]] == s[i + z[i]]) {
            ++z[i];
        }
        if (i + z[i] - 1 > r) {
            l = i;
            r = i + z[i] - 1;
        }
    }
    return z;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::string s;
    std::cin >> s;
    int L = s.length();

    // Precompute Z-arrays for all suffixes of s
    // z_arrays[i] stores the Z-array for the string s.substr(i) + s.substr(0, i)
    // This is equivalent to computing Z-array for s + s, and then taking slices.
    // More efficiently, we can compute Z-array for s + '#' + s.
    // z_s_s[i] will be the length of the longest common prefix of s and s[i...].
    // z_s_s[i+L+1] will be the length of the longest common prefix of s and s[i...L-1]s[0...i-1].
    std::string s_double = s + s;
    std::vector<int> z_s_s = compute_z_array(s_double);

    // For each possible starting character s[k] (which becomes t[0])
    // we want to find the optimal position p to query.
    double total_win_probability = 0.0;

    for (int k_initial = 0; k_initial < L; ++k_initial) {
        // k_initial is the actual k chosen by Kolya.
        // t[0] = s[k_initial].
        // We are simulating Vasya's decision process for a given t[0].
        // Vasya doesn't know k_initial, only s[k_initial].

        // Find all possible k' values such that s[k'] == s[k_initial].
        // These are the initial candidates for k.
        std::vector<int> initial_candidates;
        for (int k_prime = 0; k_prime < L; ++k_prime) {
            if (s[k_prime] == s[k_initial]) {
                initial_candidates.push_back(k_prime);
            }
        }

        // If there's only one candidate, Vasya already wins without asking for t[p].
        // But the problem states he asks for t[p] after t[0].
        // If there's only one candidate, he can pick any p and still win.
        // The probability for this t[0] is 1.
        if (initial_candidates.size() <= 1) {
            total_win_probability += 1.0;
            continue;
        }

        // Vasya needs to choose an optimal p (from 1 to L-1).
        // For each p, calculate the number of unique k' values that remain.
        int max_unique_k_for_t0 = 0;

        for (int p = 1; p < L; ++p) {
            // For a fixed p, what is the number of k' values that are uniquely determined?
            // A k' is uniquely determined if it's the only one that matches both t[0] and t[p].
            // t[0] = s[k_initial]
            // t[p] = s[(k_initial + p) % L]

            // We need to check how many k' from initial_candidates satisfy:
            // s[k'] == s[k_initial] (already filtered)
            // s[(k' + p) % L] == s[(k_initial + p) % L]

            // Count how many k' values satisfy the second condition.
            int count_matches_for_this_p = 0;
            for (int k_prime : initial_candidates) {
                if (s[(k_prime + p) % L] == s[(k_initial + p) % L]) {
                    count_matches_for_this_p++;
                }
            }

            // If only one k' matches both t[0] and t[p], Vasya wins for this t[0] and p.
            if (count_matches_for_this_p == 1) {
                max_unique_k_for_t0 = 1; // Vasya can win for this t[0]
                break; // Found an optimal p, no need to check other p's for this t[0]
            }
        }
        total_win_probability += max_unique_k_for_t0;
    }

    std::cout << std::fixed << std::setprecision(15) << total_win_probability / L << std::endl;

    return 0;
}

