#include <iostream>
#include <vector>
#include <string>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    // Initialize the state for each bit.
    // For each bit position j (0 to 9):
    // bit_state[j][0] stores the output bit if input bit x_j is 0.
    // bit_state[j][1] stores the output bit if input bit x_j is 1.
    // Initially, if input bit is 0, output is 0. If input bit is 1, output is 1.
    // This means bit_state[j][0] = 0 and bit_state[j][1] = 1 for all j.
    std::vector<std::vector<int>> bit_state(10, std::vector<int>(2));
    for (int j = 0; j < 10; ++j) {
        bit_state[j][0] = 0; // If input bit is 0, current output bit is 0
        bit_state[j][1] = 1; // If input bit is 1, current output bit is 1
    }

    for (int i = 0; i < n; ++i) {
        char op_char;
        int x;
        std::cin >> op_char >> x;

        for (int j = 0; j < 10; ++j) {
            int x_j = (x >> j) & 1; // j-th bit of constant x

            // Update bit_state[j][0] (output if input bit is 0)
            if (op_char == '&') {
                bit_state[j][0] &= x_j;
            } else if (op_char == '|') {
                bit_state[j][0] |= x_j;
            } else { // '^'
                bit_state[j][0] ^= x_j;
            }

            // Update bit_state[j][1] (output if input bit is 1)
            if (op_char == '&') {
                bit_state[j][1] &= x_j;
            } else if (op_char == '|') {
                bit_state[j][1] |= x_j;
            } else { // '^'
                bit_state[j][1] ^= x_j;
            }
        }
    }

    // Now, bit_state[j][0] and bit_state[j][1] represent the final transformation
    // for the j-th bit.
    // We need to find constants A_AND, A_OR, A_XOR such that:
    // ( ( (x_j & A_AND_j) | A_OR_j) ^ A_XOR_j ) == bit_state[j][x_j] for x_j in {0,1}

    int A_AND = 1023; // Initialize with all bits set (identity for AND)
    int A_OR = 0;     // Initialize with all bits clear (identity for OR)
    int A_XOR = 0;    // Initialize with all bits clear (identity for XOR)

    for (int j = 0; j < 10; ++j) {
        int out_0 = bit_state[j][0]; // Output bit if input bit is 0
        int out_1 = bit_state[j][1]; // Output bit if input bit is 1

        // Determine the j-th bit of A_AND, A_OR, A_XOR
        // based on the desired (0 -> out_0) and (1 -> out_1) mappings.

        // Case 1: (0 -> 0, 1 -> 0)
        // This means the output bit is always 0, regardless of input.
        // We can achieve this with:
        // (x_j & 0) | 0 ^ 0 = 0
        // So, A_AND_j = 0.
        if (out_0 == 0 && out_1 == 0) {
            A_AND &= ~(1 << j); // Set j-th bit of A_AND to 0
        }
        // Case 2: (0 -> 1, 1 -> 1)
        // This means the output bit is always 1, regardless of input.
        // We can achieve this with:
        // (x_j & 1) | 1 ^ 0 = 1
        // So, A_OR_j = 1.
        else if (out_0 == 1 && out_1 == 1) {
            A_OR |= (1 << j); // Set j-th bit of A_OR to 1
        }
        // Case 3: (0 -> 0, 1 -> 1)
        // This means the output bit is the same as the input bit (identity).
        // We can achieve this with:
        // (x_j & 1) | 0 ^ 0 = x_j
        // So, A_AND_j = 1, A_OR_j = 0, A_XOR_j = 0. (These are default values)
        // No change needed for A_AND, A_OR, A_XOR for this bit.
        else if (out_0 == 0 && out_1 == 1) {
            // A_AND_j remains 1 (default)
            // A_OR_j remains 0 (default)
            // A_XOR_j remains 0 (default)
        }
        // Case 4: (0 -> 1, 1 -> 0)
        // This means the output bit is the inverse of the input bit.
        // We can achieve this with:
        // (x_j & 1) | 0 ^ 1 = ~x_j
        // So, A_XOR_j = 1.
        else if (out_0 == 1 && out_1 == 0) {
            A_XOR |= (1 << j); // Set j-th bit of A_XOR to 1
        }
    }

    std::vector<std::pair<char, int>> result_ops;
    if (A_AND != 1023) { // If A_AND is not all 1s
        result_ops.push_back({'&', A_AND});
    }
    if (A_OR != 0) { // If A_OR is not all 0s
        result_ops.push_back({'|', A_OR});
    }
    if (A_XOR != 0) { // If A_XOR is not all 0s
        result_ops.push_back({'^', A_XOR});
    }

    std::cout << result_ops.size() << "\n";
    for (const auto& op : result_ops) {
        std::cout << op.first << " " << op.second << "\n";
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <map>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(2 * n);
    for (int i = 0; i < 2 * n; ++i) {
        std::cin >> a[i];
        if (a[i] == 2) {
            a[i] = -1;
        }
    }

    // Calculate prefix sums for the left side (jars 0 to n-1)
    // and suffix sums for the right side (jars n to 2n-1)
    // The "middle" is between index n-1 and n.
    // Left side: indices 0 to n-1
    // Right side: indices n to 2n-1

    // Suffix sums for the right side (from index n to 2n-1)
    // `right_sums[k]` stores the sum of jars from index `n` to `n+k-1`.
    // This means `k` jars are kept on the right side, starting from index `n`.
    // `right_sums[0]` is 0 (no jars kept).
    // `right_sums[k]` is sum of `a[n]`...`a[n+k-1]`
    std::vector<int> right_sums(n + 1, 0);
    for (int k = 0; k < n; ++k) {
        right_sums[k + 1] = right_sums[k] + a[n + k];
    }

    // Store the minimum number of jars removed from the right to achieve a certain sum.
    // `min_removed_right[sum]` stores the minimum `R` such that `sum_of_remaining_jars_on_right == sum`.
    // `R` is `n - k`, where `k` is the number of jars kept on the right.
    // So `k = n - R`.
    // `min_removed_right[sum]` = `n - k`
    std::map<int, int> min_removed_right;
    for (int k = 0; k <= n; ++k) { // k is number of jars kept on the right (from index n to n+k-1)
        int current_sum = right_sums[k];
        int removed_count = n - k;
        if (min_removed_right.find(current_sum) == min_removed_right.end()) {
            min_removed_right[current_sum] = removed_count;
        } else {
            min_removed_right[current_sum] = std::min(min_removed_right[current_sum], removed_count);
        }
    }

    int min_total_removed = 2 * n; // Initialize with max possible removals

    // Iterate through possible number of jars kept on the left side (from index n-1 down to 0)
    // `left_sum` is the sum of jars from index `n-k_left` to `n-1`.
    // `k_left` is the number of jars kept on the left.
    // `left_sum[0]` is 0 (no jars kept).
    // `left_sum[k_left]` is sum of `a[n-k_left]`...`a[n-1]`
    int current_left_sum = 0;
    for (int k_left = 0; k_left <= n; ++k_left) { // k_left is number of jars kept on the left
        if (k_left > 0) {
            current_left_sum += a[n - k_left];
        }

        // We need total sum to be 0. So, current_left_sum + current_right_sum = 0.
        // This means current_right_sum = -current_left_sum.
        int target_right_sum = -current_left_sum;

        if (min_removed_right.count(target_right_sum)) {
            int removed_left = n - k_left;
            int removed_right = min_removed_right[target_right_sum];
            min_total_removed = std::min(min_total_removed, removed_left + removed_right);
        }
    }

    std::cout << min_total_removed << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

