    }

    std::vector<int> left_zeros(n, 0);
    std::vector<int> right_ones(n, 0);

    // Calculate left_zeros[i]: count of consecutive zeros ending at i
    if (a[0] == 0) {
        left_zeros[0] = 1;
    }
    for (int i = 1; i < n; ++i) {
        if (a[i] == 0) {
            left_zeros[i] = left_zeros[i - 1] + 1;
        } else {
            left_zeros[i] = 0;
        }
    }

    // Calculate right_ones[i]: count of consecutive ones starting at i
    if (a[n - 1] == 1) {
        right_ones[n - 1] = 1;
    }
    for (int i = n - 2; i >= 0; --i) {
        if (a[i] == 1) {
            right_ones[i] = right_ones[i + 1] + 1;
        } else {
            right_ones[i] = 0;
        }
    }

    int max_k = 0;
    for (int i = 0; i < n - 1; ++i) {
        if (a[i] == 0 && a[i + 1] == 1) { // Found a 01 boundary
            int k_val = std::min(left_zeros[i], right_ones[i + 1]);
            max_k = std::max(max_k, k_val);
        }
    }

    std::cout << max_k << std::endl;

    std::vector<int> result_a = a;
    for (int i = 0; i < n - 1; ++i) {
        if (a[i] == 0 && a[i + 1] == 1) { // Found a 01 boundary
            int k_val = std::min(left_zeros[i], right_ones[i + 1]);
            if (k_val > 0) {
                // Change 0s to 1s
                for (int j = 0; j < k_val - max_k; ++j) {
                    result_a[i - j] = 1;
                }
                // Change 1s to 0s
                for (int j = 0; j < k_val - max_k; ++j) {
                    result_a[i + 1 + j] = 0;
                }
            }
        }
    }

    for (int i = 0; i < n; ++i) {
        std::cout << result_a[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    long long m;
    std::cin >> n >> m;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    long long low = 0;
    long long high = m - 1;
    long long ans = m - 1;

    while (low <= high) {
        long long mid = low + (high - low) / 2;
        bool possible = true;
        long long prev_b = 0; // Represents b_i for the current element

        for (int i = 0; i < n; ++i) {
            long long current_a = a[i];
            long long current_b;

            // Case 1: a_i <= prev_b
            // We need b_i >= prev_b.
            // The minimum b_i is prev_b.
            // To achieve prev_b from current_a, we need (prev_b - current_a + m) % m operations.
            // If (prev_b - current_a + m) % m <= mid, then we can set b_i = prev_b.
            if (current_a <= prev_b) {
                if (prev_b - current_a <= mid) {
                    current_b = prev_b;
                } else {
                    // Cannot make current_a equal to prev_b with 'mid' operations.
                    // We must increment current_a.
                    // The smallest possible b_i is current_a.
                    // This requires 0 operations.
                    // Since current_a < prev_b, this violates non-decreasing.
                    // So this 'mid' is not possible.
                    possible = false;
                    break;
                }
            }
            // Case 2: a_i > prev_b
            // We need b_i >= prev_b.
            // Option A: Set b_i = a_i. This requires 0 operations.
            // If a_i >= prev_b, this is a valid choice for b_i.
            // Option B: Set b_i = prev_b. This requires (prev_b - current_a + m) % m operations.
            // This is equivalent to (prev_b + m - current_a) operations.
            // If (prev_b + m - current_a) <= mid, then we can set b_i = prev_b.
            else { // current_a > prev_b
                if (current_a - prev_b <= m - mid - 1) { // This is equivalent to (prev_b + m - current_a) > mid
                    // We cannot reach prev_b from current_a with 'mid' operations.
                    // (prev_b + m - current_a) > mid
                    // So we must set b_i = a_i (or larger).
                    current_b = current_a;
                } else { // (prev_b + m - current_a) <= mid
                    // We can reach prev_b from current_a with 'mid' operations.
                    // So we can set b_i = prev_b.
                    current_b = prev_b;
                }
            }
            prev_b = current_b;
        }

        if (possible) {
            ans = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    std::cout << ans << std::endl;

    return 0;
}

#include <iostream>
