struct Element {
    long long value;
    int original_index;
};

bool compareElements(const Element& a, const Element& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long h;
    std::cin >> n >> h;

    std::vector<Element> elements(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> elements[i].value;
        elements[i].original_index = i;
    }

    std::sort(elements.begin(), elements.end(), compareElements);

    long long a1 = elements[0].value;
    long long a2 = elements[1].value;
    long long an_1 = elements[n - 2].value;
    long long an = elements[n - 1].value;

    // Case 1: All elements in one subsequence (e.g., S1). S2 is empty.
    // min_f = a1 + a2
    // max_f = an_1 + an
    // goodness = (an_1 + an) - (a1 + a2)
    long long goodness1 = (an_1 + an) - (a1 + a2);
    std::vector<int> partition1(n, 1); // All in subsequence 1

    // Case 2: Partition such that a1 and an are in different subsequences.
    // This implies min_f could be a1 + a2 (if a1, a2 same) or a1 + a2 + h (if a1, a2 different).
    // max_f could be an_1 + an (if an_1, an same) or an_1 + an + h (if an_1, an different).
    //
    // Consider a specific partition: a1 in S1, an in S2.
    // All other elements a_i (for i=2 to n-1) can be put in S1 or S2.
    //
    // To minimize max(f) - min(f), we want to make the range of f values as small as possible.
    //
    // Let's try to put a1 in S1, and an in S2.
    // The smallest possible sum is a1 + a2.
    // The largest possible sum is an_1 + an.
    //
    // If we put a1 in S1, and an in S2, then f(a1, an) = a1 + an + h.
    //
    // Consider a partition where:
    // a1 is in S1.
    // an is in S2.
    // All other elements a_i (for i=1 to n-2) are in S1.
    //
    // Values of f:
    // 1. a_i + a_j for a_i, a_j in S1 (i.e., a1, a2, ..., an-1):
    //    Min: a1 + a2
    //    Max: a_n-2 + a_n-1 (if n > 2, otherwise a1+a2)
    // 2. a_i + a_j for a_i, a_j in S2 (i.e., only an): None if S2 has only one element.
    // 3. a_i + a_j + h for a_i in S1, a_j in S2:
    //    a_i is one of {a1, ..., an-1}, a_j is an.
    //    Min: a1 + an + h
    //    Max: an_1 + an + h
    //
    // So, for this partition:
    // min_f = std::min(a1 + a2, a1 + an + h)
    // max_f = std::max(an_1 + an, an_1 + an + h)
    //
    // This simplifies to:
    // min_f = a1 + a2
    // max_f = an_1 + an + h
    //
    // Goodness = (an_1 + an + h) - (a1 + a2)
    // This is the goodness for the partition where a1, ..., an-1 are in S1, and an is in S2.
    //
    // What if we put a1 in S1, and an in S2, and all other elements in S2?
    // S1 = {a1}
    // S2 = {a2, ..., an}
    //
    // Values of f:
    // 1. a_i + a_j for a_i, a_j in S1: None.
    // 2. a_i + a_j for a_i, a_j in S2:
    //    Min: a2 + a3
    //    Max: an_1 + an
    // 3. a_i + a_j + h for a_i in S1, a_j in S2:
    //    a_i is a1, a_j is one of {a2, ..., an}.
    //    Min: a1 + a2 + h
    //    Max: a1 + an + h
    //
    // So, for this partition:
    // min_f = std::min(a2 + a3, a1 + a2 + h)
    // max_f = std::max(an_1 + an, a1 + an + h)
    //
    // This simplifies to:
    // min_f = a1 + a2 + h
    // max_f = an_1 + an
    //
    // Goodness = (an_1 + an) - (a1 + a2 + h)
    // This is the goodness for the partition where a1 is in S1, and a2, ..., an are in S2.
    //
    // The problem is that the minimum and maximum values of f can come from different types of pairs.
    //
    // Let's consider the two main strategies:
    // Strategy A: Put all elements in one subsequence.
    //   min_f = a1 + a2
    //   max_f = an_1 + an
    //   Goodness = (an_1 + an) - (a1 + a2)
    //
    // Strategy B: Put a1 in S1, and an in S2.
    //   To minimize goodness, we want to make min_f as large as possible and max_f as small as possible.
    //   The values of f are:
    //     - a_i + a_j (same subsequence)
    //     - a_i + a_j + h (different subsequences)
    //
    //   The smallest possible sum is a1 + a2.
    //   The largest possible sum is an_1 + an.
    //
    //   If a1 and a2 are in the same subsequence, min_f could be a1 + a2.
    //   If a1 and a2 are in different subsequences, min_f could be a1 + a2 + h.
    //
    //   If an_1 and an are in the same subsequence, max_f could be an_1 + an.
    //   If an_1 and an are in different subsequences, max_f could be an_1 + an + h.
    //
    //   Consider the partition where a1 is in S1, and all other elements (a2, ..., an) are in S2.
    //   S1 = {a1}
    //   S2 = {a2, ..., an}
    //   min_f:
    //     - No pairs in S1.
    //     - Pairs in S2: min is a2 + a3 (if n >= 3).
    //     - Pairs across S1 and S2: min is a1 + a2 + h.
    //     So, min_f = std::min(a2 + a3, a1 + a2 + h) if n >= 3.
    //     If n=2, S2={a2}, no pairs in S2. min_f = a1 + a2 + h.
    //   max_f:
    //     - No pairs in S1.
    //     - Pairs in S2: max is an_1 + an (if n >= 3).
    //     - Pairs across S1 and S2: max is a1 + an + h.
    //     So, max_f = std::max(an_1 + an, a1 + an + h) if n >= 3.
    //     If n=2, S2={a2}, no pairs in S2. max_f = a1 + a2 + h.
    //
    //   Let's simplify this.
    //   If n=2: S1={a1}, S2={a2}. Only one pair (a1, a2). f(a1, a2) = a1 + a2 + h.
    //     min_f = a1 + a2 + h, max_f = a1 + a2 + h. Goodness = 0.
    //     This is covered by the general case below.
    //
    //   For n >= 3:
    //   min_f = a1 + a2 + h (because a1+a2+h is always smaller than a2+a3 if h is small, but if h is large, a2+a3 could be smaller)
    //   No, this is not necessarily true.
    //   Example: a = {0, 100, 101}, h = 1.
    //   S1={0}, S2={100, 101}.
    //   Pairs in S2: (100, 101) -> 201.
    //   Pairs across: (0, 100) -> 0+100+1 = 101. (0, 101) -> 0+101+1 = 102.
    //   min_f = 101. max_f = 201. Goodness = 100.
    //
    //   The minimum value of f is `min(a_i + a_j, a_k + a_l + h)`.
    //   The maximum value of f is `max(a_i + a_j, a_k + a_l + h)`.
    //
    //   Let's consider the two most "extreme" elements: a1 and an.
    //   If a1 and an are in the same subsequence:
    //     Then all elements are in the same subsequence (e.g., S1).
    //     min_f = a1 + a2
    //     max_f = an_1 + an
    //     Goodness = (an_1 + an) - (a1 + a2)
    //     This is `goodness1`.
    //
    //   If a1 and an are in different subsequences:
    //     Let a1 be in S1, an be in S2.
    //     The values of f are:
    //       - `x + y` where x, y are both in S1 or both in S2.
    //       - `x + y + h` where x is in S1 and y is in S2.
    //
    //     The smallest possible sum `a_i + a_j` is `a1 + a2`.
    //     The largest possible sum `a_i + a_j` is `an_1 + an`.
    //
    //     The smallest possible sum `a_i + a_j + h` is `a1 + a2 + h`.
    //     The largest possible sum `a_i + a_j + h` is `an_1 + an + h`.
    //
    //     So, `min_f` will be either `a1 + a2` or `a1 + a2 + h`.
    //     And `max_f` will be either `an_1 + an` or `an_1 + an + h`.
    //
    //     Consider the partition where a1 is in S1, and all other elements (a2, ..., an) are in S2.
    //     S1 = {a1}
    //     S2 = {a2, ..., an}
    //     min_f = std::min(a2 + a3, a1 + a2 + h) (if n >= 3, else a1+a2+h)
    //     max_f = std::max(an_1 + an, a1 + an + h) (if n >= 3, else a1+a2+h)
    //
    //     Consider the partition where a1, ..., an-1 are in S1, and an is in S2.
    //     S1 = {a1, ..., an-1}
    //     S2 = {an}
    //     min_f = std::min(a1 + a2, a1 + an + h) (if n >= 3, else a1+a2+h)
    //     max_f = std::max(an_1 + an, an_1 + an + h) (if n >= 3, else a1+a2+h)
    //
    //     Let's analyze the range of values.
    //     The set of all possible sums `a_i + a_j` is `[a1+a2, an_1+an]`.
    //     The set of all possible sums `a_i + a_j + h` is `[a1+a2+h, an_1+an+h]`.
    //
    //     If we partition such that a1 and an are in different subsequences:
    //     Let a1 be in S1, an in S2.
    //     Then `a1 + an + h` is definitely one of the `f` values.
    //     What about `a1 + a2`?
    //       If a2 is in S1, then `a1 + a2` is a value.
    //       If a2 is in S2, then `a1 + a2 + h` is a value.
    //     What about `an_1 + an`?
    //       If an_1 is in S2, then `an_1 + an` is a value.
    //       If an_1 is in S1, then `an_1 + an + h` is a value.
    //
    //     The key observation is that the minimum possible value of `f` is `min(a1+a2, a1+a2+h) = a1+a2`.
    //     The maximum possible value of `f` is `max(an_1+an, an_1+an+h) = an_1+an+h`.
    //     This is if we can ensure that both `a1+a2` (same subsequence) and `an_1+an+h` (different subsequences) occur.
    //     This is not always possible.
    //
    //     The actual minimum `f` value will be `min(min_same, min_diff)`.
    //     The actual maximum `f` value will be `max(max_same, max_diff)`.
    //
    //     Consider the partition where `a1` is in `S1`, and `a2, ..., an` are in `S2`.
    //     `S1 = {a1}`
    //     `S2 = {a2, ..., an}`
    //     `min_same`: `a2 + a3` (if n >= 3, else no pairs in S2)
    //     `max_same`: `an_1 + an` (if n >= 3, else no pairs in S2)
    //     `min_diff`: `a1 + a2 + h`
    //     `max_diff`: `a1 + an + h`
    //
    //     If n=2: `S1={a1}, S2={a2}`. `min_f = a1+a2+h`, `max_f = a1+a2+h`. Goodness = 0.
    //     This is the best possible goodness.
    //     This partition is `1 2`.
    //
    //     If n >= 3:
    //     `min_f = std::min(a2 + a3, a1 + a2 + h)`
    //     `max_f = std::max(an_1 + an, a1 + an + h)`
    //     Goodness = `max_f - min_f`.
    //
    //     Let's call this `goodness2`.
    //     This partition is `1 2 2 ... 2`.
    //
    //     Consider the partition where `a1, ..., an-1` are in `S1`, and `an` is in `S2`.
    //     `S1 = {a1, ..., an-1}`
    //     `S2 = {an}`
    //     `min_same`: `a1 + a2`
    //     `max_same`: `a_n-2 + a_n-1`
    //     `min_diff`: `a1 + an + h`
    //     `max_diff`: `a_n-1 + an + h`
    //
    //     If n >= 3:
    //     `min_f = std::min(a1 + a2, a1 + an + h)`
    //     `max_f = std::max(a_n-2 + a_n-1, a_n-1 + an + h)`
    //     Goodness = `max_f - min_f`.
    //
    //     Let's call this `goodness3`.
    //     This partition is `1 1 ... 1 2`.
    //
    //     The problem states `n >= 2`.
    //     If n=2:
    //       `goodness1` (all in S1): `(a1+a2) - (a1+a2) = 0`. Partition `1 1`.
    //       `goodness2` (a1 in S1, a2 in S2): `(a1+a2+h) - (a1+a2+h) = 0`. Partition `1 2`.
    //       `goodness3` (a1 in S1, a2 in S2): Same as goodness2.
    //       So for n=2, min goodness is 0. Any partition is fine.
    //
    //     Let's re-evaluate `goodness2` and `goodness3` for `n >= 3`.
    //
    //     Partition `P2`: `S1 = {a1}`, `S2 = {a2, ..., an}`
    //     `min_f_P2 = std::min(a2 + a3, a1 + a2 + h)`
    //     `max_f_P2 = std::max(an_1 + an, a1 + an + h)`
    //     `goodness2 = max_f_P2 - min_f_P2`
    //
    //     Partition `P3`: `S1 = {a1, ..., an-1}`, `S2 = {an}`
    //     `min_f_P3 = std::min(a1 + a2, a1 + an + h)`
    //     `max_f_P3 = std::max(a_n-2 + a_n-1, an_1 + an + h)`
    //     `goodness3 = max_f_P3 - min_f_P3`
    //
    //     The problem is that `a_n-2 + a_n-1` is not necessarily `an_1 + an`.
    //     `an_1` is `elements[n-2].value`. `an` is `elements[n-1].value`.
    //     So `a_n-2 + a_n-1` is `elements[n-3].value + elements[n-2].value`.
    //     Let's use `a_i` for `elements[i-1].value`.
    //     `a1 = elements[0].value`, `a2 = elements[1].value`, ..., `an = elements[n-1].value`.
    //
    //     Partition `P1`: All in S1.
    //     `min_f = a1 + a2`
    //     `max_f = a_{n-1} + a_n`
    //     `goodness1 = (a_{n-1} + a_n) - (a1 + a2)`
    //     `partition1` is `1 1 ... 1`.
    //
    //     Partition `P2`: `S1 = {a1}`, `S2 = {a2, ..., an}`
    //     `min_f_P2 = std::min(a2 + a3, a1 + a2 + h)` (if n >= 3)
    //     `max_f_P2 = std::max(a_{n-1} + a_n, a1 + a_n + h)` (if n >= 3)
    //     If n=2: `min_f_P2 = a1 + a2 + h`, `max_f_P2 = a1 + a2 + h`. Goodness = 0.
    //     `partition2` is `1 2 2 ... 2`.
    //
    //     Partition `P3`: `S1 = {a1, ..., a_{n-1}}`, `S2 = {an}`
    //     `min_f_P3 = std::min(a1 + a2, a1 + a_n + h)` (if n >= 3)
    //     `max_f_P3 = std::max(a_{n-2} + a_{n-1}, a_{n-1} + a_n + h)` (if n >= 3)
    //     If n=2: `min_f_P3 = a1 + a2 + h`, `max_f_P3 = a1 + a2 + h`. Goodness = 0.
    //     `partition3` is `1 1 ... 1 2`.
    //
    //     Let's handle n=2 separately.
    if (n == 2) {
        std::cout << 0 << std::endl;
        std::cout << "1 1" << std::endl; // Or "1 2", both are valid.
        return 0;
    }

    // For n >= 3:
    // Calculate goodness1
    // a1 = elements[0].value, a2 = elements[1].value
    // an_1 = elements[n-2].value, an = elements[n-1].value
    goodness1 = (elements[n-2].value + elements[n-1].value) - (elements[0].value + elements[1].value);

    // Calculate goodness2 (a1 in S1, a2...an in S2)
    long long min_f_P2 = std::min(elements[1].value + elements[2].value, elements[0].value + elements[1].value + h);
    long long max_f_P2 = std::max(elements[n-2].value + elements[n-1].value, elements[0].value + elements[n-1].value + h);
    long long goodness2 = max_f_P2 - min_f_P2;

    // Calculate goodness3 (a1...an-1 in S1, an in S2)
    long long min_f_P3 = std::min(elements[0].value + elements[1].value, elements[0].value + elements[n-1].value + h);
    long long max_f_P3 = std::max(elements[n-3].value + elements[n-2].value, elements[n-2].value + elements[n-1].value + h);
    long long goodness3 = max_f_P3 - min_f_P3;

    long long min_goodness = goodness1;
    std::vector<int> result_partition(n);
    for (int i = 0; i < n; ++i) {
        result_partition[elements[i].original_index] = 1; // Default to partition1
    }

    if (goodness2 < min_goodness) {
        min_goodness = goodness2;
        result_partition[elements[0].original_index] = 1;
        for (int i = 1; i < n; ++i) {
            result_partition[elements[i].original_index] = 2;
        }
    }

    if (goodness3 < min_goodness) {
        min_goodness = goodness3;
        for (int i = 0; i < n - 1; ++i) {
            result_partition[elements[i].original_index] = 1;
        }
        result_partition[elements[n-1].original_index] = 2;
    }

    std::cout << min_goodness << std::endl;
    for (int i = 0; i < n; ++i) {
        std::cout << result_partition[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

