    std::cin >> s;
    int n = s.length();

    long long total_pairs = (long long)n * (n + 1) / 2;
    long long good_pairs = 0;

    // min_r[l] stores the minimum r such that s[l...r] contains a bad triplet.
    // If no such r exists, it's n+1.
    // We are interested in the smallest r_min such that s[l...r_min] contains a bad triplet.
    // For any r >= r_min, s[l...r] will also contain a bad triplet.
    // So, for a fixed l, the number of pairs (l, r) that contain a bad triplet is n - r_min + 1.
    // The number of pairs (l, r) that do NOT contain a bad triplet is r_min - l.
    // We want to sum (r_min - l) for all l.

    // Let's define min_r_with_triplet[l] as the smallest r (1-indexed) such that
    // the substring s[l...r] contains at least one bad triplet.
    // If no such r exists for a given l, we can set it to n + 1.
    // The indices in the problem are 1-based. Let's convert s to 0-indexed internally.
    // So, s_idx = s[idx-1].
    // A triplet is (x, x+k, x+2k) where 1 <= x < x+2k <= n.
    // In 0-indexed: (x-1, x+k-1, x+2k-1) where 0 <= x-1 < x+2k-1 <= n-1.
    // Let x_0 = x-1, k_0 = k. Then (x_0, x_0+k_0, x_0+2k_0).
    // Condition: 0 <= x_0 < x_0+2k_0 <= n-1.
    // The substring s[l...r] (1-indexed) corresponds to s[l-1...r-1] (0-indexed).
    // A triplet (x_0, x_0+k_0, x_0+2k_0) is in s[l-1...r-1] if l-1 <= x_0 and x_0+2k_0 <= r-1.
    // So, r-1 >= x_0+2k_0, which means r >= x_0+2k_0+1.
    // The smallest r for a given l that contains a triplet starting at x_0 is x_0+2k_0+1.
    // We need to find the minimum of these over all possible triplets.

    // Let's find the smallest ending index (0-indexed) for any bad triplet.
    // This is x_0 + 2k_0.
    // Let min_end_idx[x_0] be the minimum x_0 + 2k_0 for any triplet starting at x_0.
    // Initialize min_end_idx with n (or n+1 if 1-indexed).
    std::vector<int> min_end_idx_for_start(n, n); // min_end_idx_for_start[x_0] = min(x_0+2k_0) for valid k_0

    for (int x_0 = 0; x_0 < n; ++x_0) {
        for (int k_0 = 1; x_0 + 2 * k_0 < n; ++k_0) {
            if (s[x_0] == s[x_0 + k_0] && s[x_0 + k_0] == s[x_0 + 2 * k_0]) {
                min_end_idx_for_start[x_0] = std::min(min_end_idx_for_start[x_0], x_0 + 2 * k_0);
            }
        }
    }

    // Now, min_end_idx_for_start[x_0] gives the smallest 0-indexed end of a bad triplet
    // that starts at x_0. If no such triplet exists, it's n.

    // We need to find min_r_with_triplet[l_0] (0-indexed l_0).
    // min_r_with_triplet[l_0] = min(x_0 + 2k_0) for all x_0 >= l_0 that start a bad triplet.
    // This can be computed by iterating l_0 from n-1 down to 0.
    // min_r_with_triplet[l_0] = min(min_end_idx_for_start[l_0], min_r_with_triplet[l_0+1])
    // Base case: min_r_with_triplet[n-1] = min_end_idx_for_start[n-1] (which is n, as no triplet can start at n-1)
    // Initialize min_r_with_triplet with n.
    std::vector<int> min_r_with_triplet(n + 1, n); // min_r_with_triplet[l_0] is the smallest 0-indexed r_0
                                                  // such that s[l_0...r_0] contains a bad triplet.
                                                  // If no such r_0 exists, it's n.

    for (int l_0 = n - 1; l_0 >= 0; --l_0) {
        min_r_with_triplet[l_0] = min_end_idx_for_start[l_0];
        if (l_0 + 1 < n) {
            min_r_with_triplet[l_0] = std::min(min_r_with_triplet[l_0], min_r_with_triplet[l_0 + 1]);
        }
    }

    // Now, for each l_0 (0-indexed start of substring), min_r_with_triplet[l_0] is the smallest
    // 0-indexed end of a substring that contains a bad triplet.
    // If min_r_with_triplet[l_0] is n, it means no bad triplet exists for any substring starting at l_0.
    // The number of good pairs (l_0, r_0) for a fixed l_0 is (min_r_with_triplet[l_0] - l_0).
    // This is because r_0 can range from l_0 to min_r_with_triplet[l_0] - 1.
    // The length of this range is (min_r_with_triplet[l_0] - 1) - l_0 + 1 = min_r_with_triplet[l_0] - l_0.

    for (int l_0 = 0; l_0 < n; ++l_0) {
        good_pairs += (min_r_with_triplet[l_0] - l_0);
    }

    std::cout << total_pairs - good_pairs << std::endl;

    return 0;
}

#include <iostream>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    long long a, b;
    std::cin >> a >> b;

    long long MOD = 1000000007;

    // If b = 1, mod(x, 1) is always 0.
    // The condition mod(x, b) != 0 is never met.
    // So, there are no nice integers. The sum is 0.
    if (b == 1) {
        std::cout << 0 << std::endl;
        return 0;
    }

    // Calculate sum_r = sum_{r=1 to b-1} r
    // sum_r = (b-1) * b / 2
    // Since b can be up to 10^7, (b-1)*b can be up to 10^14, which fits in long long.
    // We need to perform division by 2.
    // If b is even, b/2 is integer. (b-1) * (b/2)
    // If b is odd, (b-1)/2 is integer. ((b-1)/2) * b
    // This is equivalent to (b-1) * b / 2.
    // For modulo arithmetic, we need to multiply by modular inverse of 2.
    // Modular inverse of 2 modulo 10^9 + 7 is (10^9 + 7 + 1) / 2 = 1000000008 / 2 = 500000004.
    long long inv2 = 500000004;

    long long sum_r_term = (b - 1);
    sum_r_term = (sum_r_term % MOD * (b % MOD)) % MOD;
    sum_r_term = (sum_r_term * inv2) % MOD;

    // Calculate sum_k_b_plus_1 = sum_{k=1 to a} (k * b + 1)
    // sum_k_b_plus_1 = sum_{k=1 to a} (k * b) + sum_{k=1 to a} 1
    //                = b * sum_{k=1 to a} k + a
    // sum_{k=1 to a} k = a * (a + 1) / 2
    long long sum_k_term = (a % MOD * ((a + 1) % MOD)) % MOD;
    sum_k_term = (sum_k_term * inv2) % MOD;

    long long sum_k_b_plus_1 = (b % MOD * sum_k_term) % MOD;
    sum_k_b_plus_1 = (sum_k_b_plus_1 + (a % MOD)) % MOD;

    // Total sum S = sum_r_term * sum_k_b_plus_1
    long long total_sum = (sum_r_term * sum_k_b_plus_1) % MOD;

    std::cout << total_sum << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <set>

bool check(long long T, int n, int m, const std::vector<long long>& h, const std::vector<long long>& p) {
    int p_idx = 0;
    for (int i = 0; i < n; ++i) {
        if (p_idx == m) {
            break; // All required tracks covered
        }

        long long current_h = h[i];
        long long left_reach = current_h - T;
        long long right_reach = current_h + T;

        // Find the first track p[p_idx] that can be covered by current_h
        // It must be within [left_reach, right_reach]
        if (p[p_idx] > right_reach) {
            // This head cannot reach p[p_idx] or any subsequent tracks.
            // Since heads are sorted and p are sorted, if current_h cannot reach p[p_idx],
            // then current_h cannot cover p[p_idx] and current_h cannot cover any p[k] for k > p_idx.
            // And since h[i+1] > h[i], h[i+1] might be able to cover p[p_idx],
            // but we are trying to cover p[p_idx] with current_h.
            // If p[p_idx] is too far right for current_h, then current_h cannot cover it.
            // We need to find the first p[p_idx] that current_h can cover.
            // If p[p_idx] is already too far right, this head cannot help with it.
            // This logic is slightly off. We need to find the first p[k] that current_h can cover.
            // If current_h cannot cover p[p_idx], it means p[p_idx] is too far right.
            // This head can only cover tracks to its left or around it.
            // If p[p_idx] is to the right of current_h + T, then current_h cannot cover it.
            // This head is useless for p[p_idx] and subsequent tracks.
            // This means we need to use a different head for p[p_idx].
            // The current head h[i] must cover some p[k] where k >= p_idx.
            // If h[i] cannot cover p[p_idx], it means p[p_idx] is too far right.
            // This head cannot cover p[p_idx].
            // The logic should be: for each head, cover as many tracks as possible starting from p[p_idx].
            continue; // This head cannot reach p[p_idx], try next head.
        }

        // If p[p_idx] is within [left_reach, right_reach], this head can cover it.
        // Now, we need to determine the maximum range this head can cover,
        // considering it must cover p[p_idx].
        // The head can move to any position x such that |x - current_h| <= T.
        // If it moves to x, it covers [x-T, x+T].
        // To cover p[p_idx], x must be in [p[p_idx]-T, p[p_idx]+T].
        // Also, x must be in [current_h-T, current_h+T].
        // So, x must be in [max(current_h-T, p[p_idx]-T), min(current_h+T, p[p_idx]+T)].
        // To maximize the rightmost covered track, we should choose x as large as possible.
        // The largest possible x is min(current_h+T, p[p_idx]+T).
        // If we choose x = min(current_h+T, p[p_idx]+T), the range covered is [x-T, x+T].
        // The rightmost point covered is x+T = min(current_h+T, p[p_idx]+T) + T.
        // This is not quite right.
        // The head starts at current_h. It can move to any position `pos` such that `abs(pos - current_h) <= T`.
        // From `pos`, it can cover tracks in `[pos - T, pos + T]`.
        // We need to cover `p[p_idx]`. So, `p[p_idx]` must be in `[pos - T, pos + T]`.
        // This means `pos` must be in `[p[p_idx] - T, p[p_idx] + T]`.
        // Combining these, `pos` must be in `[max(current_h - T, p[p_idx] - T), min(current_h + T, p[p_idx] + T)]`.
        // To maximize the rightmost track covered, we should choose `pos` to be the largest possible value in this range.
        // Let `optimal_pos = min(current_h + T, p[p_idx] + T)`.
        // The rightmost track covered by this head would be `optimal_pos + T`.
        // However, this is only if `optimal_pos` is a valid position.
        // The actual rightmost track covered is `max_covered_right`.
        // If `p[p_idx]` is covered, the head can be moved to `p[p_idx]`. This takes `abs(p[p_idx] - current_h)` time.
        // Remaining time is `T - abs(p[p_idx] - current_h)`.
        // With this remaining time, the head can move further.
        // So, from `p[p_idx]`, it can reach `p[p_idx] + (T - abs(p[p_idx] - current_h))`.
        // This is `p[p_idx] + T - abs(p[p_idx] - current_h)`.
        // This is the rightmost point it can reach *after* covering p[p_idx].
        // This is the correct logic for the rightmost point covered by this head.
        long long max_covered_right = p[p_idx] + (T - std::abs(p[p_idx] - current_h));

        // Advance p_idx to the first track not covered by this head.
        while (p_idx < m && p[p_idx] <= max_covered_right) {
            p_idx++;
        }
    }
    return p_idx == m;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<long long> h(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> h[i];
    }

    std::vector<long long> p(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> p[i];
    }

    long long low = 0;
    long long high = 20000000000LL; // Max possible distance is 10^10. A head can move 10^10 to cover a point, and then 10^10 more to cover another point. So 2*10^10 is a safe upper bound.
    long long ans = high;

    while (low <= high) {
        long long mid = low + (high - low) / 2;
        if (check(mid, n, m, h, p)) {
            ans = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    std::cout << ans << std::endl;

    return 0;
}

