int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n;
        std::cin >> n;
        std::vector<int> p(n);
        for (int i = 0; i < n; ++i) {
            std::cin >> p[i];
        }

        // The problem statement guarantees that a solution exists.
        // Reversing the permutation always produces a different permutation
        // with the same fingerprint.
        // F(p) = sort([p_1+p_2, p_2+p_3, ..., p_{n-1}+p_n])
        // Let p' be the reversed permutation: p'_i = p_{n-i+1}.
        // p' = [p_n, p_{n-1}, ..., p_2, p_1]
        // F(p') = sort([p_n+p_{n-1}, p_{n-1}+p_{n-2}, ..., p_2+p_1])
        // Since addition is commutative, the set of sums is the same.
        // The only case where p' might be equal to p is if p is a palindrome,
        // but a permutation cannot be a palindrome unless n=1 (not allowed)
        // or n=2 and p=[1,2] or p=[2,1] (which are not palindromes in general sense,
        // but reversing [1,2] gives [2,1] which is different).
        // For n > 1, p and reversed(p) are always different.
        // Example: n=2, p=[1,2]. Reversed p'=[2,1]. p != p'. F(p)=[3], F(p')=[3].
        // Example: n=3, p=[1,2,3]. Reversed p'=[3,2,1]. p != p'. F(p)=[3,5], F(p')=[5,3] -> [3,5].

        std::reverse(p.begin(), p.end());

        for (int i = 0; i < n; ++i) {
            std::cout << p[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    }
    return 0;
}

