#include <iostream>
#include <cmath>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int T;
    std::cin >> T;
    while (T--) {
        long long a, b;
        std::cin >> a >> b;
        if (a == b) {
            std::cout << 0 << "\n";
            continue;
        }
        long long diff = std::abs(a - b);
        long long count = 0;

        // Use as many 5s as possible
        count += diff / 5;
        diff %= 5;

        // Now diff can be 0, 1, 2, 3, 4
        if (diff == 0) {
            // No remaining difference
        } else if (diff == 1) {
            // Can be 1 (one +1 or -1)
            // Can be 2 (one +2 or -2) then -1 or +1 (total 2 presses)
            // Can be 5 (one +5 or -5) then -2 or +2 (total 2 presses)
            // The optimal for 1 is 1 press.
            // The optimal for 2 is 1 press.
            // The optimal for 3 is 2 presses (e.g., +2, +1).
            // The optimal for 4 is 2 presses (e.g., +2, +2).
            // The optimal for 0 is 0 presses.
            // So for diff=1, it's 1 press.
            // For diff=2, it's 1 press.
            // For diff=3, it's 2 presses.
            // For diff=4, it's 2 presses.
            // This can be simplified: if diff is 1 or 2, it's 1 press.
            // If diff is 3 or 4, it's 2 presses.
            // This is equivalent to ceil(diff / 2.0) for diff > 0.
            // Or (diff + 1) / 2 for integer division.
            count += (diff + 1) / 2;
        } else if (diff == 2) {
            count += 1; // One +2 or -2
        } else if (diff == 3) {
            count += 2; // One +2 and one +1, or one +5 and one -2
        } else if (diff == 4) {
            count += 2; // Two +2s, or one +5 and one -1
        }

        std::cout << count << "\n";
    }
    return 0;
}

