        if (a[i] == 1) {
            has_pos_one = true;
        } else if (a[i] == -1) {
            has_neg_one = true;
        }
    }
    for (int i = 0; i < n; ++i) {
        std::cin >> b[i];
    }

    bool possible = true;
    for (int i = n - 1; i >= 0; --i) {
        if (a[i] == b[i]) {
            // No operation needed for this element, or it's already correct.
            // If a[i] was 0, it must remain 0.
            // If a[i] was 1, it must remain 1.
            // If a[i] was -1, it must remain -1.
            // This is implicitly handled by the conditions below.
            // The crucial part is that a[i] cannot be changed by elements a[k] where k > i.
            // So, if a[i] == b[i], we just need to ensure it's possible to achieve this.
            // For a[i] == 0, b[i] == 0, it's fine.
            // For a[i] == 1, b[i] == 1, it's fine.
            // For a[i] == -1, b[i] == -1, it's fine.
            // The logic for has_pos_one and has_neg_one is for elements a[k] where k < i.
            // So, if a[i] == b[i], we just continue.
        } else if (a[i] < b[i]) {
            // To increase a[i], we need to add 1s from a[k] where k < i.
            // This requires at least one a[k] == 1 for k < i.
            if (!has_pos_one) {
                possible = false;
                break;
            }
        } else { // a[i] > b[i]
            // To decrease a[i], we need to add -1s from a[k] where k < i.
            // This requires at least one a[k] == -1 for k < i.
            if (!has_neg_one) {
                possible = false;
                break;
            }
        }

        // Update has_pos_one and has_neg_one for the next iteration (i-1)
        // These flags track if a 1 or -1 exists in a[0...i-1]
        if (a[i] == 1) {
            has_pos_one = true; // This is actually redundant for the loop, as a[i] is fixed.
                                // The flags should reflect elements *before* current i.
                                // Let's correct this: the flags should be updated *after* checking a[i].
                                // For the next iteration (i-1), a[i-1] will be the current element.
                                // The flags should reflect elements a[0...i-2].
                                // So, the flags should be updated based on a[i-1] *before* the next iteration.
                                // This means, for current `i`, `has_pos_one` and `has_neg_one`
                                // should reflect elements in `a[0...i-1]`.
                                // The initial values of `has_pos_one` and `has_neg_one` are for `a[0...n-1]`.
                                // When processing `a[n-1]`, `has_pos_one` and `has_neg_one` should reflect `a[0...n-2]`.
                                // This means we need to pre-calculate these flags for prefixes.

                                // Let's re-think the flags.
                                // `has_pos_one` means there is a 1 at an index `k < i`.
                                // `has_neg_one` means there is a -1 at an index `k < i`.
                                // When we are at index `i`, we need to know if there's a 1 or -1 in `a[0...i-1]`.
                                // The current `has_pos_one` and `has_neg_one` are for `a[0...i]`.
                                // So, before checking `a[i]`, we need to remove `a[i]`'s contribution from the flags.
                                // This is tricky if there are duplicates.

                                // A simpler approach: iterate from left to right.
                                // For each `a[i]`, it must be equal to `b[i]`.
                                // If `a[i] < b[i]`, we need to add `b[i] - a[i]` ones.
                                // If `a[i] > b[i]`, we need to add `a[i] - b[i]` negative ones.
                                // The elements `a[0...i-1]` are the ones that can be added to `a[i]`.
                                // So, we need to track if `a[0...i-1]` contains a 1 and a -1.

                                // Let's restart the logic with a left-to-right pass.
    }

    // Re-evaluate with left-to-right pass
    has_pos_one = false; // Tracks if a 1 exists in a[0...i-1]
    has_neg_one = false; // Tracks if a -1 exists in a[0...i-1]

    possible = true;
    for (int i = 0; i < n; ++i) {
        if (a[i] == b[i]) {
            // No operation needed for this element.
            // Just update flags for next iteration.
        } else if (a[i] < b[i]) {
            // Need to increase a[i]. Requires a 1 from a[k] where k < i.
            if (!has_pos_one) {
                possible = false;
                break;
            }
        } else { // a[i] > b[i]
            // Need to decrease a[i]. Requires a -1 from a[k] where k < i.
            if (!has_neg_one) {
                possible = false;
                break;
            }
        }

        // Update flags for the next iteration (i+1)
        // These flags will reflect elements in a[0...i]
        if (a[i] == 1) {
            has_pos_one = true;
        } else if (a[i] == -1) {
            has_neg_one = true;
        }
    }

    if (possible) {
        std::cout << "YES\n";
    } else {
        std::cout << "NO\n";
    }
}

