    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::vector<std::vector<int>> a(n, std::vector<int>(n));
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < n; ++j) {
            std::cin >> a[i][j];
        }
    }

    std::vector<int> p(n);
    for (int i = 0; i < n; ++i) {
        int max_val_in_row = 0;
        for (int j = 0; j < n; ++j) {
            if (i == j) continue;
            if (a[i][j] > max_val_in_row) {
                max_val_in_row = a[i][j];
            }
        }
        p[i] = max_val_in_row;
    }

    // Check if any element in p is n-1. If so, it means the actual value for that position is n.
    // This happens if the original p_i was n, then min(p_i, p_j) = p_j for all j != i.
    // The maximum of these p_j values would be n-1.
    // If no element in p is n-1, it means all p_i values are less than n.
    // This implies that the maximum value n must be present in the permutation,
    // and it must be assigned to one of the p_i values that currently holds n-1.
    // If there are multiple n-1s, it means one of them should be n.
    // The problem guarantees a solution exists.
    // The logic is: if p[i] is the maximum value in the permutation (n), then max(a[i][j] for j!=i) will be n-1.
    // If p[i] is not the maximum value (n), then max(a[i][j] for j!=i) will be p[i] (if there's a p_j > p_i)
    // or some value less than p[i] (if all p_j < p_i).
    // Since the permutation contains 1 to n, there will always be a p_j > p_i unless p_i = n.
    // So, if p[i] != n, then max(a[i][j] for j!=i) = p[i].
    // If p[i] = n, then max(a[i][j] for j!=i) = n-1.
    // So, we iterate through the calculated p values. If any p[i] is n-1, it means the actual value for that position is n.
    // If no p[i] is n-1, it means all p[i] are their true values, and the value n is missing.
    // In this case, we need to find the maximum value in the current p and increment it to n.
    // This scenario happens when n=2, and p={1,1}. One of them should be 2.
    // For n=2, a={0,1; 1,0}. max_val_in_row for both is 1. So p={1,1}.
    // We need to change one of them to 2.

    bool n_found = false;
    for (int i = 0; i < n; ++i) {
        if (p[i] == n - 1) {
            n_found = true;
            break;
        }
    }

    if (!n_found) {
        // This means no p_i was n, so all p_i are their true values, and n is missing.
        // The largest value in the current p is n-1. We need to change one of them to n.
        // It doesn't matter which one, as long as it's one of the (n-1)s.
        // The problem guarantees a solution.
        int max_p_val = 0;
        int max_p_idx = -1;
        for(int i = 0; i < n; ++i) {
            if (p[i] > max_p_val) {
                max_p_val = p[i];
                max_p_idx = i;
            }
        }
        // If n=2, p={1,1}. max_p_val=1, max_p_idx=0. p[0] becomes 2. Result {2,1}.
        // This logic works for n=2.
        // For n > 2, if n is not found, it means all p_i are their true values, and n is missing.
        // The largest value in p would be n-1. We need to change one of the (n-1)s to n.
        // Example: p = {1, 2, 3, 4}. n=5. max_p_val=4. Change p[3] to 5. Result {1,2,3,5}.
        // This is correct.
        p[max_p_idx] = n;
    }


    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

