#include <iostream>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long x;
        std::cin >> x;
        int count = 0;
        long long current_cost = 0;
        long long k = 1; // Represents the number of stairs in the current staircase (1, 3, 7, 15, ...)
        while (true) {
            // Cost for a staircase with k stairs: k * (k + 1) / 2
            // k is of the form 2^p - 1
            // So, cost is (2^p - 1) * (2^p) / 2
            // Let m = 2^p. Cost = (m - 1) * m / 2
            // For p=1, k=1, cost = 1 * 2 / 2 = 1
            // For p=2, k=3, cost = 3 * 4 / 2 = 6
            // For p=3, k=7, cost = 7 * 8 / 2 = 28
            // For p=4, k=15, cost = 15 * 16 / 2 = 120

            long long cost_of_next_staircase = k * (k + 1) / 2;

            if (current_cost + cost_of_next_staircase <= x) {
                current_cost += cost_of_next_staircase;
                count++;
                // Calculate the next k. The sequence of k is 1, 3, 7, 15, ...
                // This is 2^p - 1. So the next k is 2 * k + 1.
                k = 2 * k + 1;
            } else {
                break;
            }
        }
        std::cout << count << "\n";
    }
    return 0;
}

#include <iostream>
#include <string>
#include <algorithm>
#include <vector>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        std::string s;
        std::cin >> s;
        int max_gap = 0;
        int last_r_pos = -1; // Represents the position of the last 'R' or the starting point 0.
                             // If last_r_pos is -1, it means the frog is at cell 0.
                             // If last_r_pos is i, it means the frog is at cell i.
                             // The actual cell index is last_r_pos + 1 for string s.

        for (int i = 0; i < s.length(); ++i) {
            if (s[i] == 'R') {
                // The current cell is i+1.
                // The previous 'R' or start was at last_r_pos.
                // The distance between the current 'R' and the previous 'R' (or start) is (i+1) - (last_r_pos + 1) = i - last_r_pos.
                // Or, more simply, the distance between indices is i - last_r_pos.
                max_gap = std::max(max_gap, i - last_r_pos);
                last_r_pos = i;
            }
        }
        // After iterating through the string, consider the jump from the last 'R' (or start if no 'R's) to n+1.
        // The last 'R' was at index last_r_pos. The cell is last_r_pos + 1.
        // The target is n+1.
        // The distance is (n+1) - (last_r_pos + 1) = n - last_r_pos.
        max_gap = std::max(max_gap, (int)s.length() - last_r_pos);
        std::cout << max_gap << "\n";
    }
    return 0;
}

