int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n, k;
    std::cin >> n >> k;

    int left = 1;
    int right = k + 1; // The largest number we will use for the alternating part

    // Print the first k+1 numbers in an alternating pattern
    // This pattern generates differences k, k-1, ..., 1
    // For example, if k=2, right=3:
    // 1, 3, 2
    // Differences: |1-3|=2, |3-2|=1. Distinct: {1,2} (k distinct differences)
    // If k=3, right=4:
    // 1, 4, 2, 3
    // Differences: |1-4|=3, |4-2|=2, |2-3|=1. Distinct: {1,2,3} (k distinct differences)

    bool use_left = true;
    for (int i = 0; i <= k; ++i) {
        if (use_left) {
            std::cout << left << " ";
            left++;
        } else {
            std::cout << right << " ";
            right--;
        }
        use_left = !use_left;
    }

    // After generating k distinct differences using numbers from 1 to k+1,
    // the remaining numbers are k+2, k+3, ..., n.
    // We can append these in increasing order to ensure they only introduce
    // a difference of 1 with the previous number, or if the previous number
    // was part of the alternating sequence, it will be a difference that
    // is already covered (e.g., if the last printed was `left`, the next
    // number `k+2` will give `k+2 - left` which is `k+2 - (k/2 + 1)` or similar,
    // which is likely a new difference, but we need to be careful).

    // Let's re-evaluate the alternating part.
    // To get k distinct differences (1 to k), we can use numbers 1 to k+1.
    // Example: n=5, k=2
    // We need 2 distinct differences. Use numbers 1, 2, 3.
    // Pattern: 1, 3, 2
    // Differences: |1-3|=2, |3-2|=1. Distinct: {1,2}.
    // Remaining numbers: 4, 5.
    // Append them: 1, 3, 2, 4, 5
    // New differences: |2-4|=2, |4-5|=1. These are already in {1,2}.
    // This strategy works.

    left = 1;
    right = k + 1;

    for (int i = 0; i < k + 1; ++i) {
        if (i % 2 == 0) { // Even index, print from left
            std::cout << left++;
        } else { // Odd index, print from right
            std::cout << right--;
        }
        std::cout << " ";
    }

    // Print the remaining numbers in increasing order
    // These numbers are from k+2 to n.
    // The last number printed from the alternating sequence was either `left-1` or `right+1`.
    // If it was `left-1`, then `left` is now `(k/2)+1`.
    // If it was `right+1`, then `right` is now `k+1 - (k/2)`.
    // The next number to print is `k+2`.
    // The difference `|last_alternating - (k+2)|` will be `| (k/2)+1 - (k+2) |` or `| k+1 - (k/2) - (k+2) |`.
    // These differences will be `k/2 + 1` or `k/2 + 1`.
    // These differences are already covered by the initial k differences (1 to k).
    // For example, if k=2, last alternating was 2. Next is 4. Diff |2-4|=2. Covered.
    // If k=3, last alternating was 3. Next is 5. Diff |3-5|=2. Covered.
    // So, appending remaining numbers in increasing order works.
    for (int i = k + 2; i <= n; ++i) {
        std::cout << i << (i == n ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

