        long long count_multiples = n / m;

        if (count_multiples == 0) {
            std::cout << 0 << "\n";
            continue;
        }

        std::vector<long long> last_digits_cycle(10);
        for (int i = 1; i <= 10; ++i) {
            last_digits_cycle[i - 1] = (static_cast<long long>(i) * m) % 10;
        }

        long long sum_cycle = 0;
        for (long long digit : last_digits_cycle) {
            sum_cycle += digit;
        }

        long long num_full_cycles = count_multiples / 10;
        long long remaining_multiples = count_multiples % 10;

        long long total_sum = num_full_cycles * sum_cycle;

        for (int i = 0; i < remaining_multiples; ++i) {
            total_sum += last_digits_cycle[i];
        }

        std::cout << total_sum << "\n";
    }
    return 0;
}

