    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 1) {
        std::cout << 0 << std::endl;
        return;
    }

    // Find the rightmost peak of the suffix that is non-increasing
    // This is the first element from the right that breaks the non-increasing order
    // i.e., a[i] > a[i+1]
    int i = n - 1;
    while (i > 0 && a[i-1] >= a[i]) {
        i--;
    }
    // Now, a[i...n-1] is non-increasing.
    // If i=0, the whole array is non-increasing.

    // Find the rightmost peak of the suffix that is non-decreasing
    // This is the first element from the right that breaks the non-decreasing order
    // i.e., a[j] < a[j+1]
    int j = i; // Start search from 'i'
    while (j > 0 && a[j-1] <= a[j]) {
        j--;
    }
    // Now, a[j...n-1] is a "good" array.
    // The elements a[0...j-1] must be removed.
    // The length of the prefix to remove is j.

    std::cout << j << std::endl;
}

