void solve() {
    int n;
    std::cin >> n;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n == 1) {
        std::cout << "Yes\n";
        return;
    }

    // Calculate prefix_min_ops: minimum value a[i] can be reduced to
    // to satisfy a[0] < a[1] < ... < a[i]
    // This means a[i] must be at least i.
    // So, a[i] must be >= i.
    // If a[i] < i, it's impossible to satisfy the increasing condition up to this point.
    // We can check this by seeing if a[i] >= i for all i.
    // More precisely, we need a[i] >= i for the left part.
    // Let's find the maximum index `l` such that a[i] >= i for all 0 <= i <= l.
    int l = 0;
    while (l < n && a[l] >= l) {
        l++;
    }
    l--; // l is now the last index for which a[l] >= l.
         // If l is -1, it means a[0] < 0, which is impossible since a[0] >= 0.
         // So l will be at least 0 if a[0] >= 0.

    // Calculate suffix_min_ops: minimum value a[i] can be reduced to
    // to satisfy a[i] > a[i+1] > ... > a[n-1]
    // This means a[i] must be at least (n-1-i).
    // So, a[i] must be >= (n-1-i).
    // If a[i] < (n-1-i), it's impossible to satisfy the decreasing condition from this point.
    // Let's find the minimum index `r` such that a[i] >= (n-1-i) for all r <= i <= n-1.
    int r = n - 1;
    while (r >= 0 && a[r] >= (n - 1 - r)) {
        r--;
    }
    r++; // r is now the first index for which a[r] >= (n-1-r).
         // If r is n, it means a[n-1] < 0, which is impossible.
         // So r will be at most n-1 if a[n-1] >= 0.

    // An array can be sharpened if there exists a peak k (0-indexed)
    // such that a[0] < ... < a[k] and a[k] > ... > a[n-1].
    // This means we need to find a k such that:
    // 1. a[i] >= i for all i <= k (left part can be made increasing)
    // 2. a[i] >= (n-1-i) for all i >= k (right part can be made decreasing)

    // The `l` we found is the maximum index such that a[0...l] can be made 0, 1, ..., l.
    // The `r` we found is the minimum index such that a[r...n-1] can be made (n-1-r), ..., 1, 0.

    // If there is any overlap between the valid indices for the left part and the right part,
    // then we can pick a peak `k` in that overlap.
    // The left part is valid for indices `0` to `l`.
    // The right part is valid for indices `r` to `n-1`.
    // We need to find if there's any `k` such that `0 <= k <= l` AND `r <= k <= n-1`.
    // This is equivalent to checking if `r <= l`.
    if (r <= l) {
        std::cout << "Yes\n";
    } else {
        std::cout << "No\n";
    }
}

