            // If B is odd, C is odd, we can pair them up.
            // The product of B toys is $P_B \in (-1, 0)$. The product of C toys is $P_C \in (0, 1)$.
            // $P_B \cdot P_C \in (-1, 0)$. So this doesn't help to get to Box 1.
            // The only way to get magnitude >= 1 from only B and C toys is if we can make a product that grows.
            // This is not possible. The product of any number of toys from B and C will always be in (-1, 1).
            // So, if A=0 and D=0, Box 1 is only possible if the final product is negative and magnitude >= 1.
            // This is impossible if all initial toys are from B and C.
            // Therefore, if A=0 and D=0, Box 1 is NOT possible.
            box1_possible = false; // Re-evaluating this. If A=0 and D=0, all toys are in (-1, 1).
                                   // Any product of such toys will also be in (-1, 1).
                                   // So, magnitude >= 1 is impossible.
        }
    }
    result[0] = box1_possible ? "Ya" : "Tidak";


    // Case 2: Box 2 (fun value in (-1, 0))
    // This requires an odd number of negative factors.
    // And the final product must have magnitude < 1.
    // Magnitude < 1 is always possible if A=0 and D=0.
    // If A=0 and D=0, and (A+B) is odd, then Box 2 is possible.
    // If A > 0 or D > 0, we need to be able to "reduce" the magnitude.
    // This can be done by multiplying with toys from Box 3 or Box 2.
    // If there's at least one toy in Box 2 or Box 3, we can make the magnitude < 1.
    // If A+B is odd, and (B > 0 or C > 0), then Box 2 is possible.
    // Exception: If B=0 and C=0, then all toys are from A and D.
    // If A+B is odd, and B=0 and C=0, then A is odd. All toys are from A and D.
    // Product of A and D toys will always have magnitude >= 1. So Box 2 is not possible.

    bool box2_possible = false;
    if ((A + B) % 2 != 0) { // Final product is negative
        if (B > 0 || C > 0) { // At least one toy with magnitude < 1
            box2_possible = true;
        } else if (A > 0 && D == 0 && A == 1 && total_toys == 1) { // Special case: only one toy in Box 1
            // If A=1, B=0, C=0, D=0, then the toy is in Box 1, not Box 2.
            // This condition is for the final toy.
            // If total_toys == 1, the initial toy is the super toy.
            // If A=1, B=0, C=0, D=0, then the super toy is in Box 1.
            // So, if A=1, B=0, C=0, D=0, Box 2 is not possible.
            // The condition (B > 0 || C > 0) correctly handles this.
            // If A=1, B=0, C=0, D=0, then B>0 || C>0 is false, so box2_possible is false. Correct.
        } else if (A == 0 && D == 0 && B > 0) { // Only toys from B and C, and B > 0
            // If A=0, D=0, then all toys are from B and C.
            // If B > 0, then (A+B) is odd means B is odd.
            // The product of B and C toys will always be in (-1, 1).
            // If B is odd, the product will be negative. So it will be in (-1, 0).
            box2_possible = true;
        }
    }
    result[1] = box2_possible ? "Ya" : "Tidak";


    // Case 3: Box 3 (fun value in (0, 1))
    // This requires an even number of negative factors.
    // And the final product must have magnitude < 1.
    // If (A+B) is even, and (B > 0 or C > 0), then Box 3 is possible.
    // Exception: If B=0 and C=0, then all toys are from A and D.
    // If A+B is even, and B=0 and C=0, then A is even. All toys are from A and D.
    // Product of A and D toys will always have magnitude >= 1. So Box 3 is not possible.

    bool box3_possible = false;
    if ((A + B) % 2 == 0) { // Final product is positive
        if (B > 0 || C > 0) { // At least one toy with magnitude < 1
            box3_possible = true;
        } else if (A == 0 && D == 0 && C > 0) { // Only toys from B and C, and C > 0
            // If A=0, D=0, then all toys are from B and C.
            // If C > 0, then (A+B) is even means B is even.
            // The product of B and C toys will always be in (-1, 1).
            // If B is even, the product will be positive. So it will be in (0, 1).
            box3_possible = true;
        }
    }
    result[2] = box3_possible ? "Ya" : "Tidak";


    // Case 4: Box 4 (fun value >= 1)
    // This requires an even number of negative factors.
    // And the final product must have magnitude >= 1.
    // If (A+B) is even, and (A > 0 or D > 0), then Box 4 is possible.
    // Exception: If A=0 and D=0, then all toys are from B and C.
    // Product of B and C toys will always have magnitude < 1. So Box 4 is not possible.

    bool box4_possible = false;
    if ((A + B) % 2 == 0) { // Final product is positive
        if (A > 0 || D > 0) { // At least one toy with magnitude >= 1
            box4_possible = true;
        } else if (A == 0 && D == 0 && total_toys == 1 && C == 1) { // Special case: only one toy in Box 3
            // If A=0, B=0, C=1, D=0, then the toy is in Box 3, not Box 4.
            // This condition is for the final toy.
            // If total_toys == 1, the initial toy is the super toy.
            // If A=0, B=0, C=1, D=0, then the super toy is in Box 3.
            // So, if A=0, B=0, C=1, D=0, Box 4 is not possible.
            // The condition (A > 0 || D > 0) correctly handles this.
            // If A=0, B=0, C=1, D=0, then A>0 || D>0 is false, so box4_possible is false. Correct.
        }
    }
    result[3] = box4_possible ? "Ya" : "Tidak";

    // Special handling for total_toys == 1
    if (total_toys == 1) {
        if (A == 1) {
            result[0] = "Ya"; result[1] = "Tidak"; result[2] = "Tidak"; result[3] = "Tidak";
        } else if (B == 1) {
            result[0] = "Tidak"; result[1] = "Ya"; result[2] = "Tidak"; result[3] = "Tidak";
        } else if (C == 1) {
            result[0] = "Tidak"; result[1] = "Tidak"; result[2] = "Ya"; result[3] = "Tidak";
        } else if (D == 1) {
            result[0] = "Tidak"; result[1] = "Tidak"; result[2] = "Tidak"; result[3] = "Ya";
        }
    }

    std::cout << result[0] << " " << result[1] << " " << result[2] << " " << result[3] << std::endl;
}

