    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }
    std::sort(a.begin(), a.end());
    int count = 0;
    int j = 0; // Pointer for the elements we are trying to place (larger elements)
    for (int i = 0; i < n; ++i) { // Pointer for the original positions (smaller elements)
        // We are trying to find an element a[j] such that a[j] > a[i]
        // Since both arrays are sorted, if a[j] > a[i], then a[j+1], a[j+2], ... will also be > a[i]
        // We want to use the smallest possible a[j] that satisfies a[j] > a[i]
        // to save larger elements for later, potentially larger a[i] values.
        while (j < n && a[j] <= a[i]) {
            j++;
        }
        if (j < n) { // Found an element a[j] > a[i]
            count++;
            j++; // Move to the next element in the 'larger' pool
        } else {
            // No more elements in 'larger' pool that can be greater than a[i]
            // All remaining a[i] values cannot be matched with a strictly larger element.
            break;
        }
    }
    std::cout << count << std::endl;
    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

struct Element {
    long long val;
    int original_index;
};

bool compareElements(const Element& a, const Element& b) {
    return a.val < b.val;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int m;
    std::cin >> m;

    std::vector<long long> a(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> a[i];
    }

    std::vector<Element> b_elements(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> b_elements[i].val;
        b_elements[i].original_index = i;
    }

    // Sort array A in ascending order
    std::sort(a.begin(), a.end());

    // Sort array B elements based on their values in ascending order
    std::sort(b_elements.begin(), b_elements.end(), compareElements);

    // Create the result array A'
    // To maximize sum(F(A'_i, B_i)), we need to pair the largest A_i with the largest B_i,
    // the second largest A_i with the second largest B_i, and so on.
    // This is because F(n, k) = (n+1)/(k+1), which is an increasing function of n.
    // So, we want to pair larger A values with larger (1/(k+1)) values.
    // Since 1/(k+1) is a decreasing function of k, we want to pair larger A values with smaller B values.
    // However, the problem states F(n, k) = (n+1)/(k+1).
    // This means F(A_i, B_i) = (A_i+1)/(B_i+1).
    // To maximize sum((A_i+1)/(B_i+1)), we should pair the largest (A_i+1) with the smallest (B_i+1),
    // the second largest (A_i+1) with the second smallest (B_i+1), etc.
    // This is a standard rearrangement inequality application.
    // Sort A in ascending order. Sort B in descending order.
    // Then A'_i = A[i] and B'_i = B_sorted_desc[i].
    // The problem asks for A' as a permutation of A, such that A'_i is paired with B_i (original B).
    // So, we need to find A'_i for each original B_i.
    // Let's sort A ascending.
    // Let's sort B ascending (based on B_i values).
    // The smallest B_i (B_sorted[0]) should be paired with the largest A_j (A_sorted[m-1]).
    // The second smallest B_i (B_sorted[1]) should be paired with the second largest A_j (A_sorted[m-2]).
    // And so on.
    // B_sorted[k] should be paired with A_sorted[m-1-k].

    std::vector<long long> result_a_prime(m);
    for (int i = 0; i < m; ++i) {
        // b_elements[i] contains the i-th smallest B value and its original index.
        // This i-th smallest B value (b_elements[i].val) should be paired with the (m-1-i)-th largest A value (a[m-1-i]).
        // We store this A value at the original index of b_elements[i].
        result_a_prime[b_elements[i].original_index] = a[m - 1 - i];
    }

    for (int i = 0; i < m; ++i) {
        std::cout << result_a_prime[i] << (i == m - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>
#include <set>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    std::vector<int> prefix_max(n);
    std::vector<bool> prefix_valid(n + 1, false); // prefix_valid[k] is true if a[0...k-1] is a permutation of length k
    std::vector<bool> seen_prefix(n + 1, false);
    int current_max_prefix = 0;
    bool distinct_prefix = true;
    for (int i = 0; i < n; ++i) {
        if (a[i] > n || a[i] <= 0 || seen_prefix[a[i]]) { // a[i] > n is technically not possible due to problem constraints a_i <= n-1, but good for robustness
            distinct_prefix = false;
        }
        seen_prefix[a[i]] = true;
        current_max_prefix = std::max(current_max_prefix, a[i]);
        if (distinct_prefix && current_max_prefix == i + 1) {
            prefix_valid[i + 1] = true;
        }
    }

    std::vector<int> suffix_max(n);
    std::vector<bool> suffix_valid(n + 1, false); // suffix_valid[k] is true if a[n-k...n-1] is a permutation of length k
    std::vector<bool> seen_suffix(n + 1, false);
    int current_max_suffix = 0;
    bool distinct_suffix = true;
    for (int i = n - 1; i >= 0; --i) {
        int len = n - i;
        if (a[i] > n || a[i] <= 0 || seen_suffix[a[i]]) {
            distinct_suffix = false;
        }
        seen_suffix[a[i]] = true;
        current_max_suffix = std::max(current_max_suffix, a[i]);
        if (distinct_suffix && current_max_suffix == len) {
            suffix_valid[len] = true;
        }
    }

    std::vector<std::pair<int, int>> results;
    for (int l1 = 1; l1 < n; ++l1) { // l1 can range from 1 to n-1
        int l2 = n - l1;
        if (l2 <= 0) continue; // Should not happen with l1 < n

        if (prefix_valid[l1] && suffix_valid[l2]) {
            results.push_back({l1, l2});
        }
    }

    std::cout << results.size() << "\n";
    for (const auto& p : results) {
        std::cout << p.first << " " << p.second << "\n";
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

