#include <iostream>

long long solve() {
    long long n;
    std::cin >> n;

    long long chanek_coins = 0;
    long long opponent_coins = 0;
    bool chanek_turn = true;

    while (n > 0) {
        if (chanek_turn) {
            if (n % 2 != 0) { // N is odd
                chanek_coins += 1;
                n -= 1;
            } else { // N is even
                if (n == 2) { // Special case for N=2, always take 1
                    chanek_coins += 1;
                    n -= 1;
                } else {
                    // Check if taking N/2 is better than taking 1
                    // If N/2 is odd, opponent will take 1.
                    // If N/2 is even, opponent will take N/4.
                    // The decision depends on the parity of N/2.
                    // If N/2 is odd, taking N/2 leaves an odd number for opponent.
                    // Opponent will take 1, leaving N/2 - 1.
                    // If N/2 is even, taking N/2 leaves an even number for opponent.
                    // Opponent will take N/4, leaving N/2 - N/4 = N/4.
                    //
                    // The optimal strategy for Chanek when N is even:
                    // If N is divisible by 4 (N = 4k), then N/2 is even (2k).
                    //   Chanek can take N/2. Remaining N/2. Opponent takes N/4.
                    //   Chanek gets N/2.
                    //   If Chanek takes 1. Remaining N-1 (odd). Opponent takes 1.
                    //   Chanek gets 1.
                    //   Taking N/2 is generally better.
                    // If N is even but not divisible by 4 (N = 4k+2), then N/2 is odd (2k+1).
                    //   Chanek can take N/2. Remaining N/2 (odd). Opponent takes 1.
                    //   Chanek gets N/2.
                    //   If Chanek takes 1. Remaining N-1 (odd). Opponent takes 1.
                    //   Chanek gets 1.
                    //   Taking N/2 is generally better.
                    //
                    // The only exception is when taking N/2 leads to a state where the opponent
                    // gets a disproportionately large share later.
                    // The greedy strategy for Chanek is to take N/2 if it's available and N > 2.
                    // This is because N/2 is always greater than 1.
                    // The only time taking 1 is better is if taking N/2 leaves the opponent in a very strong position.
                    //
                    // Consider N = 4.
                    // Chanek takes N/2 = 2. N=2. Chanek: 2. Opponent's turn.
                    //   Opponent takes 1. N=1. Opponent: 1. Chanek's turn.
                    //     Chanek takes 1. N=0. Chanek: 1.
                    // Total: Chanek 2+1=3, Opponent 1.
                    //
                    // Chanek takes 1. N=3. Chanek: 1. Opponent's turn.
                    //   Opponent takes 1. N=2. Opponent: 1. Chanek's turn.
                    //     Chanek takes 1. N=1. Chanek: 1. Opponent's turn.
                    //       Opponent takes 1. N=0. Opponent: 1.
                    // Total: Chanek 1+1=2, Opponent 1+1=2.
                    //
                    // For N=4, Chanek taking N/2 (2) is better (3 vs 2).
                    //
                    // The general optimal strategy for Chanek when N is even and N > 2:
                    // If N is divisible by 4 (N % 4 == 0):
                    //   Chanek takes N/2. This is always optimal as it gives more coins immediately
                    //   and leaves an even number (N/2) for the opponent, who will also try to take N/4.
                    //   This keeps the game balanced in terms of relative coin taking.
                    // If N is even but not divisible by 4 (N % 4 == 2):
                    //   N = 4k + 2. N/2 = 2k + 1 (odd).
                    //   If Chanek takes N/2, N becomes 2k+1. Opponent takes 1.
                    //   If Chanek takes 1, N becomes 4k+1. Opponent takes 1.
                    //   In this case, taking N/2 is better because N/2 > 1.
                    //
                    // So, for N > 2 and N is even, Chanek always takes N/2.
                    chanek_coins += n / 2;
                    n /= 2;
                }
            }
        } else { // Opponent's turn
            if (n % 2 != 0) { // N is odd
                opponent_coins += 1;
                n -= 1;
            } else { // N is even
                if (n == 2) { // Special case for N=2, always take 1
                    opponent_coins += 1;
                    n -= 1;
                } else {
                    // Opponent also plays optimally, so they follow the same logic as Chanek.
                    // They will take N/2 if N is even and N > 2.
                    opponent_coins += n / 2;
                    n /= 2;
                }
            }
        }
        chanek_turn = !chanek_turn;
    }
    return chanek_coins;
}

