int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;

    long long total_steps = 0;
    long long count_a = 0;
    long long MOD = 1e9 + 7;

    // Iterate the string from right to left
    for (int i = s.length() - 1; i >= 0; --i) {
        if (s[i] == 'b') {
            // If we encounter a 'b', it means any 'a' to its left
            // will eventually interact with this 'b'.
            // Each 'a' to its left will contribute 'count_a' steps
            // when it passes this 'b'.
            // The 'b' itself will be duplicated, effectively doubling
            // the number of 'a's that need to pass it in the future.
            // So, the number of 'a's that need to pass this 'b'
            // (or its duplicates) doubles.
            total_steps = (total_steps + count_a) % MOD;
            count_a = (count_a * 2) % MOD;
        } else { // s[i] == 'a'
            // If we encounter an 'a', it means this 'a' will eventually
            // need to move past all 'b's to its right.
            // It contributes 1 to the count of 'a's that are currently
            // to the left of the 'b's we've processed so far.
            count_a = (count_a + 1) % MOD;
        }
    }

    std::cout << total_steps << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    long long current_sum = 0;
    long long current_xor_sum = 0;
    for (int i = 0; i < n; ++i) {
        long long a;
        std::cin >> a;
        current_sum += a;
        current_xor_sum ^= a;
    }

    if (current_sum == 2 * current_xor_sum) {
        std::cout << 0 << std::endl << std::endl;
        return;
    }

    // We need to append elements x, y, z such that (current_sum + x + y + z) = 2 * (current_xor_sum ^ x ^ y ^ z)
    // Let's try to append at most 3 elements.
    // It's guaranteed that a solution always exists.
    // A common strategy for these problems is to try to make the XOR sum equal to some value,
    // and then adjust the sum.

    // Let's try to append two elements.
    // We want (current_sum + b1 + b2) = 2 * (current_xor_sum ^ b1 ^ b2)
    // A simple strategy is to make the final XOR sum equal to current_xor_sum.
    // This can be achieved by appending current_xor_sum and 0.
    // Or, more generally, by appending current_xor_sum and current_xor_sum.
    // If we append current_xor_sum and 0:
    // New XOR sum = current_xor_sum ^ current_xor_sum ^ 0 = 0
    // New Sum = current_sum + current_xor_sum + 0
    // Condition: current_sum + current_xor_sum = 2 * 0 = 0
    // This only works if current_sum + current_xor_sum = 0, which means current_sum=0 and current_xor_sum=0.
    // This is not general enough.

    // Let's try to append two elements, say X and Y.
    // We want (current_sum + X + Y) = 2 * (current_xor_sum ^ X ^ Y).
    // A common trick is to make the final XOR sum equal to the current_xor_sum.
    // This can be done by appending current_xor_sum and 0.
    // New XOR sum = current_xor_sum ^ current_xor_sum ^ 0 = 0.
    // New Sum = current_sum + current_xor_sum + 0.
    // Condition: current_sum + current_xor_sum = 2 * 0 = 0.
    // This is not generally true.

    // What if we append two elements such that their XOR sum is 0? e.g., X and X.
    // New XOR sum = current_xor_sum ^ X ^ X = current_xor_sum.
    // New Sum = current_sum + X + X = current_sum + 2X.
    // Condition: current_sum + 2X = 2 * current_xor_sum.
    // 2X = 2 * current_xor_sum - current_sum.
    // X = current_xor_sum - current_sum / 2.
    // This requires (2 * current_xor_sum - current_sum) to be non-negative and even.
    // If current_sum is odd, then (2 * current_xor_sum - current_sum) is odd, so X cannot be an integer.
    // If current_sum is even, then (2 * current_xor_sum - current_sum) is even.
    // So, if current_sum is even, we can potentially find X.
    // However, current_sum and current_xor_sum must have the same parity.
    // If current_sum is even, current_xor_sum must be even.
    // Then 2 * current_xor_sum is even.
    // 2 * current_xor_sum - current_sum is even.
    // So X = (2 * current_xor_sum - current_sum) / 2 is an integer.
    // We need X >= 0.
    // If current_sum is odd, current_xor_sum must be odd.
    // Then 2 * current_xor_sum is even.
    // 2 * current_xor_sum - current_sum is odd.
    // So X cannot be an integer.

    // Let's try a different approach.
    // We need S' = 2 * X'.
    // Let's append two numbers: current_xor_sum and current_sum + current_xor_sum.
    // Let b1 = current_xor_sum.
    // Let b2 = current_sum + current_xor_sum.
    // New XOR sum = current_xor_sum ^ b1 ^ b2
    //             = current_xor_sum ^ current_xor_sum ^ (current_sum + current_xor_sum)
    //             = 0 ^ (current_sum + current_xor_sum)
    //             = current_sum + current_xor_sum.
    // New Sum = current_sum + b1 + b2
    //         = current_sum + current_xor_sum + (current_sum + current_xor_sum)
    //         = 2 * current_sum + 2 * current_xor_sum.
    // Condition: New Sum = 2 * New XOR sum
    // (2 * current_sum + 2 * current_xor_sum) = 2 * (current_sum + current_xor_sum)
    // This is always true!
    // The only constraint is that the appended elements must be non-negative.
    // current_xor_sum is always non-negative.
    // current_sum is always non-negative.
    // So current_sum + current_xor_sum is always non-negative.
    // This strategy always works and appends 2 elements.

    // So, we can always append two elements:
    // b1 = current_xor_sum
    // b2 = current_sum + current_xor_sum
    // The problem states we can append AT MOST 3 elements.
    // This solution uses 2 elements.

    long long b1 = current_xor_sum;
    long long b2 = current_sum + current_xor_sum;

    std::cout << 2 << std::endl;
    std::cout << b1 << " " << b2 << std::endl;
}

