#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long l, r, Ql, Qr;
    std::cin >> n >> l >> r >> Ql >> Qr;

    std::vector<long long> w(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> w[i];
    }

    std::vector<long long> prefix_sum(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        prefix_sum[i + 1] = prefix_sum[i] + w[i];
    }

    long long min_energy = -1;

    // Iterate through all possible counts of items taken from the left
    // Let 'i' be the number of items taken from the left (0 <= i <= n)
    // Then 'n-i' items are taken from the right.
    for (int i = 0; i <= n; ++i) {
        long long current_energy = 0;

        // Energy for items taken from the left
        current_energy += prefix_sum[i] * l;

        // Energy for items taken from the right
        // Items taken from the right are w[i]...w[n-1]
        // If 'i' items are taken from left, then 'n-i' items are taken from right.
        // The sum of weights for items taken from right is prefix_sum[n] - prefix_sum[i]
        current_energy += (prefix_sum[n] - prefix_sum[i]) * r;

        // Add extra energy for consecutive same-side picks
        int items_left = i;
        int items_right = n - i;

        if (items_left > items_right) {
            // More items taken from left.
            // The last item taken must have been from the left.
            // The difference is items_left - items_right.
            // If items_left - items_right >= 2, then there are (items_left - items_right - 1) extra Ql penalties.
            // Example: L L L R R. items_left=3, items_right=2. Diff=1. No penalty.
            // Example: L L L L R R. items_left=4, items_right=2. Diff=2. One Ql penalty.
            // Example: L L L L L R R. items_left=5, items_right=2. Diff=3. Two Ql penalties.
            current_energy += (long long)std::max(0, items_left - items_right - 1) * Ql;
        } else if (items_right > items_left) {
            // More items taken from right.
            // The last item taken must have been from the right.
            // The difference is items_right - items_left.
            // If items_right - items_left >= 2, then there are (items_right - items_left - 1) extra Qr penalties.
            current_energy += (long long)std::max(0, items_right - items_left - 1) * Qr;
        }
        // If items_left == items_right, no extra penalty from this rule.

        if (min_energy == -1 || current_energy < min_energy) {
            min_energy = current_energy;
        }
    }

    std::cout << min_energy << std::endl;

    return 0;
}

