// Function to convert a number to its 18-digit parity pattern string
std::string get_parity_pattern(long long n) {
    std::string pattern = "";
    if (n == 0) {
        pattern = "0";
    } else {
        while (n > 0) {
            if ((n % 10) % 2 == 0) { // Even digit
                pattern += '0';
            } else { // Odd digit
                pattern += '1';
            }
            n /= 10;
        }
    }
    // Pad with '0's on the left to make it 18 characters long
    // Since we built it right-to-left, padding means appending '0's
    // and then reversing. Or, more simply, just pad to 18 chars.
    // The problem states "i-th from the right digit", so we need to ensure
    // the pattern is always 18 chars long, effectively padding with 0s on the left.
    // Example: 241 -> 100. If pattern is 010, 241 matches.
    // This means 100 (from right) should match 010 (from right).
    // If we store 100, and query 010, we need to compare them.
    // The problem implies padding to the length of the longer one.
    // Let's normalize all patterns to 18 digits.
    // For number 241, its parity string is "100" (right to left).
    // Padded to 18: "000000000000000100"
    while (pattern.length() < 18) {
        pattern += '0';
    }
    return pattern;
}

int main() {
    // Optimize C++ standard streams for faster input/output.
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int t;
    std::cin >> t;

    // Use a map to store counts of each 18-digit parity pattern string.
    std::map<std::string, int> counts;

    for (int i = 0; i < t; ++i) {
        char type;
        std::cin >> type;

        if (type == '+') {
            long long a;
            std::cin >> a;
            counts[get_parity_pattern(a)]++;
        } else if (type == '-') {
            long long a;
            std::cin >> a;
            counts[get_parity_pattern(a)]--;
        } else if (type == '?') {
            std::string s;
            std::cin >> s;
            // Pad the query pattern with '0's on the left to make it 18 characters long.
            // The problem states "if the pattern is shorter than this integer, it's supplemented with 0-s from the left."
            // And "if the integer is shorter than the pattern its decimal notation is supplemented with the 0-s from the left."
            // This means we effectively compare 18-digit representations.
            // The pattern `s` is given left-to-right.
            // Example: s = "010". This means 0 for 1st digit (right), 1 for 2nd, 0 for 3rd.
            // To match our stored patterns (which are right-to-left), we need to reverse `s` first.
            std::reverse(s.begin(), s.end());
            while (s.length() < 18) {
                s += '0'; // Pad with '0's on the right (which corresponds to left in original pattern)
            }
            std::cout << counts[s] << "\n";
        }
    }

    return 0;
}

