// Function to find prime factors of a number
std::vector<long long> get_prime_factors(long long n) {
    std::vector<long long> factors;
    for (long long i = 2; i * i <= n; ++i) {
        if (n % i == 0) {
            factors.push_back(i);
            while (n % i == 0) {
                n /= i;
            }
        }
    }
    if (n > 1) {
        factors.push_back(n);
    }
    return factors;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long p, q;
        std::cin >> p >> q;

        if (p % q != 0) {
            std::cout << p << "\n";
            continue;
        }

        // p is divisible by q. We need to find the largest x < p such that x | p and x % q != 0.
        // This means we need to remove some prime factors from p that are also in q.
        // To maximize x, we should remove the minimum necessary factors.
        // Specifically, for each prime factor f of q, we need to ensure that the power of f in x
        // is less than the power of f in q.
        // To maximize x, we should try to reduce the power of only one prime factor of q at a time.

        std::vector<long long> q_prime_factors = get_prime_factors(q);
        long long max_x = 0;

        for (long long factor : q_prime_factors) {
            long long current_p = p;
            // Divide current_p by 'factor' until it's no longer divisible by q
            // or until current_p is no longer divisible by factor.
            // We want to find the largest divisor of p that is not divisible by q.
            // If p is divisible by q, we must reduce p by some factor.
            // The strategy is to take p, and for each prime factor 'f' of q,
            // divide p by 'f' repeatedly until p is no longer divisible by q.
            // The largest such resulting value will be our answer.

            long long temp_p = p;
            while (temp_p % q == 0) {
                temp_p /= factor;
            }
            max_x = std::max(max_x, temp_p);
        }
        std::cout << max_x << "\n";
    }
    return 0;
}

