int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        int n;
        std::cin >> n;
        long long min_x = -2000000000LL; // Effectively negative infinity
        long long max_x = 2000000000LL;  // Effectively positive infinity
        long long min_y = -2000000000LL; // Effectively negative infinity
        long long max_y = 2000000000LL;  // Effectively positive infinity

        for (int i = 0; i < n; ++i) {
            long long x, y;
            int f1, f2, f3, f4;
            std::cin >> x >> y >> f1 >> f2 >> f3 >> f4;

            // If f1=0, robot cannot move left. So target X must be >= current x.
            // This means X >= x.
            if (f1 == 0) {
                min_x = std::max(min_x, x);
            }
            // If f3=0, robot cannot move right. So target X must be <= current x.
            // This means X <= x.
            if (f3 == 0) {
                max_x = std::min(max_x, x);
            }
            // If f4=0, robot cannot move down. So target Y must be >= current y.
            // This means Y >= y.
            if (f4 == 0) {
                min_y = std::max(min_y, y);
            }
            // If f2=0, robot cannot move up. So target Y must be <= current y.
            // This means Y <= y.
            if (f2 == 0) {
                max_y = std::min(max_y, y);
            }
        }

        if (min_x <= max_x && min_y <= max_y) {
            // The problem guarantees that if a solution exists, one exists with coordinates
            // not exceeding 10^5 by absolute value.
            // So we can cap min_x, max_x, min_y, max_y to stay within this range
            // if they are still at their initial "infinity" values.
            // However, the problem statement implies that any valid (X,Y) is fine.
            // The simplest valid point is (min_x, min_y).
            // We just need to ensure it's within the guaranteed range if it's one of the "infinity" values.
            // The actual coordinates x_i, y_i are within [-10^5, 10^5].
            // So min_x and max_x will be bounded by these values if f1 or f3 are 0.
            // If all f1=1 and f3=1 for all robots, then min_x remains -2e9 and max_x remains 2e9.
            // In this case, we can pick any X. The problem guarantees that if a solution exists,
            // one exists with coordinates not exceeding 10^5 by absolute value.
            // So we can just pick -100000 for X if min_x is still -2e9.
            // And similarly for Y.

            // Let's pick a valid X and Y.
            // The smallest valid X is min_x.
            // The smallest valid Y is min_y.
            // If min_x is still -2e9, it means no robot restricted X to be >= some x_i.
            // In this case, we can pick any X. The problem guarantees a solution within [-10^5, 10^5].
            // So we can pick -100000.
            long long final_X = min_x;
            if (final_X < -100000) final_X = -100000;
            if (final_X > 100000) final_X = 100000; // Should not happen if min_x <= max_x and max_x is within bounds.

            long long final_Y = min_y;
            if (final_Y < -100000) final_Y = -100000;
            if (final_Y > 100000) final_Y = 100000; // Should not happen.

            std::cout << 1 << " " << final_X << " " << final_Y << "\n";
        } else {
            std::cout << 0 << "\n";
        }
    }
    return 0;
}

