int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n, d;
        std::cin >> n >> d;
        std::vector<int> a(n);
        for (int i = 0; i < n; ++i) {
            std::cin >> a[i];
        }

        long long current_a1 = a[0];
        long long remaining_days = d;

        for (int i = 1; i < n; ++i) {
            // Cost to move one haybale from pile i+1 to pile 1 is i days.
            // (Pile indices are 0-based in vector, 1-based in problem)
            // So, pile a[i] is the (i+1)-th pile.
            // Cost to move from a[i] to a[0] is i days.
            long long cost_per_haybale = i; 

            if (remaining_days >= cost_per_haybale) {
                // Calculate how many haybales can be moved from this pile
                // given the remaining days.
                long long haybales_to_move_possible_by_days = remaining_days / cost_per_haybale;

                // We can't move more haybales than are actually in the pile.
                long long haybales_to_move = std::min((long long)a[i], haybales_to_move_possible_by_days);

                current_a1 += haybales_to_move;
                remaining_days -= haybales_to_move * cost_per_haybale;
            } else {
                // Not enough days to move even one haybale from this pile.
                // Since piles are processed in increasing order of distance,
                // we won't be able to move haybales from any further piles either.
                break; 
            }
        }
        std::cout << current_a1 << std::endl;
    }
    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <numeric>
#include <set>
#include <algorithm>
#include <map>

void solve() {
    std::string s;
    std::cin >> s;

    std::vector<std::set<char>> adj(26);
    std::vector<int> degree(26, 0);
    std::vector<bool> in_s(26, false);

    for (char c : s) {
        in_s[c - 'a'] = true;
    }

    bool possible = true;
    for (size_t i = 0; i < s.length() - 1; ++i) {
        char u_char = s[i];
        char v_char = s[i+1];
        int u = u_char - 'a';
        int v = v_char - 'a';

        if (adj[u].find(v_char) == adj[u].end()) { // If this is a new adjacency
            adj[u].insert(v_char);
            adj[v].insert(u_char);
            degree[u]++;
            degree[v]++;
        }

        if (degree[u] > 2 || degree[v] > 2) {
            possible = false;
            break;
        }
    }

    if (!possible) {
        std::cout << "NO\n";
        return;
    }

    std::string layout = "";
    std::vector<bool> visited(26, false);

    // Find starting points for paths (degree 1 nodes or isolated nodes in s)
    for (int i = 0; i < 26; ++i) {
        if (in_s[i] && degree[i] <= 1 && !visited[i]) {
            char current_char = (char)('a' + i);

            // Traverse the path
            while (true) {
                layout += current_char;
                visited[current_char - 'a'] = true;

                char next_char = 0;
                for (char neighbor : adj[current_char - 'a']) {
                    if (!visited[neighbor - 'a']) {
                        next_char = neighbor;
                        break;
                    }
                }

                if (next_char == 0) { // End of path
                    break;
                }
                current_char = next_char;
            }
        }
    }

    // Check if all characters from s are included in the layout
    // This also implicitly checks for cycles or paths with degree > 2 that weren't caught earlier
    // because if there was a cycle, a node would have degree 2 and would be visited,
    // but it wouldn't be a starting point (degree 1 or 0).
    // If all nodes in s are part of a valid path, they will be visited.
    for (int i = 0; i < 26; ++i) {
        if (in_s[i] && !visited[i]) {
            // This means there's a character from s that wasn't part of a path starting from a degree 0/1 node.
            // This can happen if there's a cycle or a path where all nodes have degree 2.
            // For example, if s="abcba", a-b-c-b-a. a-b, b-c. degree(a)=1, degree(c)=1, degree(b)=2.
            // This should be handled by the degree check.
            // The only way a node in_s is not visited is if it's part of a cycle or a path where all nodes have degree 2.
            // But if all nodes have degree 2, it means it's a cycle.
            // A cycle is not allowed in a single row layout.
            // The degree check `degree[u] > 2` already handles most invalid cases.
            // If a character has degree 2 and is part of a path, it will be visited.
            // If it's part of a cycle, it won't be visited by the current logic.
            // So, if any in_s character is not visited, it implies an invalid structure (a cycle).
            possible = false;
            break;
        }
    }

    if (!possible) {
        std::cout << "NO\n";
        return;
    }

    // Add remaining characters not in s
    for (int i = 0; i < 26; ++i) {
        if (!visited[i]) {
            layout += (char)('a' + i);
        }
    }

    std::cout << "YES\n";
    std::cout << layout << "\n";
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

