    long long a, b;
    std::cin >> a >> b;
    long long MOD = 1000000007;

    if (b == 1) {
        std::cout << 0 << std::endl;
        return 0;
    }

    // Sum of k from 1 to a: S_k = a * (a + 1) / 2
    long long sum_k = (a % MOD * ((a + 1) % MOD)) % MOD;
    sum_k = (sum_k * ((MOD + 1) / 2)) % MOD; // (MOD + 1) / 2 is modular inverse of 2

    // Sum of r from 1 to b-1: S_r = (b-1) * b / 2
    long long sum_r = ((b - 1) % MOD * (b % MOD)) % MOD;
    sum_r = (sum_r * ((MOD + 1) / 2)) % MOD; // (MOD + 1) / 2 is modular inverse of 2

    // Total sum = (sum_k * b * sum_r) + (a * sum_r)
    // sum_k * b * sum_r
    long long term1 = (sum_k * (b % MOD)) % MOD;
    term1 = (term1 * sum_r) % MOD;

    // a * sum_r
    long long term2 = (a % MOD * sum_r) % MOD;

    long long total_sum = (term1 + term2) % MOD;

    std::cout << total_sum << std::endl;

    return 0;
}

#include <iostream>
#include <algorithm> // For std::min, std::max

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        long long n, m, k;
        std::cin >> n >> m >> k;

        // Ensure n <= m by swapping if necessary.
        // This simplifies logic as we can always assume n is the smaller absolute coordinate.
        if (n < 0) n = -n;
        if (m < 0) m = -m;
        if (n > m) std::swap(n, m);

        // Case 1: k is less than the minimum required moves (m)
        if (k < m) {
            std::cout << -1 << "\n";
            continue;
        }

