#include <iostream>
#include <vector>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<long long> a(n + 1);
    for (int i = 2; i <= n; ++i) {
        std::cin >> a[i];
    }

    std::vector<long long> dp_y(n + 1, 0);
    std::vector<int> dp_x(n + 1, 0);
    std::vector<bool> visited(n + 1, false);
    std::vector<bool> in_stack(n + 1, false);

    for (int i = 1; i <= n; ++i) {
        if (visited[i]) {
            continue;
        }

        std::vector<int> path;
        int current_x = i;
        long long current_y_offset = 0;
        bool cycle_detected = false;

        while (current_x > 0 && current_x <= n && !visited[current_x] && !in_stack[current_x]) {
            path.push_back(current_x);
            in_stack[current_x] = true;

            long long val_ax = a[current_x];
            current_y_offset += val_ax; // Step 2: y += a_x
            current_x += val_ax;        // Step 2: x += a_x

            if (current_x <= 0 || current_x > n) {
                break; // Terminated
            }

            val_ax = a[current_x];
            current_y_offset += val_ax; // Step 3: y += a_x
            current_x -= val_ax;        // Step 3: x -= a_x
        }

        if (current_x > 0 && current_x <= n && in_stack[current_x]) {
            cycle_detected = true;
        }

        for (int j = path.size() - 1; j >= 0; --j) {
            int node = path[j];
            visited[node] = true;
            in_stack[node] = false;

            if (cycle_detected) {
                dp_y[node] = -1;
                dp_x[node] = -1;
            } else {
                long long val_ax_node = a[node];
                long long next_x_after_step2 = node + val_ax_node;
                long long next_x_after_step3;

                if (next_x_after_step2 <= 0 || next_x_after_step2 > n) {
                    // Terminates after step 2
                    dp_y[node] = val_ax_node;
                    dp_x[node] = next_x_after_step2;
                } else {
                    long long val_ax_next_step2 = a[next_x_after_step2];
                    next_x_after_step3 = next_x_after_step2 - val_ax_next_step2;

                    if (next_x_after_step3 <= 0 || next_x_after_step3 > n) {
                        // Terminates after step 3
                        dp_y[node] = val_ax_node + val_ax_next_step2;
                        dp_x[node] = next_x_after_step3;
                    } else {
                        // Continues to next state
                        if (dp_y[next_x_after_step3] == -1) {
                            dp_y[node] = -1;
                            dp_x[node] = -1;
                        } else {
                            dp_y[node] = val_ax_node + val_ax_next_step2 + dp_y[next_x_after_step3];
                            dp_x[node] = dp_x[next_x_after_step3];
                        }
                    }
                }
            }
        }
    }

    for (int i = 1; i < n; ++i) {
        a[1] = i; // Set a_1 for this run
        long long val_a1 = a[1];
        long long next_x_after_step2 = 1 + val_a1;
        long long result_y;

        if (next_x_after_step2 <= 0 || next_x_after_step2 > n) {
            result_y = val_a1;
        } else {
            long long val_ax_next_step2 = a[next_x_after_step2];
            long long next_x_after_step3 = next_x_after_step2 - val_ax_next_step2;

            if (next_x_after_step3 <= 0 || next_x_after_step3 > n) {
                result_y = val_a1 + val_ax_next_step2;
            } else {
                if (dp_y[next_x_after_step3] == -1) {
                    result_y = -1;
                } else {
                    result_y = val_a1 + val_ax_next_step2 + dp_y[next_x_after_step3];
                }
            }
        }
        std::cout << result_y << "\n";
    }

    return 0;
}

