// Function to calculate parity of a 01-string
int calculate_parity(const std::string& s) {
    int ones_count = 0;
    for (char c : s) {
        if (c == '1') {
            ones_count++;
        }
    }
    return ones_count % 2;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::string a, b;
    std::cin >> a >> b;

    // Calculate initial parity of string a
    int parity_a = calculate_parity(a);

    // If parity_a is 0, it means an even number of '1's.
    // We can append '0's indefinitely.
    // If parity_a is 1, it means an odd number of '1's.
    // We can append '1', then the new string will have an even number of '1's,
    // so we can append '0's indefinitely after that.
    // This means we can effectively generate any suffix of '0's or '1' followed by '0's.

    // The maximum length 'a' can effectively reach for comparison is |b|.
    // If |a| < |b|, we need to append characters.
    // The maximum number of '1's we can have in 'a' is its current count + 1 (if we append a '1').
    // After that, we can only append '0's, which doesn't change the '1's count.

    // Count '1's in string a
    int ones_in_a = 0;
    for (char c : a) {
        if (c == '1') {
            ones_in_a++;
        }
    }

    // Count '1's in string b
    int ones_in_b = 0;
    for (char c : b) {
        if (c == '1') {
            ones_in_b++;
        }
    }

    // Condition 1: The number of '1's in 'b' must not exceed the maximum possible '1's we can get in 'a'.
    // The maximum '1's we can get in 'a' is `ones_in_a` if `parity_a` is 0 (we append '0's).
    // Or `ones_in_a + 1` if `parity_a` is 1 (we append '1', then '0's).
    int max_ones_a_can_have = ones_in_a + (parity_a == 1 ? 1 : 0);

    if (ones_in_b > max_ones_a_can_have) {
        std::cout << "NO\n";
        return 0;
    }

    // Condition 2: The length of 'a' must be at least the length of 'b'
    // after considering the maximum possible '1's.
    // If |a| < |b|, we must append characters.
    // The number of characters we need to append is |b| - |a|.
    // We can always append characters until 'a' is long enough.
    // The only constraint is the number of '1's.

    // If we can reach the required number of '1's in 'b' and 'a' is long enough,
    // then it's always possible.
    // The "remove first character" operation means we can effectively take any suffix of 'a'.
    // So, if we can make 'a' into a string `a_prime` such that `b` is a suffix of `a_prime`,
    // and `a_prime` has the correct number of '1's, then it's possible.

    // The logic simplifies:
    // We can always extend 'a' to be at least as long as 'b' by appending parities.
    // The only thing that matters is if the number of '1's in 'b' can be achieved.
    // If `ones_in_b` is less than or equal to `ones_in_a`, it's possible.
    // If `ones_in_b` is `ones_in_a + 1`, it's possible only if `parity_a` was 1.
    // Otherwise, it's not possible.

    // This is equivalent to:
    // If `ones_in_b <= ones_in_a`, then YES. (We can just remove leading chars from 'a' or append '0's)
    // If `ones_in_b == ones_in_a + 1` AND `parity_a == 1`, then YES. (We append '1', then remove leading chars or append '0's)
    // Otherwise, NO.

    if (ones_in_b <= ones_in_a) {
        std::cout << "YES\n";
    } else if (ones_in_b == ones_in_a + 1 && parity_a == 1) {
        std::cout << "YES\n";
    } else {
        std::cout << "NO\n";
    }

    return 0;
}

