struct Element {
    long long value;
    int original_index;
};

bool compareElements(const Element& a, const Element& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long h;
    std::cin >> n >> h;

    std::vector<Element> elements(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> elements[i].value;
        elements[i].original_index = i;
    }

    std::sort(elements.begin(), elements.end(), compareElements);

    // Case 1: All elements in one subsequence (e.g., subsequence 1).
    // All f(a_i, a_j) = a_i + a_j.
    // min_f = elements[0].value + elements[1].value
    // max_f = elements[n-2].value + elements[n-1].value
    // goodness = (elements[n-2].value + elements[n-1].value) - (elements[0].value + elements[1].value)
    long long goodness1 = (elements[n-2].value + elements[n-1].value) - (elements[0].value + elements[1].value);
    std::vector<int> partition1(n, 1);

    // Case 2: All elements in different subsequences (e.g., subsequence 1 and 2, but no two elements in same).
    // This is only possible if n=1, but problem states n >= 2.
    // If we mean one subsequence is empty, then it's Case 1.
    // If we mean every pair is in different subsequences, this is impossible for n > 2.
    // The problem implies a partition into *two* subsequences.
    // If one subsequence is empty, it's Case 1.
    // If both are non-empty, then there must be at least one pair in the same subsequence.
    // So, this "all different" case is not a valid partition for n >= 2.
    // However, the problem statement "one of the result subsequences can be empty" implies Case 1 is valid.

    // Case 3: Consider a partition where elements[0] is in one subsequence (e.g., 1)
    // and elements[1] is in the other (e.g., 2).
    // And elements[n-1] is in subsequence 1.
    // And elements[n-2] is in subsequence 2.
    // This is a general case where we try to minimize the range.

    // Let's consider the partition where elements[0] is in subseq 1, and all others are in subseq 2.
    // This is a specific partition.
    // min_f:
    //   - elements[1].value + elements[2].value (same subseq 2)
    //   - elements[0].value + elements[1].value + h (different subseqs 1 and 2)
    // min_f = std::min(elements[1].value + elements[2].value, elements[0].value + elements[1].value + h)
    // max_f:
    //   - elements[n-2].value + elements[n-1].value (same subseq 2)
    //   - elements[0].value + elements[n-1].value + h (different subseqs 1 and 2)
    // max_f = std::max(elements[n-2].value + elements[n-1].value, elements[0].value + elements[n-1].value + h)

    // The key insight is that the minimum possible sum of two elements is a_0 + a_1.
    // The maximum possible sum of two elements is a_{n-2} + a_{n-1}.
    // Let S_min = a_0 + a_1 and S_max = a_{n-2} + a_{n-1}.
    // The values of f are either in [S_min, S_max] or [S_min + h, S_max + h].

    // Option A: All elements in one subsequence (e.g., all 1s).
    // min_f = a_0 + a_1
    // max_f = a_{n-2} + a_{n-1}
    // goodness = (a_{n-2} + a_{n-1}) - (a_0 + a_1)
    // This is `goodness1` calculated above.

    // Option B: Partition where a_0 is in subseq 1, and all other elements a_1, ..., a_{n-1} are in subseq 2.
    // Pairs in subseq 2: (a_i, a_j) for i,j >= 1.
    //   min_val_same = a_1 + a_2
    //   max_val_same = a_{n-2} + a_{n-1}
    // Pairs in different subseqs: (a_0, a_j) for j >= 1.
    //   min_val_diff = a_0 + a_1 + h
    //   max_val_diff = a_0 + a_{n-1} + h
    // Overall min_f = std::min(a_1 + a_2, a_0 + a_1 + h)
    // Overall max_f = std::max(a_{n-2} + a_{n-1}, a_0 + a_{n-1} + h)
    // Goodness = max_f - min_f

    // Let's analyze the values for Option B.
    // The smallest possible sum is a_0 + a_1.
    // The largest possible sum is a_{n-2} + a_{n-1}.
    // The values of f are:
    //   - a_i + a_j (if i,j >= 1)
    //   - a_0 + a_j + h (if j >= 1)

    // The minimum value of f will be min(a_1 + a_2, a_0 + a_1 + h).
    // The maximum value of f will be max(a_{n-2} + a_{n-1}, a_0 + a_{n-1} + h).

    // Let's consider the specific partition:
    // elements[0] is in subseq 1.
    // elements[1], ..., elements[n-1] are in subseq 2.
    // This is a valid partition.
    // The minimum f value will be `min(elements[1].value + elements[2].value, elements[0].value + elements[1].value + h)`
    // (Note: if n=2, elements[1].value + elements[2].value is not possible, only elements[0].value + elements[1].value + h)
    // If n=2: min_f = elements[0].value + elements[1].value + h. max_f = elements[0].value + elements[1].value + h. goodness = 0.
    // This is covered by the general formula.
    // If n=2, elements[1].value + elements[2].value would be out of bounds.
    // For n=2, the only pair is (a_0, a_1).
    // If they are in the same subseq: f = a_0 + a_1. goodness = 0.
    // If they are in different subseqs: f = a_0 + a_1 + h. goodness = 0.
    // So for n=2, goodness is always 0.
    // Our formulas:
    // goodness1 = (a_0+a_1) - (a_0+a_1) = 0.
    // goodness2:
    //   min_f = a_0 + a_1 + h
    //   max_f = a_0 + a_1 + h
    //   goodness = 0.
    // So for n=2, both strategies yield 0.

    long long goodness2;
    std::vector<int> partition2(n);
    partition2[elements[0].original_index] = 1;
    for (int i = 1; i < n; ++i) {
        partition2[elements[i].original_index] = 2;
    }

    if (n == 2) {
        goodness2 = 0;
    } else {
        long long min_f_val = std::min(elements[1].value + elements[2].value, elements[0].value + elements[1].value + h);
        long long max_f_val = std::max(elements[n-2].value + elements[n-1].value, elements[0].value + elements[n-1].value + h);
        goodness2 = max_f_val - min_f_val;
    }

    // Compare goodness1 and goodness2
    if (goodness1 <= goodness2) {
        std::cout << goodness1 << "\n";
        for (int i = 0; i < n; ++i) {
            std::cout << partition1[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    } else {
        std::cout << goodness2 << "\n";
        for (int i = 0; i < n; ++i) {
            std::cout << partition2[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    }

    return 0;
}

