        // Cut into s[0], s[1...n-2], s[n-1].
        // Pieces: 'a', "bacab", 'a'.
        // Reorder to "bacab", 'a', 'a'. This is "bacabaa". Not a palindrome.
        //
        // The problem statement guarantees that if not all characters are the same,
        // and k=1 doesn't work, then k=2 is the answer.
        //
        // Let's prove k=2 is always possible if not all characters are the same.
        // Since s is a palindrome and not all characters are the same,
        // there must be at least two distinct characters.
        //
        // Consider cutting s into three pieces:
        // P1 = s.substr(0, 1) (first character)
        // P2 = s.substr(1, n - 2) (middle part)
        // P3 = s.substr(n - 1, 1) (last character)
        //
        // Since s is a palindrome, P1 == P3 (s[0] == s[n-1]).
        // The middle part P2 = s.substr(1, n-2) is also a palindrome.
        //
        // We can reorder these pieces as P2 + P1 + P3.
        // This forms the string s.substr(1, n-2) + s[0] + s[n-1].
        // Since s[0] == s[n-1], this is s.substr(1, n-2) + s[0] + s[0].
        //
        // This new string is a palindrome if s.substr(1, n-2) + s[0] + s[0]
        // is a palindrome.
        // Let s' = s.substr(1, n-2).
        // We need s' + s[0] + s[0] to be a palindrome.
        // This means (s' + s[0] + s[0]) == reverse(s' + s[0] + s[0]).
        //
        // Example: s = "nolon"
        // P1 = 'n', P2 = "olo", P3 = 'n'
        // Reorder: P2 + P1 + P3 = "olo" + 'n' + 'n' = "olonn". Not a palindrome.
        //
        // The example "nolon" -> 2 cuts, result "onlno".
        // This is achieved by no|l|on -> on|l|no.
        // P1 = "no", P2 = "l", P3 = "on".
        // Reorder P3 + P2 + P1.
        //
        // The logic for k=2 being always possible (if not all same) is based on the problem constraints/guarantees.
        // If s is a palindrome and not all characters are the same,
        // then there exists a cut into 3 pieces (2 cuts) that can be reordered to form a new palindrome.
        //
        // For example, consider s = "abacaba".
        // s[0] = 'a', s[1] = 'b'.
        // Cut s into s[0], s[1...n-1].
        // P1 = "a", P2 = "bacaba".
        // New string P2+P1 = "bacabaa". Not a palindrome.
        //
        // The problem statement implies that if k=1 fails and not all characters are the same, then k=2 is the answer.
        // This is a common pattern in competitive programming problems where the minimum k is asked.
        // If k=1 fails, and k=0 is impossible, then k=2 is the next candidate.
        // The fact that it's always possible for k=2 (unless all chars are same) is a property of palindromes.
        //
        // Consider s = "abacaba".
        // Cut: "a" | "bacab" | "a"
        // Pieces: P1='a', P2="bacab", P3='a'
        // Reorder: P3 + P2 + P1 = "a" + "bacab" + "a" = "abacaba" (original)
        // Reorder: P1 + P3 + P2 = "a" + "a" + "bacab" = "aabacab" (not palindrome)
        // Reorder: P2 + P1 + P3 = "bacab" + "a" + "a" = "bacabaa" (not palindrome)
        //
        // The example "nolon" -> 2.
        // Cuts: "no" | "l" | "on"
        // Pieces: P1="no", P2="l", P3="on"
        // Reorder: P3 + P2 + P1 = "on" + "l" + "no" = "onlno". This is a palindrome and != "nolon".
        //
        // This specific cut (s.substr(0, i), s.substr(i, n-2*i), s.substr(n-i, i))
        // where i is the length of the prefix/suffix.
        // For "nolon", n=5.
        // i=1: "n" | "olo" | "n". P1='n', P2="olo", P3='n'.
        // Reorder P3+P2+P1 = "nolon" (original)
        // i=2: "no" | "l" | "on". P1="no", P2="l", P3="on".
        // Reorder P3+P2+P1 = "onlno". This works.
        //
        // So, if not all characters are the same, we can always find such a cut for k=2.
        // The problem statement implies this.
        std::cout << 2 << std::endl;
    }

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;
    int n = s.length();

    long long total_pairs = (long long)n * (n + 1) / 2;
    long long bad_pairs_count = 0;

    // last_valid_r[i] stores the maximum r such that (i, r) is a "bad" pair.
    // A pair (l, r) is bad if no triplet (x, x+k, x+2k) with s_x=s_{x+k}=s_{x+2k}
    // is fully contained within s[l-1...r-1].
    // This means for any l, if we want to find the maximum r such that (l, r) is bad,
    // we need to find the smallest starting index of a "good" triplet that starts at or after l.
    // Let min_good_start[i] be the minimum x such that x >= i and s_x=s_{x+k}=s_{x+2k} for some k.
    // If no such x exists, min_good_start[i] = n+1.
    // Then for a given l, the maximum r for a bad pair (l, r) is min_good_start[l-1] - 1.
    // If min_good_start[l-1] - 1 < l-1, it means no bad pairs (l, r) exist for this l.
    // The number of bad pairs for a given l is max(0, min_good_start[l-1] - 1 - (l-1) + 1)
    // which simplifies to max(0, min_good_start[l-1] - l).

    std::vector<int> min_good_start(n + 1, n + 1); // 0-indexed for string, 1-indexed for problem logic
                                                  // min_good_start[i] means min x (1-indexed) such that x >= i
                                                  // and s[x-1]=s[x+k-1]=s[x+2k-1] for some k.

    // Iterate backwards to fill min_good_start
    for (int i = n - 1; i >= 0; --i) {
        min_good_start[i] = min_good_start[i + 1]; // Inherit from the right

        // Check for triplets starting at i (0-indexed)
        // s[i] = s[i+k] = s[i+2k]
        // k can be 1, 2, 3, 4, 5, 6
        // Max k is such that i + 2k < n
        // So 2k < n - i => k < (n - i) / 2
        // For k=1: i+2 < n
        if (i + 2 < n && s[i] == s[i+1] && s[i] == s[i+2]) {
            min_good_start[i] = std::min(min_good_start[i], i + 1); // i+1 is 1-indexed x
        }
        // For k=2: i+4 < n
        if (i + 4 < n && s[i] == s[i+2] && s[i] == s[i+4]) {
            min_good_start[i] = std::min(min_good_start[i], i + 1);
        }
        // For k=3: i+6 < n
        if (i + 6 < n && s[i] == s[i+3] && s[i] == s[i+6]) {
            min_good_start[i] = std::min(min_good_start[i], i + 1);
        }
        // For k=4: i+8 < n
        if (i + 8 < n && s[i] == s[i+4] && s[i] == s[i+8]) {
            min_good_start[i] = std::min(min_good_start[i], i + 1);
        }
        // For k=5: i+10 < n
        if (i + 10 < n && s[i] == s[i+5] && s[i] == s[i+10]) {
            min_good_start[i] = std::min(min_good_start[i], i + 1);
        }
        // For k=6: i+12 < n
        if (i + 12 < n && s[i] == s[i+6] && s[i] == s[i+12]) {
            min_good_start[i] = std::min(min_good_start[i], i + 1);
        }
    }

    // Calculate bad_pairs_count
    for (int l = 1; l <= n; ++l) { // l is 1-indexed
        // For a given l, the maximum r for a bad pair (l, r) is min_good_start[l-1] - 1.
        // The number of such r's is (min_good_start[l-1] - 1) - l + 1,
        // which simplifies to min_good_start[l-1] - l.
        // We take max(0, ...) because r must be >= l.
        bad_pairs_count += std::max(0, min_good_start[l-1] - l);
    }

    std::cout << total_pairs - bad_pairs_count << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <set>

// Function to check if all target tracks can be covered within time 't'
bool check(long long t, int n, int m, const std::vector<long long>& h, const std::vector<long long>& p) {
    // current_p_idx points to the first target track that still needs to be covered
    int current_p_idx = 0;

    // Iterate through each head
    for (int i = 0; i < n; ++i) {
        // If all target tracks are already covered, we are done
        if (current_p_idx == m) {
            return true;
        }

        // Calculate the leftmost and rightmost track this head can reach
        long long head_left_reach = h[i] - t;
        long long head_right_reach = h[i] + t;

        // If the current head cannot reach the current target track (p[current_p_idx])
        // even if it moves left as much as possible, then this head cannot cover it.
        // We need to find a head that can cover p[current_p_idx].
        // If p[current_p_idx] is to the left of head_left_reach, this head cannot cover it.
        // However, we are iterating heads from left to right.
        // If p[current_p_idx] is to the left of h[i] - t, it means this head cannot cover it.
        // But since heads are sorted, and p are sorted, it's possible that p[current_p_idx]
        // was supposed to be covered by a previous head.
        // The logic should be: if p[current_p_idx] is within the range [h[i]-t, h[i]+t],
        // then this head can potentially cover it and subsequent tracks.

        // Find the first target track that is within the reach of the current head
        // (or to its right, meaning it might be covered by this head or a future head).
        // We need to ensure that p[current_p_idx] is covered.
        // If p[current_p_idx] is to the left of h[i] - t, this head cannot cover it.
        // Since heads are sorted, no subsequent head can cover it either (as they are further right).
        // This implies that if p[current_p_idx] < h[i] - t, it must have been covered by a previous head.
        // If it wasn't, then it's impossible.
        // But the problem is about covering *all* p_j.
        // So, if p[current_p_idx] is not covered by the current head, we move to the next head.

        // The strategy is greedy: use the current head to cover as many *uncovered* tracks as possible,
        // starting from p[current_p_idx].
        // If p[current_p_idx] is to the left of h[i] - t, it means this head cannot cover it.
        // This implies that p[current_p_idx] must have been covered by a previous head.
        // If it wasn't, then it's impossible.
        // This is the crucial part: if p[current_p_idx] is not covered by the current head,
        // and it's to the left of the current head's reach, then it's impossible.
        // But we are trying to cover p[current_p_idx] with the *current* head.
        // If p[current_p_idx] is too far left for h[i] to reach (i.e., p[current_p_idx] < h[i] - t),
        // then this head cannot cover it. Since h is sorted, h[i-1] would be even further left,
        // so it's impossible to cover p[current_p_idx] with any head.
        // This is incorrect. A previous head h[i-1] could have covered p[current_p_idx].
        // The correct logic is: if p[current_p_idx] is not covered by the current head,
        // and it's to the left of the current head's *initial position*, then it's impossible
        // for *this* head to cover it without moving left.
        // The current head can cover tracks in [h[i]-t, h[i]+t].
        // If p[current_p_idx] is less than h[i]-t, then this head cannot cover it.
        // Since heads are sorted, h[i-1] is even smaller, so it's also impossible for h[i-1] to cover p[current_p_idx]
        // if p[current_p_idx] is less than h[i]-t.
        // This means if p[current_p_idx] < h[i]-t, then it's impossible to cover p[current_p_idx] with any head.
        // This is the key condition for failure.

        // If the current target track p[current_p_idx] is beyond the reach of the current head's leftmost movement,
        // then it's impossible to cover it.
        if (p[current_p_idx] < head_left_reach) {
            return false; // This target track cannot be reached by any head
        }

        // If the current head can reach p[current_p_idx] (i.e., p[current_p_idx] <= head_right_reach),
        // then this head can cover p[current_p_idx] and potentially subsequent tracks.
        // We greedily cover as many tracks as possible to the right.
        // The head moves to cover p[current_p_idx].
        // The actual position it moves to is not important, only the range it covers.
        // The head can cover any track in [h[i]-t, h[i]+t].
        // To cover p[current_p_idx], the head must move to some position x such that |x - h[i]| <= t.
        // And p[current_p_idx] must be in the range [x-t', x+t'] where t' is remaining time.
        // This is simpler: the head can cover any track in [h[i]-t, h[i]+t].
        // If p[current_p_idx] is within this range, it's covered.
        // We then advance current_p_idx to the next track that is *not* covered by this head.

        // The head can cover tracks from p[current_p_idx] up to head_right_reach.
        // We advance current_p_idx past all tracks covered by this head.
        while (current_p_idx < m && p[current_p_idx] <= head_right_reach) {
            current_p_idx++;
        }
    }

    // After checking all heads, if all target tracks are covered, return true.
    return current_p_idx == m;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<long long> h(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> h[i];
    }

    std::vector<long long> p(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> p[i];
    }

    long long low = 0;
    // Max possible distance is 10^10. So max time can be 10^10.
    // A slightly larger upper bound is safe.
    long long high = 20000000000LL; // 2 * 10^10, covers max possible distance between p_i and h_i

    long long ans = high; // Initialize with a value that will be overwritten

    while (low <= high) {
        long long mid = low + (high - low) / 2;
        if (check(mid, n, m, h, p)) {
            ans = mid;
            high = mid - 1; // Try for a smaller time
        } else {
            low = mid + 1; // Need more time
        }
    }

    std::cout << ans << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <climits>

struct Operation {
    int type;
    int l, r;
    long long val; // d for type 1, m for type 2
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<Operation> ops(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> ops[i].type >> ops[i].l >> ops[i].r >> ops[i].val;
        ops[i].l--; // 0-indexed
        ops[i].r--; // 0-indexed
    }

    std::vector<long long> b(n, LLONG_MAX); // b[i] stores the maximum possible initial value for a[i]

    // Process operations in reverse to determine upper bounds for initial values
    for (int i = m - 1; i >= 0; --i) {
        if (ops[i].type == 1) {
            // If a[j] was increased by d, then its initial value must have been d less
            // than what it would have been without this operation.
            // So, we subtract d from the current upper bound for initial values.
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                if (b[j] != LLONG_MAX) { // Only adjust if an upper bound was set
                    b[j] -= ops[i].val;
                }
            }
        } else { // ops[i].type == 2
            // For a type 2 operation (max query), the maximum value in the range [l, r]
            // must be ops[i].val. This means every element a[j] in this range must be
            // less than or equal to ops[i].val.
            // So, we update the upper bound for initial values in this range.
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                b[j] = std::min(b[j], ops[i].val);
            }
        }
    }

    // If any b[i] is still LLONG_MAX, it means no type 2 operation constrained it.
    // We can set it to 0 (or any value within bounds, 0 is simplest).
    // The problem states |a_i| <= 10^9. 0 satisfies this.
    for (int i = 0; i < n; ++i) {
        if (b[i] == LLONG_MAX) {
            b[i] = 0;
        }
    }

    // Verify the solution by simulating operations with the constructed initial array `b`
    std::vector<long long> current_a = b;
    for (int i = 0; i < m; ++i) {
        if (ops[i].type == 1) {
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                current_a[j] += ops[i].val;
            }
        } else { // ops[i].type == 2
            long long max_val = LLONG_MIN;
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                max_val = std::max(max_val, current_a[j]);
            }
            if (max_val != ops[i].val) {
                std::cout << "NO\n";
                return 0;
            }
        }
    }

    // Check if initial values are within bounds
    for (int i = 0; i < n; ++i) {
        if (b[i] < -1000000000LL || b[i] > 1000000000LL) {
            // This case should ideally not be reached if the logic is correct
            // and a solution exists within the given constraints.
            // However, it's a good sanity check.
            std::cout << "NO\n";
            return 0;
        }
    }

    std::cout << "YES\n";
    for (int i = 0; i < n; ++i) {
        std::cout << b[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

