#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
    }

    // The problem statement guarantees that a solution exists.
    // Reversing the permutation always produces a different permutation
    // (unless n=1, but n>=2) and preserves the set of adjacent sums.
    // The sorted list of adjacent sums (fingerprint) will thus be the same.
    // For example, if p = [p1, p2, p3, p4], adjacent sums are [p1+p2, p2+p3, p3+p4].
    // If p' = [p4, p3, p2, p1], adjacent sums are [p4+p3, p3+p2, p2+p1].
    // Since addition is commutative, these sets of sums are identical.
    // The only case where p' might be equal to p is if p is a palindrome,
    // e.g., [1, 2, 1] (not a permutation), or [1, 2, 3, 2, 1] (not a permutation).
    // A permutation cannot be a palindrome unless n=1 (which is not allowed)
    // or n=0. For n >= 2, a permutation [p1, ..., pn] cannot be equal to
    // its reverse [pn, ..., p1] because p1 must be different from pn
    // (as they are distinct elements from 1 to n).
    // Thus, reversing the permutation always yields a different permutation
    // with the same fingerprint.

    std::reverse(p.begin(), p.end());

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;
}

