        // The number of times we can add min_val to a[i] is (k - a[i]) / min_val.
        // Since a[i] is already sorted, a[i] >= min_val.
        // k - a[i] will be non-negative because a[i] <= k initially.
        // min_val is guaranteed to be at least 1.
        operations += (k - a[i]) / min_val;
    }

    std::cout << operations << std::endl;
}

