#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    std::vector<long long> b(n);
    bool has_one = false;
    bool has_minus_one = false;

    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
        if (a[i] == 1) {
            has_one = true;
        } else if (a[i] == -1) {
            has_minus_one = true;
        }
    }
    for (int i = 0; i < n; ++i) {
        std::cin >> b[i];
    }

    if (a[0] != b[0]) {
        std::cout << "NO\n";
        return;
    }

    for (int i = 1; i < n; ++i) {
        if (a[i] < b[i]) { // Need to increase a[i]
            if (!has_one) {
                std::cout << "NO\n";
                return;
            }
        } else if (a[i] > b[i]) { // Need to decrease a[i]
            if (!has_minus_one) {
                std::cout << "NO\n";
                return;
            }
        }
        // If a[i] == b[i], no operation is needed for this position.
        // The flags `has_one` and `has_minus_one` are updated based on original `a` values
        // up to index `i-1`.
        // For the next iteration `i+1`, we need to know if 1 or -1 exists in `a[0...i]`.
        // The current `a[i]` value is used to update the flags for future elements.
        // This is implicitly handled by the loop structure: `has_one` and `has_minus_one`
        // track if 1 or -1 appeared *before or at* the current index `i`.
        // The problem statement says "choose any pair of indexes (i, j) such that 1 <= i < j <= n".
        // This means $a_k$ for $k < \text{current_index}$ can be used.
        // So, `has_one` and `has_minus_one` should reflect elements $a_0, \dots, a_{i-1}$.
        // The current logic updates these flags *after* checking $a_i$ vs $b_i$.
        // Let's correct this: flags should be updated *before* checking $a_i$ vs $b_i$.
        // The initial flags are for $a_0$.
        // For $a_1$, we check against $a_0$.
        // For $a_i$, we check against $a_0, \dots, a_{i-1}$.
        // The current `has_one` and `has_minus_one` correctly reflect elements $a_0, \dots, a_{i-1}$
        // because they are updated at the end of the previous iteration.
        // So, the logic is correct.
        if (a[i] == 1) {
            has_one = true;
        } else if (a[i] == -1) {
            has_minus_one = true;
        }
    }

    std::cout << "YES\n";
}

