        int max_val_for_i = 0;
        for (int j = 0; j < n; ++j) {
            if (i == j) continue;
            max_val_for_i = std::max(max_val_for_i, a[i][j]);
        }
        // If max_val_for_i is n-1, it means p[i] must be n.
