        // and min(p[i], p[j]) = p[i]. So max_val_for_i would be p[i].
        // If p[i] is n, then for all j, min(p[i], p[j]) = p[j].
        // The maximum of these p[j] values would be n-1 (since p[j] cannot be n).
        // So, if max_val_for_i is n-1, p[i] must be n.
        // Otherwise, p[i] is max_val_for_i.
        if (max_val_for_i == n - 1) {
            p[i] = n;
