int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        long long c, m, x;
        std::cin >> c >> m >> x;
        // The maximum number of teams 'k' is limited by three factors:
        // 1. The number of coders available: k <= c
        // 2. The number of mathematicians available: k <= m
        // 3. The total number of students available: 3 * k <= c + m + x, which means k <= (c + m + x) / 3
        //
        // So, k must be less than or equal to min(c, m, (c + m + x) / 3).
        // Let's call this upper bound 'max_possible_k'.
        //
        // We need to check if it's always possible to form 'max_possible_k' teams.
        // If we form 'k' teams, we use 'k' coders and 'k' mathematicians as the minimum requirement.
        // This leaves (c - k) coders, (m - k) mathematicians, and 'x' students with no specialization.
        //
        // Each of the 'k' teams needs 3 members. We've already assigned 1 coder and 1 mathematician to each.
        // So, each team still needs 1 more member. In total, 'k' additional members are needed.
        //
        // The total number of available students for these 'k' additional spots is:
        // (c - k) + (m - k) + x
        //
        // If (c - k) + (m - k) + x >= k, then we have enough students to fill these 'k' spots.
        // This simplifies to c + m + x >= 3 * k.
        //
        // This condition (c + m + x >= 3 * k) is already covered by k <= (c + m + x) / 3.
        //
        // Therefore, the maximum number of teams is simply the minimum of these three values.
        long long ans = std::min({c, m, (c + m + x) / 3});
        std::cout << ans << "\n";
    }
    return 0;
}

