        std::cin >> d;

        if (d == 0.0) {
            std::cout << "Y 0.000000000 0.000000000\n";
        } else if (d < 4.0) {
            std::cout << "N\n";
        } else {
            double discriminant = d * d - 4.0 * d;
            // Since d >= 4, discriminant will be non-negative.
            // d^2 - 4d = d(d-4). If d=4, disc=0. If d>4, disc>0.
            double sqrt_discriminant = std::sqrt(discriminant);

            double a1 = (d + sqrt_discriminant) / 2.0;
            double b1 = (d - sqrt_discriminant) / 2.0;

            // We need a and b to be non-negative.
            // Since d >= 4, d is positive.
            // sqrt_discriminant = sqrt(d(d-4)).
            // If d=4, sqrt_discriminant=0, a1=b1=2. Non-negative.
            // If d>4, d-4>0, so d > sqrt(d(d-4)) because d^2 > d(d-4) => d^2 > d^2-4d => 0 > -4d => 4d > 0 => d > 0.
            // So d - sqrt_discriminant will be positive.
            // Thus, both a1 and b1 will be positive.

            std::cout << "Y " << std::fixed << std::setprecision(9) << a1 << " " << b1 << "\n";
        }
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    std::vector<int> pos(n + 1); // pos[val] stores the 0-indexed position of val in p
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
        pos[p[i]] = i;
    }

    std::string result = "";
    int current_min_idx = pos[1];
    int current_max_idx = pos[1];

    for (int m = 1; m <= n; ++m) {
        // For m=1, the segment is just [1].
        // current_min_idx and current_max_idx are already initialized to pos[1].
        // The length of the segment is 1.
        // The minimum value is 1, maximum value is 1.
        // So m=1 is always beautiful.

        // For m > 1, we need to expand the segment to include 'm'.
        // The segment must contain 1, 2, ..., m.
        // This means the current segment [current_min_idx, current_max_idx]
        // must be expanded to include pos[m].
        // After including pos[m], the new segment will span from
        // min(current_min_idx, pos[m]) to max(current_max_idx, pos[m]).
        // Let's update current_min_idx and current_max_idx to reflect this.
        current_min_idx = std::min(current_min_idx, pos[m]);
        current_max_idx = std::max(current_max_idx, pos[m]);

        // Now, the segment p[current_min_idx ... current_max_idx] contains
        // all numbers from 1 to m (and possibly other numbers if it's not a permutation of 1..m).
        // The length of this segment is (current_max_idx - current_min_idx + 1).
        // For m to be beautiful, this segment must be a permutation of 1..m.
        // This means two conditions must be met:
        // 1. The segment must contain all numbers from 1 to m. (This is guaranteed by how we expand current_min_idx/max_idx)
        // 2. The segment must contain *only* numbers from 1 to m.
        //    This is equivalent to saying that the length of the segment must be exactly m.
        //    If the length is m, and it contains 1..m, then it must be a permutation of 1..m.
        //    If the length is greater than m, it means it contains other numbers, or duplicates (not possible in permutation),
        //    or it contains 1..m plus some other numbers. In any case, it's not a permutation of 1..m.

        if (current_max_idx - current_min_idx + 1 == m) {
            result += '1';
        } else {
            result += '0';
        }
    }
    std::cout << result << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n == 1) {
        std::cout << "Yes\n";
        return;
    }

    // Calculate the maximum possible length of the strictly increasing prefix
    // ending at index i, such that a_j >= j for j <= i.
    // This is equivalent to finding the longest prefix where a_j >= j.
    // If a_j < j, then we cannot make a_j = j, so we cannot make a_j = j-1, etc.
    // The smallest possible value for a_j in an increasing sequence starting from 0
    // is j. So we need a_j >= j.
    int prefix_len = 0;
    for (int i = 0; i < n; ++i) {
        if (a[i] >= i) {
            prefix_len++;
        } else {
            break;
        }
    }

    // Calculate the maximum possible length of the strictly decreasing suffix
    // starting at index i, such that a_j >= (n-1-j) for j >= i.
    // This is equivalent to finding the longest suffix where a_j >= (n-1-j).
    // The smallest possible value for a_j in a decreasing sequence ending at 0
    // is (n-1-j). So we need a_j >= (n-1-j).
    int suffix_len = 0;
    for (int i = n - 1; i >= 0; --i) {
        if (a[i] >= (n - 1 - i)) {
            suffix_len++;
        } else {
            break;
        }
    }

    // If the sum of the lengths of these two potential parts is greater than n,
    // it means there is an overlap, and thus a potential peak element exists.
    // This implies we can find a k such that the conditions are met.
    // For example, if prefix_len = 3 and suffix_len = 3 for n=4,
    // prefix covers indices 0, 1, 2.
    // suffix covers indices 1, 2, 3.
    // Overlap at 1, 2. We can pick k=2 (index 1) or k=3 (index 2).
    // If prefix_len = 2 and suffix_len = 2 for n=3,
    // prefix covers indices 0, 1.
    // suffix covers indices 1, 2.
    // Overlap at 1. We can pick k=2 (index 1).
    if (prefix_len + suffix_len > n) {
        std::cout << "Yes\n";
    } else {
        std::cout << "No\n";
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

