// Function to check if Box 1 can be the special box
bool can_be_box1(long long A, long long B, long long C, long long D) {
    // Box 1: fun value <= -1
    // Requires an odd number of negative factors, and product magnitude >= 1.

    // Case 1: Final product is negative.
    // This means the total count of negative numbers multiplied must be odd.
    // The initial negative numbers are from Box 1 and Box 2.
    // Let N_neg = A + B.
    // If N_neg is odd, the final product will be negative.
    // If N_neg is even, the final product will be positive.

    // To get to Box 1, we need an odd number of negative factors AND magnitude >= 1.

    // Scenario 1.1: We can make a product with odd negatives and magnitude >= 1.
    // This is possible if:
    // (A + B) is odd AND (A + D > 0 OR (A + D == 0 AND B + C > 0 AND B is odd))
    // The condition (A + D > 0) means there's at least one toy with magnitude >= 1.
    // If A+D > 0, we can always ensure magnitude >= 1 by multiplying with a large number.
    // If A+D == 0, all initial toys have magnitude < 1 (from B and C).
    // In this case, to get magnitude >= 1, we need to multiply two numbers from B or C such that their product is >= 1.
    // This is impossible if all initial toys have magnitude < 1.
    // So, if A+D == 0, the final product will always have magnitude < 1.
    // Thus, if A+D == 0, Box 1 is impossible.
    // So, for Box 1, we must have A+D > 0.

    // If A+D > 0:
    // If (A + B) is odd, the final product can be negative.
    // Since A+D > 0, we can always ensure magnitude >= 1.
    // So, if (A + B) is odd and A + D > 0, Box 1 is possible.

    // What if (A + B) is even? The final product will be positive.
    // Can we make it negative? Yes, if we can introduce an odd number of negative factors.
    // This means we need to change the parity of negative factors.
    // This happens if we have at least one toy from Box 2 (B > 0) and at least one toy from Box 3 (C > 0).
    // If B > 0 and C > 0, we can multiply a toy from B and a toy from C.
    // Example: (-0.5) * (0.5) = -0.25 (Box 2). This doesn't change the parity of negatives.
    // The parity of negative numbers is fixed by (A+B) initially.
    // Any multiplication of two numbers:
    // N*N -> P (N_neg decreases by 2)
    // N*P -> N (N_neg unchanged)
    // P*P -> P (N_neg unchanged)
    // So, the parity of negative numbers (A+B) is invariant.

    // Therefore, for Box 1, we need (A + B) to be odd.
    // And we need to be able to achieve magnitude >= 1.
    // This is possible if A + D > 0.
    // If A + D == 0, all initial toys have magnitude < 1. Any product will also have magnitude < 1.
    // So, if A + D == 0, Box 1 is impossible.

    // Summary for Box 1:
    // Condition 1: (A + B) % 2 == 1 (final product is negative)
    // Condition 2: A + D > 0 (can achieve magnitude >= 1)
    // Both must be true.

    return ((A + B) % 2 == 1) && (A + D > 0);
}

// Function to check if Box 2 can be the special box
bool can_be_box2(long long A, long long B, long long C, long long D) {
    // Box 2: fun value in (-1, 0)
    // Requires an odd number of negative factors, and product magnitude < 1.

    // Condition 1: (A + B) % 2 == 1 (final product is negative)
    // Condition 2: Can achieve magnitude < 1.
    // This is always possible unless all toys have magnitude >= 1 (A=0, B=0, C=0, D>0).
    // If A+D > 0, we can always pick a toy from B or C (if available) and multiply it with something to keep magnitude < 1.
    // Or, if we have multiple toys with magnitude >= 1, we can multiply them to get a large number, then multiply by a small number.
    // The only way to *not* be able to achieve magnitude < 1 is if all toys are from Box 1 or Box 4, and there are no toys from Box 2 or Box 3.
    // i.e., B=0, C=0.
    // If B=0 and C=0, and A+D > 0, then all toys have magnitude >= 1.
    // The product of numbers with magnitude >= 1 will always have magnitude >= 1.
    // So, if B=0 and C=0, Box 2 is impossible.

    // If B > 0 or C > 0, we can always achieve magnitude < 1.
    // For example, if B > 0, we can pick a toy from B. Its value is already < 1.
    // If C > 0, we can pick a toy from C. Its value is already < 1.
    // If we have only A and D, and B=0, C=0, then all values are >= 1 in magnitude.
    // The product will always be >= 1 in magnitude. So Box 2 is impossible.

    // So, for Box 2:
    // Condition 1: (A + B) % 2 == 1 (final product is negative)
    // Condition 2: B + C > 0 (can achieve magnitude < 1)
    // Both must be true.

    return ((A + B) % 2 == 1) && (B + C > 0);
}

// Function to check if Box 3 can be the special box
bool can_be_box3(long long A, long long B, long long C, long long D) {
    // Box 3: fun value in (0, 1)
    // Requires an even number of negative factors, and product magnitude < 1.

    // Condition 1: (A + B) % 2 == 0 (final product is positive)
    // Condition 2: Can achieve magnitude < 1.
    // This is possible if B + C > 0. (Same logic as Box 2)
    // If B=0 and C=0, then all toys have magnitude >= 1. Product will be >= 1. So Box 3 is impossible.

    // So, for Box 3:
    // Condition 1: (A + B) % 2 == 0 (final product is positive)
    // Condition 2: B + C > 0 (can achieve magnitude < 1)
    // Both must be true.

    return ((A + B) % 2 == 0) && (B + C > 0);
}

// Function to check if Box 4 can be the special box
bool can_be_box4(long long A, long long B, long long C, long long D) {
    // Box 4: fun value >= 1
    // Requires an even number of negative factors, and product magnitude >= 1.

    // Condition 1: (A + B) % 2 == 0 (final product is positive)
    // Condition 2: Can achieve magnitude >= 1.
    // This is possible if A + D > 0. (Same logic as Box 1)
    // If A=0 and D=0, then all toys have magnitude < 1. Product will be < 1. So Box 4 is impossible.

    // So, for Box 4:
    // Condition 1: (A + B) % 2 == 0 (final product is positive)
    // Condition 2: A + D > 0 (can achieve magnitude >= 1)
    // Both must be true.

    return ((A + B) % 2 == 0) && (A + D > 0);
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int T;
    std::cin >> T;
    while (T--) {
        long long A, B, C, D;
        std::cin >> A >> B >> C >> D;

        // Special case: If total toys is 1, that toy is the super toy.
        // The box it's in is the special box.
        long long total_toys = A + B + C + D;
        if (total_toys == 1) {
            std::cout << (A == 1 ? "Ya" : "Tidak") << " "
                      << (B == 1 ? "Ya" : "Tidak") << " "
                      << (C == 1 ? "Ya" : "Tidak") << " "
                      << (D == 1 ? "Ya" : "Tidak") << "\n";
            continue;
        }

        // General case: total_toys > 1
        std::cout << (can_be_box1(A, B, C, D) ? "Ya" : "Tidak") << " "
                  << (can_be_box2(A, B, C, D) ? "Ya" : "Tidak") << " "
                  << (can_be_box3(A, B, C, D) ? "Ya" : "Tidak") << " "
                  << (can_be_box4(A, B, C, D) ? "Ya" : "Tidak") << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <cmath>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    long long s;
    std::cin >> n >> s;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    std::sort(a.begin(), a.end());

    long long operations = 0;
    int mid_idx = n / 2; // For 0-indexed array, (n-1)/2 is the middle index

    // First, make the median element equal to s
    operations += std::abs(a[mid_idx] - s);

    // If a[mid_idx] is less than s, we need to increase it.
    // All elements to its right (a[mid_idx+1] to a[n-1]) that are less than s
    // must also be increased to at least s.
    if (a[mid_idx] < s) {
        for (int i = mid_idx + 1; i < n; ++i) {
            if (a[i] < s) {
                operations += (s - a[i]);
            } else {
                // Since the array is sorted, all subsequent elements will also be >= s
                break;
            }
        }
    }
    // If a[mid_idx] is greater than s, we need to decrease it.
    // All elements to its left (a[0] to a[mid_idx-1]) that are greater than s
    // must also be decreased to at most s.
    else if (a[mid_idx] > s) {
        for (int i = mid_idx - 1; i >= 0; --i) {
            if (a[i] > s) {
                operations += (a[i] - s);
            } else {
                // Since the array is sorted, all preceding elements will also be <= s
                break;
            }
        }
    }
    // If a[mid_idx] == s, no additional operations are needed for other elements
    // to maintain s as median, as long as they are already on the correct side.
    // The loops above correctly handle this by not adding operations if a[i] is already on the correct side.

    std::cout << operations << std::endl;

    return 0;
}

