#include <iostream>
#include <vector>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }
    std::sort(a.begin(), a.end());
    int count = 0;
    int left_ptr = 0; // Pointer for elements to be placed (from sorted 'a')
    int right_ptr = 0; // Pointer for positions in the original array (from sorted 'a')

    // We want to find a_j > a_i for as many pairs (i, j) as possible.
    // Sort 'a'. Let the sorted array be a_0, a_1, ..., a_{n-1}.
    // We iterate through the sorted array with 'right_ptr' representing a_i (the element at a position).
    // We try to find an a_j (represented by a_left_ptr) such that a_j > a_i.
    // To maximize the count, we should use the smallest possible a_j that is greater than a_i.
    // This greedy approach works because if we use a larger a_j for a_i,
    // that larger a_j could have been used for a larger a_k later,
    // and using a smaller a_j for a_i leaves the larger a_j available for later.
    // So, we maintain two pointers. 'left_ptr' points to the current element we are trying to place.
    // 'right_ptr' points to the current position in the original sorted array.
    // We try to find an element a[left_ptr] such that a[left_ptr] > a[right_ptr].
    // If we find such an element, we increment both pointers and the count.
    // If a[left_ptr] is not greater than a[right_ptr], it means a[left_ptr] is too small
    // to be placed at position 'right_ptr'. So we try the next available element a[left_ptr+1]
    // by only incrementing 'left_ptr'.
    while (left_ptr < n && right_ptr < n) {
        if (a[left_ptr] > a[right_ptr]) {
            count++;
            left_ptr++;
            right_ptr++;
        } else {
            left_ptr++;
        }
    }
    std::cout << count << std::endl;
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>
#include <set>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    std::vector<bool> is_prefix_perm(n + 1, false);
    std::vector<bool> is_suffix_perm(n + 1, false);

    // Check for prefix permutations
    std::vector<bool> seen_prefix(n + 1, false);
    int max_val_prefix = 0;
    bool distinct_prefix = true;
    for (int i = 0; i < n; ++i) {
        if (a[i] > n || seen_prefix[a[i]]) { // a[i] > n is an optimization, max_val_prefix will handle a[i] > i+1
            distinct_prefix = false;
        }
        if (distinct_prefix) {
            seen_prefix[a[i]] = true;
            max_val_prefix = std::max(max_val_prefix, a[i]);
            if (max_val_prefix == i + 1) {
                is_prefix_perm[i + 1] = true;
            }
        }
    }

    // Check for suffix permutations
    std::vector<bool> seen_suffix(n + 1, false);
    int max_val_suffix = 0;
    bool distinct_suffix = true;
    for (int i = n - 1; i >= 0; --i) {
        int current_len = n - i;
        if (a[i] > n || seen_suffix[a[i]]) { // a[i] > n is an optimization, max_val_suffix will handle a[i] > current_len
            distinct_suffix = false;
        }
        if (distinct_suffix) {
            seen_suffix[a[i]] = true;
            max_val_suffix = std::max(max_val_suffix, a[i]);
            if (max_val_suffix == current_len) {
                is_suffix_perm[current_len] = true;
            }
        }
    }

    std::vector<std::pair<int, int>> results;
    for (int l1 = 1; l1 < n; ++l1) {
        int l2 = n - l1;
        if (is_prefix_perm[l1] && is_suffix_perm[l2]) {
            results.push_back({l1, l2});
        }
    }

    std::cout << results.size() << "\n";
    for (const auto& p : results) {
        std::cout << p.first << " " << p.second << "\n";
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

