#include <iostream>
#include <vector>
#include <numeric>
#include <functional>

void solve() {
    int n;
    std::cin >> n;
    long long current_sum = 0;
    long long current_xor_sum = 0;
    for (int i = 0; i < n; ++i) {
        long long a;
        std::cin >> a;
        current_sum += a;
        current_xor_sum ^= a;
    }

    if (current_sum == 2 * current_xor_sum) {
        std::cout << 0 << std::endl;
        std::cout << std::endl;
    } else {
        // We need to append at most 3 elements.
        // Let S be current_sum, X be current_xor_sum.
        // We want S + b1 + b2 = 2 * (X ^ b1 ^ b2).
        // A simple strategy is to append two elements:
        // b1 = X
        // b2 = S + X
        // New sum S' = S + X + (S + X) = 2S + 2X
        // New XOR sum X' = X ^ X ^ (S + X) = S + X
        // Check condition: S' = 2X'
        // 2S + 2X = 2 * (S + X)
        // This is always true.
        // So we can always append X and S+X.
        // The problem states that appended elements don't have to be different.
        // The problem also states that 0 <= b_i <= 10^18.
        // S can be up to 10^5 * 10^9 = 10^14.
        // X can be up to 2^60 (approx 10^18).
        // So S+X can be up to 10^14 + 10^18, which fits in long long.

        std::cout << 2 << std::endl;
        std::cout << current_xor_sum << " " << current_sum + current_xor_sum << std::endl;
    }
}

