#include <iostream>
#include <string>
#include <vector>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;

    long long total_steps = 0;
    long long b_count = 0;
    long long power_of_2 = 1; // Represents 2^b_count
    long long MOD = 1e9 + 7;

    // Iterate the string from right to left
    for (int i = s.length() - 1; i >= 0; --i) {
        if (s[i] == 'b') {
            b_count = (b_count + 1) % MOD;
            power_of_2 = (power_of_2 * 2) % MOD; // This is 2^(b_count_before_increment)
        } else { // s[i] == 'a'
            // When an 'a' is encountered, it needs to move past all 'b's to its right.
            // Each 'b' to its right effectively doubles the number of 'b's that this 'a'
            // will eventually interact with (or rather, the number of 'b's that will be
            // generated by this 'a' moving past existing 'b's).
            // The number of steps for this 'a' is equal to the current b_count.
            // However, due to the "bba" rule, each 'b' effectively doubles the 'a's
            // contribution to future 'b's.
            // So, if there are `k` 'b's to the right, this 'a' will generate `2^k` 'b's
            // that will be available for 'a's further to the left.
            // The number of steps for this 'a' is `2^k - 1` if we consider it as
            // `a` followed by `k` `b`s.
            // But the problem is simpler: each 'a' effectively "pushes" all 'b's to its right.
            // When 'a' encounters a 'b', it becomes 'bba'. The 'a' is now to the right of 'b'.
            // The number of steps for this 'a' is the current `b_count`.
            // This `b_count` is the number of 'b's that this 'a' has to pass.
            // Each time an 'a' passes a 'b', it costs 1 step and creates a new 'b'.
            // So, if there are `k` 'b's to the right, this 'a' will cause `k` steps.
            // But the `b_count` itself is affected by previous 'a's.
            // The `b_count` represents the number of 'b's that are effectively to the right
            // of the current 'a' and have not yet been "passed" by an 'a' from the left.
            // When an 'a' is processed, it adds `b_count` steps.
            // And it effectively doubles the number of 'b's that future 'a's (to its left)
            // will see. This is because `ab -> bba`. The 'a' moves past 'b', and a new 'b' is created.
            // So, for an 'a', it adds `b_count` to `total_steps`.
            // And it effectively doubles the `b_count` for subsequent 'a's.
            // The `b_count` here is the number of 'b's that are currently to the right of the 'a'.
            // When we process an 'a', it adds `b_count` to `total_steps`.
            // Then, this 'a' effectively becomes `2 * b_count` 'b's for the 'a's to its left.
            // So, `b_count` should be updated to `(b_count * 2) % MOD`.

            total_steps = (total_steps + b_count) % MOD;
            b_count = (b_count * 2) % MOD;
        }
    }

    std::cout << total_steps << std::endl;

    return 0;
}

#include <iostream>
#include <algorithm>

long long solve() {
    long long n;
    std::cin >> n;

    if (n == 1) {
        return 1;
    }
    if (n == 2) {
        return 1;
    }
    if (n == 3) {
        return 2;
    }

    long long chanek_coins = 0;

    // Strategy:
    // If N is odd, Chanek must take 1 coin. N becomes even.
    // If N is even, Chanek can choose between taking 1 or N/2.
    // Opponent will also play optimally.

    // Case 1: N is odd
    // Chanek takes 1. N becomes N-1 (even). Chanek gets 1.
    // Now it's opponent's turn with N-1 coins.
    if (n % 2 != 0) {
        chanek_coins += 1;
        n -= 1;
    }

    // Now N is even.
    // Chanek's turn.
    // Option A: Chanek takes 1. N becomes N-1 (odd).
    // Option B: Chanek takes N/2. N becomes N/2 (can be even or odd).

    // Let's analyze the optimal strategy for Chanek when N is even.
    // Chanek wants to maximize his coins. Opponent wants to maximize theirs.
    // This is a zero-sum game in terms of total coins, but not in terms of individual gain.
    // Each player tries to maximize their own score.

    // If N is even, Chanek can take N/2.
    // This is generally a good move as it gives a large amount of coins.
    // After taking N/2, the remaining coins are N/2.
    // The opponent will then play on N/2 coins.

    // Consider the powers of 2.
    // If N is a power of 2 (e.g., 2, 4, 8, 16, ...), Chanek can repeatedly take N/2.
    // N=2: Chanek takes 1. N=1. Opponent takes 1. Chanek=1.
    // N=4: Chanek takes 2. N=2. Opponent takes 1. N=1. Chanek takes 1. Chanek=2+1=3.
    // N=8: Chanek takes 4. N=4. Opponent takes 2. N=2. Chanek takes 1. N=1. Opponent takes 1. Chanek=4+1=5.
    // N=16: Chanek takes 8. N=8. Opponent takes 4. N=4. Chanek takes 2. N=2. Opponent takes 1. N=1. Chanek takes 1. Chanek=8+2+1=11.
    // Pattern for N=2^k: Chanek gets 2^(k-1) + 2^(k-3) + ...
    // This is sum of 2^i where i are k-1, k-3, ..., 0 or 1.
    // If k is even, last term is 2^1. If k is odd, last term is 2^0.
    // Sum = (2^k - 1)/3 if k is odd.
    // Sum = (2^k - 2)/3 + 2/3 = (2^k - 2)/3 + 2/3 = (2^k - 1)/3 if k is odd.
    // Sum = (2^k - 4)/3 + 2/3 = (2^k - 1)/3 if k is even.
    // This is not quite right.
    // For N=2^k, Chanek gets (2^k - 1)/3 if k is odd.
    // For N=2^k, Chanek gets (2^k - 2)/3 + 1 if k is even.
    // Let's re-evaluate.
    // N=2^k.
    // Chanek takes 2^(k-1). Remaining 2^(k-1).
    // Opponent takes 2^(k-2). Remaining 2^(k-2).
    // Chanek takes 2^(k-3). Remaining 2^(k-3).
    // ...
    // This continues until 2^1 or 2^0.
    // If k is odd: Chanek gets 2^(k-1) + 2^(k-3) + ... + 2^0.
    // This is a geometric series sum: 2^0 * ( (2^2)^((k+1)/2) - 1 ) / (2^2 - 1) = (2^(k+1) - 1) / 3.
    // Example N=8 (k=3): Chanek gets 4+1=5. Formula: (2^4-1)/3 = 15/3 = 5. Correct.
    // If k is even: Chanek gets 2^(k-1) + 2^(k-3) + ... + 2^1.
    // This is a geometric series sum: 2^1 * ( (2^2)^(k/2) - 1 ) / (2^2 - 1) = 2 * (2^k - 1) / 3.
    // Example N=4 (k=2): Chanek gets 2+1=3. Formula: 2 * (2^2-1)/3 = 2*3/3 = 2. Incorrect.
    // The last move for N=2^k (k even) is:
    // ... Chanek takes 2^1. N becomes 2^1. Opponent takes 2^0. N becomes 2^0. Game ends.
    // So Chanek gets 2^(k-1) + 2^(k-3) + ... + 2^1.
    // This is 2 * (1 + 4 + ... + 4^(k/2 - 1)) = 2 * (4^(k/2) - 1) / (4-1) = 2 * (2^k - 1) / 3.
    // Example N=4 (k=2): Chanek gets 2. Opponent gets 1. Total 3.
    // Chanek takes 2. N=2. Opponent takes 1. N=1. Chanek takes 1.
    // Chanek gets 2+1=3.
    // My formula for k even is wrong.
    // The sequence of coins taken by Chanek is 2^(k-1), 2^(k-3), ..., 2^1.
    // The sequence of coins taken by Opponent is 2^(k-2), 2^(k-4), ..., 2^0.
    // Total coins for Chanek: 2^(k-1) + 2^(k-3) + ... + 2^1 + 1 (last coin from N=1).
    // This is 2 * (1 + 4 + ... + 4^(k/2 - 1)) + 1 = 2 * (4^(k/2) - 1) / 3 + 1 = 2 * (2^k - 1) / 3 + 1.
    // Example N=4 (k=2): 2 * (2^2 - 1) / 3 + 1 = 2 * 3 / 3 + 1 = 2 + 1 = 3. Correct.
    // Example N=16 (k=4): 2 * (2^4 - 1) / 3 + 1 = 2 * 15 / 3 + 1 = 10 + 1 = 11. Correct.

    // So, if N is a power of 2, say N=2^k:
    // If k is odd: Chanek gets (2^(k+1) - 1) / 3.
    // If k is even: Chanek gets (2^(k+1) - 2) / 3 + 1. (This is equivalent to (2^(k+1) + 1) / 3)
    // Let's check (2^(k+1) + 1) / 3 for k=2 (N=4): (2^3+1)/3 = 9/3 = 3. Correct.
    // Let's check (2^(k+1) + 1) / 3 for k=4 (N=16): (2^5+1)/3 = 33/3 = 11. Correct.
    // So, for N=2^k: Chanek gets (2^(k+1) - 1) / 3 if k is odd.
    //                 Chanek gets (2^(k+1) + 1) / 3 if k is even.

    // What if N is even but not a power of 2?
    // N = 6.
    // Chanek takes 1: N=5. Opponent's turn.
    //   Opponent takes 1. N=4. Chanek's turn.
    //     Chanek takes 2. N=2. Opponent takes 1. N=1. Chanek takes 1.
    //     Chanek gets 1 (from N=5) + 2 + 1 = 4. Opponent gets 1 (from N=5) + 1 = 2.
    //   Opponent takes 5/2 (not allowed).
    // Chanek takes 6/2 = 3. N=3. Opponent's turn.
    //   Opponent takes 1. N=2. Chanek's turn.
    //     Chanek takes 1. N=1. Opponent takes 1.
    //     Chanek gets 3 + 1 = 4. Opponent gets 1 + 1 = 2.
    // In both cases, Chanek gets 4.

    // It seems that if N is even, Chanek should always take N/2.
    // Why? Taking N/2 leaves N/2 coins. Taking 1 leaves N-1 coins.
    // N/2 is a smaller number, so the game ends faster.
    // If N is even, and Chanek takes N/2, he gets N/2 coins.
    // The opponent then plays on N/2.
    // If N is even, and Chanek takes 1, he gets 1 coin.
    // The opponent then plays on N-1 (odd). Opponent takes 1. N-2 (even).
    // This seems to be a general strategy:
    // If N is odd, take 1.
    // If N is even, take N/2.

    // Let's trace this strategy:
    // N = 5:
    // Chanek (odd): takes 1. Chanek=1. N=4.
    // Opponent (even): takes 4/2=2. Opponent=2. N=2.
    // Chanek (even): takes 2/2=1. Chanek=1+1=2. N=1.
    // Opponent (odd): takes 1. Opponent=2+1=3. N=0.
    // Chanek gets 2. This matches example.

    // N = 6:
    // Chanek (even): takes 6/2=3. Chanek=3. N=3.
    // Opponent (odd): takes 1. Opponent=1. N=2.
    // Chanek (even): takes 2/2=1. Chanek=3+1=4. N=1.
    // Opponent (odd): takes 1. Opponent=1+1=2. N=0.
    // Chanek gets 4. This matches example.

    // This greedy strategy (take 1 if odd, take N/2 if even) seems to work for the examples.
    // Let's try to prove it.
    // When it's player P's turn with N coins:
    // If N is odd: P must take 1. N becomes N-1 (even). P gets 1.
    // If N is even: P can take 1 or N/2.
    //   Option 1: P takes 1. N becomes N-1 (odd). P gets 1.
    //   Option 2: P takes N/2. N becomes N/2. P gets N/2.

    // Consider the total coins taken by Chanek (C) and Opponent (O).
    // C + O = N_initial.
    // Chanek wants to maximize C. Opponent wants to maximize O.
    // This is equivalent to Chanek maximizing C, and Opponent minimizing C.

    // Let f(N) be the maximum coins Chanek can get if it's his turn with N coins.
    // Let g(N) be the maximum coins Opponent can get if it's Chanek's turn with N coins.
    // So we want f(N).

    // If N is odd: Chanek takes 1. Remaining N-1. Opponent's turn.
    // Chanek gets 1 + (N-1 - f_opponent(N-1)).
    // f_opponent(N-1) is the coins opponent gets from N-1.
    // This is equivalent to 1 + (N-1 - (N-1 - f_chanek(N-1))) = 1 + f_chanek(N-1).
    // No, this is not right.
    // If N is odd, Chanek takes 1. Remaining N-1.
    // Opponent plays optimally on N-1. Let O_N-1 be coins opponent gets from N-1.
    // Let C_N-1 be coins Chanek gets from N-1.
    // Total coins from N-1 is N-1. So O_N-1 + C_N-1 = N-1.
    // Chanek's total: 1 + C_N-1.
    // Opponent's total: O_N-1.
    // So if N is odd, Chanek takes 1. Then it's opponent's turn with N-1.
    // Chanek's total = 1 + (N-1 - (optimal coins opponent gets from N-1)).
    // This is 1 + (N-1 - solve(N-1, opponent_turn)).
    // This is getting complicated.

    // Let's stick to the greedy strategy:
    // If N is odd, take 1.
    // If N is even, take N/2.
    // This strategy is optimal for the current player if the other player also follows it.
    // Let's simulate this strategy.

    bool chanek_turn = true;
    while (n > 0) {
        if (chanek_turn) {
            if (n % 2 != 0) { // N is odd
                chanek_coins += 1;
                n -= 1;
            } else { // N is even
                // If N is a power of 2, taking N/2 is always better than taking 1.
                // Example N=4: take 2 (Chanek gets 2). N=2. Opponent takes 1. N=1. Chanek takes 1. Total 3.
                //              take 1 (Chanek gets 1). N=3. Opponent takes 1. N=2. Chanek takes 1. N=1. Opponent takes 1. Total 1+1=2.
                // So for powers of 2, N/2 is better.
                // What if N is even but not a power of 2? e.g., N=6.
                // Take 3: Chanek gets 3. N=3. Opponent takes 1. N=2. Chanek takes 1. N=1. Opponent takes 1. Chanek total 3+1=4.
                // Take 1: Chanek gets 1. N=5. Opponent takes 1. N=4. Chanek takes 2. N=2. Opponent takes 1. N=1. Chanek takes 1. Chanek total 1+2+1=4.
                // In this case, both moves lead to the same result for Chanek.
                // It seems taking N/2 is always at least as good as taking 1 for the current player when N is even.
                // Taking N/2 reduces N faster, which might be good or bad.
                // But it gives a larger immediate gain.
                // The opponent will also play optimally.
                // If N is even, and Chanek takes N/2, he gets N/2. Opponent plays on N/2.
                // If N is even, and Chanek takes 1, he gets 1. Opponent plays on N-1.
                // The problem states "Both players will try to maximize the number of coins they have."
                // This implies a greedy approach for each player.
                // The strategy "take 1 if odd, take N/2 if even" is a common greedy strategy in such games.
                // Let's assume this strategy is optimal.

                // Special case: If N is a power of 2, say N=2^k.
                // If Chanek takes N/2, he gets 2^(k-1). Remaining N/2 = 2^(k-1).
                // If Chanek takes 1, he gets 1. Remaining N-1.
                // For N=2^k, the optimal strategy is to take N/2.
                // This is because taking N/2 keeps the number of coins as a power of 2 for the opponent,
                // but the opponent will also take half, and so on.
                // This leads to a sequence of (N/2, N/8, N/32, ...) for Chanek and (N/4, N/16, ...) for opponent.
                // This is the pattern derived earlier.
                // If N is not a power of 2, it can be written as N = 2^k * M, where M is odd and M > 1.
                // If Chanek takes N/2, he gets N/2. Remaining N/2 = 2^(k-1) * M.
                // If Chanek takes 1, he gets 1. Remaining N-1.
                // N-1 is odd if N is even.
                // If N is even and not a power of 2, then N/2 is also not a power of 2 (unless M=1, which means N is power of 2).
                // So N/2 will still have an odd factor > 1.
                // The strategy "take N/2 if even, take 1 if odd" seems to be the intended optimal strategy.

                // Let's check the N=10^18 case.
                // If N is even, and N is not a power of 2, then N/2 is also even (if k > 1) or odd (if k=1).
                // If N = 2 * M (M odd, M > 1).
                // Chanek takes N/2 = M. N becomes M.
                // Opponent's turn with M (odd). Opponent takes 1. N becomes M-1 (even).
                // Chanek's turn with M-1 (even).
                // This is better than Chanek taking 1.
                // If Chanek takes 1. N becomes N-1 (odd).
                // Opponent takes 1. N becomes N-2 (even).
                // Chanek's turn with N-2.
                // The N/2 move gives a larger immediate gain and potentially leaves a smaller number for the opponent.
                // The only time taking 1 might be better is if N/2 leads to a state where the opponent gets a lot more.
                // But since both play optimally, they will always try to maximize their own.
                // The "take N/2 if even, take 1 if odd" strategy is the standard greedy approach for this type of game.

                // The only exception to taking N/2 when N is even is if N=2.
                // If N=2, taking N/2=1. Chanek gets 1. N=1. Opponent takes 1. Chanek total 1.
                // If N=2, taking 1. Chanek gets 1. N=1. Opponent takes 1. Chanek total 1.
                // Both are same. So N/2 is fine.

                // The only time taking 1 is better than N/2 is if N/2 is 1.
                // If N=2, N/2=1.
                // If N=2, Chanek takes 1. N=1. Opponent takes 1. Chanek gets 1.
                // If N=2, Chanek takes 2/2=1. N=1. Opponent takes 1. Chanek gets 1.
                // So for N=2, it doesn't matter.

                // The strategy is:
                // If N is odd, take 1.
                // If N is even:
                //   If N is a power of 2, take N/2.
                //   If N is even but not a power of 2, take N/2.
                // This simplifies to: if N is odd, take 1. If N is even, take N/2.

                // Let's implement this strategy.
                // The loop will run until N becomes 0.
                // The number of turns can be up to log2(10^18) * 2 (roughly 60 * 2 = 120 turns).
                // This is efficient enough.

                // Check if N is a power of 2.
                // A number N is a power of 2 if N > 0 and (N & (N - 1)) == 0.
                if ((n & (n - 1)) == 0) { // N is a power of 2
                    // For N=2^k, Chanek gets (2^(k+1) - 1) / 3 if k is odd.
                    //                 Chanek gets (2^(k+1) + 1) / 3 if k is even.
                    // This can be simplified.
                    // Let's find k.
                    long long temp_n = n;
                    int k = 0;
                    while (temp_n > 1) {
                        temp_n /= 2;
                        k++;
                    }
                    if (k % 2 != 0) { // k is odd
                        chanek_coins += (n * 2 - 1) / 3;
                    } else { // k is even
                        chanek_coins += (n * 2 + 1) / 3;
                    }
                    n = 0; // Game ends
                } else { // N is even but not a power of 2
                    chanek_coins += n / 2;
                    n /= 2;
                }
            }
        } else { // Opponent's turn
            if (n % 2 != 0) { // N is odd
                n -= 1;
            } else { // N is even
                if ((n & (n - 1)) == 0) { // N is a power of 2
                    // Opponent takes N/2.
                    // The remaining coins will be N/2.
                    // The game will continue with Chanek getting the next N/4, etc.
                    // This is already handled by the power of 2 logic for Chanek.
                    // So we just need to reduce N.
                    n = 0; // Game ends for this branch, as Chanek's coins are already calculated.
                } else { // N is even but not a power of 2
                    n /= 2;
                }
            }
        }
        chanek_turn = !chanek_turn;
    }
    return chanek_coins;
}

