#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n, d;
        std::cin >> n >> d;
        std::vector<int> a(n);
        for (int i = 0; i < n; ++i) {
            std::cin >> a[i];
        }

        long long current_a1 = a[0];
        long long remaining_days = d;

        for (int i = 1; i < n; ++i) { // Piles are 0-indexed, so pile i is a[i]
            int pile_idx = i; // 0-indexed pile index
            int distance_to_pile1 = pile_idx; // Cost to move one haybale to pile 0

            if (distance_to_pile1 == 0) { // This is pile 0 itself, skip
                continue;
            }

            if (remaining_days <= 0) {
                break; // No more days left
            }

            // Calculate how many haybales can be moved from this pile
            // based on remaining days and cost per haybale.
            // Each haybale from pile_idx costs distance_to_pile1 days.
            long long haybales_can_move = remaining_days / distance_to_pile1;

            // We can move at most a[pile_idx] haybales from this pile.
            long long actual_haybales_to_move = std::min((long long)a[pile_idx], haybales_can_move);

            current_a1 += actual_haybales_to_move;
            remaining_days -= actual_haybales_to_move * distance_to_pile1;
        }
        std::cout << current_a1 << std::endl;
    }
    return 0;
}

