// Function to convert a number to its parity pattern string
std::string to_parity_pattern(long long n) {
    std::string pattern_str = "";
    if (n == 0) {
        return "000000000000000000"; // 18 zeros for 0
    }
    while (n > 0) {
        if ((n % 10) % 2 == 0) {
            pattern_str += '0';
        } else {
            pattern_str += '1';
        }
        n /= 10;
    }
    // Pad with '0's from the left to a fixed length (18)
    while (pattern_str.length() < 18) {
        pattern_str += '0';
    }
    std::reverse(pattern_str.begin(), pattern_str.end()); // Reverse to get correct order
    return pattern_str;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int t;
    std::cin >> t;

    std::map<std::string, int> counts;

    for (int i = 0; i < t; ++i) {
        char type;
        std::cin >> type;

        if (type == '+') {
            long long a;
            std::cin >> a;
            counts[to_parity_pattern(a)]++;
        } else if (type == '-') {
            long long a;
            std::cin >> a;
            counts[to_parity_pattern(a)]--;
        } else { // type == '?'
            std::string s;
            std::cin >> s;
            // Pad the query pattern with '0's from the left to fixed length 18
            std::string padded_s = s;
            while (padded_s.length() < 18) {
                padded_s = '0' + padded_s;
            }
            std::cout << counts[padded_s] << "\n";
        }
    }

    return 0;
}

