    // First pass: Determine necessary '0's in w
    // If s_i is '0', then both w_{i-x} and w_{i+x} must be '0'
    for (int i = 0; i < n; ++i) {
        if (s[i] == '0') {
            if (i - x >= 0) {
                w[i - x] = '0';
            }
            if (i + x < n) {
                w[i + x] = '0';
            }
        }
    }

    // Second pass: Verify if the constructed w produces s
    // Construct s_prime from w and compare with s
    std::string s_prime(n, '0');
