#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long l, r, Ql, Qr;
    std::cin >> n >> l >> r >> Ql >> Qr;

    std::vector<long long> w(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> w[i];
    }

    std::vector<long long> prefix_sum(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        prefix_sum[i + 1] = prefix_sum[i] + w[i];
    }

    long long min_energy = -1;

    // Iterate through all possible counts of items taken from the left
    // Let 'i' be the number of items taken from the left (0 <= i <= n)
    // Then 'n-i' items are taken from the right.
    for (int i = 0; i <= n; ++i) {
        long long current_energy = 0;

        // Energy for items taken from the left
        // These are items w[0]...w[i-1]
        current_energy += prefix_sum[i] * l;

        // Energy for items taken from the right
        // These are items w[i]...w[n-1] (if i items are taken from left, then n-i items are taken from right)
        // The items taken from the right are w[n-(n-i)] ... w[n-1]
        // which is w[i] ... w[n-1]
        current_energy += (prefix_sum[n] - prefix_sum[i]) * r;

        // Add bonus energy for consecutive picks
        int left_count = i;
        int right_count = n - i;

        if (left_count > right_count) {
            // More items taken from left. The last item must have been from left.
            // The difference is (left_count - right_count).
            // If left_count = right_count + 1, no bonus.
            // If left_count = right_count + 2, one bonus.
            // So, bonus is for (left_count - right_count - 1) items.
            current_energy += (left_count - right_count - 1) * Ql;
        } else if (right_count > left_count) {
            // More items taken from right. The last item must have been from right.
            // The difference is (right_count - left_count).
            // If right_count = left_count + 1, no bonus.
            // If right_count = left_count + 2, one bonus.
            // So, bonus is for (right_count - left_count - 1) items.
            current_energy += (right_count - left_count - 1) * Qr;
        }

        if (min_energy == -1 || current_energy < min_energy) {
            min_energy = current_energy;
        }
    }

    std::cout << min_energy << std::endl;

    return 0;
}

