// Function to find prime factors of a number
std::vector<long long> get_prime_factors(long long n) {
    std::vector<long long> factors;
    for (long long i = 2; i * i <= n; ++i) {
        if (n % i == 0) {
            factors.push_back(i);
            while (n % i == 0) {
                n /= i;
            }
        }
    }
    if (n > 1) {
        factors.push_back(n);
    }
    return factors;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long p, q;
        std::cin >> p >> q;

        if (p % q != 0) {
            std::cout << p << "\n";
            continue;
        }

        // p is divisible by q. We need to find a divisor x of p such that x is not divisible by q.
        // To maximize x, we want to remove as few factors from p as possible,
        // specifically, factors that make p divisible by q.

        // Get prime factors of q.
        // Any x that is not divisible by q must have at least one prime factor r_j
        // from q with a lower exponent than in q.
        std::vector<long long> q_prime_factors = get_prime_factors(q);

        long long max_x = 1;

        for (long long r : q_prime_factors) {
            // For each prime factor r of q, we want to find the largest divisor of p
            // that is not divisible by q, by reducing the power of r in p.

            // Calculate p_temp = p
            // Divide p_temp by r until it's no longer divisible by q.
            long long current_p = p;
            while (current_p % q == 0) {
                current_p /= r;
            }
            max_x = std::max(max_x, current_p);
        }
        std::cout << max_x << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::string s;
    std::cin >> s;

    std::vector<int> ans(n);
    bool found_solution = false;

    for (int p = 0; p <= 9; ++p) {
        std::vector<int> current_ans(n);
        std::string s1_str = "";
        std::string s2_str = "";

        // First pass: assign digits < p to color 1, digits > p to color 2
        // Digits == p are temporarily unassigned (marked 0)
        for (int i = 0; i < n; ++i) {
            int digit = s[i] - '0';
            if (digit < p) {
                current_ans[i] = 1;
                s1_str += s[i];
            } else if (digit > p) {
                current_ans[i] = 2;
                s2_str += s[i];
            } else { // digit == p
                current_ans[i] = 0; // Mark as unassigned for now
            }
        }

        // Second pass: assign digits == p
        // The first occurrence of 'p' and subsequent 'p's that maintain sorted order for S1
        // are assigned to color 1.
        // The remaining 'p's are assigned to color 2.

        // Find the first 'p' that should go to S2.
        // This is the first 'p' such that if it goes to S1, S1 would become unsorted.
        // Or, if it goes to S2, S2 would become unsorted.
        // A simpler approach: find the first 'p' that breaks the non-decreasing property if it were to be part of S1.
        // All 'p's before this point go to S1, all 'p's after this point go to S2.

        int split_idx_for_p = -1; // Index in original string s where 'p's switch from color 1 to color 2

        // Find the last digit in s1_str (if any)
        char last_s1_char = (s1_str.empty() ? '0' : s1_str.back());

        for (int i = 0; i < n; ++i) {
            if (s[i] - '0' == p) {
                if (s[i] >= last_s1_char) { // Can potentially extend S1
                    current_ans[i] = 1;
                    last_s1_char = s[i];
                } else { // Cannot extend S1 with this 'p' without breaking non-decreasing order
                    split_idx_for_p = i;
                    break;
                }
            }
        }

        // If a split point was found, all subsequent 'p's must go to color 2
        if (split_idx_for_p != -1) {
            for (int i = split_idx_for_p; i < n; ++i) {
                if (s[i] - '0' == p) {
                    current_ans[i] = 2;
                }
            }
        }

        // Now reconstruct s1_str and s2_str based on current_ans
        s1_str = "";
        s2_str = "";
        for (int i = 0; i < n; ++i) {
            if (current_ans[i] == 1) {
                s1_str += s[i];
            } else if (current_ans[i] == 2) {
                s2_str += s[i];
            }
        }

        // Check if the resulting sequences are valid
        bool s1_sorted = true;
        for (size_t i = 0; i + 1 < s1_str.length(); ++i) {
            if (s1_str[i] > s1_str[i+1]) {
                s1_sorted = false;
                break;
            }
        }

        bool s2_sorted = true;
        for (size_t i = 0; i + 1 < s2_str.length(); ++i) {
            if (s2_str[i] > s2_str[i+1]) {
                s2_sorted = false;
                break;
            }
        }

        bool combined_sorted = true;
        if (!s1_str.empty() && !s2_str.empty()) {
            if (s1_str.back() > s2_str.front()) {
                combined_sorted = false;
            }
        }

        if (s1_sorted && s2_sorted && combined_sorted) {
            found_solution = true;
            ans = current_ans;
            break; 
        }
    }

    if (found_solution) {
        for (int i = 0; i < n; ++i) {
            std::cout << ans[i];
        }
        std::cout << "\n";
    } else {
        std::cout << "-\n";
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <algorithm>
#include <vector>

void solve() {
    int n;
    std::cin >> n;

    long long min_x = -2000000000LL; // Effectively negative infinity
    long long max_x = 2000000000LL;  // Effectively positive infinity
    long long min_y = -2000000000LL; // Effectively negative infinity
    long long max_y = 2000000000LL;  // Effectively positive infinity

    for (int i = 0; i < n; ++i) {
        long long x, y;
        int f1, f2, f3, f4;
        std::cin >> x >> y >> f1 >> f2 >> f3 >> f4;

        // f1: can move left (x-1)
        // f2: can move up (y+1)
        // f3: can move right (x+1)
        // f4: can move down (y-1)

        // If robot cannot move left (f1=0), it must end up at an X >= its current x.
        // So, X must be >= x. This updates the lower bound for X.
        if (f1 == 0) {
            min_x = std::max(min_x, x);
        }

        // If robot cannot move up (f2=0), it must end up at a Y <= its current y.
        // So, Y must be <= y. This updates the upper bound for Y.
        if (f2 == 0) {
            max_y = std::min(max_y, y);
        }

        // If robot cannot move right (f3=0), it must end up at an X <= its current x.
        // So, X must be <= x. This updates the upper bound for X.
        if (f3 == 0) {
            max_x = std::min(max_x, x);
        }

        // If robot cannot move down (f4=0), it must end up at a Y >= its current y.
        // So, Y must be >= y. This updates the lower bound for Y.
        if (f4 == 0) {
            min_y = std::max(min_y, y);
        }
    }

    if (min_x <= max_x && min_y <= max_y) {
        // A valid point exists. We can pick any point within the rectangle [min_x, max_x] x [min_y, max_y].
        // The problem guarantees that if a solution exists, one exists with coordinates <= 10^5 abs value.
        // Our bounds can be larger, but we can just pick min_x and min_y.
        // The initial large values for min/max_x/y ensure that if no constraints are imposed,
        // min_x will remain -2e9, max_x will remain 2e9, etc.
        // The problem statement implies that the coordinates of the target point should not exceed 10^5 by absolute value.
        // However, the example output shows -100000, which is within the range.
        // The bounds for x_i, y_i are -10^5 to 10^5.
        // If min_x is -2e9 and max_x is 2e9, we can pick 0.
        // If min_x is 5 and max_x is 10, we can pick 5.
        // If min_x is -100000 and max_x is -50000, we can pick -100000.
        // So, min_x and min_y are valid choices if they are within the allowed range.
        // The problem guarantees that if a solution exists, one of such points has both coordinates not exceeding 10^5 by absolute value.
        // So, we can just output min_x and min_y, as they will be within the guaranteed range if a solution exists.
        std::cout << 1 << " " << min_x << " " << min_y << "\n";
    } else {
        std::cout << 0 << "\n";
    }
}

