}

#include <iostream>
#include <vector>
#include <string>
#include <set>
#include <algorithm>
#include <map>

void solve() {
    std::string s;
    std::cin >> s;

    std::map<char, std::set<char>> adj;
    std::set<char> used_in_password;

    for (size_t i = 0; i < s.length(); ++i) {
        used_in_password.insert(s[i]);
        if (i + 1 < s.length()) {
            adj[s[i]].insert(s[i+1]);
            adj[s[i+1]].insert(s[i]);
        }
    }

    for (const auto& pair : adj) {
        if (pair.second.size() > 2) {
            std::cout << "NO\n";
            return;
        }
    }

    std::string layout = "";
    std::set<char> visited;
    char start_node = '\0';

    // Find a starting node (a character with only one neighbor in the password graph)
    // or any character if all have two neighbors (a cycle or a single node)
    for (char c : used_in_password) {
        if (adj[c].size() == 1) {
            start_node = c;
            break;
        }
    }
    if (start_node == '\0' && !used_in_password.empty()) { // All nodes have 2 neighbors, or only one node
        start_node = *used_in_password.begin();
    } else if (used_in_password.empty()) { // Empty password case, any layout is fine
        start_node = 'a'; // Just pick 'a' to start building a full layout
    }

    if (start_node != '\0') {
        char current = start_node;
        char prev = '\0'; // Sentinel for the first step

        while (visited.find(current) == visited.end()) {
            layout += current;
            visited.insert(current);

            char next_char = '\0';
            for (char neighbor : adj[current]) {
                if (neighbor != prev) {
                    next_char = neighbor;
                    break;
                }
            }

            if (next_char == '\0') { // No unvisited neighbor, path ends
                break;
            }
            prev = current;
            current = next_char;
        }
    }

    // Check if all characters from the password graph are included in the layout
    if (layout.length() != used_in_password.size()) {
        std::cout << "NO\n";
        return;
    }

    // Add remaining characters not in the password to the layout
    for (char c = 'a'; c <= 'z'; ++c) {
        if (visited.find(c) == visited.end()) {
            layout += c;
        }
    }

    std::cout << "YES\n";
    std::cout << layout << "\n";
}

