#include <iostream>

long long sum_arithmetic_progression(long long n) {
    if (n <= 0) {
        return 0;
    }
    long long mod = 1000000007;
    long long n_mod = n % mod;
    long long n_plus_1_mod = (n + 1) % mod;

    // Calculate (n * (n + 1) / 2) % mod
    // Since n and n+1 are coprime, one of them is even.
    // So either n/2 or (n+1)/2 is an integer.
    // We need to find the modular inverse of 2.
    // For mod = 10^9 + 7, which is prime, inv(2) = (mod + 1) / 2 = 500000004.
    long long inv2 = 500000004;

    long long term1 = n_mod;
    long long term2 = n_plus_1_mod;

    long long product = (term1 * term2) % mod;
    long long result = (product * inv2) % mod;

    return result;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    long long a, b;
    std::cin >> a >> b;

    long long mod = 1000000007;

    // If b = 1, mod(x, 1) is always 0, so no nice integers.
    if (b == 1) {
        std::cout << 0 << std::endl;
        return 0;
    }

    // Sum_r = sum_{r=1 to b-1} r
    // Sum_r = (b-1) * b / 2
    long long sum_r = sum_arithmetic_progression(b - 1);

    // Sum_k_term = sum_{k=1 to a} (k * b + 1)
    // Sum_k_term = sum_{k=1 to a} (k * b) + sum_{k=1 to a} 1
    // Sum_k_term = b * sum_{k=1 to a} k + a
    // Sum_k_term = b * (a * (a+1) / 2) + a
    long long sum_k_val = sum_arithmetic_progression(a); // This is (a * (a+1) / 2) % mod

    long long term_b_times_sum_k = (b % mod * sum_k_val) % mod;
    long long term_a = a % mod;

    long long sum_k_term = (term_b_times_sum_k + term_a) % mod;

    // Total sum = Sum_r * Sum_k_term
    long long total_sum = (sum_r * sum_k_term) % mod;

    std::cout << total_sum << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <numeric>
#include <algorithm>
#include <iomanip>
#include <map>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;
    int n = s.length();

    std::vector<int> z(n);
    std::vector<int> s_ext(2 * n);
    for (int i = 0; i < n; ++i) {
        s_ext[i] = s[i] - 'a';
        s_ext[i + n] = s[i] - 'a';
    }

    std::vector<std::vector<int>> lcp_table(n, std::vector<int>(n));

    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < n; ++j) {
            int len = 0;
            while (len < n && s_ext[i + len] == s_ext[j + len]) {
                len++;
            }
            lcp_table[i][j] = len;
        }
    }

    double total_prob = 0.0;

    for (int k_actual = 0; k_actual < n; ++k_actual) {
        char first_char = s[k_actual];

        std::vector<int> possible_k_indices;
        for (int i = 0; i < n; ++i) {
            if (s[i] == first_char) {
                possible_k_indices.push_back(i);
            }
        }

        if (possible_k_indices.size() <= 1) {
            total_prob += 1.0;
            continue;
        }

        int max_unique_count = 0;

        for (int p = 1; p < n; ++p) { // Vasya chooses position p
            std::map<char, std::vector<int>> groups;
            for (int k_cand : possible_k_indices) {
                char char_at_p = s[(k_cand + p) % n];
                groups[char_at_p].push_back(k_cand);
            }

            int current_unique_count = 0;
            for (auto const& [char_val, k_list] : groups) {
                if (k_list.size() == 1) {
                    current_unique_count++;
                } else {
                    // Check if any k_cand in k_list can be uniquely identified
                    // by comparing with other k_cand in k_list
                    for (int i = 0; i < k_list.size(); ++i) {
                        bool is_unique_in_group = true;
                        for (int j = 0; j < k_list.size(); ++j) {
                            if (i == j) continue;
                            int k1 = k_list[i];
                            int k2 = k_list[j];

                            // Check if k1 and k2 are distinguishable
                            // They are distinguishable if s[k1+x] != s[k2+x] for some x
                            // and x is not p and x is not 0.
                            // We need to check if k1 and k2 are distinguishable by *any* other position.
                            // This means checking if s[k1+x] == s[k2+x] for all x in [0, n-1]
                            // except for x=0 and x=p.
                            // If s[k1+x] == s[k2+x] for all x, then k1 and k2 are identical shifts.
                            // This is equivalent to checking if s[k1:]+s[:k1] == s[k2:]+s[:k2]
                            // which means k1 and k2 are equivalent.
                            // The problem states "if there are at least two cyclic shifts of s that fit the information Vasya knowns, Vasya loses."
                            // This means if k1 and k2 are indistinguishable by (0, p), and they are distinct values, Vasya loses.
                            // So, if k_list.size() > 1, and all elements in k_list are distinct, Vasya loses for this group.
                            // The only way to win for a k_cand in this group is if it's the only one in the group.
                            // The problem is about identifying k_actual.
                            // If k_actual is in a group of size > 1, Vasya loses for k_actual.
                            // So, only k_actuals that end up in a group of size 1 contribute to the win.
                            // The current logic for `current_unique_count` is correct: it counts groups of size 1.
                        }
                    }
                }
            }
            max_unique_count = std::max(max_unique_count, current_unique_count);
        }
        total_prob += static_cast<double>(max_unique_count) / possible_k_indices.size();
    }

    std::cout << std::fixed << std::setprecision(15) << total_prob / n << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <map>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(2 * n);
    for (int i = 0; i < 2 * n; ++i) {
        std::cin >> a[i];
    }

    // Calculate prefix sums for the left side (jars n-1 down to 0)
    // diff_L[i] = (count of 1s) - (count of 2s) for jars a[n-1], ..., a[n-i]
    // This corresponds to emptying i jars from the left.
    std::map<int, int> diff_L_to_jars_emptied;
    diff_L_to_jars_emptied[0] = 0; // 0 jars emptied, diff is 0
    int current_diff_L = 0;
    for (int i = 0; i < n; ++i) {
        // Jar a[n-1-i] is the (i+1)-th jar from the left to be emptied
        if (a[n - 1 - i] == 1) {
            current_diff_L++;
        } else {
            current_diff_L--;
        }
        if (diff_L_to_jars_emptied.find(current_diff_L) == diff_L_to_jars_emptied.end()) {
            diff_L_to_jars_emptied[current_diff_L] = i + 1;
        }
    }

    // Calculate prefix sums for the right side (jars n up to 2n-1)
    // diff_R[i] = (count of 1s) - (count of 2s) for jars a[n], ..., a[n+i-1]
    // This corresponds to emptying i jars from the right.
    // We want to find a diff_R[i] such that diff_L[j] + diff_R[i] = initial_diff
    // Or, diff_R[i] = initial_diff - diff_L[j]
    // We want to minimize i + j.
    int min_total_emptied = 2 * n; // Max possible jars to empty

    // Case 0: No jars emptied from the right.
    // We need diff_L[j] = initial_diff.
    // If initial_diff is in diff_L_to_jars_emptied, then j jars are emptied.
    int initial_diff = 0;
    for (int x : a) {
        if (x == 1) {
            initial_diff++;
        } else {
            initial_diff--;
        }
    }

    if (diff_L_to_jars_emptied.count(initial_diff)) {
        min_total_emptied = std::min(min_total_emptied, diff_L_to_jars_emptied[initial_diff]);
    }

    // Iterate through emptying jars from the right
    int current_diff_R = 0;
    for (int i = 0; i < n; ++i) {
        // Jar a[n+i] is the (i+1)-th jar from the right to be emptied
        if (a[n + i] == 1) {
            current_diff_R++;
        } else {
            current_diff_R--;
        }

        int target_diff_L = initial_diff - current_diff_R;
        if (diff_L_to_jars_emptied.count(target_diff_L)) {
            min_total_emptied = std::min(min_total_emptied, (i + 1) + diff_L_to_jars_emptied[target_diff_L]);
        }
    }

    std::cout << min_total_emptied << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    std::string s;
    std::cin >> s;
    int n = s.length();
    long long good_substrings_count = 0;

    // Precompute positions of '1's
    std::vector<int> one_indices;
    for (int i = 0; i < n; ++i) {
        if (s[i] == '1') {
            one_indices.push_back(i);
        }
    }

    // Iterate through all possible right endpoints r
    for (int r = 0; r < n; ++r) {
        // Case 1: Substrings starting with '0'
        // These substrings must have length equal to their binary value.
        // Since they start with '0', their binary value is at most 2^(length-1)-1.
        // For length L, value is at most 2^(L-1)-1.
        // We need L = value.
        // This implies L <= 2^(L-1)-1.
        // This inequality holds for L >= 3.
        // For L=1, value=0, L=1. Not possible.
        // For L=2, value=0 or 1, L=2. Not possible.
        // So, if a substring starts with '0', its value is too small to match its length,
        // unless the length is very small.
        // The only way for a substring starting with '0' to be good is if its value is 0.
        // This means all characters are '0'.
        // So, for s_l...s_r to be good and start with '0', it must be all '0's.
        // In this case, f(s_l...s_r) = 0.
        // The condition becomes r - l + 1 = 0, which is impossible for a non-empty substring.
        // Therefore, any good substring must start with '1'.
        // This simplifies the problem significantly.

        // Find the first '1' to the left of or at r.
        // If s[r] is '0', we can't start a good substring at r.
        // If s[r] is '1', it can be a good substring of length 1 (f('1')=1).
        // This is handled by the general loop below.

        // Iterate through possible starting positions of '1's
        // A good substring s_l...s_r must start with '1'.
        // Let s_k be the first '1' in s_l...s_r. So l <= k <= r.
        // The actual binary value is determined by s_k...s_r.
        // The length is r - l + 1.
        // The number of leading zeros before s_k is k - l.
        // The value f(s_l...s_r) = f(s_k...s_r).
        // So we need r - l + 1 = f(s_k...s_r).

        // Find the index of the first '1' that could be the start of a good substring ending at r.
        // We are looking for s_k...s_r where s_k = '1'.
        // The length of s_k...s_r is r - k + 1.
        // The value f(s_k...s_r) can be at most 2^(r-k+1) - 1.
        // The length of s_l...s_r is r - l + 1.
        // We need r - l + 1 = f(s_k...s_r).
        // Since s_k is the first '1', l <= k.
        // So r - l + 1 >= r - k + 1.
        // This means f(s_k...s_r) >= r - k + 1.
        // Also, f(s_k...s_r) <= 2^(r-k+1) - 1.
        // The maximum length of a substring we need to check is limited.
        // If r - k + 1 > 20 (approx), then 2^(r-k+1) - 1 is very large.
        // For example, if r - k + 1 = 20, 2^20 - 1 is about 10^6.
        // The maximum possible length of s is 2 * 10^5.
        // So, if r - k + 1 > 20, then f(s_k...s_r) will be much larger than n,
        // and thus much larger than any possible r - l + 1.
        // So we only need to consider substrings s_k...s_r where r - k + 1 is small, say up to 20.
        // This means k must be at least r - 19.
        // Let's use a slightly larger bound, say 60, to be safe, as the actual length is r-l+1.
        // The maximum value of r-l+1 is N.
        // If f(s_k...s_r) > N, then it cannot be equal to r-l+1.
        // 2^18 is about 2.6 * 10^5. So if r-k+1 > 18, f(s_k...s_r) can exceed N.
        // Let's iterate k from r down to max(0, r - 60) to cover all relevant lengths.

        long long current_val = 0;
        long long power_of_2 = 1; // Represents 2^(r-j)
        for (int k = r; k >= 0 && r - k + 1 <= 60; --k) { // Iterate k from r backwards
            if (s[k] == '1') {
                current_val += power_of_2;

                // Now current_val is f(s_k...s_r)
                // We need to find l such that r - l + 1 = current_val.
                // This means l = r + 1 - current_val.

                // Check if this l is valid:
                // 1. l >= 0 (start index must be non-negative)
                // 2. l <= k (s_k must be the first '1', so s_l...s_{k-1} must be all '0's)
                // 3. s_l...s_{k-1} must be all '0's.

                long long target_l = r + 1 - current_val;

                if (target_l >= 0 && target_l <= k) {
                    // Check condition 3: s_l...s_{k-1} must be all '0's.
                    // This means the number of leading zeros is k - target_l.
                    // We need to ensure there are no '1's in s_target_l...s_{k-1}.
                    // This is equivalent to checking if the count of '1's in s_target_l...s_{k-1} is 0.
                    // We can use the precomputed one_indices for this.

                    // Find the first '1' at or after target_l.
                    auto it = std::lower_bound(one_indices.begin(), one_indices.end(), target_l);

                    // If such a '1' exists and its index is less than k, then s_target_l...s_{k-1} contains a '1'.
                    if (it == one_indices.end() || *it >= k) {
                        // All characters from s_target_l to s_{k-1} are '0's.
                        // This means s_target_l...s_r is a good substring.
                        good_substrings_count++;
                    }
                }
            }
            // Update power_of_2 for the next iteration (k-1)
            // This is equivalent to power_of_2 *= 2, but we are going backwards.
            // So power_of_2 for s_k is 2^(r-k).
            // For s_{k-1}, it would be 2^(r-(k-1)) = 2^(r-k+1).
            // So we multiply by 2.
            // But we need to be careful about overflow if current_val gets too large.
            // The maximum value of current_val is N (2*10^5).
            // The maximum power_of_2 needed is 2^59 (for length 60). This fits in long long.
            // current_val itself can exceed N, but we only care if it's <= N.
            // If current_val exceeds N, then target_l will be negative, so it won't be counted.
            // So current_val won't overflow long long if we cap it at N+1.
            // However, the problem is that current_val is f(s_k...s_r), which can be large.
            // We need to check if current_val > N. If it is, then target_l will be negative,
            // or if target_l is positive, it will be too small (meaning too many leading zeros).
            // The condition target_l >= 0 implies current_val <= r + 1.
            // Since r+1 <= N, current_val will not exceed N.
            // So current_val will not overflow long long.
            if (k > 0) { // Avoid shifting for k=0 if we don't need it
                power_of_2 *= 2;
            }
        }
    }

    std::cout << good_substrings_count << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 2) { // Sequences of length 1 or 2 are always stable
        std::cout << 0 << "\n";
        for (int i = 0; i < n; ++i) {
            std::cout << a[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
        return 0;
    }

    std::vector<int> L(n, 0), R(n, 0);

    // Calculate L[i]: length of consecutive identical elements ending at i
    L[0] = 1;
    for (int i = 1; i < n; ++i) {
        if (a[i] == a[i - 1]) {
            L[i] = L[i - 1] + 1;
        } else {
            L[i] = 1;
        }
    }

    // Calculate R[i]: length of consecutive identical elements starting at i
    R[n - 1] = 1;
    for (int i = n - 2; i >= 0; --i) {
        if (a[i] == a[i + 1]) {
            R[i] = R[i + 1] + 1;
        } else {
            R[i] = 1;
        }
    }

    int max_k = 0;
    for (int i = 0; i < n; ++i) {
        if (a[i] == 0) { // Find max k for 0s
            if (i > 0 && a[i - 1] == 1) { // 10...
                max_k = std::max(max_k, (L[i] + 1) / 2);
            }
            if (i < n - 1 && a[i + 1] == 1) { // ...01
                max_k = std::max(max_k, (R[i] + 1) / 2);
            }
        } else { // Find max k for 1s
            if (i > 0 && a[i - 1] == 0) { // 01...
                max_k = std::max(max_k, (L[i] + 1) / 2);
            }
            if (i < n - 1 && a[i + 1] == 0) { // ...10
                max_k = std::max(max_k, (R[i] + 1) / 2);
            }
        }
    }

    std::cout << max_k << "\n";

    std::vector<int> b(n);
    b[0] = a[0];
    b[n - 1] = a[n - 1];

    for (int i = 1; i < n - 1; ++i) {
        if (a[i] == a[i - 1] && a[i] == a[i + 1]) { // 000 or 111
            b[i] = a[i];
        } else if (a[i - 1] == a[i + 1]) { // 010 or 101
            b[i] = a[i - 1]; // a[i-1] == a[i+1]
        } else { // 001, 011, 100, 110
            // This is the case where a[i-1] != a[i+1]
            // The median is a[i]
            b[i] = a[i];
        }
    }

    for (int i = 1; i < n - 1; ++i) {
        if (a[i] == 0) { // Current element is 0
            if (i > 0 && a[i - 1] == 1) { // 10...
                if (L[i] <= max_k) { // 10...0 (L[i] zeros)
                    b[i] = 1;
                }
            }
            if (i < n - 1 && a[i + 1] == 1) { // ...01
                if (R[i] <= max_k) { // 0...01 (R[i] zeros)
                    b[i] = 1;
                }
            }
        } else { // Current element is 1
            if (i > 0 && a[i - 1] == 0) { // 01...
                if (L[i] <= max_k) { // 01...1 (L[i] ones)
                    b[i] = 0;
                }
            }
            if (i < n - 1 && a[i + 1] == 0) { // ...10
                if (R[i] <= max_k) { // 1...10 (R[i] ones)
                    b[i] = 0;
                }
            }
        }
    }

    for (int i = 0; i < n; ++i) {
        std::cout << b[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    // For each bit position (0-9), track how it transforms 0 and 1.
    // state[bit_idx][0] = result if initial bit is 0
    // state[bit_idx][1] = result if initial bit is 1
    // Initially, if bit is 0, it stays 0. If bit is 1, it stays 1.
    std::vector<std::vector<int>> state(10, std::vector<int>(2));
    for (int i = 0; i < 10; ++i) {
        state[i][0] = 0; // 0 -> 0
        state[i][1] = 1; // 1 -> 1
    }

    for (int k = 0; k < n; ++k) {
        char op_char;
        int val;
        std::cin >> op_char >> val;

        for (int i = 0; i < 10; ++i) {
            int bit_val = (val >> i) & 1;
            if (op_char == '&') {
                state[i][0] &= bit_val;
                state[i][1] &= bit_val;
            } else if (op_char == '|') {
                state[i][0] |= bit_val;
                state[i][1] |= bit_val;
            } else { // '^'
                state[i][0] ^= bit_val;
                state[i][1] ^= bit_val;
            }
        }
    }

    // Now, determine the combined operations.
    // We need to find A, O, X such that:
    // ( ( ( (input & A) | O ) ^ X ) )
    // For each bit i:
    // If input_bit is 0: ( ( (0 & A_i) | O_i ) ^ X_i ) == state[i][0]
    // If input_bit is 1: ( ( (1 & A_i) | O_i ) ^ X_i ) == state[i][1]

    // Let's try to find A, O, X.
    // A_i: If A_i is 0, then (0 & A_i) is 0 and (1 & A_i) is 0.
    //      If A_i is 1, then (0 & A_i) is 0 and (1 & A_i) is 1.
    // This means A_i determines if the input bit is preserved (A_i=1) or forced to 0 (A_i=0) before OR/XOR.

    // We can construct the final A, O, X values bit by bit.
    int final_and_val = 1023; // Initialize to all 1s (no effect)
    int final_or_val = 0;     // Initialize to all 0s (no effect)
    int final_xor_val = 0;    // Initialize to all 0s (no effect)

    for (int i = 0; i < 10; ++i) {
        int s0 = state[i][0]; // Result for input bit 0
        int s1 = state[i][1]; // Result for input bit 1

        if (s0 == 0 && s1 == 0) {
            // Both 0 and 1 map to 0.
            // This means the bit must be forced to 0.
            // We can achieve this with '& 0'.
            final_and_val &= ~(1 << i); // Set i-th bit of final_and_val to 0
        } else if (s0 == 1 && s1 == 1) {
            // Both 0 and 1 map to 1.
            // This means the bit must be forced to 1.
            // We can achieve this with '| 1'.
            final_or_val |= (1 << i); // Set i-th bit of final_or_val to 1
        } else if (s0 == 0 && s1 == 1) {
            // 0 maps to 0, 1 maps to 1.
            // This means the bit is preserved.
            // No change needed for this bit by AND, OR, XOR.
            // (x & 1) | 0 ^ 0 = x
            // final_and_val already has 1 at this bit.
            // final_or_val already has 0 at this bit.
            // final_xor_val already has 0 at this bit.
        } else { // s0 == 1 && s1 == 0
            // 0 maps to 1, 1 maps to 0.
            // This means the bit is flipped.
            // We can achieve this with '^ 1'.
            final_xor_val |= (1 << i); // Set i-th bit of final_xor_val to 1
        }
    }

    std::vector<std::pair<char, int>> result_ops;

    // The order of operations matters.
    // A common canonical form is ( (x & A) | O ) ^ X.
    // Let's verify this form.
    // For each bit i:
    // If input_bit is 0:
    //   ( (0 & A_i) | O_i ) ^ X_i
    //   ( 0 | O_i ) ^ X_i
    //   O_i ^ X_i should be s0
    // If input_bit is 1:
    //   ( (1 & A_i) | O_i ) ^ X_i
    //   ( A_i | O_i ) ^ X_i should be s1

    // Let's re-derive A, O, X based on the canonical form.
    // For each bit i:
    // Let A_i, O_i, X_i be the i-th bits of final_and_val, final_or_val, final_xor_val.
    // We need to find A_i, O_i, X_i such that:
    // 1) O_i ^ X_i = s0
    // 2) (A_i | O_i) ^ X_i = s1

    // From (1), X_i = O_i ^ s0. Substitute into (2):
    // (A_i | O_i) ^ (O_i ^ s0) = s1

    // Case 1: s0 = 0, s1 = 0
    // O_i ^ X_i = 0  => X_i = O_i
    // (A_i | O_i) ^ O_i = 0
    // If O_i = 0: (A_i | 0) ^ 0 = 0 => A_i ^ 0 = 0 => A_i = 0. So (A_i, O_i, X_i) = (0,0,0)
    // If O_i = 1: (A_i | 1) ^ 1 = 0 => 1 ^ 1 = 0. This is always true. So (A_i, O_i, X_i) = (any,1,1)
    // To minimize operations, we prefer (0,0,0). This means A_i=0, O_i=0, X_i=0.
    // This corresponds to forcing the bit to 0.
    // (x & 0) | 0 ^ 0 = 0.
    // So, A_i = 0.

    // Case 2: s0 = 0, s1 = 1
    // O_i ^ X_i = 0  => X_i = O_i
    // (A_i | O_i) ^ O_i = 1
