int N;

// Function to compute the result for a given starting x.
// Returns {total_y_added, final_x_value}.
// total_y_added is the sum of a[x_curr] + a[x_temp] for all steps.
// final_x_value is the x value at termination.
std::pair<long long, long long> compute_path(long long curr_x) {
    // Check for termination conditions
    if (curr_x <= 0 || curr_x > N) {
        return {0, curr_x}; // No y added, x is the termination point
