    }
    if (visited[curr_x] == 1) { // Currently visiting, means cycle detected
        return {-1, -1}; // Indicate non-termination
    }

    visited[curr_x] = 1; // Mark as visiting

    long long val1 = A[curr_x];
    long long y_added_this_step = val1;

    long long x_temp = curr_x + val1;
    long long y_temp = y_added_this_step; // y_temp is just the y added in this step, not total y

