    }

    long long val2 = A[x_temp];
    y_added_this_step += val2;

    long long x_next = x_temp - val2;

    // Recursively compute the rest of the path
    std::pair<long long, long long> next_result = compute_path(x_next);

    long long total_y = -1;
    long long final_x = -1;

    if (next_result.first == -1) { // Path leads to non-termination
        total_y = -1;
        final_x = -1;
    } else {
        total_y = y_added_this_step + next_result.first;
        final_x = next_result.second;
    }

    visited[curr_x] = 2; // Mark as computed
    memo[curr_x] = {total_y, final_x};
    return memo[curr_x];
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::cin >> N;

    A.resize(N + 1);
    for (int i = 2; i <= N; ++i) {
        std::cin >> A[i];
    }

    // Initialize memoization table for x > 1
    memo.resize(N + 1);
    visited.resize(N + 1, 0);

    // Precompute results for all x from 2 to N.
    // This is done in reverse order to ensure dependencies are met,
    // or just iterate and let recursion handle it.
    // Iterating from N down to 2 might be slightly more efficient for cache,
    // but recursion with memoization handles any order.
    for (int i = 2; i <= N; ++i) {
        if (visited[i] == 0) { // If not yet computed
            compute_path(i);
        }
    }

    // Now, for each query (i from 1 to N-1):
    for (long long i = 1; i < N; ++i) {
        A[1] = i; // Set a[1] for the current query

        long long current_x = 1;
        long long current_y = 0;

        // Simulate the first step (from x=1)
        // This part cannot use memoization directly because A[1] changes.
        // We need to manually perform the first cycle and then use memoization for subsequent steps.

        // Step 2 from x=1
        long long val1 = A[current_x];
        current_x = current_x + val1;
        current_y = current_y + val1;

        // Check termination after step 2
        if (current_x <= 0 || current_x > N) {
            std::cout << current_y << "\n";
            continue; // Move to next query
        }

        // Step 3 from current_x (which is now 1 + A[1])
        long long val2 = A[current_x];
        current_y = current_y + val2;
        current_x = current_x - val2;

        // Now, current_x is the starting point for the next full cycle.
        // We can use the precomputed `memo` table for `current_x` if `current_x > 1`.
        // If `current_x == 1`, it means we've returned to the start, which implies a cycle.
        // If `current_x <= 0` or `current_x > N`, it means termination.

        if (current_x <= 0 || current_x > N) {
            std::cout << current_y << "\n";
        } else if (current_x == 1) {
            // If x returns to 1, and A[1] is positive, it will loop indefinitely.
            // A[1] is always positive (1 <= i <= N-1).
            std::cout << -1 << "\n";
        } else { // current_x > 1, use memoized results
            std::pair<long long, long long> result = memo[current_x];
            if (result.first == -1) { // Path from current_x leads to non-termination
                std::cout << -1 << "\n";
            } else {
                std::cout << current_y + result.first << "\n";
            }
        }
    }

    return 0;
}

