int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int T;
    std::cin >> T;
    while (T--) {
        int n;
        long long k;
        std::cin >> n >> k;
        std::vector<long long> a(n);
        long long min_val = k + 1; // Initialize with a value larger than any possible a_i
        int min_idx = -1;
        for (int i = 0; i < n; ++i) {
            std::cin >> a[i];
            if (a[i] < min_val) {
                min_val = a[i];
                min_idx = i;
            }
        }

        long long total_spells = 0;
        for (int i = 0; i < n; ++i) {
            if (i == min_idx) {
                continue; // Cannot copy a pile to itself
            }
            // For each other pile a[i], we can add min_val to it
            // as long as a[i] + min_val * num_adds <= k
            // num_adds <= (k - a[i]) / min_val
            if (min_val == 0) { // Should not happen based on constraints (a_i >= 1)
                // If min_val is 0, we can add it infinitely without changing the sum.
                // But problem constraints say a_i >= 1.
                // This branch is mostly for robustness, though not strictly needed.
                // If a_i >= 1, min_val >= 1.
            } else {
                total_spells += (k - a[i]) / min_val;
            }
        }
        std::cout << total_spells << "\n";
    }
    return 0;
}

