void solve() {
    int n, d;
    std::cin >> n >> d;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    long long current_a1 = a[0];
    long long remaining_days = d;

    for (int i = 1; i < n; ++i) {
        // Cost to move one haybale from pile i+1 (0-indexed i) to pile 1 is i days.
        // (Pile 1 is 0-indexed 0, Pile 2 is 0-indexed 1, ..., Pile n is 0-indexed n-1)
        // So, from pile (i+1) to pile 1, it takes i moves.
        int cost_per_haybale = i; 

        if (remaining_days >= cost_per_haybale) {
            // Calculate how many haybales can be moved from this pile
            // based on remaining days.
            long long haybales_can_move_by_days = remaining_days / cost_per_haybale;

            // We can move at most a[i] haybales from this pile.
            long long haybales_to_move = std::min((long long)a[i], haybales_can_move_by_days);

            current_a1 += haybales_to_move;
            remaining_days -= haybales_to_move * cost_per_haybale;
        } else {
            // Not enough days to move even one haybale from this pile.
            // Since we iterate from closest piles, we won't have enough days
            // for further piles either.
            break; 
        }
    }

    std::cout << current_a1 << std::endl;
}

