}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
    }

    // The problem statement guarantees that a solution exists.
    // A simple strategy that often works for such problems is to reverse the permutation.
    // Let p' be the reversed permutation of p.
    // p'_i = p_{n-i+1}
    // The adjacent sums for p are [p_1+p_2, p_2+p_3, ..., p_{n-1}+p_n].
    // The adjacent sums for p' are [p'_1+p'_2, p'_2+p'_3, ..., p'_{n-1}+p'_n].
    // Which are [p_n+p_{n-1}, p_{n-1}+p_{n-2}, ..., p_2+p_1].
    // These are exactly the same set of sums, just in reverse order.
    // Sorting them will yield the same fingerprint.
    // The only case where p' might be equal to p is if p is a palindrome.
    // However, for a permutation of distinct integers from 1 to n,
    // p can only be a palindrome if n=1 (not allowed, n>=2) or if n=2 and p=[1,2] or p=[2,1].
    // For n=2, if p=[1,2], p'=[2,1], which is different.
    // If p=[2,1], p'=[1,2], which is different.
    // For n > 2, a permutation of 1 to n cannot be a palindrome.
    // For example, if p_1 = 1, then p_n must be 1 for it to be a palindrome, but elements must be distinct.
    // If p_1 = k, then p_n must be k. But all elements are distinct.
    // The only way for p to be a palindrome is if p_i = p_{n-i+1} for all i.
    // This implies that if p_1 = x, then p_n = x. But all elements are distinct.
    // This means p_1 cannot be equal to p_n unless n=1.
    // So for n >= 2, p cannot be a palindrome.
    // Therefore, reversing p always yields a different permutation p'.
    // And F(p') will always be equal to F(p).

    std::reverse(p.begin(), p.end());

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;
}

