void solve() {
    std::string s, t;
    std::cin >> s >> t;

    // We need to check if there is at least one common character
    // that exists in both strings s and t.
    // If such a character 'c' exists, we can propagate 'c' throughout
    // string s to make s consist entirely of 'c's.
    // Similarly, we can propagate 'c' throughout string t to make t
    // consist entirely of 'c's.
    // After these operations, both s and t would be equal (e.g., "ccc...c").
    // If no common character exists, then it's impossible to make them equal.
    // For example, if s has only 'a's and t has only 'b's, they can never share a character.

    // A simple way to check for common characters is to use frequency arrays
    // or a boolean array for presence.

    std::vector<bool> s_has_char(26, false);
    for (char c : s) {
        s_has_char[c - 'a'] = true;
    }

    bool common_char_found = false;
    for (char c : t) {
        if (s_has_char[c - 'a']) {
            common_char_found = true;
            break;
        }
    }

    if (common_char_found) {
        std::cout << "YES\n";
    } else {
        std::cout << "NO\n";
    }
}

