#include <iostream>
#include <vector>
#include <algorithm> // For std::min

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 1) {
        std::cout << 0 << "\n";
        return;
    }

    int bad_prices_count = 0;
    int min_suffix_price = a[n - 1]; // Initialize with the last element

    // Iterate from right to left, starting from the second to last element
    // (index n-2) down to the first element (index 0).
    for (int i = n - 2; i >= 0; --i) {
        // If the current price a[i] is greater than the minimum price
        // found so far in the suffix a[i+1...n-1], then a[i] is a bad price.
        if (a[i] > min_suffix_price) {
            bad_prices_count++;
        } else {
            // If a[i] is not greater than min_suffix_price, it means
            // a[i] is less than or equal to all prices in a[i+1...n-1].
            // In this case, a[i] itself becomes the new minimum for the
            // suffix a[i...n-1].
            min_suffix_price = a[i];
        }
    }

    std::cout << bad_prices_count << "\n";
}

