int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        std::string s;
        std::cin >> s;
        int n = s.length();
        int max_dist = 0;
        int last_R_idx = -1; // Represents the last 'R' cell or the starting cell 0.
                             // A jump from 0 to any cell i <= d is possible.
                             // A jump from cell i (s[i-1]=='R') to any cell j in [i+1, min(n+1, i+d)] is possible.

        // We need to find the maximum distance between consecutive 'R' cells (or 0 and first 'R', or last 'R' and n+1).
        // The frog must be able to jump over any sequence of 'L's.
        // If the frog is at cell `prev_R_idx` (which is either 0 or an 'R' cell),
        // it needs to reach the next 'R' cell `curr_R_idx` or the target `n+1`.
        // The distance it needs to cover is `curr_R_idx - prev_R_idx`.
        // If `d` is chosen, it must be at least this distance.
        // So, we find the maximum such distance.

        // Consider the jump from 0 to the first 'R' cell or n+1 if no 'R's.
        // The distance is `first_R_idx - 0`.
        // If there are no 'R's, the frog must jump from 0 to n+1, distance `n+1`.

        // Iterate through the string to find 'R's.
        for (int i = 0; i < n; ++i) {
            if (s[i] == 'R') {
                // Current 'R' cell is i+1.
                // Distance from previous 'R' cell (or 0) to current 'R' cell.
                // The previous 'R' cell was at index `last_R_idx + 1`.
                // The current 'R' cell is at index `i + 1`.
                // The distance is `(i + 1) - (last_R_idx + 1) = i - last_R_idx`.
                max_dist = std::max(max_dist, i - last_R_idx);
                last_R_idx = i; // Update last_R_idx to the current 'R' cell's 0-based index.
            }
        }

        // Consider the jump from the last 'R' cell to n+1.
        // The last 'R' cell was at index `last_R_idx + 1`.
        // The target is `n + 1`.
        // The distance is `(n + 1) - (last_R_idx + 1) = n - last_R_idx`.
        max_dist = std::max(max_dist, n - last_R_idx);

        std::cout << max_dist << "\n";
    }
    return 0;
}

