int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    double h;
    std::cin >> n >> h;

    // The total area of the carrot is A = (1/2) * base * height = (1/2) * 1 * h = h/2.
    // Each of the n pieces should have an area of A_piece = A / n = (h/2) / n = h / (2n).

    // Consider a cut at distance x from the apex. This cut forms a smaller triangle
    // similar to the original carrot. If its height is x, its base will be x/h.
    // The area of this smaller triangle is A_x = (1/2) * (x/h) * x = x^2 / (2h).

    // The i-th cut (from the apex) is at distance x_i.
    // The area of the triangle formed by the i-th cut from the apex must be
    // i times the area of a single piece.
    // That is, A_{x_i} = i * A_piece = i * (h / (2n)).

    // So, x_i^2 / (2h) = i * (h / (2n))
    // x_i^2 = i * (h / (2n)) * (2h)
    // x_i^2 = i * h^2 / n
    // x_i = sqrt(i * h^2 / n)
    // x_i = h * sqrt(i / n)

    std::cout << std::fixed << std::setprecision(12);

    for (int i = 1; i < n; ++i) {
        double x_i = h * std::sqrt(static_cast<double>(i) / n);
        std::cout << x_i << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

