#include <iostream>
#include <algorithm>

// Function to check if it's possible to form 'k' teams
bool check(long long k, long long c, long long m, long long x) {
    // To form k teams, we need at least k coders and k mathematicians.
    // If we don't have enough of either, we can't form k teams.
    if (c < k || m < k) {
        return false;
    }

    // After assigning one coder and one mathematician to each of the k teams,
    // we have used k coders and k mathematicians.
    // Remaining students:
    // c_rem = c - k
    // m_rem = m - k
    // x_rem = x (no change to x students yet)

    // Each of the k teams still needs one more member.
    // So, we need k additional members in total.
    // These k additional members can come from:
    // 1. Remaining coders (c - k)
    // 2. Remaining mathematicians (m - k)
    // 3. Students with no specialization (x)

    // The total number of available students for these k remaining spots is:
    // (c - k) + (m - k) + x

    // If this sum is less than k, we cannot fill all the remaining spots.
    return (c - k) + (m - k) + x >= k;
}

int main() {
    // Optimize C++ standard streams for faster input/output.
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int q;
    std::cin >> q; // Read the number of queries

    while (q--) {
        long long c, m, x;
        std::cin >> c >> m >> x; // Read c, m, x for each query

        // The maximum possible number of teams is limited by:
        // 1. The number of coders (c)
        // 2. The number of mathematicians (m)
        // 3. The total number of students divided by 3 ((c + m + x) / 3)
        // So, the upper bound for binary search can be min(c, m, (c + m + x) / 3).
        // A simpler safe upper bound is min(c, m) or even just (c + m + x).
        // Since k cannot exceed c or m, min(c, m) is a good practical upper bound.
        // Also, k cannot exceed (c+m+x)/3.
        // So, a tight upper bound is std::min({c, m, (c + m + x) / 3}).
        // Let's use a slightly looser but still correct upper bound for simplicity:
        // The maximum number of teams is at most min(c, m) because each team needs at least one coder and one mathematician.
        // Also, the maximum number of teams is at most (c + m + x) / 3 because each team needs 3 members.
        // So, the absolute maximum is min(c, m, (c + m + x) / 3).
        // Let's use min(c, m) as a practical upper bound for binary search, as the check function already handles the total student count implicitly.
        long long low = 0;
        long long high = std::min({c, m, (c + m + x) / 3}); // A tighter upper bound
        long long ans = 0;

        // Binary search for the maximum k
        while (low <= high) {
            long long mid = low + (high - low) / 2;
            if (check(mid, c, m, x)) {
                ans = mid; // It's possible to form 'mid' teams, try for more
                low = mid + 1;
            } else {
                high = mid - 1; // Not possible, need fewer teams
            }
        }
        std::cout << ans << "\n"; // Print the result for the current query
    }

    return 0;
}

