int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, k;
    std::cin >> n >> k;
    std::string s;
    std::cin >> s;

    std::string result = "";
    int open_count = 0;
    int close_count = 0;
    int balance = 0;

    for (char c : s) {
        if (result.length() == k) {
            break;
        }

        if (c == '(') {
            // If we still need open brackets and adding one won't exceed k/2
            if (open_count < k / 2) {
                result += '(';
                open_count++;
                balance++;
            }
        } else { // c == ')'
            // If we still need close brackets, and we have an open bracket to match,
            // and adding one won't exceed k/2
            if (close_count < k / 2 && balance > 0) {
                result += ')';
                close_count++;
                balance--;
            }
        }
    }

    std::cout << result << std::endl;

    return 0;
}

