int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        long long n, m;
        std::cin >> n >> m;

        long long count = n / m; // Number of multiples of m up to n

        if (count == 0) {
            std::cout << 0 << "\n";
            continue;
        }

        // Calculate the sum of last digits for one full cycle (10 multiples)
        // The last digits of k*m are (k*m) % 10.
        // This sequence is periodic with a period of at most 10.
        // Specifically, (k*m)%10 for k=1..10 will cover one full cycle.
        // (1*m)%10, (2*m)%10, ..., (10*m)%10
        long long sum_of_first_10_last_digits = 0;
        for (int i = 1; i <= 10; ++i) {
            sum_of_first_10_last_digits += (static_cast<long long>(i) * m) % 10;
        }

        // Number of full cycles of 10 multiples
        long long num_full_cycles = count / 10;
        long long total_sum = num_full_cycles * sum_of_first_10_last_digits;

        // Remaining multiples after full cycles
        long long remaining_multiples = count % 10;
        for (long long i = 1; i <= remaining_multiples; ++i) {
            total_sum += (i * m) % 10;
        }

        std::cout << total_sum << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    std::vector<int> pos(n + 1); // pos[val] stores the 0-indexed position of val in p
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
        pos[p[i]] = i;
    }

    std::string result = "";
    int current_min_idx = pos[1];
    int current_max_idx = pos[1];

    for (int m = 1; m <= n; ++m) {
        // For m=1, the segment is just [1].
        // current_min_idx and current_max_idx are already initialized to pos[1].
        // The length is 1. min_val is 1, max_val is 1.
        // So, m=1 is always beautiful.

        // For m > 1, we consider the number 'm'.
        // We need to expand the current segment [current_min_idx, current_max_idx]
        // to include 'm' (which is at pos[m]).
        // The new segment must cover all numbers from 1 to m.
        // This means the new segment must span from min(current_min_idx, pos[m])
        // to max(current_max_idx, pos[m]).
        current_min_idx = std::min(current_min_idx, pos[m]);
        current_max_idx = std::max(current_max_idx, pos[m]);

        // A segment p[current_min_idx ... current_max_idx] contains all numbers
        // from 1 to m if and only if its length is exactly m.
        // The length of this segment is (current_max_idx - current_min_idx + 1).
        if (current_max_idx - current_min_idx + 1 == m) {
            result += '1';
        } else {
            result += '0';
        }
    }
    std::cout << result << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

