void solve() {
    int n;
    std::cin >> n;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n == 1) {
        std::cout << "Yes\n";
        return;
    }

    // Calculate prefix_min_ops
    // prefix_min_ops[i] stores the minimum value a[i] must be reduced to
    // to satisfy a[0] < a[1] < ... < a[i]
    // Specifically, a[i] must be at least i.
    // If a[i] < i, it's impossible to make a[i] = i.
    // If a[i] >= i, we can make a[i] = i.
    // So, we need a[i] >= i for all i in the increasing prefix.
    // The actual value we need to check is a[i] >= i.
    // We can stop increasing prefix if a[i] < i.
    int left_reach = 0;
    for (int i = 0; i < n; ++i) {
        if (a[i] >= i) {
            left_reach = i;
        } else {
            break;
        }
    }

    // Calculate suffix_min_ops
    // suffix_min_ops[i] stores the minimum value a[i] must be reduced to
    // to satisfy a[i] > a[i+1] > ... > a[n-1]
    // Specifically, a[i] must be at least (n-1-i).
    // If a[i] < (n-1-i), it's impossible to make a[i] = (n-1-i).
    // If a[i] >= (n-1-i), we can make a[i] = (n-1-i).
    // So, we need a[i] >= (n-1-i) for all i in the decreasing suffix.
    // We can stop decreasing suffix if a[i] < (n-1-i).
    int right_reach = n - 1;
    for (int i = n - 1; i >= 0; --i) {
        if (a[i] >= (n - 1 - i)) {
            right_reach = i;
        } else {
            break;
        }
    }

    // If there is any k such that left_reach >= k and right_reach <= k,
    // then it's possible.
    // This means there is an overlap between the indices reachable from left
    // and indices reachable from right.
    // The condition is simply left_reach >= right_reach.
    if (left_reach >= right_reach) {
        std::cout << "Yes\n";
    } else {
        std::cout << "No\n";
    }
}

