int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    long long s;
    std::cin >> n >> s;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    std::sort(a.begin(), a.end());

    long long operations = 0;
    int mid_idx = n / 2; // (n-1)/2 for 0-indexed array

    // Operations for elements smaller than s that must be >= s
    // These are elements a[0]...a[mid_idx-1] that are > s
    // Or elements a[mid_idx] that is > s
    // Or elements a[mid_idx+1]...a[n-1] that are > s
    // This logic is simpler:
    // All elements a[i] for i < mid_idx must be <= s.
    // If a[i] > s, we must decrease it to s.
    // All elements a[i] for i > mid_idx must be >= s.
    // If a[i] < s, we must increase it to s.
    // The median element a[mid_idx] must be exactly s.

    // Cost for the median element itself
    operations += std::abs(a[mid_idx] - s);

    // Cost for elements to the left of median (indices 0 to mid_idx-1)
    // These elements must be <= s. If a[i] > s, we must decrease it to s.
    for (int i = 0; i < mid_idx; ++i) {
        if (a[i] > s) {
            operations += (a[i] - s);
        }
    }

    // Cost for elements to the right of median (indices mid_idx+1 to n-1)
    // These elements must be >= s. If a[i] < s, we must increase it to s.
    for (int i = mid_idx + 1; i < n; ++i) {
        if (a[i] < s) {
            operations += (s - a[i]);
        }
    }

    std::cout << operations << std::endl;

    return 0;
}

