struct Element {
    long long value;
    int original_index;
};

bool compareElements(const Element& a, const Element& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int m;
    std::cin >> m;

    std::vector<Element> a_elements(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> a_elements[i].value;
        a_elements[i].original_index = i; // Not strictly needed for A, but good practice
    }

    std::vector<Element> b_elements(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> b_elements[i].value;
        b_elements[i].original_index = i;
    }

    // Sort A in ascending order
    std::sort(a_elements.begin(), a_elements.end(), compareElements);

    // Sort B in ascending order based on B_i
    std::sort(b_elements.begin(), b_elements.end(), compareElements);

    // Create the result array A'
    std::vector<long long> a_prime(m);

    // The strategy is to assign the largest A_i to the B_j that results in the largest F value.
    // F(n, k) = (n+1) / (k+1).
    // To maximize sum( (A'_i+1) / (B_i+1) ), we should pair large (A'_i+1) with small (B_i+1).
    // This means pairing large A'_i with small B_i.
    // So, sort A ascending, sort B ascending.
    // The largest A_i (from sorted A) should be paired with the smallest B_i (from sorted B).
    // The second largest A_i should be paired with the second smallest B_i, and so on.
    // This means if sorted A is A_0, A_1, ..., A_{m-1} and sorted B is B_0, B_1, ..., B_{m-1},
    // then A_{m-1} is paired with B_0, A_{m-2} with B_1, ..., A_0 with B_{m-1}.
    // The original index of B_j is b_elements[j].original_index.
    // So, a_prime[b_elements[j].original_index] = a_elements[m-1-j].value.

    for (int i = 0; i < m; ++i) {
        // a_elements[m - 1 - i].value is the i-th largest value from original A.
        // b_elements[i].original_index is the original position of the i-th smallest B value.
        a_prime[b_elements[i].original_index] = a_elements[m - 1 - i].value;
    }

    for (int i = 0; i < m; ++i) {
        std::cout << a_prime[i] << (i == m - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

