// Function to check if a prefix of length `len` is a permutation
// It uses a frequency array and checks max element.
bool is_permutation_prefix(int len, const std::vector<int>& a, const std::vector<int>& max_prefix_val, const std::vector<int>& freq_prefix) {
    if (len == 0) return false; // Permutation length must be non-zero
    if (max_prefix_val[len - 1] != len) return false; // Max element must be equal to length
    if (freq_prefix[len] != 1) return false; // Check if 'len' appears exactly once
    return true;
}

// Function to check if a suffix of length `len` is a permutation
// It uses a frequency array and checks max element.
bool is_permutation_suffix(int len, int n, const std::vector<int>& a, const std::vector<int>& max_suffix_val, const std::vector<int>& freq_suffix) {
    if (len == 0) return false; // Permutation length must be non-zero
    if (max_suffix_val[n - len] != len) return false; // Max element must be equal to length
    if (freq_suffix[len] != 1) return false; // Check if 'len' appears exactly once
    return true;
}

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    // Precompute prefix properties
    std::vector<int> max_prefix_val(n);
    std::vector<int> freq_prefix_count(n + 1, 0); // Frequencies for elements 1 to n
    std::vector<int> distinct_prefix_count(n, 0); // Number of distinct elements in prefix

    int current_max = 0;
    int current_distinct = 0;
    for (int i = 0; i < n; ++i) {
        current_max = std::max(current_max, a[i]);
        max_prefix_val[i] = current_max;

        if (freq_prefix_count[a[i]] == 0) {
            current_distinct++;
        }
        freq_prefix_count[a[i]]++;
        distinct_prefix_count[i] = current_distinct;
    }

    // Precompute suffix properties
    std::vector<int> max_suffix_val(n);
    std::fill(freq_prefix_count.begin(), freq_prefix_count.end(), 0); // Reset for suffix
    std::vector<int> distinct_suffix_count(n, 0); // Number of distinct elements in suffix

    current_max = 0;
    current_distinct = 0;
    for (int i = n - 1; i >= 0; --i) {
        current_max = std::max(current_max, a[i]);
        max_suffix_val[i] = current_max;

        if (freq_prefix_count[a[i]] == 0) {
            current_distinct++;
        }
        freq_prefix_count[a[i]]++;
        distinct_suffix_count[i] = current_distinct;
    }

    std::vector<std::pair<int, int>> results;

    // Iterate through all possible split points l1
    // l1 ranges from 1 to n-1 (since l2 must be at least 1)
    for (int l1 = 1; l1 < n; ++l1) {
        int l2 = n - l1;

        // Check if prefix a[0...l1-1] is a permutation of length l1
        bool p1_is_perm = (max_prefix_val[l1 - 1] == l1) && (distinct_prefix_count[l1 - 1] == l1);

        // Check if suffix a[l1...n-1] is a permutation of length l2
        bool p2_is_perm = (max_suffix_val[l1] == l2) && (distinct_suffix_count[l1] == l2);

        if (p1_is_perm && p2_is_perm) {
            results.push_back({l1, l2});
        }
    }

    std::cout << results.size() << "\n";
    for (const auto& p : results) {
        std::cout << p.first << " " << p.second << "\n";
    }
}

