long long solve() {
    long long n;
    std::cin >> n;

    long long chanek_score = 0;
    long long opponent_score = 0;
    bool chanek_turn = true;

    while (n > 0) {
        if (chanek_turn) {
            // Mr. Chanek's turn
            if (n % 2 == 1) {
                // N is odd. Must take 1.
                chanek_score += 1;
                n -= 1;
            } else {
                // N is even. Can take 1 or N/2.
                // Option 1: Take 1 coin.
                // Remaining coins: N-1. Opponent's turn.
                // Opponent will try to maximize their score from N-1.
                // If N-1 is odd, opponent takes 1.
                // If N-1 is even, opponent can take 1 or (N-1)/2.
                // This path is complex. Let's analyze the N/2 move.

                // If N is even, consider taking N/2.
                // This is generally a good move if N/2 is large.
                // The game state becomes N/2.
                // The opponent will then play optimally from N/2.

                // Let's consider the two options for Chanek:
                // 1. Take 1 coin:
                //   Chanek gets 1. N becomes N-1. Opponent's turn.
                //   If N-1 is odd, opponent takes 1. N becomes N-2. Chanek's turn.
                //   If N-1 is even, opponent can take 1 or (N-1)/2.
                //   This path is hard to evaluate without recursion.

                // 2. Take N/2 coins:
                //   Chanek gets N/2. N becomes N/2. Opponent's turn.

                // The key insight for optimal play on even N is often related to powers of 2.
                // If N is a power of 2 (N = 2^k, k > 0):
                //   Chanek takes N/2. N becomes N/2.
                //   Opponent takes (N/2)/2 = N/4. N becomes N/4.
                //   ...
                //   This continues until N becomes 1.
                //   Chanek gets N/2 + N/8 + N/32 + ...
                //   Opponent gets N/4 + N/16 + N/64 + ...
                //   Total coins taken by Chanek: N/2 * (1 + 1/4 + 1/16 + ...) = N/2 * (1 / (1 - 1/4)) = N/2 * (4/3) = 2N/3.
                //   Total coins taken by Opponent: N/4 * (1 + 1/4 + 1/16 + ...) = N/4 * (4/3) = N/3.
                //   This strategy gives Chanek 2N/3 and Opponent N/3.
                //   If Chanek takes 1 instead, N becomes N-1 (odd). Opponent takes 1. N becomes N-2.
                //   This seems worse for Chanek if N is a power of 2.

                // What if N is even but not a power of 2?
                // N = 2^k * M, where M is odd and M > 1.
                // If Chanek takes N/2: N becomes N/2 = 2^(k-1) * M.
                // If Chanek takes 1: N becomes N-1 (odd).

                // Consider the strategy:
                // If N is odd, take 1.
                // If N is even:
                //   Find the largest power of 2 that divides N. Let N = 2^k * M where M is odd.
                //   If M = 1 (N is a power of 2), take N/2.
                //   If M > 1 (N is even but not a power of 2):
                //     If Chanek takes N/2, the remaining coins are N/2.
                //     If Chanek takes 1, the remaining coins are N-1 (odd).
                //     If Chanek takes 1, N becomes N-1. Opponent's turn. Opponent takes 1. N becomes N-2. Chanek's turn.
                //     This means Chanek gets 1, Opponent gets 1. Total 2 coins removed.
                //     If Chanek takes N/2, Chanek gets N/2. N becomes N/2. Opponent's turn.
                //     The opponent will then face N/2.
                //     The opponent will also follow this strategy.
                //     If N/2 is odd, opponent takes 1.
                //     If N/2 is even, opponent takes N/4 (if N/2 is power of 2) or 1 (if N/2 is even, not power of 2, and 1 is better).

                // Let's try a greedy approach based on the example and common patterns:
                // If N is odd, take 1.
                // If N is even:
                //   If N is a power of 2 (e.g., 2, 4, 8, 16, ...), take N/2.
                //   If N is even but not a power of 2 (e.g., 6, 10, 12, 14, ...), take 1.
                // Why? If N is even and not a power of 2, N = 2^k * M where M > 1 is odd.
                // If Chanek takes N/2, N becomes 2^(k-1) * M.
                // If Chanek takes 1, N becomes 2^k * M - 1 (odd). Opponent takes 1. N becomes 2^k * M - 2.
                // This strategy seems to be the one that maximizes the current player's score.

                // Let's test this strategy:
                // N=5: Chanek (odd) takes 1. C=1, O=0, N=4.
                // N=4: Opponent (even, power of 2) takes 4/2=2. C=1, O=2, N=2.
                // N=2: Chanek (even, power of 2) takes 2/2=1. C=2, O=2, N=1.
                // N=1: Opponent (odd) takes 1. C=2, O=3, N=0.
                // Chanek gets 2. Matches example.

                // N=6: Chanek (even, not power of 2) takes 1. C=1, O=0, N=5.
                // N=5: Opponent (odd) takes 1. C=1, O=1, N=4.
                // N=4: Chanek (even, power of 2) takes 4/2=2. C=3, O=1, N=2.
                // N=2: Opponent (even, power of 2) takes 2/2=1. C=3, O=2, N=1.
                // N=1: Chanek (odd) takes 1. C=4, O=2, N=0.
                // Chanek gets 4. Matches example.

                // This strategy seems to work for the examples.
                // Let's formalize the "power of 2" check:
                // A number X is a power of 2 if (X > 0) and ((X & (X - 1)) == 0).

                if ((n & (n - 1)) == 0) { // N is a power of 2
                    chanek_score += n / 2;
                    n /= 2;
                } else { // N is even but not a power of 2
                    chanek_score += 1;
                    n -= 1;
                }
            }
        } else {
            // Opponent's turn
            if (n % 2 == 1) {
                opponent_score += 1;
                n -= 1;
            } else {
                if ((n & (n - 1)) == 0) { // N is a power of 2
                    opponent_score += n / 2;
                    n /= 2;
                } else { // N is even but not a power of 2
                    opponent_score += 1;
                    n -= 1;
                }
            }
        }
        chanek_turn = !chanek_turn;
    }
    return chanek_score;
}

