void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 2) {
        std::cout << 0 << std::endl;
        return;
    }

    // Find the rightmost index `p` such that a[p...n-1] is non-decreasing.
    // This means a[p] <= a[p+1] <= ... <= a[n-1].
    // If we remove a prefix of length `p`, the remaining array starts with a[p].
    // We are looking for the smallest `p` such that a[p...n-1] is good.
    // The maximum possible `p` is `n-1` (array [a[n-1]] is good).
    // The minimum possible `p` is `0`.

    // Step 1: Find the longest suffix that is non-decreasing.
    // This suffix is a candidate for being part of the "right side" of the good array.
    int p_suffix_inc = n - 1;
    while (p_suffix_inc > 0 && a[p_suffix_inc - 1] <= a[p_suffix_inc]) {
        p_suffix_inc--;
    }
    // After this loop, a[p_suffix_inc ... n-1] is non-decreasing.
    // If p_suffix_inc is 0, the whole array is non-decreasing.

    // Step 2: Find the longest suffix that is non-increasing.
    // This suffix is a candidate for being part of the "left side" of the good array.
    int p_suffix_dec = n - 1;
    while (p_suffix_dec > 0 && a[p_suffix_dec - 1] >= a[p_suffix_dec]) {
        p_suffix_dec--;
    }
    // After this loop, a[p_suffix_dec ... n-1] is non-increasing.
    // If p_suffix_dec is 0, the whole array is non-increasing.

    // The "pivot" point for the good array structure must be at or before min(p_suffix_inc, p_suffix_dec).
    // Let `pivot_idx` be the index where the "good" suffix starts.
    // We need to find the smallest `pivot_idx` such that `a[pivot_idx ... n-1]` is good.
    // The elements `a[pivot_idx ... p_suffix_dec-1]` must be picked from the left.
    // The elements `a[p_suffix_dec ... n-1]` must be picked from the right.
    // The elements `a[p_suffix_inc ... n-1]` must be picked from the right.

    // The structure of a good array is:
    // [L_k, L_{k-1}, ..., L_1, M_1, M_2, ..., M_j, R_1, R_2, ..., R_l]
    // where L_i are picked from left, R_i are picked from right, M_i are picked from left/right.
    // The key observation is that the elements picked from the left form a prefix of the original array,
    // and elements picked from the right form a suffix of the original array.
    // The remaining elements in the middle must be empty.
    // So, the elements picked from the left are `a[start_idx], a[start_idx+1], ..., a[k-1]`
    // and elements picked from the right are `a[j+1], ..., a[n-1]`.
    // The elements `a[k], ..., a[j]` are never picked. This is not how it works.

    // The problem states: "select either the first or the last element of b, remove it from b, and append it to the end of the array c."
    // This means the elements remaining in `b` always form a contiguous subarray.
    // So, if we have `b = [b_0, ..., b_{m-1}]`, we pick `b_0` or `b_{m-1}`.
    // The elements that are picked from the original array `a` (after removing prefix)
    // will be `a[k], a[k+1], ..., a[n-1]`.
    // The elements `a[k], ..., a[p_suffix_dec-1]` must be picked from the left.
    // The elements `a[p_suffix_dec], ..., a[n-1]` must be picked from the right.
    // This is the structure: `a[k], a[k+1], ..., a[p_suffix_dec-1]` (left part, non-decreasing when picked in reverse order)
    // and `a[p_suffix_dec], ..., a[n-1]` (right part, non-decreasing when picked in order).
    // The elements `a[p_suffix_dec], ..., a[n-1]` are already non-increasing.
    // So, if we pick them from right to left, they will be non-decreasing.
    // Example: `[4,3,3,8,4,5,2]`. `p_suffix_dec = 6` (index of 2). `[2]` is non-increasing.
    // `p_suffix_dec = 5` (index of 5). `[5,2]` is not non-increasing.
    // `p_suffix_dec = 4` (index of 4). `[4,5,2]` is not non-increasing.
    // `p_suffix_dec = 3` (index of 8). `[8,4,5,2]` is not non-increasing.
    // `p_suffix_dec = 2` (index of 3). `[3,8,4,5,2]` is not non-increasing.
    // `p_suffix_dec = 1` (index of 3). `[3,3,8,4,5,2]` is not non-increasing.
    // `p_suffix_dec = 0` (index of 4). `[4,3,3,8,4,5,2]` is not non-increasing.

    // Let's re-evaluate the structure of a good array.
    // The elements picked form a sequence `c`.
    // The elements `b_0, ..., b_{m-1}` are picked.
    // The elements picked from the left form a prefix `b_0, b_1, ..., b_k`.
    // The elements picked from the right form a suffix `b_{m-1}, b_{m-2}, ..., b_j`.
    // The remaining elements `b_{k+1}, ..., b_{j-1}` are never picked. This is wrong.
    // All elements are picked.
    // The elements picked from the left are `b_0, b_1, ..., b_k`.
    // The elements picked from the right are `b_{m-1}, b_{m-2}, ..., b_j`.
    // The elements `b_{k+1}, ..., b_{j-1}` must be empty.
    // This means the elements picked from the left are `b_0, ..., b_k` and from the right are `b_{k+1}, ..., b_{m-1}`.
    // This is not correct. The example `[1,2,3,4,4,2,1]` shows `b_1`, then `b_m`, then `b_{m-1}`, then `b_2`.
    // This means the elements picked from the left are `b_0, b_1, ..., b_k` and from the right are `b_{m-1}, b_{m-2}, ..., b_j`.
    // The elements `b_{k+1}, ..., b_{j-1}` are picked in some order.
    // This implies that the elements `b_0, ..., b_k` are picked in increasing order of index.
    // And `b_{m-1}, ..., b_j` are picked in decreasing order of index.
    // The elements `b_{k+1}, ..., b_{j-1}` are picked in some order.
    // This is equivalent to saying that the array `b` can be split into two parts:
    // `b[0...k]` and `b[k+1...m-1]`.
    // We pick elements from `b[0...k]` from left to right.
    // We pick elements from `b[k+1...m-1]` from right to left.
    // The elements picked from `b[0...k]` must be non-decreasing.
    // The elements picked from `b[k+1...m-1]` must be non-decreasing when picked from right to left.
    // This means `b[k+1] <= b[k+2] <= ... <= b[m-1]` is NOT what we want.
    // We want `b[m-1] >= b[m-2] >= ... >= b[k+1]`.
    // And the last element picked from `b[0...k]` must be <= the first element picked from `b[k+1...m-1]`.
    // This is the "mountain" or "valley" structure.

    // A good array `b` has the property that it can be split into two parts:
    // `b[0...k]` and `b[k+1...m-1]` (for some `k` from -1 to `m-1`).
    // The elements `b[0], ..., b[k]` are picked from left to right.
    // The elements `b[m-1], ..., b[k+1]` are picked from right to left.
    // The resulting sequence `c` is `[b_0, ..., b_k, b_{m-1}, b_{m-2}, ..., b_{k+1}]` (this is one possible order).
    // This means `b_0 <= b_1 <= ... <= b_k` AND `b_{m-1} >= b_{m-2} >= ... >= b_{k+1}`.
    // And `b_k <= b_{m-1}`.
    // This is the "valley" structure: `b_0 <= b_1 <= ... <= b_k >= b_{k+1} >= ... >= b_{m-1}`.
    // The elements are picked from the ends.
    // The elements picked from the left form a non-decreasing sequence.
    // The elements picked from the right form a non-decreasing sequence.
    // The last element picked from the left must be <= the first element picked from the right.

    // Let's consider the suffix `a[i...n-1]`.
    // We need to find the smallest `i` such that `a[i...n-1]` is good.
    // A good array `b` of length `m` can be formed by picking elements from its ends.
    // The elements picked from the left form a prefix `b[0], ..., b[L-1]`.
    // The elements picked from the right form a suffix `b[R], ..., b[m-1]`.
    // The elements `b[L], ..., b[R-1]` are picked in some order.
    // This is the key: the elements `b[L], ..., b[R-1]` must be picked from the ends of the *remaining* array.
    // This means that the elements `b[L], ..., b[R-1]` must form a "valley" or "mountain" shape.
    // Specifically, the elements `b[L], ..., b[R-1]` must be picked such that they form a non-decreasing sequence.
    // This implies that `b[L], ..., b[R-1]` must be a "valley" shape:
    // `b[L] >= b[L+1] >= ... >= b_peak <= ... <= b[R-1]`. This is not right.

    // The definition of a good array is that it can be reduced to an empty array by repeatedly taking an end element and appending it to `c`, such that `c` is non-decreasing.
    // This means that at any point, if the current array is `[x_1, ..., x_k]`, we must pick either `x_1` or `x_k`.
    // Let `last_c_val` be the last element added to `c`.
    // If we pick `x_1`, then `x_1 >= last_c_val`.
    // If we pick `x_k`, then `x_k >= last_c_val`.
    // We want to find the smallest `i` such that `a[i...n-1]` is good.
    // Let `b = a[i...n-1]`.
    // The elements `a[p_suffix_dec ... n-1]` are non-increasing.
    // If we pick them from right to left, they form a non-decreasing sequence.
    // `a[n-1], a[n-2], ..., a[p_suffix_dec]`.
    // The elements `a[p_suffix_inc ... n-1]` are non-decreasing.
    // If we pick them from left to right, they form a non-decreasing sequence.
    // `a[p_suffix_inc], a[p_suffix_inc+1], ..., a[n-1]`.

    // The structure of a good array `b` is that it must be a "valley" shape.
    // That is, there exists an index `k` such that `b_0 <= b_1 <= ... <= b_k` and `b_k >= b_{k+1} >= ... >= b_{m-1}`.
    // This is because we can pick `b_0, b_1, ..., b_k` from the left, and then `b_{m-1}, b_{m-2}, ..., b_{k+1}` from the right.
    // The resulting `c` would be `[b_0, ..., b_k, b_{m-1}, ..., b_{k+1}]`.
    // For `c` to be non-decreasing, we need `b_0 <= ... <= b_k` and `b_{m-1} >= ... >= b_{k+1}`.
    // And `b_k <= b_{m-1}`.
    // This is the condition for a "good" array.

    // So, we need to find the smallest `i` such that `a[i...n-1]` forms a "valley".
    // Let `b = a[i...n-1]`.
    // We need to find `k` such that `b[0...k]` is non-decreasing and `b[k...m-1]` is non-increasing.
    // This means `a[i] <= a[i+1] <= ... <= a[i+k]` and `a[i+k] >= a[i+k+1] >= ... >= a[n-1]`.

    // Let's find the rightmost peak.
    // `p_suffix_dec` is the first index from the right such that `a[p_suffix_dec-1] < a[p_suffix_dec]`.
    // So `a[p_suffix_dec ... n-1]` is non-increasing.
    // `p_suffix_inc` is the first index from the right such that `a[p_suffix_inc-1] > a[p_suffix_inc]`.
    // So `a[p_suffix_inc ... n-1]` is non-decreasing.

    // The "valley" structure means:
    // `a[i] <= a[i+1] <= ... <= a[peak_idx]`
    // `a[peak_idx] >= a[peak_idx+1] >= ... >= a[n-1]`
    // The `peak_idx` must be somewhere in `[i, n-1]`.

    // We are looking for the smallest `i`.
    // The suffix `a[p_suffix_dec ... n-1]` is non-increasing.
    // This means `a[p_suffix_dec] >= a[p_suffix_dec+1] >= ... >= a[n-1]`.
    // This suffix can be picked from right to left to form a non-decreasing sequence.
    // So, `a[p_suffix_dec ... n-1]` is a good array.
    // The elements `a[p_suffix_dec ... n-1]` form the right part of the valley.
    // Now we need to find the left part of the valley.
    // We need to find the smallest `i` such that `a[i] <= a[i+1] <= ... <= a[p_suffix_dec-1]`
    // and `a[p_suffix_dec-1] >= a[p_suffix_dec]`.
    // This is not quite right. The `peak_idx` can be anywhere.

    // Let's consider the example `[1, 2, 3, 4, 4, 2, 1]`.
    // `n=7`.
    // `p_suffix_dec`:
    // `a[6]=1`. `a[5]=2`. `a[5] > a[6]`. `p_suffix_dec` is 6. `[1]` is non-increasing.
    // `a[4]=4`. `a[3]=4`. `a[3] >= a[4]`.
