// Function to convert a number to its parity pattern string
std::string get_parity_pattern(long long n) {
    std::string pattern_str = "";
    if (n == 0) {
        pattern_str = "0";
    } else {
        while (n > 0) {
            if ((n % 10) % 2 == 0) {
                pattern_str += '0';
            } else {
                pattern_str += '1';
            }
            n /= 10;
        }
    }
    // Pad with leading zeros to a fixed length (e.g., 18 for 10^18-1)
    // The problem states "If the pattern is shorter than this integer, it's supplemented with 0-s from the left."
    // and "if the integer is shorter than the pattern its decimal notation is supplemented with the 0-s from the left."
    // This implies we should normalize both to a common length, and 0s are even.
    // So, we pad with '0's (even parity) to the left.
    // Since we build the string from right to left, we append '0's.
    while (pattern_str.length() < 18) { // Max 18 digits for 10^18-1
        pattern_str += '0';
    }
    return pattern_str;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int t;
    std::cin >> t;

    std::map<std::string, int> counts;

    for (int i = 0; i < t; ++i) {
        char type;
        std::cin >> type;

        if (type == '+') {
            long long a;
            std::cin >> a;
            counts[get_parity_pattern(a)]++;
        } else if (type == '-') {
            long long a;
            std::cin >> a;
            counts[get_parity_pattern(a)]--;
        } else { // type == '?'
            std::string s;
            std::cin >> s;
            // Pad the query pattern with '0's to the right to match the fixed length
            // This is because get_parity_pattern builds from right to left, so '0's are appended.
            // A pattern like "010" for 18 digits would be "010000000000000000"
            // The problem states "If the pattern is shorter than this integer, it's supplemented with 0-s from the left."
            // This means if pattern is "010", it effectively becomes "0...0010" for comparison.
            // Our get_parity_pattern function generates "01000...0" (reversed digits, then padded).
            // So, we need to reverse the input pattern string and then pad it.
            std::string query_pattern_padded = "";
            for (char c : s) {
                query_pattern_padded += c;
            }
            while (query_pattern_padded.length() < 18) {
                query_pattern_padded += '0';
            }

            std::cout << counts[query_pattern_padded] << "\n";
        }
    }

    return 0;
}

