    int n = s.length();
    std::string w(n, '1'); // Initialize w with all '1's

    // If s_i is '0', then w_{i-x} and w_{i+x} must be '0'
    for (int i = 0; i < n; ++i) {
        if (s[i] == '0') {
            if (i - x >= 0) {
                w[i - x] = '0';
            }
            if (i + x < n) {
                w[i + x] = '0';
            }
        }
    }

    // Now, verify if this candidate w can produce s
    std::string s_prime(n, '0'); // Build s_prime from our candidate w
    for (int i = 0; i < n; ++i) {
        bool is_one = false;
        if (i - x >= 0 && w[i - x] == '1') {
            is_one = true;
        }
        if (i + x < n && w[i + x] == '1') {
            is_one = true;
        }
        if (is_one) {
            s_prime[i] = '1';
        }
    }

    if (s_prime == s) {
        std::cout << w << std::endl;
