            if (diff > 1) { // If diff is 1, no extra penalty (last item could be from right)
                current_energy += (long long)(diff - 1) * Ql;
            }
        } else if (j > i) { // More items from right
            int diff = j - i;
            if (diff > 1) { // If diff is 1, no extra penalty (last item could be from left)
                current_energy += (long long)(diff - 1) * Qr;
            }
        }

        if (min_energy == -1 || current_energy < min_energy) {
            min_energy = current_energy;
        }
    }

    std::cout << min_energy << std::endl;

    return 0;
}

