#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>
#include <cmath>

// Function to find prime factors of a number
// Returns a vector of pairs: (prime_factor, exponent)
std::vector<std::pair<long long, int>> get_prime_factors(long long n) {
    std::vector<std::pair<long long, int>> factors;
    for (long long i = 2; i * i <= n; ++i) {
        if (n % i == 0) {
            int count = 0;
            while (n % i == 0) {
                n /= i;
                count++;
            }
            factors.push_back({i, count});
        }
    }
    if (n > 1) {
        factors.push_back({n, 1});
    }
    return factors;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long p, q;
        std::cin >> p >> q;

        if (p % q != 0) {
            std::cout << p << "\n";
            continue;
        }

        // p is divisible by q. We need to find the largest x such that p % x == 0 and x % q != 0.
        // This means x must be p / (some factor of p that makes x not divisible by q).
        // To maximize x, we need to divide p by the smallest possible factor that achieves x % q != 0.
        // This factor must be related to prime factors of q.

        // Get prime factors of q
        std::vector<std::pair<long long, int>> q_factors = get_prime_factors(q);

        long long max_x = 1; // Initialize with a value that will be overwritten

        for (const auto& factor_pair : q_factors) {
            long long prime_f = factor_pair.first;
            // int exponent_q = factor_pair.second; // Not directly needed, we just need the prime factor

            // Calculate p_prime_f_power: the highest power of prime_f that divides p
            long long current_p = p;
            long long p_prime_f_power = 0;
            while (current_p > 0 && current_p % prime_f == 0) {
                current_p /= prime_f;
                p_prime_f_power++;
            }

            // Calculate q_prime_f_power: the highest power of prime_f that divides q
            long long current_q = q;
            long long q_prime_f_power = 0;
            while (current_q > 0 && current_q % prime_f == 0) {
                current_q /= prime_f;
                q_prime_f_power++;
            }

            // We need to remove enough factors of prime_f from p to make x not divisible by q.
            // Specifically, we need x to have fewer than q_prime_f_power factors of prime_f.
            // The largest such x would have exactly (q_prime_f_power - 1) factors of prime_f.
            // To achieve this, we must divide p by prime_f raised to the power of (p_prime_f_power - (q_prime_f_power - 1)).
            // This simplifies to dividing p by prime_f raised to the power of (p_prime_f_power - q_prime_f_power + 1).
            // Let this divisor be `div_factor = prime_f^(p_prime_f_power - q_prime_f_power + 1)`.
            // The candidate x is `p / div_factor`.

            long long div_factor = 1;
            for (int i = 0; i < p_prime_f_power - q_prime_f_power + 1; ++i) {
                div_factor *= prime_f;
            }

            max_x = std::max(max_x, p / div_factor);
        }
        std::cout << max_x << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <algorithm>
#include <numeric>

void solve() {
    int n;
    std::cin >> n;
    std::string s;
    std::cin >> s;

    std::vector<int> d(n);
    for (int i = 0; i < n; ++i) {
        d[i] = s[i] - '0';
    }

    for (int p = 0; p <= 9; ++p) {
        std::vector<int> colors(n);
        bool possible_p = true;
        int last1 = -1; // Last digit colored 1
        int first2 = 10; // First digit colored 2

        // First pass: assign colors based on p
        // Digits < p are 1, digits > p are 2.
        // Digits == p are initially 0 (unassigned).
        for (int i = 0; i < n; ++i) {
            if (d[i] < p) {
                colors[i] = 1;
            } else if (d[i] > p) {
                colors[i] = 2;
            } else { // d[i] == p
                colors[i] = 0; // Mark as unassigned for now
            }
        }

        // Second pass: assign colors for digits == p
        // All d[i] == p that appear before the first d[j] > p are colored 1.
        // All d[i] == p that appear after or at the first d[j] > p are colored 2.
        // This ensures that all 1s come before all 2s among digits equal to p.

        // Find the first occurrence of a digit > p
        int first_greater_than_p_idx = -1;
        for(int i = 0; i < n; ++i) {
            if (d[i] > p) {
                first_greater_than_p_idx = i;
                break;
            }
        }

        if (first_greater_than_p_idx == -1) { // No digit > p, all digits are <= p
            // All digits are <= p.
            // All d[i] < p are 1.
            // All d[i] == p can be 1.
            // This means all digits are colored 1.
            // Check if the sequence is sorted.
            bool current_seq_sorted = true;
            for (int i = 0; i < n; ++i) {
                colors[i] = 1; // All digits are colored 1
            }
            for (int i = 0; i < n - 1; ++i) {
                if (d[i] > d[i+1]) {
                    current_seq_sorted = false;
                    break;
                }
            }
            if (current_seq_sorted) {
                for (int color : colors) {
                    std::cout << color;
                }
                std::cout << "\n";
                return;
            }
            // If not sorted, this p doesn't work. Continue to next p.
            continue;
        }

        // If there are digits > p, then we must split digits == p.
        // Digits == p before first_greater_than_p_idx are 1.
        // Digits == p after first_greater_than_p_idx are 2.
        for (int i = 0; i < n; ++i) {
            if (d[i] == p) {
                if (i < first_greater_than_p_idx) {
                    colors[i] = 1;
                } else {
                    colors[i] = 2;
                }
            }
        }

        // Validate the constructed coloring
        std::vector<int> s1_digits;
        std::vector<int> s2_digits;

        for (int i = 0; i < n; ++i) {
            if (colors[i] == 1) {
                s1_digits.push_back(d[i]);
            } else {
                s2_digits.push_back(d[i]);
            }
        }

        // Check if S1 is non-decreasing
        for (size_t i = 0; i + 1 < s1_digits.size(); ++i) {
            if (s1_digits[i] > s1_digits[i+1]) {
                possible_p = false;
                break;
            }
        }
        if (!possible_p) continue;

        // Check if S2 is non-decreasing
        for (size_t i = 0; i + 1 < s2_digits.size(); ++i) {
            if (s2_digits[i] > s2_digits[i+1]) {
                possible_p = false;
                break;
            }
        }
        if (!possible_p) continue;

        // Check if last digit of S1 <= first digit of S2
        if (!s1_digits.empty() && !s2_digits.empty()) {
            if (s1_digits.back() > s2_digits.front()) {
                possible_p = false;
            }
        }
        if (!possible_p) continue;

        // If all checks pass, this coloring is valid
        for (int color : colors) {
            std::cout << color;
        }
        std::cout << "\n";
        return;
    }

    // If no pivot p works
    std::cout << "-\n";
}

