void solve() {
    int n;
    std::cin >> n;

    // Initialize bounds for the target point (X, Y)
    // X must be >= min_x and <= max_x
    // Y must be >= min_y and <= max_y
    long long min_x = -2000000000LL; // Effectively negative infinity
    long long max_x = 2000000000LL;  // Effectively positive infinity
    long long min_y = -2000000000LL; // Effectively negative infinity
    long long max_y = 2000000000LL;  // Effectively positive infinity

    for (int i = 0; i < n; ++i) {
        long long x, y;
        int f1, f2, f3, f4;
        std::cin >> x >> y >> f1 >> f2 >> f3 >> f4;

        // f1: can move left (x-1)
        // f2: can move up (y+1)
        // f3: can move right (x+1)
        // f4: can move down (y-1)

        // If robot cannot move left (f1=0), then X must be >= its current x.
        // Because if X < x, it would need to move left to reach X, but it can't.
        // So, it must be that X >= x.
        if (f1 == 0) { // Cannot move left
            min_x = std::max(min_x, x);
        }

        // If robot cannot move up (f2=0), then Y must be <= its current y.
        // Because if Y > y, it would need to move up to reach Y, but it can't.
        // So, it must be that Y <= y.
        if (f2 == 0) { // Cannot move up
            max_y = std::min(max_y, y);
        }

        // If robot cannot move right (f3=0), then X must be <= its current x.
        // Because if X > x, it would need to move right to reach X, but it can't.
        // So, it must be that X <= x.
        if (f3 == 0) { // Cannot move right
            max_x = std::min(max_x, x);
        }

        // If robot cannot move down (f4=0), then Y must be >= its current y.
        // Because if Y < y, it would need to move down to reach Y, but it can't.
        // So, it must be that Y >= y.
        if (f4 == 0) { // Cannot move down
            min_y = std::max(min_y, y);
        }
    }

    // Check if a valid (X, Y) exists
    if (min_x <= max_x && min_y <= max_y) {
        // A valid point exists. We can pick any point within the valid range.
        // The problem guarantees that if a solution exists, one with coordinates
        // not exceeding 10^5 by absolute value also exists.
        // So, we can clamp min_x and min_y to stay within this range if they
        // are outside the typical problem constraints, though the current
        // initialization values are large enough that min_x/min_y will be
        // set by actual robot coordinates or stay at -2e9.
        // The problem statement says "Both X and Y should not exceed 10^5 by absolute value".
        // This implies we should pick a point within [-10^5, 10^5] if possible.
        // The current min_x, min_y, max_x, max_y are derived from robot positions
        // which are within [-10^5, 10^5]. So the resulting range will also be within
        // [-10^5, 10^5] or tighter.
        // Thus, min_x and min_y will be valid choices.
        std::cout << 1 << " " << min_x << " " << min_y << "\n";
    } else {
        std::cout << 0 << "\n";
    }
}

