    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    long long a, b;
    std::cin >> a >> b;

    long long MOD = 1000000007;

    // Calculate sum_r = sum_{r=1 to b-1} r
    // This is (b-1) * b / 2
    long long sum_r_term;
    if (b == 1) { // If b=1, then b-1=0, sum is 0.
        sum_r_term = 0;
    } else {
        long long b_minus_1 = b - 1;
        long long b_val = b;

        // One of b_minus_1 or b_val must be even.
        // Divide by 2 first to avoid overflow before multiplication,
        // though for b <= 10^7, (b-1)*b is at most 10^14, which fits long long.
        // But it's good practice for modulo arithmetic.
        if (b_minus_1 % 2 == 0) {
            sum_r_term = (b_minus_1 / 2) % MOD;
            sum_r_term = (sum_r_term * b_val) % MOD;
        } else {
            sum_r_term = (b_val / 2) % MOD;
            sum_r_term = (sum_r_term * b_minus_1) % MOD;
        }
    }

    // Calculate sum_k_term = sum_{k=1 to a} (k * b + 1)
    // This is (b * sum_{k=1 to a} k) + (sum_{k=1 to a} 1)
    // sum_{k=1 to a} k = a * (a + 1) / 2
    // sum_{k=1 to a} 1 = a

    long long sum_k_val;
    long long a_plus_1 = a + 1;

    if (a % 2 == 0) {
        sum_k_val = (a / 2) % MOD;
        sum_k_val = (sum_k_val * a_plus_1) % MOD;
    } else {
        sum_k_val = (a_plus_1 / 2) % MOD;
        sum_k_val = (sum_k_val * a) % MOD;
    }

    long long term1 = (b % MOD * sum_k_val) % MOD;
    long long term2 = a % MOD;
    long long sum_k_term = (term1 + term2) % MOD;

    // Total sum = (sum_r_term * sum_k_term) % MOD
    long long total_sum = (sum_r_term * sum_k_term) % MOD;

    std::cout << total_sum << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <numeric>
#include <algorithm>
#include <iomanip>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;
    int n = s.length();

    std::vector<std::vector<int>> char_indices(26);
    for (int i = 0; i < n; ++i) {
        char_indices[s[i] - 'a'].push_back(i);
    }

    std::vector<std::vector<int>> next_occurrence(n, std::vector<int>(26, -1));
    for (int c = 0; c < 26; ++c) {
        if (char_indices[c].empty()) continue;
        int current_idx = 0;
        for (int i = 0; i < n; ++i) {
            while (current_idx < char_indices[c].size() && char_indices[c][current_idx] < i) {
                current_idx++;
            }
            if (current_idx < char_indices[c].size()) {
                next_occurrence[i][c] = char_indices[c][current_idx];
            } else {
                next_occurrence[i][c] = char_indices[c][0] + n; // Wrap around
            }
        }
    }

    double total_prob = 0.0;

    for (int k_val = 0; k_val < n; ++k_val) { // Iterate over all possible initial k values
        char first_char_t = s[k_val]; // t[0] = s[k_val]

        // Find all k' values such that s[k'] == first_char_t
        std::vector<int> possible_k_prime;
        for (int k_prime_candidate : char_indices[first_char_t - 'a']) {
            possible_k_prime.push_back(k_prime_candidate);
        }

        if (possible_k_prime.size() <= 1) { // If only one k' matches t[0], Vasya wins immediately
            total_prob += 1.0;
            continue;
        }

        // Vasya needs to choose p to maximize win probability for this specific first_char_t
        double max_win_prob_for_char_t = 0.0;

        // Iterate over all possible positions p (1-indexed, so p-1 is 0-indexed)
        // Vasya can choose any p from 1 to n-1.
        // The problem statement says "open one more letter on some position",
        // and t[0] is already known. So p cannot be 0.
        // If p=1, he opens t[0] again, which is useless. So p must be >= 2.
        // The problem implies p is 1-indexed, so t[p-1].
        // If p=1, t[0] is opened. If p=2, t[1] is opened.
        // The problem says "open one more letter on some position".
        // This means p-1 can be any index from 0 to n-1.
        // If p-1 = 0, he re-opens t[0]. This is useless.
        // So p-1 must be from 1 to n-1.
        // Let's consider p from 1 to n-1 (0-indexed position).
        // So Vasya chooses an index `idx_to_open` from `[1, n-1]`.
        for (int idx_to_open = 1; idx_to_open < n; ++idx_to_open) {
            // For a fixed `idx_to_open`, what is the probability of winning?
            // This is 1 / (number of k' that match t[0] and t[idx_to_open])
            // We need to count how many k' values (from possible_k_prime)
            // result in a unique pair (t[0], t[idx_to_open]).

            // For each k' in possible_k_prime, calculate the character at t[idx_to_open]
            // This is s[(idx_to_open + k') % n].

            // We need to count how many k' values lead to a unique pair (s[k'], s[(idx_to_open + k') % n]).
            // This is equivalent to counting how many k' values lead to a unique pair (first_char_t, s[(idx_to_open + k') % n]).
            // We group k' values by the second character they produce.

            std::vector<int> counts_for_second_char(26, 0);
            for (int k_prime : possible_k_prime) {
                char second_char_t = s[(idx_to_open + k_prime) % n];
                counts_for_second_char[second_char_t - 'a']++;
            }

            int unique_matches = 0;
            for (int count : counts_for_second_char) {
                if (count == 1) { // If only one k' produces this (t[0], t[idx_to_open]) pair
                    unique_matches++;
                }
            }
            max_win_prob_for_char_t = std::max(max_win_prob_for_char_t, (double)unique_matches / possible_k_prime.size());
        }
        total_prob += max_win_prob_for_char_t;
    }

    std::cout << std::fixed << std::setprecision(15) << total_prob / n << std::endl;

    return 0;
}

#include <iostream>
