int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;

    int k = static_cast<int>(std::sqrt(n));
    // k is the target length for LIS and LDS.
    // We want to construct a permutation where LIS and LDS are both around k.
    // The construction strategy is to divide the numbers 1 to n into blocks of size k.
    // For each block, we print the numbers in decreasing order.
    // This ensures that within each block, we have a decreasing subsequence of length k.
    // And across blocks, we can form an increasing subsequence by picking the smallest element of each block.

    // Example: n=4, k=2
    // Block 1: [1, 2] -> print 2 1
    // Block 2: [3, 4] -> print 4 3
    // Result: 2 1 4 3
    // LIS: [2,4] or [1,3] or [1,4] (length 2)
    // LDS: [2,1] or [4,3] (length 2)
    // Sum = 4. This is optimal for n=4.
    // The example output for n=4 is 3 4 1 2.
    // LIS: [3,4] or [1,2] (length 2)
    // LDS: [3,1] or [3,2] or [4,1] or [4,2] (length 2)
    // Sum = 4. This is also optimal.

    // Let's try the example output's strategy:
    // For n=4, k=2.
    // Block 1: [1, 2]
    // Block 2: [3, 4]
    // Output: 3 4 1 2
    // This looks like:
    // Block 2 (reversed): 4 3
    // Block 1 (reversed): 2 1
    // Then concatenate: 4 3 2 1. This gives LIS=1, LDS=4. Sum=5. Not optimal.

    // The example output 3 4 1 2 for n=4:
    // It seems to be:
    // Block 1: [1, 2]
    // Block 2: [3, 4]
    // Print block 2, then block 1.
    // But within each block, it's not reversed.
    // It's 3 4 (block 2) then 1 2 (block 1).
    // This is not a simple block reversal.

    // Let's re-evaluate the strategy for minimizing LIS+LDS.
    // The Erdos-Szekeres theorem states that any permutation of length n has an LIS of length at least ceil(sqrt(n))
    // or an LDS of length at least ceil(sqrt(n)).
    // More strongly, LIS * LDS >= n.
    // To minimize LIS + LDS, we want LIS and LDS to be as close as possible, ideally both around sqrt(n).
    // Let k = ceil(sqrt(n)). We aim for LIS = k and LDS = k.
    // A common construction for this is to divide the numbers 1 to n into blocks of size k.
    // For each block, print the numbers in decreasing order.
    // Example: n=4, k=ceil(sqrt(4))=2.
    // Blocks: [1,2], [3,4]
    // Print [2,1], then [4,3]. Result: 2 1 4 3.
    // LIS: [2,4] or [1,3] or [1,4] (length 2)
    // LDS: [2,1] or [4,3] (length 2)
    // Sum = 4. This is optimal.

    // Example: n=5, k=ceil(sqrt(5))=3.
    // Blocks: [1,2,3], [4,5]
    // Print [3,2,1], then [5,4]. Result: 3 2 1 5 4.
    // LIS: [3,5], [3,4], [2,5], [2,4], [1,5], [1,4] (length 2)
    // LDS: [3,2,1], [5,4] (length 3)
    // Sum = 2+3 = 5.
    // For n=5, LIS*LDS >= 5. Possible (2,3) or (3,2). Sum=5. This is optimal.

    // Example: n=9, k=ceil(sqrt(9))=3.
    // Blocks: [1,2,3], [4,5,6], [7,8,9]
    // Print [3,2,1], then [6,5,4], then [9,8,7]. Result: 3 2 1 6 5 4 9 8 7.
    // LIS: [3,6,9] (length 3)
    // LDS: [3,2,1], [6,5,4], [9,8,7] (length 3)
    // Sum = 3+3 = 6. Optimal.

    // This strategy seems to work.
    // The strategy is:
    // 1. Determine block size `k = ceil(sqrt(n))`.
    // 2. Iterate from `n` down to `1`.
    // 3. For each number `i`, if it's the start of a new block (i.e., `i % k == 0` or `i == n`),
    //    print the numbers from `i` down to `max(1, i - k + 1)`.
    //    This is equivalent to printing blocks in reverse order, and elements within each block in reverse order.

    // Let's refine the block printing.
    // We want to print numbers in groups of `k`.
    // The first group will be `(k-1)*k + 1` to `k*k`.
    // The second group will be `(k-2)*k + 1` to `(k-1)*k`.
    // ...
    // The last group will be `1` to `k`.
    // And within each group, print in decreasing order.

    // Let `k = ceil(sqrt(n))`.
    // The number of full blocks is `n / k`.
    // The size of the last (possibly partial) block is `n % k`. If `n % k == 0`, it's `k`.

    // Let's use the strategy from a known solution for this problem:
    // Divide the numbers 1 to n into blocks of size `k = ceil(sqrt(n))`.
    // For each block, print its elements in decreasing order.
    // Example: n=4, k=ceil(sqrt(4))=2.
    // Blocks: [1,2], [3,4]
    // Print [2,1], then [4,3]. Result: 2 1 4 3.
    // This is not what the example output for n=4 (3 4 1 2) does.
    // The example output for n=4 (3 4 1 2) has LIS=2, LDS=2. Sum=4.
    // My strategy for n=4 (2 1 4 3) has LIS=2, LDS=2. Sum=4. Both are optimal.
    // So my strategy is valid.

    // Let's implement the strategy:
    // Iterate from `n` down to `1`.
    // For each `i`, if `i` is the largest element in its block, print the block in reverse.
    // A block starts at `(block_idx * k) + 1` and ends at `(block_idx + 1) * k`.
    // The numbers are `1, ..., n`.
    // The blocks are `[1, k], [k+1, 2k], ..., [m*k+1, n]`.
    // We want to print `[k, k-1, ..., 1]`, then `[2k, 2k-1, ..., k+1]`, etc.
    // This means we print blocks in increasing order of their starting values, but elements within blocks in decreasing order.

    // Let's try another way to construct:
    // Iterate `i` from `0` to `n-1`.
    // The current number is `i+1`.
    // We want to print `k` numbers in decreasing order, then the next `k` numbers in decreasing order, etc.
    // This means we print `k, k-1, ..., 1`, then `2k, 2k-1, ..., k+1`, etc.
    // This is equivalent to:
    // For `start = 1, start += k`:
    //   For `j = min(start + k - 1, n)` down to `start`:
    //     print `j`.

    // Example: n=4, k=2
    // start = 1:
    //   j from min(1+2-1, 4)=2 down to 1: print 2, 1. Output: 2 1
    // start = 1+2 = 3:
    //   j from min(3+2-1, 4)=4 down to 3: print 4, 3. Output: 2 1 4 3
    // This matches my previous derivation.

    // Example: n=2, k=ceil(sqrt(2))=2
    // start = 1:
    //   j from min(1+2-1, 2)=2 down to 1: print 2, 1. Output: 2 1
    // This matches the example output.

    // Example: n=1, k=ceil(sqrt(1))=1
    // start = 1:
    //   j from min(1+1-1, 1)=1 down to 1: print 1. Output: 1
    // LIS=1, LDS=1. Sum=2. Optimal.

    // This strategy seems robust and matches the examples where my output differs but is still optimal.

    // Let's consider the value of k.
    // If n=1, k=1. Output: 1.
    // If n=2, k=2. Output: 2 1.
    // If n=3, k=2.
    // start=1: j from min(1+2-1,3)=2 down to 1: print 2 1.
    // start=3: j from min(3+2-1,3)=3 down to 3: print 3.
    // Output: 2 1 3.
    // LIS: [2,3] or [1,3] (length 2)
    // LDS: [2,1] (length 2)
    // Sum = 4.
    // For n=3, LIS*LDS >= 3. Possible (1,3), (3,1), (2,2).
    // (1,3) sum=4. (3,1) sum=4. (2,2) sum=4.
    // So 2 1 3 is optimal.

    // If n=4, k=2. Output: 2 1 4 3.
    // If n=5, k=3.
    // start=1: j from min(1+3-1,5)=3 down to 1: print 3 2 1.
    // start=4: j from min(4+3-1,5)=5 down to 4: print 5 4.
    // Output: 3 2 1 5 4.
    // LIS: [3,5], [3,4], [2,5], [2,4], [1,5], [1,4] (length 2)
    // LDS: [3,2,1], [5,4] (length 3)
    // Sum = 2+3 = 5.
    // For n=5, LIS*LDS >= 5. Possible (1,5), (5,1), (2,3), (3,2).
    // (1,5) sum=6. (5,1) sum=6. (2,3) sum=5. (3,2) sum=5.
    // So 3 2 1 5 4 is optimal.

    // The strategy seems correct and produces optimal results.

    // The block size `k` should be `ceil(sqrt(n))`.
    // `k = static_cast<int>(std::sqrt(n))` might truncate.
    // For `n=4`, `sqrt(4)=2`, `k=2`. Correct.
    // For `n=5`, `sqrt(5)=2.23`, `k=2`. But `ceil(sqrt(5))=3`.
    // So `k` should be `static_cast<int>(std::ceil(std::sqrt(n)))`.

    k = static_cast<int>(std::ceil(std::sqrt(n)));

    for (int start_val = 1; start_val <= n; start_val += k) {
        int end_val = std::min(start_val + k - 1, n);
        for (int j = end_val; j >= start_val; --j) {
            std::cout << j << (j == start_val && end_val == n ? "" : " ");
        }
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <map>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(2 * n);
    for (int i = 0; i < 2 * n; ++i) {
        std::cin >> a[i];
        if (a[i] == 2) {
            a[i] = -1;
        }
    }

    // Calculate prefix sums for the left side (jars 1 to n)
    // and suffix sums for the right side (jars n+1 to 2n).
    // The values are 1 for strawberry, -1 for blueberry.

    // Left side: jars 1 to n
    // prefix_sums_left[k] = sum of a[0]...a[k-1]
    // This represents the balance of the first k jars (1 to k).
    std::vector<int> prefix_sums_left(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        prefix_sums_left[i + 1] = prefix_sums_left[i] + a[i];
    }

    // Right side: jars n+1 to 2n
    // suffix_sums_right[k] = sum of a[2n-1]...a[2n-k]
    // This represents the balance of the last k jars (2n-k+1 to 2n).
    std::vector<int> suffix_sums_right(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        suffix_sums_right[i + 1] = suffix_sums_right[i] + a[2 * n - 1 - i];
    }

    // Map to store the minimum number of jars eaten from the left
    // to achieve a certain balance.
    // key: balance, value: jars eaten from left
    std::map<int, int> left_balances;
    for (int k_L = 0; k_L <= n; ++k_L) {
        int current_balance = prefix_sums_left[k_L];
        // We are interested in the balance of the *remaining* jars on the left.
        // If k_L jars are eaten from the left, the remaining jars are from index k_L to n-1.
        // The balance of these remaining jars is (total balance of jars 1 to n) - (balance of jars 1 to k_L).
        // However, the problem states we want the balance of the *entire remaining segment* to be 0.
        // So, if we eat k_L jars from the left, the jars 1...k_L are gone.
        // The jars n+1...2n-k_R are remaining.
        // The total balance of all 2n jars is prefix_sums_left[n] + suffix_sums_right[n].
        // If we eat k_L jars from left and k_R jars from right,
        // the balance of the eaten jars is prefix_sums_left[k_L] + suffix_sums_right[k_R].
        // The balance of the remaining jars is (total balance) - (balance of eaten jars).
        // We want (total balance) - (balance of eaten jars) = 0.
        // So, (balance of eaten jars) = (total balance).
        // prefix_sums_left[k_L] + suffix_sums_right[k_R] = prefix_sums_left[n] + suffix_sums_right[n].
        // This is equivalent to:
        // suffix_sums_right[k_R] = (prefix_sums_left[n] + suffix_sums_right[n]) - prefix_sums_left[k_L].
        // Let target_balance_eaten = prefix_sums_left[n] + suffix_sums_right[n].
        // We need suffix_sums_right[k_R] = target_balance_eaten - prefix_sums_left[k_L].

        // Let's re-evaluate.
        // The jars remaining are from index k_L to 2n-1-k_R.
        // The balance of these remaining jars must be 0.
        // This means sum(a[k_L]...a[2n-1-k_R]) = 0.
        // This is equivalent to:
        // (sum(a[0]...a[2n-1])) - (sum(a[0]...a[k_L-1])) - (sum(a[2n-k_R]...a[2n-1])) = 0.
        // Let total_balance = sum(a[0]...a[2n-1]).
        // total_balance - prefix_sums_left[k_L] - suffix_sums_right[k_R] = 0.
        // So, suffix_sums_right[k_R] = total_balance - prefix_sums_left[k_L].

        // The balance of the jars from 1 to n (left side) is prefix_sums_left[n].
        // The balance of the jars from n+1 to 2n (right side) is suffix_sums_right[n].
        // The total balance of all 2n jars is prefix_sums_left[n] + suffix_sums_right[n].

        // If we eat k_L jars from the left, the balance of the remaining jars on the left is
        // prefix_sums_left[n] - prefix_sums_left[k_L].
        // If we eat k_R jars from the right, the balance of the remaining jars on the right is
        // suffix_sums_right[n] - suffix_sums_right[k_R].
        // The total balance of remaining jars is (prefix_sums_left[n] - prefix_sums_left[k_L]) + (suffix_sums_right[n] - suffix_sums_right[k_R]).
        // We want this to be 0.
        // So, prefix_sums_left[n] - prefix_sums_left[k_L] + suffix_sums_right[n] - suffix_sums_right[k_R] = 0.
        // This means:
        // prefix_sums_left[k_L] + suffix_sums_right[k_R] = prefix_sums_left[n] + suffix_sums_right[n].
        // Let target_sum_eaten_balance = prefix_sums_left[n] + suffix_sums_right[n].
        // We need to find k_L, k_R such that prefix_sums_left[k_L] + suffix_sums_right[k_R] = target_sum_eaten_balance.
        // And minimize k_L + k_R.

        // Store the minimum k_L for each prefix_sums_left[k_L] value.
        // The balance of the first k_L jars (a[0]...a[k_L-1]) is prefix_sums_left[k_L].
        if (left_balances.find(prefix_sums_left[k_L]) == left_balances.end()) {
            left_balances[prefix_sums_left[k_L]] = k_L;
        } else {
            left_balances[prefix_sums_left[k_L]] = std::min(left_balances[prefix_sums_left[k_L]], k_L);
        }
    }

    int min_jars_eaten = 2 * n; // Max possible jars eaten

    // Iterate through possible number of jars eaten from the right (k_R)
    for (int k_R = 0; k_R <= n; ++k_R) {
        // The balance of the last k_R jars (a[2n-k_R]...a[2n-1]) is suffix_sums_right[k_R].

        // We need to find a k_L such that:
        // prefix_sums_left[k_L] + suffix_sums_right[k_R] = prefix_sums_left[n] + suffix_sums_right[n]
        // Rearranging for prefix_sums_left[k_L]:
        int required_left_balance = (prefix_sums_left[n] + suffix_sums_right[n]) - suffix_sums_right[k_R];

        if (left_balances.count(required_left_balance)) {
            int k_L = left_balances[required_left_balance];
            min_jars_eaten = std::min(min_jars_eaten, k_L + k_R);
        }
    }

    std::cout << min_jars_eaten << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    // Initialize the state for each bit position (0-9)
    // For each bit, we track what happens if it's initially 0 and if it's initially 1.
    // state[bit_idx][0] = final value if initial bit is 0
    // state[bit_idx][1] = final value if initial bit is 1
    // Initially, if bit is 0, it stays 0. If bit is 1, it stays 1.
    std::vector<std::vector<int>> state(10, std::vector<int>(2));
    for (int i = 0; i < 10; ++i) {
        state[i][0] = 0;
        state[i][1] = 1;
    }

    for (int k = 0; k < n; ++k) {
        char op_char;
        int val;
        std::cin >> op_char >> val;

        for (int i = 0; i < 10; ++i) {
            int bit_val = (val >> i) & 1; // i-th bit of the constant

            if (op_char == '&') {
                state[i][0] &= bit_val;
                state[i][1] &= bit_val;
            } else if (op_char == '|') {
                state[i][0] |= bit_val;
                state[i][1] |= bit_val;
            } else if (op_char == '^') {
                state[i][0] ^= bit_val;
                state[i][1] ^= bit_val;
            }
        }
    }

    // Now, reconstruct the simplified operations.
    // We need to find A, B, C such that:
    // (x & A | B) ^ C
    // or some equivalent form.

    // Let's determine the final values for an input of 0 and an input of 1023.
    // These two inputs cover all combinations of initial bit states.
    // For input 0: all bits are 0. The final value is `final_val_0`.
    // For input 1023: all bits are 1. The final value is `final_val_1023`.
    int final_val_0 = 0;
    int final_val_1023 = 0;
    for (int i = 0; i < 10; ++i) {
        final_val_0 |= (state[i][0] << i);
        final_val_1023 |= (state[i][1] << i);
    }

    // The simplified operations can be represented as:
    // x_new = (x & AND_mask | OR_mask) ^ XOR_mask
    //
    // Let's find AND_mask, OR_mask, XOR_mask.
    //
    // Consider the effect on a bit `i`:
    // If `x_i` is 0, it becomes `state[i][0]`.
    // If `x_i` is 1, it becomes `state[i][1]`.
    //
    // We want to find `a_i`, `o_i`, `x_i` such that:
    // (0 & a_i | o_i) ^ x_i = state[i][0]
    // (1 & a_i | o_i) ^ x_i = state[i][1]
    //
    // This simplifies to:
    // (o_i) ^ x_i = state[i][0]  (Eq 1)
    // (a_i | o_i) ^ x_i = state[i][1] (Eq 2)
    //
    // From (Eq 1), we can say `o_i ^ x_i` is fixed.
    // From (Eq 2), we can say `(a_i | o_i) ^ x_i` is fixed.
    //
    // Let's try to find the masks.
    //
    // XOR_mask:
    // If `state[i][0] == state[i][1]`:
    //   This means the output bit `i` is independent of the input bit `i`.
    //   It's always `state[i][0]`.
    //   To achieve this with `(x_i & a_i | o_i) ^ x_i`:
    //   If `x_i=0`: `o_i ^ x_i = state[i][0]`
    //   If `x_i=1`: `(a_i | o_i) ^ x_i = state[i][0]`
    //   This implies `o_i ^ x_i = (a_i | o_i) ^ x_i`.
    //   This can be satisfied if `a_i=0` and `o_i = state[i][0] ^ x_i`.
    //   Then `(0 & 0 | (state[i][0] ^ x_i)) ^ x_i = state[i][0] ^ x_i ^ x_i = state[i][0]`.
    //   And `(1 & 0 | (state[i][0] ^ x_i)) ^ x_i = (state[i][0] ^ x_i) ^ x_i = state[i][0]`.
    //   So, if `state[i][0] == state[i][1]`, we can set `a_i=0`, `o_i = state[i][0]`, `x_i=0`.
    //   This means `AND_mask` has 0, `OR_mask` has `state[i][0]`, `XOR_mask` has 0.
    //   The bit `i` becomes `(x_i & 0 | state[i][0]) ^ 0 = state[i][0]`. Correct.
    //
    // If `state[i][0] != state[i][1]`:
    //   This means the output bit `i` depends on the input bit `i`.
    //   Specifically, `state[i][1] = 1 - state[i][0]`.
    //   To achieve this with `(x_i & a_i | o_i) ^ x_i`:
    //   If `x_i=0`: `o_i ^ x_i = state[i][0]`
    //   If `x_i=1`: `(a_i | o_i) ^ x_i = state[i][1]`
    //   This implies `o_i ^ x_i = state[i][0]` and `(a_i | o_i) ^ x_i = 1 - state[i][0]`.
    //   This can be satisfied if `a_i=1` and `o_i = state[i][0]`.
    //   Then `(0 & 1 | state[i][0]) ^ x_i = state[i][0] ^ x_i`.
    //   And `(1 & 1 | state[i][0]) ^ x_i = (1 | state[i][0]) ^ x_i = 1 ^ x_i`.
    //   So, if `state[i][0] != state[i][1]`, we can set `a_i=1`, `o_i = state[i][0]`, `x_i=0`.
    //   The bit `i` becomes `(x_i & 1 | state[i][0]) ^ 0`.
    //   If `x_i=0`, it's `(0 | state[i][0]) = state[i][0]`. Correct.
    //   If `x_i=1`, it's `(1 | state[i][0]) = 1`. Correct, since `state[i][1]` must be 1.
    //   This means `AND_mask` has 1, `OR_mask` has `state[i][0]`, `XOR_mask` has 0.
    //
    // This logic is for `(x & A | B) ^ C`.
    // Let's try to simplify the operations to `& A`, `| B`, `^ C`.
    //
    // The final state of bit `i` is `state[i][0]` if input bit `i` is 0, and `state[i][1]` if input bit `i` is 1.
    //
    // Let's define three masks:
    // `and_val`: bits that must be 1 for the output to be 1 (if input bit is 1)
    // `or_val`: bits that must be 1 for the output to be 1 (if input bit is 0)
    // `xor_val`: bits that flip the output
    //
    // Consider the effect of `& A`, `| B`, `^ C` on a single bit `x_i`:
    // `((x_i & a_i) | b_i) ^ c_i`
    //
    // If `x_i = 0`: `(0 & a_i | b_i) ^ c_i = b_i ^ c_i`. This must equal `state[i][0]`.
    // If `x_i = 1`: `(1 & a_i | b_i) ^ c_i = (a_i | b_i) ^ c_i`. This must equal `state[i][1]`.
    //
    // From these two equations, we can determine `a_i, b_i, c_i` for each bit `i`.
    //
    // `b_i ^ c_i = state[i][0]`
    // `(a_i | b_i) ^ c_i = state[i][1]`
    //
    // Case 1: `state[i][0] == 0` and `state[i][1] == 0`
    //   `b_i ^ c_i = 0`  => `b_i = c_i`
    //   `(a_i | b_i) ^ c_i = 0` => `a_i | b_i = c_i`
    //   Since `b_i = c_i`, we have `a_i | b_i = b_i`. This implies `a_i` can be 0 or 1, but `a_i` must be 0 for `a_i | b_i = b_i` to hold for `a_i=1` only if `b_i=1`.
    //   If `a_i=0`, then `0 | b_i = b_i`, which is always true.
    //   So, `a_i=0, b_i=0, c_i=0` works. `((x_i & 0) | 0) ^ 0 = 0`.
    //
    // Case 2: `state[i][0] == 0` and `state[i][1] == 1`
    //   `b_i ^ c_i = 0`  => `b_i = c_i`
    //   `(a_i | b_i) ^ c_i = 1` => `a_i | b_i = 1 ^ c_i`
    //   Since `b_i = c_i`, we have `a_i | b_i = 1 ^ b_i`.
    //   If `b_i = 0`: `a_i | 0 = 1 ^ 0` => `a_i = 1`.
    //     So, `a_i=1, b_i=0, c_i=0` works. `((x_i & 1) | 0) ^ 0 = x_i`.
    //   If `b_i = 1`: `a_i | 1 = 1 ^ 1` => `1 = 0`. Impossible.
    //   So, `a_i=1, b_i=0, c_i=0` is the only solution.
    //
    // Case 3: `state[i][0] == 1` and `state[i][1] == 0`
    //   `b_i ^ c_i = 1`  => `b_i = 1 ^ c_i`
    //   `(a_i | b_i) ^ c_i = 0` => `a_i | b_i = c_i`
    //   Substitute `b_i`: `a_i | (1 ^ c_i) = c_i`.
    //   If `c_i = 0`: `a_i | 1 = 0` => `1 = 0`. Impossible.
    //   If `c_i = 1`: `a_i | 0 = 1` => `a_i = 1`.
    //     So, `a_i=1, c_i=1`. Then `b_i = 1 ^ 1 = 0`.
    //     `a_i=1, b_i=0, c_i=1` works. `((x_i & 1) | 0) ^ 1 = x_i ^ 1`.
    //
    // Case 4: `state[i][0] == 1` and `state[i][1] == 1`
    //   `b_i ^ c_i = 1`  => `b_i = 1 ^ c_i`
    //   `(a_i | b_i) ^ c_i = 1` => `a_i | b_i = 1 ^ c_i`
    //   Substitute `b_i`: `a_i | (1 ^ c_i) = 1 ^ c_i`.
    //   This implies `a_i` must be 0.
    //   So, `a_i=0`. Then `b_i = 1 ^ c_i`.
    //   We can choose `c_i=0`, then `b_i=1`.
    //   So, `a_i=0, b_i=1, c_i=0` works. `((x_i & 0) | 1) ^ 0 = 1`.
    //
    // Summary for `((x_i & a_i) | b_i) ^ c_i`:
    // (s0, s1) = (0,0) => (a,b,c) = (0,0,0)
    // (s0, s1) = (0,1) => (a,b,c) = (1,0,0)
    // (s0, s1) = (1,0) => (a,b,c) = (1,0,1)
    // (s0, s1) = (1,1) => (a,b,c) = (0,1,0)
    //
    // Let's construct the masks:
    int final_AND_mask = 0; // A
    int final_OR_mask = 0;  // B
    int final_XOR_mask = 0; // C

    for (int i = 0; i < 10; ++i) {
        int s0 = state[i][0];
        int s1 = state[i][1];

        if (s0 == 0 && s1 == 0) {
            // a_i=0, b_i=0, c_i=0
        } else if (s0 == 0 && s1 == 1) {
            // a_i=1, b_i=0, c_i=0
            final_AND_mask |= (1 << i);
        } else if (s0 == 1 && s1 == 0) {
            // a_i=1, b_i=0, c_i=1
            final_AND_mask |= (1 << i);
            final_XOR_mask |= (1 << i);
        } else if (s0 == 1 && s1 == 1) {
            // a_i=0, b_i=1, c_i=0
            final_OR_mask |= (1 << i);
        }
    }

    std::vector<std::pair<char, int>> result_ops;
    if (final_AND_mask != 1023) { // If not all bits are 1, then & operation is meaningful
        result_ops.push_back({'&', final_AND_mask});
    }
    if (final_OR_mask != 0) { // If not all bits are 0, then | operation is meaningful
        result_ops.push_back({'|', final_OR_mask});
    }
    if (final_XOR_mask != 0) { // If not all bits are 0, then ^ operation is meaningful
        result_ops.push_back({'^', final_XOR_mask});
    }

    std::cout << result_ops.size() << "\n";
    for (const auto& op : result_ops) {
        std::cout << op.first << " " << op.second << "\n";
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 2) { // Sequences of length 1 or 2 are always stable by definition
        std::cout << 0 << std::endl;
        for (int i = 0; i < n; ++i) {
            std::cout << a[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << std::endl;
        return 0;
    }

    std::vector<int> first_zero_block_len(n, 0);
    std::vector<int> first_one_block_len(n, 0);
    std::vector<int> last_zero_block_len(n, 0);
    std::vector<int> last_one_block_len(n, 0);

    // Calculate first_zero_block_len and first_one_block_len
    for (int i = 0; i < n; ++i) {
        if (a[i] == 0) {
            first_zero_block_len[i] = (i > 0 ? first_zero_block_len[i - 1] : 0) + 1;
        }
        if (a[i] == 1) {
            first_one_block_len[i] = (i > 0 ? first_one_block_len[i - 1] : 0) + 1;
        }
    }

    // Calculate last_zero_block_len and last_one_block_len
    for (int i = n - 1; i >= 0; --i) {
        if (a[i] == 0) {
            last_zero_block_len[i] = (i < n - 1 ? last_zero_block_len[i + 1] : 0) + 1;
        }
        if (a[i] == 1) {
            last_one_block_len[i] = (i < n - 1 ? last_one_block_len[i + 1] : 0) + 1;
        }
    }

    int max_steps = 0;
    for (int i = 0; i < n; ++i) {
        if (a[i] == 0) { // Current element is 0
            if (i > 0 && a[i - 1] == 1) { // 10...
                int len_ones = first_one_block_len[i - 1];
                int len_zeros = last_zero_block_len[i];
                if (len_ones > 0 && len_zeros > 0) {
                    max_steps = std::max(max_steps, (std::min(len_ones, len_zeros) + 1) / 2);
                }
            }
        } else { // Current element is 1
            if (i > 0 && a[i - 1] == 0) { // 01...
                int len_zeros = first_zero_block_len[i - 1];
                int len_ones = last_one_block_len[i];
                if (len_zeros > 0 && len_ones > 0) {
                    max_steps = std::max(max_steps, (std::min(len_zeros, len_ones) + 1) / 2);
                }
            }
        }
    }

    std::cout << max_steps << std::endl;

    std::vector<int> result_a = a;
    for (int i = 0; i < n; ++i) {
        if (a[i] == 0) { // Current element is 0
            if (i > 0 && a[i - 1] == 1) { // 10...
                int len_ones = first_one_block_len[i - 1];
                int len_zeros = last_zero_block_len[i];
                if (len_ones > 0 && len_zeros > 0) {
                    if (len_ones <= max_steps) {
                        result_a[i] = 1;
                    }
                }
            }
        } else { // Current element is 1
            if (i > 0 && a[i - 1] == 0) { // 01...
                int len_zeros = first_zero_block_len[i - 1];
                int len_ones = last_one_block_len[i];
                if (len_zeros > 0 && len_ones > 0) {
                    if (len_zeros <= max_steps) {
                        result_a[i] = 0;
                    }
                }
            }
        }
    }

    for (int i = 0; i < n; ++i) {
        std::cout << result_a[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

