    // 1. Pairs within S1: None (S1 has only 1 element)
    // 2. Pairs within S2: elements[i].value + elements[j].value for i,j in [1, n-1]
    //    Min: elements[1].value + elements[2].value
    //    Max: elements[n-1].value + elements[n-2].value
    // 3. Pairs across S1 and S2: elements[0].value + elements[j].value + h for j in [1, n-1]
    //    Min: elements[0].value + elements[1].value + h
    //    Max: elements[0].value + elements[n-1].value + h
    //
    // Overall min_f: std::min(elements[1].value + elements[2].value, elements[0].value + elements[1].value + h)
    // Overall max_f: std::max(elements[n-1].value + elements[n-2].value, elements[0].value + elements[n-1].value + h)
    //
    // This specific partition strategy is:
    // elements[0] goes to partition 1.
    // elements[1] goes to partition 2.
    // elements[2]...elements[n-1] go to partition 2.
    //
    // Let's calculate min_f and max_f for this partition.
    //
    // min_f_same_subseq = elements[1].value + elements[2].value (from S2)
    // min_f_diff_subseq = elements[0].value + elements[1].value + h (from S1 and S2)
    // min_f_overall = std::min(min_f_same_subseq, min_f_diff_subseq)
    //
    // max_f_same_subseq = elements[n-1].value + elements[n-2].value (from S2)
    // max_f_diff_subseq = elements[0].value + elements[n-1].value + h (from S1 and S2)
    // max_f_overall = std::max(max_f_same_subseq, max_f_diff_subseq)
    //
    // Goodness = max_f_overall - min_f_overall

    if (n >= 2) { // This partition strategy requires at least 2 elements.
        long long min_f_same_subseq_S2 = elements[1].value + elements[2].value; // Smallest sum in S2
        long long max_f_same_subseq_S2 = elements[n - 1].value + elements[n - 2].value; // Largest sum in S2

        long long min_f_diff_subseq = elements[0].value + elements[1].value + h; // Smallest sum across S1 and S2
        long long max_f_diff_subseq = elements[0].value + elements[n - 1].value + h; // Largest sum across S1 and S2

        long long current_min_f;
        if (n == 2) { // S2 has only one element (elements[1]), no pairs within S2
            current_min_f = min_f_diff_subseq;
        } else {
            current_min_f = std::min(min_f_same_subseq_S2, min_f_diff_subseq);
        }

        long long current_max_f = std::max(max_f_same_subseq_S2, max_f_diff_subseq);

        long long goodness2 = current_max_f - current_min_f;

        if (goodness2 < min_goodness) {
            min_goodness = goodness2;
            best_partition[elements[0].original_index] = 1;
            for (int i = 1; i < n; ++i) {
                best_partition[elements[i].original_index] = 2;
            }
        }
    }

    // Case 3: Partition with elements[0] and elements[n-1] in different subsequences.
    // This is the key insight. If elements[0] and elements[n-1] are in different subsequences,
    // then f(elements[0], elements[n-1]) = elements[0].value + elements[n-1].value + h.
    // This value is likely to be the maximum f value.
    //
    // Consider the partition:
    // S1 = {elements[0], elements[1], ..., elements[n-2]}
    // S2 = {elements[n-1]}
    //
    // Possible f values:
    // 1. Pairs within S1: elements[i].value + elements[j].value for i,j in [0, n-2]
    //    Min: elements[0].value + elements[1].value
    //    Max: elements[n-2].value + elements[n-3].value (if n-2 >= 1)
    // 2. Pairs within S2: None (S2 has only 1 element)
    // 3. Pairs across S1 and S2: elements[i].value + elements[n-1].value + h for i in [0, n-2]
    //    Min: elements[0].value + elements[n-1].value + h
    //    Max: elements[n-2].value + elements[n-1].value + h
    //
    // Overall min_f: elements[0].value + elements[1].value
    // Overall max_f: elements[n-2].value + elements[n-1].value + h
    //
    // Goodness = (elements[n-2].value + elements[n-1].value + h) - (elements[0].value + elements[1].value)
    //
    // This partition strategy is:
    // elements[0]...elements[n-2] go to partition 1.
    // elements[n-1] goes to partition 2.

    if (n >= 2) { // This partition strategy requires at least 2 elements.
        long long current_min_f_case3;
        if (n == 2) { // S1 has only one element (elements[0]), no pairs within S1
            current_min_f_case3 = elements[0].value + elements[1].value + h; // Only cross-subsequence pair
        } else {
            current_min_f_case3 = elements[0].value + elements[1].value; // Smallest sum within S1
        }

        long long current_max_f_case3 = elements[n - 2].value + elements[n - 1].value + h; // Largest sum across S1 and S2

        long long goodness3 = current_max_f_case3 - current_min_f_case3;

        if (goodness3 < min_goodness) {
            min_goodness = goodness3;
            for (int i = 0; i < n - 1; ++i) {
                best_partition[elements[i].original_index] = 1;
            }
            best_partition[elements[n - 1].original_index] = 2;
        }
    }

    std::cout << min_goodness << "\n";
    for (int i = 0; i < n; ++i) {
        std::cout << best_partition[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;
    int n = s.length();

    long long total_pairs = (long long)n * (n + 1) / 2;
    long long invalid_pairs = 0;

    // max_r_for_l[i] stores the maximum r such that the substring s[i...r]
    // does NOT contain any 3-AP.
    // Initialize with n, meaning s[i...n] is initially considered valid.
    // We will update this to be smaller if a 3-AP is found.
    std::vector<int> max_r_for_l(n + 1);
    std::iota(max_r_for_l.begin(), max_r_for_l.end(), 0); // max_r_for_l[i] = i initially
    // For 1-based indexing, max_r_for_l[i] = i-1.
    // Let's use 0-based indexing for max_r_for_l to match string indices.
    // max_r_for_l[i] will store the largest index j such that s[i...j] is valid.
    // Initialize max_r_for_l[i] = i-1.
    // This means for a given l (0-indexed), any r < l is invalid.
    // We want to find the smallest r_min such that s[l...r_min] contains a 3-AP.
    // Then all r >= r_min will contain a 3-AP.
    // The number of invalid pairs (l, r) for a fixed l is (r_min - 1) - l + 1 = r_min - l.
    // If no 3-AP starts at or after l, then r_min = n+1.
    // So, for each l, we want to find the smallest r_min such that s[l...r_min] contains a 3-AP.
    // All pairs (l, r) with r < r_min are invalid.
    // The number of such r's is r_min - l.
    // We can iterate l from n-1 down to 0.
    // For each l, the smallest r_min for s[l...] is at most the smallest r_min for s[l+1...].
    // Let's define `min_r_with_3AP[l]` as the smallest `r` (0-indexed) such that `s[l...r]` contains a 3-AP.
    // If no such `r` exists, `min_r_with_3AP[l] = n`.
    // We want to sum `min_r_with_3AP[l] - l` for all `l`.
    // Initialize `min_r_with_3AP[l] = n` for all `l`.
    std::vector<int> min_r_with_3AP(n + 1, n); // min_r_with_3AP[l] stores the smallest r (0-indexed)
                                              // such that s[l...r] contains a 3-AP.
                                              // If no such r, it's n.

    // Iterate through all possible x and k to find 3-APs
    // x is 0-indexed, k is 1-indexed
    // s_x = s_{x+k} = s_{x+2k}
    // x+2k must be < n
    for (int x = 0; x < n; ++x) {
        for (int k = 1; x + 2 * k < n; ++k) {
            if (s[x] == s[x + k] && s[x + k] == s[x + 2 * k]) {
                // Found a 3-AP: (x, x+k, x+2k)
                // This 3-AP starts at index x and ends at index x+2k.
                // Any substring s[l...r] where l <= x and r >= x+2k contains this 3-AP.
                // For any l' <= x, the smallest r that makes s[l'...r] contain a 3-AP
                // is at most x+2k.
                // So, we update min_r_with_3AP[l'] for all l' from 0 to x.
                // Specifically, for each l' from 0 to x, min_r_with_3AP[l'] = min(min_r_with_3AP[l'], x+2k).
                // This means we need to update a range.
                // The `min_r_with_3AP` array should be non-increasing.
                // If `min_r_with_3AP[x]` is updated to `x+2k`, then `min_r_with_3AP[x-1]`
                // should be at most `x+2k` (or its previous value if smaller).
                // We can process this efficiently by iterating `l` from `n-1` down to `0`.
                // When we find a 3-AP ending at `x+2k`, it affects `min_r_with_3AP[x]`.
                // The value `min_r_with_3AP[l]` for `l < x` will be `min(min_r_with_3AP[l+1], current_min_r_for_l)`.
                // Let's re-think the loop structure.
                // The current approach is to find all (x, k) and then update min_r_with_3AP.
                // For a fixed x, k, the 3-AP is (x, x+k, x+2k).
                // This means for any l from 0 to x, the substring s[l ... x+2k] contains this 3-AP.
                // So, for any l in [0, x], min_r_with_3AP[l] should be at most x+2k.
                // We want to find the minimum r for each l.
                // So, for each l from 0 to x, we update min_r_with_3AP[l] = min(min_r_with_3AP[l], x+2k).
                // This is a range minimum update.
                // A simpler way is to iterate l from x down to 0.
                // min_r_with_3AP[l] = min(min_r_with_3AP[l], x+2k).
                // This is correct.
                min_r_with_3AP[x] = std::min(min_r_with_3AP[x], x + 2 * k);
            }
        }
    }

    // Now, propagate the minimums.
    // For any l, min_r_with_3AP[l] must be less than or equal to min_r_with_3AP[l+1].
    // If s[l+1...r'] contains a 3-AP, then s[l...r'] also contains it.
    // So, min_r_with_3AP[l] <= min_r_with_3AP[l+1].
    for (int l = n - 2; l >= 0; --l) {
        min_r_with_3AP[l] = std::min(min_r_with_3AP[l], min_r_with_3AP[l + 1]);
    }

    // Calculate the number of invalid pairs (l, r).
    // For each l (0-indexed), any r such that l <= r < min_r_with_3AP[l] is an invalid pair.
    // The number of such r's is min_r_with_3AP[l] - l.
    for (int l = 0; l < n; ++l) {
        invalid_pairs += (min_r_with_3AP[l] - l);
    }

    std::cout << total_pairs - invalid_pairs << std::endl;

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <algorithm>
#include <numeric>

// Function to check if a string is a palindrome
bool is_palindrome(const std::string& str) {
    std::string reversed_str = str;
    std::reverse(reversed_str.begin(), reversed_str.end());
    return str == reversed_str;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::string s;
    std::cin >> s;

    int n = s.length();

    // Check for k=1
    // A single cut divides s into s1 and s2.
    // We can form s2 + s1.
    // We need s2 + s1 to be a palindrome and s2 + s1 != s.
    // Iterate through all possible cut positions (n-1 positions).
    for (int i = 1; i < n; ++i) {
        std::string s1 = s.substr(0, i);
        std::string s2 = s.substr(i);
        std::string new_s = s2 + s1;
        if (new_s != s && is_palindrome(new_s)) {
            std::cout << 1 << std::endl;
            return 0;
        }
    }

    // Check for k=2
    // Two cuts divide s into s1, s2, s3.
    // We need to find if any permutation of these pieces forms a palindrome
    // that is not equal to s.
    // The problem statement implies that pieces are substrings of the initial string
    // in their original order, and then they can be shuffled.
    // For k=2, we have s1, s2, s3.
    // The total length of the string is N.
    // If all characters in s are the same (e.g., "aaaa"), then any permutation
    // of pieces will result in the same string "aaaa".
    // In this case, it's impossible to get a different string.
    // We can check this by counting unique characters.
    bool all_same_char = true;
    for (int i = 1; i < n; ++i) {
        if (s[i] != s[0]) {
            all_same_char = false;
            break;
        }
    }

    if (all_same_char) {
        std::cout << "Impossible" << std::endl;
        return 0;
    }

    // If not all characters are the same, and k=1 didn't work,
    // then k=2 is always possible for a palindrome of length > 1.
    // Consider s = "abacaba".
    // If we cut it as "a" | "bacab" | "a", pieces are p1="a", p2="bacab", p3="a".
    // We can reorder to p3 + p2 + p1 = "a" + "bacab" + "a" = "abacaba" (same as s).
    //
    // The problem states: "cut the paper minimum number of times k, so they got k+1 pieces of paper with substrings of the initial string, and then unite those pieces together to get a new string."
    // This means the pieces are s[0...i-1], s[i...j-1], s[j...N-1].
    //
    // If s is a palindrome and not all characters are the same,
    // then we can always achieve a different palindrome with k=2.
    // Example: "nolon" -> "no" | "l" | "on". Reorder to "on" | "l" | "no" -> "onlno". This is a palindrome and != "nolon".
    // Example: "abacaba". Cut as "a" | "bacab" | "a". Reorder to "a" + "bacab" + "a" = "abacaba".
    // This is not a different string.
    //
    // Let's re-evaluate the k=2 case.
    // If s is a palindrome and not all characters are the same,
    // then there must be at least one character s[i] such that s[i] != s[0].
    // Since s is a palindrome, s[i] == s[n-1-i].
    //
    // Consider cutting s into s[0...i-1], s[i...n-1-i], s[n-i...n-1].
    // Let p1 = s.substr(0, i), p2 = s.substr(i, n-1-2*i), p3 = s.substr(n-i).
    // This is for a specific i.
    //
    // A simpler argument for k=2:
    // If s is a palindrome and not all characters are the same,
    // then there exists some `i` such that `s[i] != s[0]`.
    // Consider the string `s` and its reverse `s_rev`. Since `s` is a palindrome, `s == s_rev`.
    //
    // If `s` is a palindrome and not all characters are the same,
    // then `s` must have at least two distinct characters.
    // For example, `s = "abacaba"`.
    // Cut `s` into `s[0...i-1]`, `s[i...n-1-i]`, `s[n-i...n-1]`.
    // Let `i = 1`. Pieces are `s[0]`, `s[1...n-2]`, `s[n-1]`.
    // `p1 = s[0]`, `p2 = s.substr(1, n-2)`, `p3 = s[n-1]`.
    // Since `s` is a palindrome, `s[0] == s[n-1]`. So `p1 == p3`.
    // The original string is `p1 + p2 + p3`.
    // We can reorder to `p3 + p2 + p1`. This is `p1 + p2 + p1`.
    // This is the same as `s`.
    //
    // What if we cut `s` into `s[0...i-1]`, `s[i...j-1]`, `s[j...n-1]`?
    //
    // The key insight for k=2 is that if `s` is a palindrome and not all characters are the same,
    // we can always find a cut that allows forming a different palindrome.
    //
    // Consider the first half of the string `s_half = s.substr(0, n/2)`.
    // If `s_half` is not all the same character, then there exists `i < n/2` such that `s[i] != s[0]`.
    //
    // Let's try to cut `s` into `s[0...i-1]`, `s[i...n-1-i]`, `s[n-i...n-1]`.
    // Let `p1 = s.substr(0, i)`, `p2 = s.substr(i, n - 2*i)`, `p3 = s.substr(n-i)`.
    // Since `s` is a palindrome, `p1` is the reverse of `p3` (if `i` is chosen such that `p1` and `p3` are symmetric parts).
    // More precisely, `p1` is `s[0...i-1]` and `p3` is `s[n-i...n-1]`.
    // `p3` is `s[n-i]s[n-i+1]...s[n-1]`.
    // `p1` is `s[0]s[1]...s[i-1]`.
    // Since `s` is a palindrome, `s[k] == s[n-1-k]`.
    // So `s[0] == s[n-1]`, `s[1] == s[n-2]`, ..., `s[i-1] == s[n-i]`.
    // This means `p1` is the reverse of `p3` if `p3` is read from right to left.
    // Or, `p1` is equal to `std::string(p3.rbegin(), p3.rend())`.
    //
    // Let's take `s = "abacaba"`. `n=7`.
    // `s[0] = 'a'`, `s[1] = 'b'`, `s[2] = 'a'`, `s[3] = 'c'`.
    // `s[0] != s[1]`.
    // Cut at `i=1`. Pieces are `s[0]`, `s[1...5]`, `s[6]`.
    // `p1 = "a"`, `p2 = "bacab"`, `p3 = "a"`.
    // `p1 + p2 + p3 = "abacaba"`.
    // `p3 + p2 + p1 = "abacaba"`.
    //
    // What if we cut `s` into `s[0...i-1]`, `s[i...j-1]`, `s[j...n-1]`?
    // We need to find `i` and `j` such that `0 < i < j < n`.
    // Let `p1 = s.substr(0, i)`, `p2 = s.substr(i, j-i)`, `p3 = s.substr(j)`.
    // We need to find a permutation `P(p1, p2, p3)` that is a palindrome and not `s`.
    //
    // Consider `s = "nolon"`. `n=5`.
    // `s[0] = 'n'`, `s[1] = 'o'`, `s[2] = 'l'`.
    // `s[0] != s[1]`.
    //
    // If we cut `s` into `s[0...i-1]`, `s[i...n-1-i]`, `s[n-i...n-1]`.
    // For `i=1`: `p1="n"`, `p2="olo"`, `p3="n"`.
    // Permutations: `p1+p2+p3` ("nolon"), `p3+p2+p1` ("nolon").
    //
    // The example "nolon" -> "onlno" uses cuts "no|l|on".
    // Here `p1="no"`, `p2="l"`, `p3="on"`.
    // `i=2`, `j=3`.
    // `p1 = s.substr(0, 2) = "no"`.
    // `p2 = s.substr(2, 1) = "l"`.
    // `p3 = s.substr(3) = "on"`.
    //
    // The new string is `p3 + p2 + p1 = "on" + "l" + "no" = "onlno"`.
    // `is_palindrome("onlno")` is true.
    // `onlno != nolon`.
    // So for "nolon", the answer is 2.
    //
    // This implies that if `k=1` doesn't work, and not all characters are the same,
    // then `k=2` is always the answer.
    //
    // Why is `k=2` always possible if `k=1` fails and not all chars are same?
    // If `k=1` fails, it means for any split `s = s1 + s2`, `s2 + s1` is either `s` or not a palindrome.
    //
    // If `s` is a palindrome and not all characters are the same, then `s` has at least two distinct characters.
    // Let `s = c_0 c_1 ... c_{N-1}`.
    // Since `s` is a palindrome, `c_i = c_{N-1-i}`.
    // Since not all characters are the same, there exists some `i` such that `c_i != c_0`.
    //
    // Consider the string `s_prime = s.substr(0, n-1)`. This is `s` without its last character.
    // If `s_prime` is not a palindrome, then we can cut `s` into `s_prime` and `s[n-1]`.
    // `s1 = s_prime`, `s2 = s[n-1]`.
    // `s2 + s1 = s[n-1] + s_prime`.
    // If `s[n-1] + s_prime` is a palindrome and not equal to `s`, then `k=1`.
    //
    // The problem statement implies that if `k=1` fails, and not all characters are the same,
    // then `k=2` is the answer.
    // This is a common pattern in competitive programming problems: if the simplest cases don't work,
    // and there's no obvious "Impossible" condition, then the next simplest case is the answer.
    //
    // The only "Impossible" case is when all characters are the same.
    // If `s = "qqqq"`, `n=4`.
    // `k=1`:
    // "q" + "qqq" -> "qqqq" (same)
    // "qq" + "qq" -> "qqqq" (same)
    // "qqq" + "q" -> "qqqq" (same)
    // `k=2`:
    // Any permutation of "q", "q", "qq" will be "qqqq".
    // Any permutation of "q", "qq", "q" will be "qqqq".
    // Any permutation of "qq", "q", "q" will be "qqqq".
    // So "Impossible" for "qqqq". This matches our `all_same_char` check.
    //
    // So the logic is:
    // 1. Check if `k=1` is possible. If yes, print 1.
    // 2. If `k=1` is not possible, check if all characters in `s` are the same. If yes, print "Impossible".
    // 3. Otherwise (if `k=1` is not possible, but not all characters are the same), print 2.

    std::cout << 2 << std::endl;

    return 0;
}

#include <iostream>
#include <string>
#include <numeric>
#include <algorithm>

// Function to calculate the number of '1's in a string
int count_ones(const std::string& s) {
    return std::count(s.begin(), s.end(), '1');
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::string a, b;
    std::cin >> a >> b;

    // Calculate initial number of ones in string a
    int ones_in_a = count_ones(a);

    // Calculate initial number of ones in string b
    int ones_in_b = count_ones(b);

    // The maximum possible number of ones in string a after any number of append operations
    // is its current number of ones plus its current length.
    // This is because each append operation adds at most one '1' (if parity is 1).
    // The maximum length of a string is 1000.
    // If a string has length L, and all characters are '1', it has L ones.
    // If we append parity, it becomes L+1. If parity was '1', it now has L+1 ones.
    // So, the maximum number of ones a string of length L can have is L.
    // The maximum number of ones we can ever generate from string 'a' is its initial
    // number of ones plus the number of characters we can append.
    // The maximum length of 'a' can grow up to 1000 (length of b) + (some extra).
    // If we consider the maximum possible length of 'a' to be 2000 (initial 1000 + 1000 appends),
    // then the maximum number of ones would be 2000.
    // However, a simpler bound is that the number of ones can never exceed the length of the string.
    // And the length of the string 'a' that we are interested in (before trimming)
    // must be at least |b|.
    // So, the maximum number of ones in 'a' that we can possibly achieve
