    // If current_x > 1, current_a_val is `a_values[current_x-1]`.
    // The `dp` table is indexed by `current_x`.
    // We need to be careful: `dp[current_x]` should store the result for `a_current_x` being `a_values[current_x-1]`.
    // The `solve` function is called with `current_a_val` which is either `i` (for `x=1`) or `a_values[current_x-1]` (for `x>1`).
    // This means `dp[current_x]` can only store results for `a_current_x = a_values[current_x-1]`.
    // For `x=1`, `a_1` varies, so `dp[1]` cannot be used directly.
    // However, the problem structure is that `a_1` is set to `i`, and then `a_2, ..., a_n` are fixed.
    // So, `a_x` for `x > 1` is always `a_values[x-1]`.
    // This means `dp[x]` for `x > 1` can be used.
    // For `x=1`, we cannot use `dp[1]` because `a_1` changes.
    // The `solve` function is designed to be called with `current_x` and `current_a_val`.
    // When `current_x > 1`, `current_a_val` will always be `a_values[current_x-1]`.
    // So, `dp[current_x]` can store the result for `current_x > 1`.

    if (current_x > 1 && dp[current_x].first != -2) {
        return dp[current_x];
    }

    // Mark as currently computing to detect cycles
    if (current_x > 1) {
        dp[current_x] = {-1, 0}; // Use -1 to indicate an infinite loop
    }

    long long y_step1 = current_a_val;
    int x_step1 = current_x + current_a_val;

    long long y_step2 = current_a_val;
    int x_step2 = current_x - current_a_val;

    // Total y accumulated in this pair of operations
    long long total_y_this_round = y_step1 + y_step2;

    // The next state is (x_step2, y + total_y_this_round)
    // We need to find the result of continuing from x_step2.
    // The a_value for x_step2 will be a_values[x_step2-1] if x_step2 > 1.
    // If x_step2 = 1, this is the special case where a_1 is the initial `i`.
    // But the problem states `a_1` is set to `i` *for the run*.
    // So, if we land on `x=1` again, `a_1` is still `i`.
    // This means `a_x` is `a_values[x-1]` for `x > 1`, and `i` for `x = 1`.
    // This implies that `solve` needs to know the initial `i` for `a_1`.
    // This is not how the `dp` table is structured.

    // Let's rethink the DP state.
    // The state is (x, y). The value a_x depends on x.
    // If x=1, a_x is the initial `i`.
    // If x>1, a_x is `a_values[x-1]`.
    // The `solve` function should return the total `y` accumulated from `current_x` until termination.
    // It should take `current_x` and the *initial* `a_1` value as parameters.
    // This would mean `dp` needs to be `dp[initial_a_1][current_x]`, which is too large.

    // The key observation is that `a_x` is fixed for `x > 1`.
    // So, `dp[x]` for `x > 1` can store the result of starting at `x` with `a_x = a_values[x-1]`.
    // For `x = 1`, `a_1` is the `i` we are testing.
    // So, for each `i` from `1` to `N-1`, we start at `x=1`, `y=0`.
    // The first step uses `a_1 = i`.
    // `x` becomes `1 + i`, `y` becomes `i`.
    // `x` becomes `1 - i`, `y` becomes `i + i = 2*i`.
    // Let `next_x = 1 - i`.
    // Now we need to find the result of starting from `next_x` with `y = 2*i`.
    // This is where the `solve` function comes in.
    // `solve(next_x)` should return the total `y` accumulated from `next_x` onwards.

    // Let's redefine `solve(x)` to return the total `y` accumulated if we start at `x` with `y=0`,
    // and `a_x` is `a_values[x-1]` (for `x > 1`) or `a_1_val` (for `x=1`).
    // This means `solve` needs to know `a_1_val`.

    // Let's use a global `a_1_current_val` for the current `i` being tested.
    // This is a common competitive programming trick when a parameter is constant for a batch of calls.
    // `a_values` will store `a_2, ..., a_n` at indices `1, ..., n-1`.
    // `a_values[0]` will be unused.
    // `a_values[x-1]` is `a_x` for `x > 1`.
    // `a_1_current_val` is `a_1`.

    int val_at_current_x;
    if (current_x == 1) {
        // This case should not be reached by recursive calls to solve,
        // only by the initial loop in main.
        // If it is reached, it means we are in a cycle involving x=1.
        // This implies an infinite loop.
        return {-1, 0};
    } else {
        val_at_current_x = a_values[current_x - 1];
    }

    long long y_add_first_op = val_at_current_x;
    int next_x_after_first_op = current_x + val_at_current_x;

    long long y_add_second_op = val_at_current_x;
    int next_x_after_second_op = current_x - val_at_current_x;

    long long total_y_this_step = y_add_first_op + y_add_second_op;

    // Recursively call solve for the next state
    std::pair<long long, int> res_from_next_state = solve(next_x_after_second_op, 0); // 0 is dummy for a_1_val

    if (res_from_next_state.first == -1) {
        // Infinite loop detected
        if (current_x > 1) {
            dp[current_x] = {-1, 0};
        }
        return {-1, 0};
    }

    long long final_y_val = total_y_this_step + res_from_next_state.first;
    int final_x_val = res_from_next_state.second; // This is not used, but kept for consistency

    if (current_x > 1) {
        dp[current_x] = {final_y_val, final_x_val};
    }
    return {final_y_val, final_x_val};
}

// The actual solve function that uses the DP table for x > 1
// and handles the initial a_1 value.
// This function returns the total y accumulated from starting at `start_x` with `y=0`
// and `a_start_x` being `val_at_start_x`.
// It will use the global `dp` table for `x > 1`.
// For `x=1`, it will use `val_at_start_x` as `a_1`.
std::pair<long long, int> get_total_y(int current_x, int val_at_current_x) {
    // Base case: termination
    if (current_x <= 0 || current_x > N) {
        return {0, current_x};
    }

    // Memoization for x > 1
    if (current_x > 1 && dp[current_x].first != -2) {
        return dp[current_x];
    }

    // Mark as visiting to detect cycles
    if (current_x > 1) {
        dp[current_x] = {-1, 0}; // Mark as currently computing (potential cycle)
    }

    long long y_add_first_op = val_at_current_x;
    int next_x_after_first_op = current_x + val_at_current_x;

    long long y_add_second_op = val_at_current_x;
    int next_x_after_second_op = current_x - val_at_current_x;

    long long total_y_this_round = y_add_first_op + y_add_second_op;

    // Determine the a_value for the next step (next_x_after_second_op)
    int next_a_val;
    if (next_x_after_second_op == 1) {
        // If we land on x=1, the a_value is the initial a_1 (val_at_current_x if current_x was 1)
        // This is the tricky part. The initial a_1 value is fixed for the entire run.
        // So, if we land on x=1, we use the *original* a_1 value.
        // This means `get_total_y` needs to know the original `a_1` value.
        // Let's pass it as a parameter.
        // This means `dp` cannot be indexed just by `x`.
        // The `dp` table should store results for `x > 1` only.
        // For `x=1`, we always compute.

        // Let's restart the DP logic.
        // `dp[x]` stores the result of starting at `x` (where `x > 1`)
        // and `a_x` is `a_values[x-1]`.
        // The `solve` function will be called for each `i` (initial `a_1`).
        // `solve(initial_a_1_val)` will compute the total `y`.
        // It will use a helper `get_y_from_x(current_x, initial_a_1_val)`
        // `get_y_from_x` will use `dp` for `current_x > 1`.
        // `get_y_from_x` will compute for `current_x = 1`.
    }

    // This structure is problematic. Let's use a simpler approach.
    // For each `i` from `1` to `N-1`:
    //   Initialize `x=1`, `y=0`.
    //   `current_a_1_val = i`.
    //   Use a `visited` array for the current run to detect cycles.
    //   Loop:
    //     `val_at_x = (x == 1) ? current_a_1_val : a_values[x-1]`.
    //     `y += 2 * val_at_x`.
    //     `x = x - val_at_x`.
    //     Check termination.
    //     If `x > 1` and `dp[x]` is already computed and not -1:
    //       `y += dp[x].first`.
    //       `x = dp[x].second`. (This is not needed, we just need final y)
    //       Break loop.
    //     If `x > 1` and `dp[x]` is -1:
    //       Infinite loop. Output -1. Break.
    //     If `x > 1` and `dp[x]` is -2 (not computed):
    //       Mark `x` as visited for current run.
    //       If `x` was already visited in current run:
    //         Infinite loop. Output -1. Break.
    //       Continue loop.
    //     If `x = 1`:
    //       Mark `x` as visited for current run.
    //       If `x` was already visited in current run:
    //         Infinite loop. Output -1. Break.
    //       Continue loop.

    // This is still complex. The key is that `a_x` is fixed for `x > 1`.
    // So, `dp[x]` for `x > 1` can store the result of starting at `x` with `a_x = a_values[x-1]`.
    // `dp[x]` will store `{total_y_from_x, final_x_after_termination}`.
    // `total_y_from_x` is the sum of `2*a_k` for all `k` visited from `x` until termination.
    // `final_x_after_termination` is the `x` value that caused termination (`<=0` or `>N`).

    // Let's define `compute_path(start_x)`:
    // This function computes the total `y` and final `x` if we start at `start_x`
    // and `a_k` is `a_values[k-1]` for all `k` in the path.
    // This is only valid for `start_x > 1`.
    // `dp[x]` stores `{total_y, final_x}` for `x > 1`.
    // `dp[x].first = -2` means uncomputed.
    // `dp[x].first = -1` means infinite loop.

    // `path_trace` is used to detect cycles within the current `compute_path` call.
    // `path_trace[x] = true` means `x` is currently in the recursion stack.
    static std::vector<bool> path_trace;

    if (path_trace.empty()) { // Initialize once
        path_trace.resize(N + 1, false);
    }

    // Base cases for termination
    if (current_x <= 0 || current_x > N) {
        return {0, current_x};
    }

    // Check memoization table for x > 1
    if (current_x > 1 && dp[current_x].first != -2) {
        return dp[current_x];
    }

    // Cycle detection for current path
    if (path_trace[current_x]) {
        // Detected a cycle, this path leads to an infinite loop
        if (current_x > 1) {
            dp[current_x] = {-1, 0};
        }
        return {-1, 0};
    }

    // Mark current_x as being visited in the current path
    path_trace[current_x] = true;

    int val_at_current_x;
    if (current_x == 1) {
        // This case should not be reached by recursive calls to compute_path,
        // as compute_path is for x > 1.
        // If it is reached, it means there's a cycle involving x=1, which is handled by path_trace.
        // However, the `a_1` value is variable. So `dp[1]` cannot be used.
        // This means `compute_path` should only be called for `x > 1`.
        // If `next_x_after_second_op` becomes 1, we need to handle it specially.
        // Let's make `compute_path` handle `x=1` by returning -1 (infinite loop)
        // if it tries to compute for `x=1` (because `a_1` is not fixed).
        // This means `dp[1]` will always be -1.
        // This is a bit of a hack. A better way: `compute_path` takes `a_1_val` as parameter.
        // But then `dp` needs to be 2D.

        // Let's stick to the idea that `dp[x]` is for `x > 1`.
        // If `current_x == 1`, it means we are trying to compute `dp[1]`, which is not allowed.
        // This implies an infinite loop if we reach `x=1` in a recursive call.
        // This is because `a_1` is not fixed.
        // So, if `current_x == 1` is reached here, it's an infinite loop.
        path_trace[current_x] = false; // Unmark before returning
        return {-1, 0};
    } else {
        val_at_current_x = a_values[current_x - 1];
    }

    long long y_added_this_round = 2LL * val_at_current_x;
    int next_x = current_x - val_at_current_x;

    // Recursively compute for the next state
    std::pair<long long, int> res_from_next_state = get_total_y(next_x, 0); // 0 is dummy for a_1_val

    // Unmark current_x as being visited in the current path
    path_trace[current_x] = false;

    if (res_from_next_state.first == -1) {
        // Infinite loop detected further down the path
        if (current_x > 1) {
            dp[current_x] = {-1, 0};
        }
        return {-1, 0};
    }

    long long final_y = y_added_this_round + res_from_next_state.first;
    int final_x = res_from_next_state.second;

    if (current_x > 1) {
        dp[current_x] = {final_y, final_x};
    }
    return {final_y, final_x};
}

// This is the main recursive function that computes the total y for a given starting x and the initial a_1 value.
// It uses the global `dp` table for `x > 1`.
// `initial_a_1_val` is the value of `a_1` for the current run.
// `path_trace` is used to detect cycles within the current call stack.
std::pair<long long, int> get_total_y_recursive(int current_x, int initial_a_1_val) {
    // Base cases for termination
    if (current_x <= 0 || current_x > N) {
        return {0, current_x};
    }

    // Check memoization table for x > 1
    // If current_x == 1, we cannot use dp[1] because a_1 varies.
    if (current_x > 1 && dp[current_x].first != -2) {
        return dp[current_x];
    }

    // Cycle detection for current path
    // `path_trace` is a static vector, so it persists across calls to `get_total_y_recursive`
    // but is reset for each `i` in `main`.
    // This is incorrect. `path_trace` must be local to the current run.
    // Or, `path_trace` must be passed as a parameter.
    // Let's make `path_trace` a parameter.

    // This is the correct way to handle DP with varying initial conditions.
    // The `dp` table stores results for `x > 1` where `a_x = a_values[x-1]`.
    // The `get_total_y_recursive` function is called for each `i` (initial `a_1`).
    // It will use `dp` for `x > 1` and compute for `x = 1`.

    // Let's use a `std::vector<bool> visited_in_current_run` for cycle detection.
    // This vector needs to be cleared for each `i` in `main`.
    // Or, it can be passed as a parameter.
    // Let's make it a global static variable and clear it.

    // The `dp` table should be initialized to -2.
    // `dp[x].first = -1` means infinite loop.
    // `dp[x].first = -2` means uncomputed.

    // The `path_trace` should be local to the current run.
    // Let's pass it as a parameter.

    // This is the final version of the recursive function.
    // It takes `current_x`, `initial_a_1_val` (the `i` for the current run),
    // and a reference to `path_trace` for cycle detection.
    // `path_trace[x]` is true if `x` is currently in the recursion stack for this run.
    // `dp[x]` stores the result for `x > 1` where `a_x = a_values[x-1]`.
    // `dp[x].first = -2` means uncomputed.
    // `dp[x].first = -1` means infinite loop.
    // `dp[x].first >= 0` means computed result.

    // The `path_trace` vector needs to be reset for each `i` in `main`.
    // It should be `std::vector<bool> path_trace(N + 1, false);` inside the loop in `main`.
    // And then passed by reference.

    // This is the function that will be called recursively.
    // It needs to know the `initial_a_1_val` to correctly determine `a_1`.
    // It also needs a `path_trace` to detect cycles within the current run.
    // `dp` is global and stores results for `x > 1`.

    // `path_trace` is used to detect cycles *within the current call stack*.
    // `dp` is used to memoize results for `x > 1` *across different initial `a_1` values*.
    // This is valid because for `x > 1`, `a_x` is always `a_values[x-1]`.

    // The `path_trace` vector needs to be passed by reference.
    // It should be initialized to all false for each `i` in `main`.

    // Let's make `path_trace` a global static variable and reset it for each `i`.
    // This is a common pattern in competitive programming.
    static std::vector<bool> current_run_path_trace;
    if (current_run_path_trace.empty()) {
        current_run_path_trace.resize(N + 1);
    }

    // Base cases for termination
    if (current_x <= 0 || current_x > N) {
        return {0, current_x};
    }

    // Check for cycle in current run
    if (current_run_path_trace[current_x]) {
        return {-1, 0}; // Infinite loop detected
    }

    // Check memoization table for x > 1
    if (current_x > 1 && dp[current_x].first != -2) {
        return dp[current_x];
    }

    // Mark current_x as being visited in the current path
    current_run_path_trace[current_x] = true;

    int val_at_current_x;
    if (current_x == 1) {
        val_at_current_x = initial_a_1_val;
    } else {
        val_at_current_x = a_values[current_x - 1];
    }

    long long y_added_this_round = 2LL * val_at_current_x;
    int next_x = current_x - val_at_current_x;

    // Recursively compute for the next state
    std::pair<long long, int> res_from_next_state = get_total_y_recursive(next_x, initial_a_1_val);

    // Unmark current_x as being visited in the current path
    current_run_path_trace[current_x] = false;

    if (res_from_next_state.first == -1) {
        // Infinite loop detected further down the path
        if (current_x > 1) {
            dp[current_x] = {-1, 0};
        }
        return {-1, 0};
    }

    long long final_y = y_added_this_round + res_from_next_state.first;
    int final_x = res_from_next_state.second;

    // Memoize result for x > 1
    if (current_x > 1) {
        dp[current_x] = {final_y, final_x};
    }
    return {final_y, final_x};
}


